    private enum ControlAction {
        LEFT("Left", "left", LanProtocol.INPUT_LEFT, KeyCode.A, KeyCode.LEFT, KeyCode.F, KeyCode.J),
        RIGHT("Right", "right", LanProtocol.INPUT_RIGHT, KeyCode.D, KeyCode.RIGHT, KeyCode.H, KeyCode.L),
        JUMP("Jump", "jump", LanProtocol.INPUT_JUMP, KeyCode.W, KeyCode.UP, KeyCode.T, KeyCode.I),
        ATTACK("Attack", "attack", LanProtocol.INPUT_ATTACK, KeyCode.SPACE, KeyCode.ENTER, KeyCode.Y, KeyCode.O),
        SPECIAL("Special", "special", LanProtocol.INPUT_SPECIAL, KeyCode.SHIFT, KeyCode.SLASH, KeyCode.U, KeyCode.P),
        GRAB("Grab", "grab", LanProtocol.INPUT_GRAB, KeyCode.R, KeyCode.BACK_SPACE, KeyCode.N, KeyCode.SEMICOLON),
        BLOCK("Block / Fast Fall", "block", LanProtocol.INPUT_BLOCK, KeyCode.S, KeyCode.DOWN, KeyCode.G, KeyCode.K),
        TAUNT_CYCLE("Taunt Cycle", "taunt_cycle", LanProtocol.INPUT_TAUNT_CYCLE, KeyCode.Q, KeyCode.NUMPAD1, KeyCode.NUMPAD2, KeyCode.NUMPAD3),
        TAUNT_EXECUTE("Taunt Execute", "taunt_execute", LanProtocol.INPUT_TAUNT_EXEC, KeyCode.E, KeyCode.NUMPAD4, KeyCode.NUMPAD5, KeyCode.NUMPAD6);

        final String label;
        final String prefKey;
        final int inputMask;
        final KeyCode[] defaults;

        ControlAction(String label, String prefKey, int inputMask, KeyCode... defaults) {
            this.label = label;
            this.prefKey = prefKey;
            this.inputMask = inputMask;
            this.defaults = defaults;
        }

        KeyCode defaultKey(int playerIdx) {
            if (playerIdx >= 0 && playerIdx < defaults.length) {
                return defaults[playerIdx];
            }
            return defaults[0];
        }
    }

    private static final String[] CONTROL_ACTION_PREF_KEYS = Arrays.stream(ControlAction.values())
            .map(action -> action.prefKey)
            .toArray(String[]::new);

    private Node controllerGlyphHint(String glyph, String glyphColor, String text) {
        StackPane badge = new StackPane();
        double badgeWidth = glyph != null && glyph.length() > 1 ? Math.max(54.0, glyph.length() * 12.0 + 18.0) : 34.0;
        badge.setMinSize(badgeWidth, 34);
        badge.setPrefSize(badgeWidth, 34);
        badge.setMaxSize(badgeWidth, 34);
        badge.setStyle("-fx-background-color: " + glyphColor + "; -fx-background-radius: 18; -fx-border-color: rgba(255,255,255,0.5); -fx-border-width: 1.5; -fx-border-radius: 18;");

        Label glyphLabel = new Label(glyph == null ? "" : glyph.toUpperCase(Locale.ROOT));
        glyphLabel.setFont(Font.font("Arial Black", FontWeight.BOLD, glyph != null && glyph.length() > 1 ? 11 : 18));
        glyphLabel.setTextFill(Color.WHITE);
        badge.getChildren().add(glyphLabel);

        Label textLabel = new Label(text);
        textLabel.setFont(Font.font("Consolas", 15));
        textLabel.setTextFill(Color.web("#ECEFF1"));
        applyNoEllipsis(textLabel);

        HBox hint = new HBox(8, badge, textLabel);
        hint.setAlignment(Pos.CENTER_LEFT);
        return hint;
    }

