        return String.format(
                Locale.US,
                "Health: %.1f | Size: %.2fx | Power: %.2fx | Speed: %.2fx",
                nullRockTrueFormHealth(),
                nullRockTrueFormSizeMultiplier(),
                nullRockTrueFormPowerMultiplier(),
                nullRockTrueFormSpeedMultiplier()
        );
