    private int adjustedBossCpuLevel(int playerIdx, int level) {
        if (playerIdx < 0 || playerIdx >= players.length || playerIdx >= isAI.length || !isAI[playerIdx]) return level;
        Bird bird = players[playerIdx];
        if (bird == null || !isBossName(bird.name)) return level;
        int reduction = BOSS_CPU_LEVEL_REDUCTION;
        if (isBossRushBossContext(bird.name)) {
            reduction += BOSS_RUSH_CPU_LEVEL_REDUCTION;
        }
        return Math.max(1, level - reduction);
    }

    private void playMenuMusic() {
        disposeGameplayMusicPlayer();
        victoryMusicPlayer = stopMediaPlayer(victoryMusicPlayer, false);
        if (!musicEnabled) {
            menuMusicPlayer = stopMediaPlayer(menuMusicPlayer, false);
            return;
        }
        if (menuMusicPlayer != null) {
            MediaPlayer.Status status = menuMusicPlayer.getStatus();
            if (status != MediaPlayer.Status.PLAYING && status != MediaPlayer.Status.STALLED) {
                menuMusicPlayer.play();
            }
        }
    }

    private MediaPlayer startStandaloneMusicTrack() {
        stopPersistentMusicPlayers();
        disposeGameplayMusicPlayer();
        if (!musicEnabled) {
            return null;
        }
        try {
            MediaPlayer player = new MediaPlayer(new Media(resourceUrl("/sounds/" + "wild-west-ultimate-battle.mp3")));
            player.setCycleCount(MediaPlayer.INDEFINITE);
            player.setVolume(BirdGame3.MATCH_MUSIC_BASE_VOLUME * effectiveMusicVolume());
            player.play();
            return player;
        } catch (Exception e) {
            System.out.println("Music not found: " + "wild-west-ultimate-battle.mp3");
            return null;
        }
    }

    // === WIIMOTE-FRIENDLY MENU NAVIGATION (WASD + Space) ===
    private void setupKeyboardNavigation(Scene scene) {
        fitSceneButtons(scene.getRoot());
        javafx.application.Platform.runLater(() -> fitSceneButtons(scene.getRoot()));
        scene.widthProperty().addListener((obs, oldV, newV) -> fitSceneButtons(scene.getRoot()));
        scene.heightProperty().addListener((obs, oldV, newV) -> fitSceneButtons(scene.getRoot()));
        applyFocusRingStyle(scene);
        scene.addEventFilter(MouseEvent.MOUSE_PRESSED, e -> {
            setConsoleHighlightActive(false, scene);
            if (!(e.getTarget() instanceof Node target)) return;
            if (isInteractiveTarget(target)) return;
            Node focus = scene.getFocusOwner();
            if (focus != null) focus.requestFocus();
            e.consume();
        });
        scene.setOnKeyPressed(e -> {
            KeyCode code = e.getCode();

            if (code == KeyCode.F11 && scene.getWindow() instanceof Stage s) {
                fullscreenEnabled = !fullscreenEnabled;
                applyDisplaySettings(s);
                saveAchievements();
                e.consume();
                return;
            }

            // WASD -> arrows for focus
            KeyCode arrow = switch (code) {
                case W -> KeyCode.UP;
                case S -> KeyCode.DOWN;
                case A -> KeyCode.LEFT;
                case D -> KeyCode.RIGHT;
                default -> null;
            };
            if (arrow != null) {
                e.consume();
                Node focus = scene.getFocusOwner();
                if (focus != null) {
                    focus.fireEvent(new KeyEvent(KeyEvent.KEY_PRESSED, "", "", arrow, false, false, false, false));
                }
            }

            // SPACE/ENTER = SELECT + CLICK SOUND ON EVERY BUTTON
            if (code == KeyCode.SPACE || code == KeyCode.ENTER) {
                Node focus = scene.getFocusOwner();
                if (activateInteractiveNode(focus)) {
                    e.consume();
                }
            }
        });
    }

    private void startWiimoteMenuTimer() {
        if (wiimoteMenuTimer != null) {
            wiimoteMenuTimer.stop();
        }
        wiimoteMenuTimer = new AnimationTimer() {
            @Override
            public void handle(long now) {
                pollWiimoteMenuNavigation();
            }
        };
        wiimoteMenuTimer.start();
    }

    private WiimoteMappedState mergedControllerState(WiimoteMappedState first, WiimoteMappedState second) {
        WiimoteMappedState a = first == null ? WiimoteMappedState.off("Controller unavailable") : first;
        WiimoteMappedState b = second == null ? WiimoteMappedState.off("Controller unavailable") : second;
        boolean connected = a.connected() || b.connected();
        String status = connected
                ? (a.connected() ? a.status() : b.status())
                : ((a.status() != null && !a.status().isBlank()) ? a.status() : b.status());
        return new WiimoteMappedState(
                connected,
                a.left() || b.left(),
                a.right() || b.right(),
                a.jump() || b.jump(),
                a.attack() || b.attack(),
                a.special() || b.special(),
                a.block() || b.block(),
                a.grab() || b.grab(),
                a.tauntCycle() || b.tauntCycle(),
                a.tauntExecute() || b.tauntExecute(),
                a.menuUp() || b.menuUp(),
                a.menuDown() || b.menuDown(),
                a.menuLeft() || b.menuLeft(),
                a.menuRight() || b.menuRight(),
                a.menuUpHeld() || b.menuUpHeld(),
                a.menuDownHeld() || b.menuDownHeld(),
                a.menuLeftHeld() || b.menuLeftHeld(),
                a.menuRightHeld() || b.menuRightHeld(),
                a.menuSelectHeld() || b.menuSelectHeld(),
                a.menuBackHeld() || b.menuBackHeld(),
                a.menuPauseHeld() || b.menuPauseHeld(),
                a.menuSelect() || b.menuSelect(),
                a.menuBack() || b.menuBack(),
                a.menuPause() || b.menuPause(),
                status
        );
    }

    private boolean usesXboxControllerAssignments() {
        Scene scene = currentStage == null ? null : currentStage.getScene();
        if (scene != null && fightSetupSelectorController(scene) != null) {
            return false;
        }
        return scene != gameplayScene || isPlainLocalFightGameplay();
    }

    private boolean isPlainLocalFightGameplay() {
        return lanModeActive
                || trainingModeActive
                || storyModeActive
                || adventureModeActive
                || classicModeActive
                || competitionSeriesActive;
    }

    private boolean keyboardControlsPlayer(int playerIdx) {
        return !usesXboxControllerAssignments() && xboxAssignedSlotForPlayer(playerIdx) >= 0;
    }

    private int xboxAssignedSlotForPlayer(int playerIdx) {
        if (playerIdx < 0 || playerIdx >= xboxAssignedSlotByPlayer.length) {
            return -1;
        }
        return xboxAssignedSlotByPlayer[playerIdx];
    }

    private int xboxAssignedPlayerForSlot(int xboxSlot) {
        if (xboxSlot < 0 || xboxSlot >= xboxAssignedPlayerBySlot.length) {
            return -1;
        }
        return xboxAssignedPlayerBySlot[xboxSlot];
    }

    private void clearXboxAssignmentForPlayer(int playerIdx) {
        if (playerIdx < 0 || playerIdx >= xboxAssignedSlotByPlayer.length) {
            return;
        }
        int xboxSlot = xboxAssignedSlotByPlayer[playerIdx];
        xboxAssignedSlotByPlayer[playerIdx] = -1;
        if (xboxSlot >= 0 && xboxSlot < xboxAssignedPlayerBySlot.length && xboxAssignedPlayerBySlot[xboxSlot] == playerIdx) {
            xboxAssignedPlayerBySlot[xboxSlot] = -1;
        }
        if (xboxPendingAssignPlayerIdx == playerIdx) {
            xboxPendingAssignPlayerIdx = -1;
        }
    }

    private void clearXboxAssignmentForSlot(int xboxSlot) {
        if (xboxSlot < 0 || xboxSlot >= xboxAssignedPlayerBySlot.length) {
            return;
        }
        int playerIdx = xboxAssignedPlayerBySlot[xboxSlot];
        xboxAssignedPlayerBySlot[xboxSlot] = -1;
        if (playerIdx >= 0 && playerIdx < xboxAssignedSlotByPlayer.length && xboxAssignedSlotByPlayer[playerIdx] == xboxSlot) {
            xboxAssignedSlotByPlayer[playerIdx] = -1;
            if (xboxPendingAssignPlayerIdx == playerIdx) {
                xboxPendingAssignPlayerIdx = -1;
            }
        }
    }

    private boolean assignXboxControllerToPlayer(int xboxSlot, int playerIdx) {
        if (xboxSlot < 0 || xboxSlot >= xboxAssignedPlayerBySlot.length) {
            return false;
        }
        if (playerIdx < 0 || playerIdx >= activePlayers || playerIdx >= xboxAssignedSlotByPlayer.length || isAI[playerIdx]) {
            return false;
        }
        int existingPlayer = xboxAssignedPlayerForSlot(xboxSlot);
        if (existingPlayer == playerIdx) {
            xboxPendingAssignPlayerIdx = -1;
            return false;
        }
        clearXboxAssignmentForSlot(xboxSlot);
        clearXboxAssignmentForPlayer(playerIdx);
        xboxAssignedPlayerBySlot[xboxSlot] = playerIdx;
        xboxAssignedSlotByPlayer[playerIdx] = xboxSlot;
        xboxPendingAssignPlayerIdx = -1;
        return true;
    }

    private void normalizeXboxAssignmentsForLocalSetup() {
        boolean[] usedSlots = new boolean[xboxAssignedPlayerBySlot.length];
        Arrays.fill(xboxAssignedPlayerBySlot, -1);
        for (int playerIdx = 0; playerIdx < xboxAssignedSlotByPlayer.length; playerIdx++) {
            int xboxSlot = xboxAssignedSlotByPlayer[playerIdx];
            boolean valid = playerIdx < activePlayers
                    && !isAI[playerIdx]
                    && xboxSlot >= 0
                    && xboxSlot < xboxAssignedPlayerBySlot.length
                    && !usedSlots[xboxSlot];
            if (!valid) {
                xboxAssignedSlotByPlayer[playerIdx] = -1;
                continue;
            }
            usedSlots[xboxSlot] = true;
            xboxAssignedPlayerBySlot[xboxSlot] = playerIdx;
        }
        if (xboxPendingAssignPlayerIdx >= activePlayers
                || xboxPendingAssignPlayerIdx >= isAI.length
                || (xboxPendingAssignPlayerIdx >= 0 && isAI[xboxPendingAssignPlayerIdx])) {
            xboxPendingAssignPlayerIdx = -1;
        }
    }

    private int nextOpenXboxJoinPlayer() {
        for (int playerIdx = 1; playerIdx < activePlayers; playerIdx++) {
            if (!isAI[playerIdx] && xboxAssignedSlotForPlayer(playerIdx) < 0) {
                return playerIdx;
            }
        }
        if (activePlayers > 0 && !isAI[0] && xboxAssignedSlotForPlayer(0) < 0) {
            return 0;
        }
        return -1;
    }

    private void resetXboxJoinHeldState() {
        Arrays.fill(xboxJoinHeld, false);
        Arrays.fill(xboxLeaveHeld, false);
        Arrays.fill(xboxLastConnectedBySlot, false);
    }

    private void pollXboxJoinAssignments(Scene scene, FightSetupSelectorController controller) {
        if (scene == null || controller == null || xboxInputManager == null) {
            resetXboxJoinHeldState();
            return;
        }
        normalizeXboxAssignmentsForLocalSetup();
        boolean changed = false;
        boolean assignmentChanged = false;
        for (int xboxSlot = 0; xboxSlot < xboxJoinHeld.length; xboxSlot++) {
            WiimoteMappedState state = xboxInputManager.stateForSlot(xboxSlot);
            boolean connected = state.connected();
            if (xboxLastConnectedBySlot[xboxSlot] != connected) {
                xboxLastConnectedBySlot[xboxSlot] = connected;
                changed = true;
            }
            int assignedPlayer = xboxAssignedPlayerForSlot(xboxSlot);
            boolean leaveHeld = connected && xboxInputManager.viewPressedForSlot(xboxSlot);
            if (leaveHeld && !xboxLeaveHeld[xboxSlot] && assignedPlayer >= 0) {
                clearXboxAssignmentForSlot(xboxSlot);
                if (xboxDisconnectPlayerIdx == assignedPlayer) {
                    xboxDisconnectPlayerIdx = -1;
                }
                changed = true;
                assignmentChanged = true;
            }
            xboxLeaveHeld[xboxSlot] = leaveHeld;

            boolean joinHeld = connected && state.menuSelect();
            if (joinHeld && !xboxJoinHeld[xboxSlot] && xboxAssignedPlayerForSlot(xboxSlot) < 0) {
                int targetPlayer = xboxPendingAssignPlayerIdx >= 0 ? xboxPendingAssignPlayerIdx : nextOpenXboxJoinPlayer();
                if (assignXboxControllerToPlayer(xboxSlot, targetPlayer)) {
                    changed = true;
                    assignmentChanged = true;
                }
            }
            xboxJoinHeld[xboxSlot] = joinHeld;
        }
        if (assignmentChanged) {
            playButtonClick();
        }
        if (changed) {
            controller.refreshControllerAssignments();
        }
    }

    private WiimoteMappedState xboxStateForPlayer(int playerIdx) {
        if (xboxInputManager == null) {
            return WiimoteMappedState.off("Xbox controller unavailable");
        }
        if (usesXboxControllerAssignments()) {
            return xboxInputManager.stateForSlot(playerIdx);
        }
        int xboxSlot = xboxAssignedSlotForPlayer(playerIdx);
        if (xboxSlot < 0) {
            return WiimoteMappedState.off("Xbox controller unassigned");
        }
        return xboxInputManager.stateForSlot(xboxSlot);
    }

    private boolean isXboxSlotConnected(int xboxSlot) {
        if (xboxInputManager == null || xboxSlot < 0 || xboxSlot >= XBOX_CONTROLLER_SLOTS) {
            return false;
        }
        return xboxInputManager.isConnected(xboxSlot);
    }

    private List<Integer> disconnectedAssignedXboxPlayers() {
        if (usesXboxControllerAssignments()) {
            return List.of();
        }
        List<Integer> disconnected = new ArrayList<>();
        int maxPlayers = Math.min(activePlayers, xboxAssignedSlotByPlayer.length);
        for (int playerIdx = 0; playerIdx < maxPlayers; playerIdx++) {
            int xboxSlot = xboxAssignedSlotForPlayer(playerIdx);
            if (xboxSlot >= 0 && !isXboxSlotConnected(xboxSlot)) {
                disconnected.add(playerIdx);
            }
        }
        return disconnected;
    }

    private boolean hasDisconnectedAssignedXboxPlayers() {
        return !disconnectedAssignedXboxPlayers().isEmpty();
    }

    private void refreshXboxDisconnectMarker() {
        List<Integer> disconnected = disconnectedAssignedXboxPlayers();
        xboxDisconnectPlayerIdx = disconnected.isEmpty() ? -1 : disconnected.getFirst();
    }

    private boolean handleAssignedXboxDisconnectDuringGameplay() {
        if (isPlainLocalFightGameplay()
                || currentStage == null
                || currentStage.getScene() != gameplayScene
                || isPaused) {
            return false;
        }
        refreshXboxDisconnectMarker();
        if (xboxDisconnectPlayerIdx < 0) {
            return false;
        }
        togglePause(currentStage);
        return true;
    }

    private String xboxDisconnectSummary(int playerIdx) {
        int xboxSlot = xboxAssignedSlotForPlayer(playerIdx);
        String slotText = xboxSlot >= 0 ? "Xbox " + (xboxSlot + 1) : "assigned controller";
        return "P" + (playerIdx + 1) + " lost " + slotText + ".";
    }

    private WiimoteMappedState controllerMenuState() {
        WiimoteMappedState wiimoteState = wiimoteInputManager == null
                ? WiimoteMappedState.off("Wiimote HID unavailable")
                : wiimoteInputManager.menuState();
        WiimoteMappedState xboxState = xboxInputManager == null
                ? WiimoteMappedState.off("Xbox controller unavailable")
                : xboxInputManager.menuState();
        return mergedControllerState(wiimoteState, xboxState);
    }

    private WiimoteMappedState controllerStateForPlayer(int playerIdx) {
        WiimoteMappedState wiimoteState = wiimoteInputManager == null
                ? WiimoteMappedState.off("Wiimote HID unavailable")
                : wiimoteInputManager.stateForPlayer(playerIdx);
        WiimoteMappedState xboxState = xboxStateForPlayer(playerIdx);
        return mergedControllerState(wiimoteState, xboxState);
    }

    private void pollWiimoteMenuNavigation() {
        if ((wiimoteInputManager == null && xboxInputManager == null) || currentStage == null) {
            return;
        }
        if (!currentStage.isFocused()) {
            resetWiimoteMenuHeldState();
            resetWiimoteSelectorHeldState();
            return;
        }
        Scene scene = currentStage.getScene();
        if (scene == null || (scene == gameplayScene && !isPaused)) {
            resetWiimoteMenuHeldState();
            resetWiimoteSelectorHeldState();
            return;
        }

        if (isWiimoteSelectorScene(scene)) {
            pollWiimoteSelectorNavigation(scene);
            return;
        }

        resetWiimoteSelectorHeldState();

        WiimoteMappedState state = controllerMenuState();
        if (pollWiimotePausedGameplayMenu(scene, state)) {
            Arrays.fill(wiimoteMenuDirectionHeld, false);
            return;
        }
        if (pollWiimoteMenuPointer(scene, state)) {
            Arrays.fill(wiimoteMenuDirectionHeld, false);
            return;
        }
        if (state.menuUp() && !wiimoteMenuDirectionHeld[0]) {
            dispatchWiimoteMenuDirectional(scene, KeyCode.UP);
        }
        wiimoteMenuDirectionHeld[0] = state.menuUp();
        if (state.menuDown() && !wiimoteMenuDirectionHeld[1]) {
            dispatchWiimoteMenuDirectional(scene, KeyCode.DOWN);
        }
        wiimoteMenuDirectionHeld[1] = state.menuDown();
        if (state.menuLeft() && !wiimoteMenuDirectionHeld[2]) {
            dispatchWiimoteMenuDirectional(scene, KeyCode.LEFT);
        }
        wiimoteMenuDirectionHeld[2] = state.menuLeft();
        if (state.menuRight() && !wiimoteMenuDirectionHeld[3]) {
            dispatchWiimoteMenuDirectional(scene, KeyCode.RIGHT);
        }
        wiimoteMenuDirectionHeld[3] = state.menuRight();

        boolean selectHeld = state.menuSelect();
        if (selectHeld && !wiimoteMenuSelectHeld) {
            dispatchWiimoteMenuKey(scene, KeyCode.ENTER);
        }
        wiimoteMenuSelectHeld = selectHeld;

        boolean backHeld = state.menuBack();
        if (backHeld && !wiimoteMenuBackHeld) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteMenuBackHeld = backHeld;

        boolean pauseHeld = state.menuPause();
        if (pauseHeld && !wiimoteMenuPauseHeld) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteMenuPauseHeld = pauseHeld;
    }

    private boolean pollWiimotePausedGameplayMenu(Scene scene, WiimoteMappedState state) {
        if (scene != gameplayScene || !isPaused) {
            resetWiimotePauseMenuHeldState();
            return false;
        }
        VBox pauseMenu = currentPauseMenu();
        if (pauseMenu == null) {
            resetWiimotePauseMenuHeldState();
            return false;
        }
        boolean connected = state != null && state.connected();
        long now = System.nanoTime();
        if (connected && shouldTriggerPauseMenuDirection(0, state.menuUpHeld(), now)) {
            movePauseMenuFocus(scene, pauseMenu, KeyCode.UP);
        }
        if (connected && shouldTriggerPauseMenuDirection(1, state.menuDownHeld(), now)) {
            movePauseMenuFocus(scene, pauseMenu, KeyCode.DOWN);
        }
        if (connected && shouldTriggerPauseMenuDirection(2, state.menuLeftHeld(), now)) {
            movePauseMenuFocus(scene, pauseMenu, KeyCode.LEFT);
        }
        if (connected && shouldTriggerPauseMenuDirection(3, state.menuRightHeld(), now)) {
            movePauseMenuFocus(scene, pauseMenu, KeyCode.RIGHT);
        }
        if (!connected) {
            resetWiimotePauseMenuHeldState();
        }

        boolean selectHeld = connected && state.menuSelect();
        if (selectHeld && !wiimoteMenuSelectHeld) {
            Node focus = scene.getFocusOwner();
            if (focus instanceof Button button) {
                playButtonClick();
                button.fire();
            }
        }
        wiimoteMenuSelectHeld = selectHeld;

        boolean backHeld = connected && state.menuBack();
        if (backHeld && !wiimoteMenuBackHeld && currentStage != null) {
            togglePause(currentStage);
            wiimoteMenuBackHeld = true;
            return true;
        }
        wiimoteMenuBackHeld = backHeld;

        boolean pauseHeld = connected && state.menuPause();
        if (pauseHeld && !wiimoteMenuPauseHeld && currentStage != null) {
            togglePause(currentStage);
            wiimoteMenuPauseHeld = true;
            return true;
        }
        wiimoteMenuPauseHeld = pauseHeld;
        return true;
    }

    private boolean shouldTriggerPauseMenuDirection(int index, boolean held, long now) {
        return wiimotePauseMenuDirectionRepeater.shouldTrigger(index, held, now);
    }

    private boolean pollWiimoteMenuPointer(Scene scene, WiimoteMappedState state) {
        if (!usesWiimoteUiPointer(scene)) {
            return false;
        }
        Robot robot = wiimoteUiRobot();
        if (robot == null) {
            return false;
        }

        syncWiimoteMenuPointer(scene);
        setConsoleHighlightActive(false, scene);

        long now = System.nanoTime();
        double dtSeconds = wiimoteMenuPointerDeltaSeconds(now);
        double horizontal = 0.0;
        double vertical = 0.0;
        if (state != null && state.connected()) {
            if (state.menuLeftHeld()) {
                horizontal -= 1.0;
            }
            if (state.menuRightHeld()) {
                horizontal += 1.0;
            }
            if (state.menuUpHeld()) {
                vertical -= 1.0;
            }
            if (state.menuDownHeld()) {
                vertical += 1.0;
            }
        }
        if (horizontal != 0.0 || vertical != 0.0) {
            moveWiimoteMenuPointer(scene, horizontal, vertical, dtSeconds);
        }

        boolean selectHeld = state != null && state.connected() && state.menuSelectHeld();
        if (selectHeld && !wiimoteMenuSelectHeld) {
            setFightSetupClawCursor(scene, true);
            robot.mousePress(MouseButton.PRIMARY);
            wiimoteMenuMousePressed = true;
        } else if (!selectHeld && wiimoteMenuSelectHeld) {
            releaseWiimoteMenuPointerPress();
            setFightSetupClawCursor(scene, false);
        }
        wiimoteMenuSelectHeld = selectHeld;

        boolean backHeld = state != null && state.connected() && state.menuBack();
        if (backHeld && !wiimoteMenuBackHeld) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteMenuBackHeld = backHeld;

        boolean pauseHeld = state != null && state.connected() && state.menuPause();
        if (pauseHeld && !wiimoteMenuPauseHeld) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteMenuPauseHeld = pauseHeld;
        return true;
    }

    private boolean usesWiimoteUiPointer(Scene scene) {
        return scene != null && scene != gameplayScene && !isWiimoteSelectorScene(scene);
    }

    private Robot wiimoteUiRobot() {
        if (wiimoteUiRobot != null) {
            return wiimoteUiRobot;
        }
        try {
            wiimoteUiRobot = new Robot();
        } catch (Exception e) {
            wiimoteUiRobot = null;
        }
        return wiimoteUiRobot;
    }

    private void installWiimoteMenuPointerTracking(Scene scene) {
        if (scene == null || Boolean.TRUE.equals(scene.getProperties().get(SCENE_PROP_WIIMOTE_POINTER_TRACKING))) {
            return;
        }
        scene.getProperties().put(SCENE_PROP_WIIMOTE_POINTER_TRACKING, Boolean.TRUE);
        EventHandler<MouseEvent> tracker = e -> updateWiimoteMenuPointerScenePosition(scene, e.getSceneX(), e.getSceneY());
        scene.addEventFilter(MouseEvent.MOUSE_MOVED, tracker);
        scene.addEventFilter(MouseEvent.MOUSE_DRAGGED, tracker);
        scene.addEventFilter(MouseEvent.MOUSE_PRESSED, tracker);
        scene.addEventFilter(MouseEvent.MOUSE_RELEASED, tracker);
    }

    private void syncWiimoteMenuPointer(Scene scene) {
        if (scene == null) {
            return;
        }
        if (wiimoteMenuPointerScene == scene && wiimoteMenuPointerInitialized) {
            clampWiimoteMenuPointerToScene(scene);
            return;
        }
        wiimoteMenuPointerScene = scene;
        wiimoteMenuPointerLastNs = 0L;

        Point2D scenePoint = wiimoteMenuPointerSceneFromRobot(scene);
        if (scenePoint != null) {
            updateWiimoteMenuPointerScenePosition(scene, scenePoint.getX(), scenePoint.getY());
        } else {
            double width = scene.getWidth() > 0 ? scene.getWidth() : WIDTH;
            double height = scene.getHeight() > 0 ? scene.getHeight() : HEIGHT;
            updateWiimoteMenuPointerScenePosition(scene, width / 2.0, height / 2.0);
        }
        moveWiimoteMenuPointerTo(scene, wiimoteMenuPointerSceneX, wiimoteMenuPointerSceneY);
    }

    private Point2D wiimoteMenuPointerSceneFromRobot(Scene scene) {
        Robot robot = wiimoteUiRobot();
        if (scene == null || robot == null) {
            return null;
        }
        Point2D screenPoint = robot.getMousePosition();
        Window window = scene.getWindow();
        if (window == null) {
            return null;
        }
        return new Point2D(
                screenPoint.getX() - window.getX() - scene.getX(),
                screenPoint.getY() - window.getY() - scene.getY()
        );
    }

    private void moveWiimoteMenuPointer(Scene scene, double horizontal, double vertical, double dtSeconds) {
        if (scene == null) {
            return;
        }
        double length = Math.hypot(horizontal, vertical);
        if (length <= 0.0) {
            return;
        }
        double distance = WIIMOTE_UI_CURSOR_SPEED * Math.max(0.0, dtSeconds);
        double nextX = wiimoteMenuPointerSceneX + horizontal / length * distance;
        double nextY = wiimoteMenuPointerSceneY + vertical / length * distance;
        moveWiimoteMenuPointerTo(scene, nextX, nextY);
    }

    private void moveWiimoteMenuPointerTo(Scene scene, double sceneX, double sceneY) {
        Robot robot = wiimoteUiRobot();
        Point2D screenPoint = sceneToScreenPoint(scene, sceneX, sceneY);
        if (scene == null || robot == null || screenPoint == null) {
            return;
        }
        updateWiimoteMenuPointerScenePosition(scene, sceneX, sceneY);
        robot.mouseMove(screenPoint.getX(), screenPoint.getY());
    }

    private Point2D sceneToScreenPoint(Scene scene, double sceneX, double sceneY) {
        if (scene == null) {
            return null;
        }
        Window window = scene.getWindow();
        if (window == null) {
            return null;
        }
        return new Point2D(window.getX() + scene.getX() + clampWiimoteMenuPointerSceneX(sceneX, scene),
                window.getY() + scene.getY() + clampWiimoteMenuPointerSceneY(sceneY, scene));
    }

    private void updateWiimoteMenuPointerScenePosition(Scene scene, double sceneX, double sceneY) {
        wiimoteMenuPointerScene = scene;
        wiimoteMenuPointerSceneX = clampWiimoteMenuPointerSceneX(sceneX, scene);
        wiimoteMenuPointerSceneY = clampWiimoteMenuPointerSceneY(sceneY, scene);
        wiimoteMenuPointerInitialized = true;
    }

    private void clampWiimoteMenuPointerToScene(Scene scene) {
        wiimoteMenuPointerSceneX = clampWiimoteMenuPointerSceneX(wiimoteMenuPointerSceneX, scene);
        wiimoteMenuPointerSceneY = clampWiimoteMenuPointerSceneY(wiimoteMenuPointerSceneY, scene);
    }

    private double clampWiimoteMenuPointerSceneX(double sceneX, Scene scene) {
        double width = scene != null && scene.getWidth() > 0 ? scene.getWidth() : WIDTH;
        return Math.clamp(sceneX, 0.0, Math.max(0.0, width - 1.0));
    }

    private double clampWiimoteMenuPointerSceneY(double sceneY, Scene scene) {
        double height = scene != null && scene.getHeight() > 0 ? scene.getHeight() : HEIGHT;
        return Math.clamp(sceneY, 0.0, Math.max(0.0, height - 1.0));
    }

    private double wiimoteMenuPointerDeltaSeconds(long now) {
        long last = wiimoteMenuPointerLastNs;
        wiimoteMenuPointerLastNs = now;
        if (last <= 0L || now <= last) {
            return 1.0 / 60.0;
        }
        return Math.clamp((now - last) / 1_000_000_000.0, 1.0 / 240.0, 1.0 / 20.0);
    }

    private void releaseWiimoteMenuPointerPress() {
        if (!wiimoteMenuMousePressed) {
            return;
        }
        Robot robot = wiimoteUiRobot();
        if (robot != null) {
            robot.mouseRelease(MouseButton.PRIMARY);
        }
        wiimoteMenuMousePressed = false;
    }

    private boolean isWiimoteSelectorScene(Scene scene) {
        return scene != null && Boolean.TRUE.equals(scene.getProperties().get(SCENE_PROP_WIIMOTE_SELECTOR));
    }

    private int wiimoteSelectorPlayerCount(Scene scene) {
        if (scene == null) {
            return 0;
        }
        Object rawCount = scene.getProperties().get(SCENE_PROP_WIIMOTE_SELECTOR_PLAYERS);
        if (rawCount instanceof Number number) {
            return Math.clamp(number.intValue(), 0, wiimoteSelectorAttackHeld.length);
        }
        return Math.clamp(activePlayers, 0, wiimoteSelectorAttackHeld.length);
    }

    private void pollWiimoteSelectorNavigation(Scene scene) {
        if (scene == null || (wiimoteInputManager == null && xboxInputManager == null)) {
            resetWiimoteSelectorHeldState();
            resetXboxJoinHeldState();
            return;
        }

        FightSetupSelectorController controller = fightSetupSelectorController(scene);
        pollXboxJoinAssignments(scene, controller);

        int selectorPlayers = wiimoteSelectorPlayerCount(scene);
        List<Integer> connectedSources = new ArrayList<>();
        WiimoteMappedState[] states = new WiimoteMappedState[selectorPlayers];
        for (int playerIdx = 0; playerIdx < selectorPlayers; playerIdx++) {
            WiimoteMappedState state = controllerStateForPlayer(playerIdx);
            states[playerIdx] = state;
            if (state.connected()) {
                connectedSources.add(playerIdx);
            }
        }

        if (controller != null) {
            wiimoteSoloSelectorTarget = 0;
            wiimoteSoloSelectorNextHeld = false;
            wiimoteSoloSelectorPrevHeld = false;
            for (int playerIdx = 0; playerIdx < wiimoteSelectorAttackHeld.length; playerIdx++) {
                boolean activeSource = playerIdx < selectorPlayers;
                WiimoteMappedState state = activeSource ? states[playerIdx] : null;
                if (!activeSource || state == null || !state.connected()) {
                    wiimoteSelectorAttackHeld[playerIdx] = false;
                    wiimoteSelectorSpecialHeld[playerIdx] = false;
                    wiimoteSelectorBackHeld[playerIdx] = false;
                    wiimoteSelectorPauseHeld[playerIdx] = false;
                    wiimoteSelectorLastMoveNs[playerIdx] = 0L;
                    Arrays.fill(wiimoteSelectorDirectionHeld[playerIdx], false);
                    controller.setClawConnected(playerIdx, false);
                    if (playerIdx == 0) {
                        releaseWiimoteMenuPointerPress();
                        setFightSetupClawCursor(scene, false);
                    }
                    continue;
                }
                dispatchWiimoteSelectorState(scene, playerIdx, playerIdx, state);
            }
            return;
        }

        if (connectedSources.size() == 1 && selectorPlayers > 1) {
            int sourceIdx = connectedSources.getFirst();
            WiimoteMappedState sourceState = states[sourceIdx];
            wiimoteSoloSelectorTarget = Math.clamp(wiimoteSoloSelectorTarget, 0, selectorPlayers - 1);

            boolean nextHeld = sourceState.tauntCycle();
            if (nextHeld && !wiimoteSoloSelectorNextHeld) {
                wiimoteSoloSelectorTarget = (wiimoteSoloSelectorTarget + 1) % selectorPlayers;
                Arrays.fill(wiimoteSelectorDirectionHeld[sourceIdx], false);
                wiimoteSelectorAttackHeld[sourceIdx] = false;
                wiimoteSelectorSpecialHeld[sourceIdx] = false;
            }
            wiimoteSoloSelectorNextHeld = nextHeld;

            boolean prevHeld = sourceState.tauntExecute();
            if (prevHeld && !wiimoteSoloSelectorPrevHeld) {
                wiimoteSoloSelectorTarget = (wiimoteSoloSelectorTarget - 1 + selectorPlayers) % selectorPlayers;
                Arrays.fill(wiimoteSelectorDirectionHeld[sourceIdx], false);
                wiimoteSelectorAttackHeld[sourceIdx] = false;
                wiimoteSelectorSpecialHeld[sourceIdx] = false;
            }
            wiimoteSoloSelectorPrevHeld = prevHeld;

            resetInactiveWiimoteSelectorHeldState(sourceIdx);
            dispatchWiimoteSelectorState(scene, sourceIdx, wiimoteSoloSelectorTarget, sourceState);
            return;
        }

        wiimoteSoloSelectorTarget = 0;
        wiimoteSoloSelectorNextHeld = false;
        wiimoteSoloSelectorPrevHeld = false;
        for (int playerIdx = 0; playerIdx < wiimoteSelectorAttackHeld.length; playerIdx++) {
            boolean activeSelector = playerIdx < selectorPlayers;
            WiimoteMappedState state = activeSelector ? states[playerIdx] : null;
            if (!activeSelector || state == null || !state.connected()) {
                wiimoteSelectorAttackHeld[playerIdx] = false;
                wiimoteSelectorSpecialHeld[playerIdx] = false;
                wiimoteSelectorBackHeld[playerIdx] = false;
                wiimoteSelectorPauseHeld[playerIdx] = false;
                Arrays.fill(wiimoteSelectorDirectionHeld[playerIdx], false);
                continue;
            }
            dispatchWiimoteSelectorState(scene, playerIdx, playerIdx, state);
        }
    }

    private void dispatchWiimoteSelectorState(Scene scene, int sourceIdx, int targetIdx, WiimoteMappedState state) {
        if (scene == null || state == null || sourceIdx < 0 || sourceIdx >= wiimoteSelectorDirectionHeld.length) {
            return;
        }
        FightSetupSelectorController controller = fightSetupSelectorController(scene);
        if (controller != null) {
            updateControllerNullRockSecretInput(sourceIdx, state, controller);
            if (sourceIdx == 0) {
                controller.setClawConnected(sourceIdx, false);
                long now = System.nanoTime();
                double dtSeconds = selectorDeltaSeconds(sourceIdx, now);
                double horizontal = 0.0;
                double vertical = 0.0;
                if (state.menuLeftHeld()) {
                    horizontal -= 1.0;
                }
                if (state.menuRightHeld()) {
                    horizontal += 1.0;
                }
                if (state.menuUpHeld()) {
                    vertical -= 1.0;
                }
                if (state.menuDownHeld()) {
                    vertical += 1.0;
                }

                syncWiimoteMenuPointer(scene);
                setConsoleHighlightActive(false, scene);
                if (horizontal != 0.0 || vertical != 0.0) {
                    moveWiimoteMenuPointer(scene, horizontal, vertical, dtSeconds);
                }

                boolean selectHeld = state.menuSelectHeld();
                if (selectHeld && !wiimoteSelectorAttackHeld[sourceIdx]) {
                    Robot robot = wiimoteUiRobot();
                    if (robot != null) {
                        setFightSetupClawCursor(scene, true);
                        robot.mousePress(MouseButton.PRIMARY);
                        wiimoteMenuMousePressed = true;
                    }
                } else if (!selectHeld && wiimoteSelectorAttackHeld[sourceIdx]) {
                    releaseWiimoteMenuPointerPress();
                    setFightSetupClawCursor(scene, false);
                }
                wiimoteSelectorAttackHeld[sourceIdx] = selectHeld;

                boolean specialHeld = state.special() && !state.menuBack();
                if (specialHeld && !wiimoteSelectorSpecialHeld[sourceIdx]) {
                    controller.tryStartMatch();
                }
                wiimoteSelectorSpecialHeld[sourceIdx] = specialHeld;

                boolean backHeld = state.menuBack();
                if (backHeld && !wiimoteSelectorBackHeld[sourceIdx]) {
                    dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
                }
                wiimoteSelectorBackHeld[sourceIdx] = backHeld;

                boolean pauseHeld = state.menuPause();
                if (pauseHeld && !wiimoteSelectorPauseHeld[sourceIdx]) {
                    dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
                }
                wiimoteSelectorPauseHeld[sourceIdx] = pauseHeld;
                return;
            }
            controller.setClawConnected(sourceIdx, true);
            long now = System.nanoTime();
            double dtSeconds = selectorDeltaSeconds(sourceIdx, now);
            double horizontal = 0.0;
            double vertical = 0.0;
            if (state.menuLeftHeld()) {
                horizontal -= 1.0;
            }
            if (state.menuRightHeld()) {
                horizontal += 1.0;
            }
            if (state.menuUpHeld()) {
                vertical -= 1.0;
            }
            if (state.menuDownHeld()) {
                vertical += 1.0;
            }
            if (horizontal != 0.0 || vertical != 0.0) {
                controller.moveClaw(sourceIdx, horizontal, vertical, dtSeconds);
            }

            boolean selectHeld = state.menuSelectHeld();
            if (selectHeld && !wiimoteSelectorAttackHeld[sourceIdx]) {
                controller.beginClawGrab(sourceIdx);
            } else if (!selectHeld && wiimoteSelectorAttackHeld[sourceIdx]) {
                controller.releaseClawGrab(sourceIdx);
            }
            wiimoteSelectorAttackHeld[sourceIdx] = selectHeld;

            boolean specialHeld = state.special() && !state.menuBack();
            if (specialHeld && !wiimoteSelectorSpecialHeld[sourceIdx]) {
                controller.tryStartMatch();
            }
            wiimoteSelectorSpecialHeld[sourceIdx] = specialHeld;

            boolean backHeld = state.menuBack();
            if (backHeld && !wiimoteSelectorBackHeld[sourceIdx]) {
                dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
            }
            wiimoteSelectorBackHeld[sourceIdx] = backHeld;

            boolean pauseHeld = state.menuPause();
            if (pauseHeld && !wiimoteSelectorPauseHeld[sourceIdx]) {
                dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
            }
            wiimoteSelectorPauseHeld[sourceIdx] = pauseHeld;
            return;
        }

        if (state.menuLeft() && !wiimoteSelectorDirectionHeld[sourceIdx][0]) {
            dispatchWiimoteMenuKey(scene, leftKeyForPlayer(targetIdx));
        }
        wiimoteSelectorDirectionHeld[sourceIdx][0] = state.menuLeft();
        if (state.menuRight() && !wiimoteSelectorDirectionHeld[sourceIdx][1]) {
            dispatchWiimoteMenuKey(scene, rightKeyForPlayer(targetIdx));
        }
        wiimoteSelectorDirectionHeld[sourceIdx][1] = state.menuRight();
        if (state.menuUp() && !wiimoteSelectorDirectionHeld[sourceIdx][2]) {
            dispatchWiimoteMenuKey(scene, jumpKeyForPlayer(targetIdx));
        }
        wiimoteSelectorDirectionHeld[sourceIdx][2] = state.menuUp();
        if (state.menuDown() && !wiimoteSelectorDirectionHeld[sourceIdx][3]) {
            dispatchWiimoteMenuKey(scene, blockKeyForPlayer(targetIdx));
        }
        wiimoteSelectorDirectionHeld[sourceIdx][3] = state.menuDown();

        boolean attackHeld = state.attack();
        if (attackHeld && !wiimoteSelectorAttackHeld[sourceIdx]) {
            dispatchWiimoteMenuKey(scene, attackKeyForPlayer(targetIdx));
        }
        wiimoteSelectorAttackHeld[sourceIdx] = attackHeld;

        boolean specialHeld = state.special();
        if (specialHeld && !wiimoteSelectorSpecialHeld[sourceIdx]) {
            dispatchWiimoteMenuKey(scene, specialKeyForPlayer(targetIdx));
        }
        wiimoteSelectorSpecialHeld[sourceIdx] = specialHeld;

        boolean backHeld = state.menuBack();
        if (backHeld && !wiimoteSelectorBackHeld[sourceIdx]) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteSelectorBackHeld[sourceIdx] = backHeld;

        boolean pauseHeld = state.menuPause();
        if (pauseHeld && !wiimoteSelectorPauseHeld[sourceIdx]) {
            dispatchWiimoteMenuKey(scene, KeyCode.ESCAPE);
        }
        wiimoteSelectorPauseHeld[sourceIdx] = pauseHeld;
    }

    private void updateControllerNullRockSecretInput(int sourceIdx,
                                                     WiimoteMappedState state,
                                                     FightSetupSelectorController controller) {
        if (controller == null || state == null || sourceIdx < 0 || sourceIdx >= wiimoteSelectorDirectionHeld.length) {
            return;
        }
        boolean leftPressed = state.menuLeftHeld();
        if (leftPressed && !wiimoteSelectorDirectionHeld[sourceIdx][0]) {
            controller.advanceNullRockSecret(sourceIdx, 'L');
        }
        wiimoteSelectorDirectionHeld[sourceIdx][0] = leftPressed;

        boolean rightPressed = state.menuRightHeld();
        if (rightPressed && !wiimoteSelectorDirectionHeld[sourceIdx][1]) {
            controller.advanceNullRockSecret(sourceIdx, 'R');
        }
        wiimoteSelectorDirectionHeld[sourceIdx][1] = rightPressed;

        boolean upPressed = state.menuUpHeld();
        if (upPressed && !wiimoteSelectorDirectionHeld[sourceIdx][2]) {
            controller.advanceNullRockSecret(sourceIdx, 'U');
        }
        wiimoteSelectorDirectionHeld[sourceIdx][2] = upPressed;

        boolean downPressed = state.menuDownHeld();
        if (downPressed && !wiimoteSelectorDirectionHeld[sourceIdx][3]) {
            controller.advanceNullRockSecret(sourceIdx, 'D');
        }
        wiimoteSelectorDirectionHeld[sourceIdx][3] = downPressed;
    }

    private void resetInactiveWiimoteSelectorHeldState(int activeSourceIdx) {
        for (int playerIdx = 0; playerIdx < wiimoteSelectorAttackHeld.length; playerIdx++) {
            if (playerIdx == activeSourceIdx) {
                continue;
            }
            wiimoteSelectorAttackHeld[playerIdx] = false;
            wiimoteSelectorSpecialHeld[playerIdx] = false;
            wiimoteSelectorBackHeld[playerIdx] = false;
            wiimoteSelectorPauseHeld[playerIdx] = false;
            wiimoteSelectorLastMoveNs[playerIdx] = 0L;
            Arrays.fill(wiimoteSelectorDirectionHeld[playerIdx], false);
        }
    }

    private void resetWiimoteMenuHeldState() {
        releaseWiimoteMenuPointerPress();
        Arrays.fill(wiimoteMenuDirectionHeld, false);
        resetWiimotePauseMenuHeldState();
        wiimoteMenuSelectHeld = false;
        wiimoteMenuBackHeld = false;
        wiimoteMenuPauseHeld = false;
        wiimoteMenuPointerLastNs = 0L;
    }

    private void resetWiimotePauseMenuHeldState() {
        wiimotePauseMenuDirectionRepeater.reset();
    }

    private void resetWiimoteSelectorHeldState() {
        Arrays.fill(wiimoteSelectorAttackHeld, false);
        Arrays.fill(wiimoteSelectorSpecialHeld, false);
        Arrays.fill(wiimoteSelectorBackHeld, false);
        Arrays.fill(wiimoteSelectorPauseHeld, false);
        Arrays.fill(wiimoteSelectorLastMoveNs, 0L);
        wiimoteSoloSelectorTarget = 0;
        wiimoteSoloSelectorNextHeld = false;
        wiimoteSoloSelectorPrevHeld = false;
        for (boolean[] directionHeld : wiimoteSelectorDirectionHeld) {
            Arrays.fill(directionHeld, false);
        }
    }

    private double selectorDeltaSeconds(int sourceIdx, long now) {
        if (sourceIdx < 0 || sourceIdx >= wiimoteSelectorLastMoveNs.length) {
            return 1.0 / 60.0;
        }
        long last = wiimoteSelectorLastMoveNs[sourceIdx];
        wiimoteSelectorLastMoveNs[sourceIdx] = now;
        if (last <= 0L || now <= last) {
            return 1.0 / 60.0;
        }
        return Math.clamp((now - last) / 1_000_000_000.0, 1.0 / 240.0, 1.0 / 20.0);
    }

    private void dispatchWiimoteMenuDirectional(Scene scene, KeyCode code) {
        if (scene == null || code == null) return;
        Node focus = scene.getFocusOwner();
        if (focus != null) {
            focus.fireEvent(new KeyEvent(KeyEvent.KEY_PRESSED, "", "", code, false, false, false, false));
            return;
        }
        Event.fireEvent(scene, new KeyEvent(KeyEvent.KEY_PRESSED, "", "", code, false, false, false, false));
    }

    private void dispatchWiimoteMenuKey(Scene scene, KeyCode code) {
        if (scene == null || code == null) return;
        Event.fireEvent(scene, new KeyEvent(KeyEvent.KEY_PRESSED, "", "", code, false, false, false, false));
    }

    private void bindEscape(Scene scene, Runnable action) {
        if (scene == null || action == null) return;
        scene.addEventFilter(KeyEvent.KEY_PRESSED, e -> {
            if (e.getCode() == KeyCode.ESCAPE) {
                action.run();
                e.consume();
            }
        });
    }

    private void bindEscape(Scene scene, Button backButton) {
        if (backButton == null) return;
        bindEscape(scene, backButton::fire);
    }

    private boolean isInteractiveTarget(Node target) {
        Node node = target;
        while (node != null) {
            if (node instanceof Control) return true;
            if (node.getProperties().get("uiAction") instanceof Runnable) {
                return true;
            }
            if (node.getOnMousePressed() != null
                    || node.getOnMouseClicked() != null
                    || node.getOnMouseDragged() != null
                    || node.getOnMouseReleased() != null) {
                return true;
            }
            node = node.getParent();
        }
        return false;
    }

    private boolean activateInteractiveNode(Node node) {
        if (node == null) return false;
        Node cursor = node;
        while (cursor != null) {
            if (cursor instanceof Button button) {
                playButtonClick();
                button.fire();
                return true;
            }
            Object action = cursor.getProperties().get("uiAction");
            if (action instanceof Runnable runnable) {
                playButtonClick();
                runnable.run();
                return true;
            }
            cursor = cursor.getParent();
        }
        return false;
    }

    private void makeSceneResponsive(Scene scene) {
        if (!sceneContainsCanvas(scene.getRoot())) return;
        if (scene.getRoot() instanceof StackPane sp && "responsiveContainer".equals(sp.getId())) return;

        Node content = scene.getRoot();
        StackPane container = new StackPane(content);
        container.setId("responsiveContainer");
        scene.setRoot(container);

        Runnable applyScale = () -> {
            double sx = scene.getWidth() / WIDTH;
            double sy = scene.getHeight() / HEIGHT;
            // Fill the full window on any aspect ratio (no letterboxing borders).
            content.setScaleX(Math.max(0.01, sx));
            content.setScaleY(Math.max(0.01, sy));
        };
        scene.widthProperty().addListener((obs, oldV, newV) -> applyScale.run());
        scene.heightProperty().addListener((obs, oldV, newV) -> applyScale.run());
        applyScale.run();
    }

    private boolean sceneContainsCanvas(Node node) {
        if (node instanceof Canvas) return true;
        if (node instanceof Parent p) {
            for (Node child : p.getChildrenUnmodifiable()) {
                if (sceneContainsCanvas(child)) return true;
            }
        }
        return false;
    }

    private boolean sceneContainsScrollPane(Node node) {
        if (node instanceof ScrollPane) return true;
        if (node instanceof Parent p) {
            for (Node child : p.getChildrenUnmodifiable()) {
                if (sceneContainsScrollPane(child)) return true;
            }
        }
        return false;
    }

    private void fitSceneButtons(Node node) {
        if (node instanceof Button b) {
            installButtonFontLock(b);
            fitButtonText(b);
        }
        if (node instanceof Parent p) {
            for (Node child : p.getChildrenUnmodifiable()) {
                fitSceneButtons(child);
            }
        }
    }

    private void fitButtonText(Button b) {
        String original = (String) b.getProperties().computeIfAbsent("origText", k -> b.getText());
        if (original == null || original.isBlank()) return;
        if (b.getGraphic() != null) return;

        b.setWrapText(true);
        applyNoEllipsis(b);
        b.setTextAlignment(TextAlignment.CENTER);
        b.setAlignment(Pos.CENTER);

        Font baseFont = (Font) b.getProperties().computeIfAbsent("baseFont", k ->
                b.getFont() != null ? b.getFont() : Font.font("Arial Black", 30));
        double size = baseFont.getSize();
        double minSize = Math.min(12, size);
        double width = b.getPrefWidth() > 0 ? b.getPrefWidth() : 420;
        double height = b.getPrefHeight() > 0 ? b.getPrefHeight() : 96;
        double availableW = Math.max(110, width - 40);
        double availableH = Math.max(40, height - 16);

        List<String> bestLines = List.of(original);
        double chosen = minSize;
        while (size > minSize) {
            Font trial = Font.font(baseFont.getFamily(), size);
            List<String> lines = wrapTextToLines(original, trial, availableW);
            double lineH = measureTextHeight(trial) * 1.12;
            double blockH = lines.size() * lineH;
            double blockW = maxLineWidth(lines, trial);
            if (blockH <= availableH && blockW <= availableW) {
                bestLines = lines;
                chosen = size;
                break;
            }
            size -= 2;
        }

        if (size <= minSize) {
            Font trial = Font.font(baseFont.getFamily(), minSize);
            bestLines = wrapTextToLines(original, trial, availableW);
            chosen = minSize;
        }

        setLockedButtonFont(b, Font.font(baseFont.getFamily(), chosen));
        b.setText(String.join("\n", bestLines));
    }

    private void fitWrappedLabelText(Label label, String original, double availableW, double availableH, double minSize) {
        if (label == null || original == null || original.isBlank()) return;

        label.setWrapText(true);
        label.setTextAlignment(TextAlignment.CENTER);
        label.setAlignment(Pos.CENTER);
        applyNoEllipsis(label);

        Font current = label.getFont() != null ? label.getFont() : Font.font("Consolas", 14);
        double size = current.getSize();
        double chosen = Math.max(minSize, size);
        List<String> bestLines = wrapTextToLines(original, current, availableW);

        while (size >= minSize) {
            Font trial = Font.font(current.getFamily(), size);
            List<String> lines = wrapTextToLines(original, trial, availableW);
            double lineH = measureTextHeight(trial) * 1.12;
            double blockH = lines.size() * lineH;
            double blockW = maxLineWidth(lines, trial);
            if (blockH <= availableH && blockW <= availableW) {
                bestLines = lines;
                chosen = size;
                break;
            }
            size -= 1;
        }

        if (size < minSize) {
            Font trial = Font.font(current.getFamily(), minSize);
            bestLines = wrapTextToLines(original, trial, availableW);
            chosen = minSize;
        }

        label.setFont(Font.font(current.getFamily(), chosen));
        label.setText(String.join("\n", bestLines));
        label.setPrefWidth(availableW);
        label.setMaxWidth(availableW);
    }

    private void installButtonFontLock(Button b) {
        if (b == null) return;
        if (Boolean.TRUE.equals(b.getProperties().get("fontLockInstalled"))) {
            enforceLockedFont(b);
            return;
        }
        b.getProperties().put("fontLockInstalled", true);
        b.getProperties().putIfAbsent("baseFont", b.getFont());
        storeLockedFont(b, b.getFont());

        ChangeListener<Boolean> enforce = (obs, oldVal, newVal) -> enforceLockedFont(b);
        b.hoverProperty().addListener(enforce);
        b.focusedProperty().addListener(enforce);
        b.pressedProperty().addListener(enforce);
        b.fontProperty().addListener((obs, oldFont, newFont) -> {
            if (Boolean.TRUE.equals(b.getProperties().get("fontLockUpdating"))) return;
            if (newFont == null) return;
            Font locked = (Font) b.getProperties().get("lockedFont");
            if (locked == null) {
                storeLockedFont(b, newFont);
                return;
            }
            if (!newFont.equals(locked)) {
                enforceLockedFont(b);
            }
        });
    }

    private void storeLockedFont(Button b, Font font) {
        if (b == null || font == null) return;
        b.getProperties().put("lockedFont", font);
    }

    private void setLockedButtonFont(Button b, Font font) {
        if (b == null || font == null) return;
        b.getProperties().put("fontLockUpdating", true);
        try {
            storeLockedFont(b, font);
            b.setFont(font);
        } finally {
            b.getProperties().put("fontLockUpdating", false);
        }
    }

    private void enforceLockedFont(Button b) {
        if (b == null) return;
        Font locked = (Font) b.getProperties().get("lockedFont");
        if (locked == null) return;
        Font current = b.getFont();
        if (current != null && current.equals(locked)) return;
        setLockedButtonFont(b, locked);
    }

    private List<String> wrapTextToLines(String text, Font font, double maxWidth) {
        List<String> lines = new ArrayList<>();
        if (text == null || text.isBlank()) return lines;

        String[] words = text.trim().split("\\s+");
        String current = "";
        for (String word : words) {
            if (measureTextWidth(word, font) > maxWidth) {
                if (!current.isEmpty()) {
                    lines.add(current);
                    current = "";
                }
                lines.addAll(splitWordToFit(word, font, maxWidth));
                continue;
            }
            String candidate = current.isEmpty() ? word : current + " " + word;
            if (measureTextWidth(candidate, font) <= maxWidth || current.isEmpty()) {
                current = candidate;
            } else {
                lines.add(current);
                current = word;
            }
        }
        if (!current.isEmpty()) lines.add(current);
        return lines;
    }

    List<KillFeedRenderBlock> buildKillFeedRenderBlocks() {
        List<KillFeedRenderBlock> blocks = new ArrayList<>();

        for (int i = 0; i < killFeed.size(); i++) {
            String msg = killFeed.get(i);
            if (msg == null || msg.isBlank()) continue;
            double alpha = Math.max(0.3, 1.0 - (i / (double) MAX_FEED_LINES));
            List<String> lines = wrapTextToLines(msg, HUD_FEED_FONT, 180);
            if (lines.isEmpty()) {
                lines = List.of(msg);
            }
            blocks.add(new KillFeedRenderBlock(lines, alpha));
        }
        return blocks;
    }

    private List<String> splitWordToFit(String word, Font font, double maxWidth) {
        List<String> chunks = new ArrayList<>();
        if (word == null || word.isEmpty()) return chunks;

        StringBuilder current = new StringBuilder();
        for (int i = 0; i < word.length(); i++) {
            current.append(word.charAt(i));
            if (measureTextWidth(current.toString(), font) > maxWidth) {
                if (current.length() == 1) {
                    chunks.add(current.toString());
                    current.setLength(0);
                } else {
                    char last = current.charAt(current.length() - 1);
                    current.deleteCharAt(current.length() - 1);
                    chunks.add(current.toString());
                    current.setLength(0);
                    current.append(last);
                }
            }
        }
        if (!current.isEmpty()) {
            chunks.add(current.toString());
        }
        return chunks;
    }

    private double maxLineWidth(List<String> lines, Font font) {
        double max = 0;
        for (String line : lines) {
            max = Math.max(max, measureTextWidth(line, font));
        }
        return max;
    }

    private double measureTextWidth(String text, Font font) {
        Text t = new Text(text);
        t.setFont(font);
        return t.getLayoutBounds().getWidth();
    }

    private double measureTextHeight(Font font) {
        Text t = new Text("Ag");
        t.setFont(font);
        return t.getLayoutBounds().getHeight();
    }

    private void fitMainMenuButtonSingleLine(Button b, double maxSize, double minSize) {
        if (b == null) return;
        String text = b.getText();
        if (text == null || text.isBlank()) return;

        b.setWrapText(false);
        applyNoEllipsis(b);

        double w = b.getWidth() > 0 ? b.getWidth() : (b.getPrefWidth() > 0 ? b.getPrefWidth() : 420);
        double h = b.getHeight() > 0 ? b.getHeight() : (b.getPrefHeight() > 0 ? b.getPrefHeight() : 100);
        double availableW = Math.max(120, w - 44);
        double availableH = Math.max(40, h - 18);

        double size = maxSize;
        while (size > minSize) {
            Font f = Font.font("Arial Black", size);
            if (measureTextWidth(text, f) <= availableW && measureTextHeight(f) <= availableH) {
                b.setFont(f);
                return;
            }
            size -= 1.0;
        }
        b.setFont(Font.font("Arial Black", minSize));
    }

    private void applyNoEllipsis(Button b) {
        b.setTextOverrun(OverrunStyle.CLIP);
        b.setEllipsisString("");
        String style = b.getStyle();
        if (style == null) style = "";
        if (!style.contains("-fx-text-overrun: clip")) {
            b.setStyle(style + (style.isBlank() ? "" : "; ") + "-fx-text-overrun: clip;");
        }
    }

    private void applyNoEllipsis(Label label) {
        label.setTextOverrun(OverrunStyle.CLIP);
        label.setEllipsisString("");
    }

    private void fitLabelSingleLine(Label label, double maxSize, double minSize, double maxWidth) {
        if (label == null) return;
        String text = label.getText();
        if (text == null || text.isBlank()) return;
        double size = maxSize;
        while (size > minSize) {
            Font f = Font.font("Arial Black", size);
            if (measureTextWidth(text, f) <= maxWidth) {
                label.setFont(f);
                return;
            }
            size -= 1.0;
        }
        label.setFont(Font.font("Arial Black", minSize));
    }

    private void lockRegionSize(Region region, double width, double height) {
        if (region == null) return;
        region.setMinSize(width, height);
        region.setPrefSize(width, height);
        region.setMaxSize(width, height);
    }

    private void lockRegionWidth(Region region, double width) {
        if (region == null) return;
        region.setMinWidth(width);
        region.setPrefWidth(width);
        region.setMaxWidth(width);
    }

    private void installRegionClip(Region region, double arcWidth, double arcHeight) {
        if (region == null) return;
        Rectangle clip = new Rectangle();
        clip.widthProperty().bind(region.widthProperty());
        clip.heightProperty().bind(region.heightProperty());
        clip.setArcWidth(arcWidth);
        clip.setArcHeight(arcHeight);
        region.setClip(clip);
    }

    private void bindScaleToFit(Scene scene, Node content) {
        Runnable apply = () -> {
            if (scene.getRoot() instanceof StackPane sp && "uiFrame".equals(sp.getId())) {
                return;
            }
            content.applyCss();
            content.autosize();
            Bounds bounds = content.getBoundsInLocal();
            double w = bounds.getWidth();
            double h = bounds.getHeight();
            if (w <= 0 || h <= 0) {
                content.setScaleX(1.0);
                content.setScaleY(1.0);
                return;
            }
            double availW = Math.max(1.0, scene.getWidth() - (double) 40 * 2);
            double availH = Math.max(1.0, scene.getHeight() - (double) 40 * 2);
            double scale = Math.min(1.0, Math.min(availW / w, availH / h));
            content.setScaleX(scale);
            content.setScaleY(scale);
        };
        scene.widthProperty().addListener((obs, oldVal, newVal) -> apply.run());
        scene.heightProperty().addListener((obs, oldVal, newVal) -> apply.run());
        content.boundsInLocalProperty().addListener((obs, oldVal, newVal) -> apply.run());
        javafx.application.Platform.runLater(apply);
    }

    private void bindFixedFrameScale(Scene scene, Node content) {
        bindFixedFrameScale(scene, content, 8.0);
    }

    private void bindFixedFrameScale(Scene scene, Node content, double margin) {
        Runnable apply = () -> {
            double availW = Math.max(1.0, scene.getWidth() - margin * 2.0);
            double availH = Math.max(1.0, scene.getHeight() - margin * 2.0);
            double scale = Math.min(availW / 1600.0, availH / 950.0);
            content.setScaleX(scale);
            content.setScaleY(scale);
        };
        scene.widthProperty().addListener((obs, oldVal, newVal) -> apply.run());
        scene.heightProperty().addListener((obs, oldVal, newVal) -> apply.run());
        javafx.application.Platform.runLater(apply);
    }

    private Bounds measureUiContentBounds(Node content) {
        if (content == null) return null;
        content.applyCss();
        if (content instanceof Parent parent) {
            parent.layout();
        }
        Bounds bounds = content.getLayoutBounds();
        if (bounds == null || bounds.getWidth() <= 0 || bounds.getHeight() <= 0) {
            bounds = content.getBoundsInLocal();
        }
        return bounds;
    }

    private double computeUiFitScale(double contentWidth, double contentHeight,
                                     double sceneWidth, double sceneHeight) {
        if (contentWidth <= 0 || contentHeight <= 0 || sceneWidth <= 0 || sceneHeight <= 0) {
            return 1.0;
        }
        double availW = Math.max(1.0, sceneWidth - 28.0 * 2.0);
        double availH = Math.max(1.0, sceneHeight - 28.0 * 2.0);
        return Math.min(1.0, Math.min(availW / contentWidth, availH / contentHeight));
    }

    private void ensureSceneAutoScaled(Scene scene) {
        if (scene == null) return;
        Node root = scene.getRoot();
        switch (root) {
            case null -> {
                return;
            }
            case StackPane sp when "responsiveContainer".equals(sp.getId()) -> {
                return;
            }
            case StackPane sp when "uiFrame".equals(sp.getId()) -> {
                return;
            }
            default -> {
            }
        }
        if (Boolean.TRUE.equals(root.getProperties().get("noAutoScale"))) return;
        javafx.application.Platform.runLater(() -> wrapAndScaleUiScene(scene));
    }

    private void applyFocusRingStyle(Scene scene) {
        if (scene == null) return;
        Node root = scene.getRoot();
        if (!(root instanceof Region region)) return;
        String focusStyle = "-fx-focus-color: transparent; -fx-faint-focus-color: transparent;";
        String style = region.getStyle();
        if (style == null) style = "";
        if (!style.contains("-fx-focus-color")) {
            region.setStyle(style + (style.isBlank() ? "" : "; ") + focusStyle);
        }
    }

    private void wrapAndScaleUiScene(Scene scene) {
        if (scene == null) return;
        Node root = scene.getRoot();
        switch (root) {
            case null -> {
                return;
            }
            case StackPane sp when "responsiveContainer".equals(sp.getId()) -> {
                return;
            }
            case StackPane sp when "uiFrame".equals(sp.getId()) -> {
                return;
            }
            default -> {
            }
        }

        boolean hasScroll = (root instanceof ScrollPane) || sceneContainsScrollPane(root);
        Region backgroundSource = null;
        if (root instanceof ScrollPane scrollRoot) {
            installTransparentScrollViewport(scrollRoot);
            if (scrollRoot.getContent() instanceof Region region) {
                backgroundSource = region;
            }
        } else if (root instanceof Region region) {
            backgroundSource = region;
        }
        String rootStyle = backgroundSource != null ? backgroundSource.getStyle() : "";
        String backgroundStyle = extractBackgroundStyle(rootStyle);
        String strippedStyle = stripBackgroundStyle(rootStyle);
        if (backgroundSource != null) {
            backgroundSource.setStyle(strippedStyle);
        }

        if (root instanceof ScrollPane sp) {
            String style = sp.getStyle();
            if (style == null) style = "";
            if (!style.contains("-fx-background-color")) {
                sp.setStyle(style + (style.isBlank() ? "" : "; ")
                        + "-fx-background-color: transparent; -fx-border-color: transparent; "
                        + "-fx-background-insets: 0; -fx-padding: 0;");
            }
            sp.setFitToWidth(true);
            sp.setFitToHeight(false);
            installTransparentScrollViewport(sp);
        }

        installTransparentScrollViewports(root);

        StackPane frame = new StackPane(root);
        frame.setId("uiFrame");
        frame.setAlignment(Pos.CENTER);
        if (!backgroundStyle.isBlank()) {
            frame.setStyle(backgroundStyle);
        }
        frame.setMaxSize(Double.MAX_VALUE, Double.MAX_VALUE);
        scene.setRoot(frame);
        Runnable sizeFrame = () -> {
            double w = scene.getWidth();
            double h = scene.getHeight();
            if (w > 0 && h > 0) {
                frame.setMinSize(w, h);
                frame.setPrefSize(w, h);
                frame.setMaxSize(w, h);
            }
        };
        scene.widthProperty().addListener((obs, oldV, newV) -> {
            double w = newV.doubleValue();
            frame.setMinWidth(w);
            frame.setPrefWidth(w);
            frame.setMaxWidth(w);
        });
        scene.heightProperty().addListener((obs, oldV, newV) -> {
            double h = newV.doubleValue();
            frame.setMinHeight(h);
            frame.setPrefHeight(h);
            frame.setMaxHeight(h);
        });
        javafx.application.Platform.runLater(sizeFrame);

        if (!hasScroll) {
            Runnable applyScale = () -> {
                Bounds bounds = measureUiContentBounds(root);
                if (bounds == null) {
                    root.setScaleX(1.0);
                    root.setScaleY(1.0);
                    return;
                }
                double scale = computeUiFitScale(
                        bounds.getWidth(),
                        bounds.getHeight(),
                        scene.getWidth(),
                        scene.getHeight()
                );
                root.setScaleX(scale);
                root.setScaleY(scale);
            };
            scene.widthProperty().addListener((obs, oldV, newV) -> applyScale.run());
            scene.heightProperty().addListener((obs, oldV, newV) -> applyScale.run());
            root.layoutBoundsProperty().addListener((obs, oldV, newV) -> applyScale.run());
            javafx.application.Platform.runLater(applyScale);
        }
    }

    private String extractBackgroundStyle(String style) {
        if (style == null || style.isBlank()) return "";
        StringBuilder sb = new StringBuilder();
        String[] parts = style.split(";");
        for (String part : parts) {
            String trimmed = part.trim();
            if (trimmed.isBlank()) continue;
            if (trimmed.startsWith("-fx-background")) {
                if (!sb.isEmpty()) sb.append("; ");
                sb.append(trimmed);
            }
        }
        return sb.toString();
    }

    private String stripBackgroundStyle(String style) {
        if (style == null || style.isBlank()) return "";
        StringBuilder sb = new StringBuilder();
        String[] parts = style.split(";");
        for (String part : parts) {
            String trimmed = part.trim();
            if (trimmed.isBlank()) continue;
            if (trimmed.startsWith("-fx-background")) continue;
            if (!sb.isEmpty()) sb.append("; ");
            sb.append(trimmed);
        }
        return sb.toString();
    }

    private ScrollPane wrapInScroll(Parent content) {
        ScrollPane scroll = new ScrollPane(content);
        scroll.setFitToWidth(true);
        scroll.setFitToHeight(false);
        scroll.setPannable(true);
        scroll.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        scroll.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        scroll.setStyle("-fx-background: transparent; -fx-background-color: transparent; "
                + "-fx-control-inner-background: transparent; -fx-border-color: transparent; "
                + "-fx-background-insets: 0; -fx-padding: 0;");
        installTransparentScrollViewport(scroll);
        return scroll;
    }

    private void installTransparentScrollViewports(Node node) {
        switch (node) {
            case ScrollPane scroll -> {
                installTransparentScrollViewport(scroll);
                installTransparentScrollViewports(scroll.getContent());
            }
            case Parent parent -> {
                for (Node child : parent.getChildrenUnmodifiable()) {
                    installTransparentScrollViewports(child);
                }
            }
            case null, default -> {
            }
        }
    }

    private void installTransparentScrollViewport(ScrollPane scroll) {
        if (scroll == null) return;
        Runnable apply = () -> {
            Node viewport = scroll.lookup(".viewport");
            if (viewport instanceof Region region) {
                region.setStyle("-fx-background-color: transparent; -fx-background-insets: 0;");
            }
            Node corner = scroll.lookup(".corner");
            if (corner instanceof Region region) {
                region.setStyle("-fx-background-color: transparent;");
            }
        };
        if (Boolean.TRUE.equals(scroll.getProperties().get("transparentViewportInstalled"))) {
            javafx.application.Platform.runLater(apply);
            return;
        }
        scroll.getProperties().put("transparentViewportInstalled", true);
        scroll.skinProperty().addListener((obs, oldVal, newVal) -> javafx.application.Platform.runLater(apply));
        scroll.sceneProperty().addListener((obs, oldVal, newVal) -> javafx.application.Platform.runLater(apply));
        javafx.application.Platform.runLater(apply);
    }

