    private VBox buildVolumeSettingsRow(String title, String description, String accent,
                                        double initialValue, DoubleConsumer onValueChanged, Runnable preview) {
        Label titleLabel = new Label(title);
        titleLabel.setFont(Font.font("Arial Black", 24));
        titleLabel.setTextFill(Color.web("#ECEFF1"));
        applyNoEllipsis(titleLabel);

        Label valueLabel = new Label(formatVolumePercent(initialValue));
        valueLabel.setFont(Font.font("Consolas", 22));
        valueLabel.setTextFill(Color.web(accent));
        applyNoEllipsis(valueLabel);

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        HBox header = new HBox(16, titleLabel, spacer, valueLabel);
        header.setAlignment(Pos.CENTER_LEFT);
        header.setMaxWidth(620);

        Slider slider = new Slider(0, 100, Math.round(sanitizeVolume(initialValue) * 100.0));
        slider.setPrefWidth(620);
        slider.setMaxWidth(620);
        slider.setBlockIncrement(5);
        slider.setMajorTickUnit(25);
        slider.setMinorTickCount(4);
        slider.setShowTickMarks(true);
        slider.setShowTickLabels(true);
        slider.setStyle("-fx-accent: " + accent + ";");
        slider.valueProperty().addListener((obs, oldValue, newValue) -> {
            double normalized = sanitizeVolume(newValue.doubleValue() / 100.0);
            valueLabel.setText(formatVolumePercent(normalized));
            onValueChanged.accept(normalized);
        });
        if (preview != null) {
            slider.setOnMouseReleased(e -> preview.run());
            slider.addEventHandler(KeyEvent.KEY_RELEASED, e -> {
                KeyCode code = e.getCode();
                if (code == KeyCode.LEFT || code == KeyCode.RIGHT
                        || code == KeyCode.UP || code == KeyCode.DOWN
                        || code == KeyCode.HOME || code == KeyCode.END
                        || code == KeyCode.PAGE_UP || code == KeyCode.PAGE_DOWN) {
                    preview.run();
                }
            });
        }

        Label descriptionLabel = new Label(description);
        descriptionLabel.setFont(Font.font("Consolas", 20));
        descriptionLabel.setTextFill(Color.web("#B3E5FC"));
        descriptionLabel.setWrapText(true);
        descriptionLabel.setMaxWidth(620);
        descriptionLabel.setPrefWidth(620);
        descriptionLabel.setTextAlignment(TextAlignment.LEFT);
        descriptionLabel.setAlignment(Pos.CENTER_LEFT);
        descriptionLabel.setPadding(new Insets(0, 0, 0, 14));
        applyNoEllipsis(descriptionLabel);

        VBox row = new VBox(8, header, slider, descriptionLabel);
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(12, 14, 12, 14));
        row.setStyle(MenuTheme.insetPanelStyle(accent, 20));
        return row;
    }

    private boolean shouldRenderFrame(long now) {
        return frameRateLimiter.shouldRender(now, fpsCap);
    }

    private void resetRenderTimer() {
        frameRateLimiter.reset();
    }

    private int sanitizeFpsCap(int value) {
        return FrameRateLimiter.sanitizeFpsCap(value);
    }

    private void refreshFpsCapButton(Button btn) {
        String label = fpsCap <= 0 ? "FPS CAP: UNCAPPED" : "FPS CAP: " + fpsCap;
        String color = fpsCap <= 0 ? "#546E7A" : "#1E88E5";
        btn.setText(label);
        btn.setStyle(MenuTheme.buttonStyle(color, 24));
    }

    private void cycleFpsCap(Button btn) {
        int idx = -1;
        for (int i = 0; i < FPS_CAPS.length; i++) {
            if (FPS_CAPS[i] == fpsCap) {
                idx = i;
                break;
            }
        }
        int next = (idx + 1) % FPS_CAPS.length;
        fpsCap = FPS_CAPS[next];
        refreshFpsCapButton(btn);
        resetRenderTimer();
        saveAchievements();
    }

    private KeyCode[][] createDefaultControlBindings() {
        KeyCode[][] bindings = new KeyCode[4][ControlAction.values().length];
        applyDefaultControlBindings(bindings);
        return bindings;
    }

    private void applyDefaultControlBindings(KeyCode[][] bindings) {
        if (bindings == null) return;
        for (int playerIdx = 0; playerIdx < bindings.length; playerIdx++) {
            for (ControlAction action : ControlAction.values()) {
                bindings[playerIdx][action.ordinal()] = action.defaultKey(playerIdx);
            }
        }
    }

    private void resetControlBindingsToDefaults() {
        applyDefaultControlBindings(playerKeyBindings);
    }

    private void applyControlBindingNames(String[][] bindingNames) {
        resetControlBindingsToDefaults();
        if (bindingNames == null) return;
        for (int playerIdx = 0; playerIdx < playerKeyBindings.length; playerIdx++) {
            for (ControlAction action : ControlAction.values()) {
                String raw = playerIdx < bindingNames.length && action.ordinal() < bindingNames[playerIdx].length
                        ? bindingNames[playerIdx][action.ordinal()]
                        : null;
                if (raw == null || raw.isBlank()) continue;
                try {
                    KeyCode loaded = KeyCode.valueOf(raw);
                    if (!isReservedBindingKey(loaded)) {
                        playerKeyBindings[playerIdx][action.ordinal()] = loaded;
                    }
                } catch (IllegalArgumentException ignored) {
                }
            }
        }
    }

    private String[][] captureControlBindingNames() {
        String[][] bindingNames = new String[playerKeyBindings.length][ControlAction.values().length];
        for (int playerIdx = 0; playerIdx < playerKeyBindings.length; playerIdx++) {
            for (ControlAction action : ControlAction.values()) {
                bindingNames[playerIdx][action.ordinal()] = keyForPlayer(playerIdx, action).name();
            }
        }
        return bindingNames;
    }

    WiimoteControlMode wiimoteModeForPlayer(int playerIdx) {
        if (playerIdx < 0 || playerIdx >= wiimoteModes.length) {
            return WiimoteControlMode.OFF;
        }
        return wiimoteModes[playerIdx];
    }

    void setWiimoteModeForPlayer(int playerIdx, WiimoteControlMode mode) {
        if (playerIdx < 0 || playerIdx >= wiimoteModes.length) {
            return;
        }
        wiimoteModes[playerIdx] = mode == null ? WiimoteControlMode.OFF : mode;
        if (wiimoteInputManager != null) {
            wiimoteInputManager.setPlayerMode(playerIdx, wiimoteModes[playerIdx]);
        }
    }

    private void applyWiimoteModeNames(String[] wiimoteModeNames) {
        for (int playerIdx = 0; playerIdx < wiimoteModes.length; playerIdx++) {
            String modeName = wiimoteModeNames != null && playerIdx < wiimoteModeNames.length
                    ? wiimoteModeNames[playerIdx]
                    : WiimoteControlMode.OFF.name();
            WiimoteControlMode loaded = WiimoteControlMode.fromPreference(modeName);
            setWiimoteModeForPlayer(playerIdx, loaded);
        }
    }

    private String[] captureWiimoteModeNames() {
        String[] modeNames = new String[wiimoteModes.length];
        for (int playerIdx = 0; playerIdx < wiimoteModes.length; playerIdx++) {
            modeNames[playerIdx] = wiimoteModeForPlayer(playerIdx).name();
        }
        return modeNames;
    }

    private void syncWiimoteModesToManager() {
        if (wiimoteInputManager == null) return;
        for (int playerIdx = 0; playerIdx < wiimoteModes.length; playerIdx++) {
            wiimoteInputManager.setPlayerMode(playerIdx, wiimoteModes[playerIdx]);
        }
    }

    private BirdGame3GlobalSettingsState captureGlobalSettingsState() {
        BirdGame3GlobalSettingsState state = new BirdGame3GlobalSettingsState();
        state.controlBindingNames = captureControlBindingNames();
        state.wiimoteModeNames = captureWiimoteModeNames();
        state.lanLastHost = lanLastHost;
        state.musicEnabled = musicEnabled;
        state.sfxEnabled = sfxEnabled;
        state.musicVolume = musicVolume;
        state.sfxVolume = sfxVolume;
        state.screenShakeEnabled = screenShakeEnabled;
        state.fullscreenEnabled = fullscreenEnabled;
        state.particleEffectsEnabled = particleEffectsEnabled;
        state.ambientEffectsEnabled = ambientEffectsEnabled;
        state.fpsCap = fpsCap;
        return state;
    }

    private void applyGlobalSettingsState(BirdGame3GlobalSettingsState state) {
        BirdGame3GlobalSettingsState resolved = state == null ? new BirdGame3GlobalSettingsState() : state;
        applyControlBindingNames(resolved.controlBindingNames);
        applyWiimoteModeNames(resolved.wiimoteModeNames);
        lanLastHost = resolved.lanLastHost;
        musicEnabled = resolved.musicEnabled;
        sfxEnabled = resolved.sfxEnabled;
        musicVolume = sanitizeVolume(resolved.musicVolume);
        sfxVolume = sanitizeVolume(resolved.sfxVolume);
        musicEnabled = !isMutedVolume(musicVolume);
        sfxEnabled = !isMutedVolume(sfxVolume);
        screenShakeEnabled = resolved.screenShakeEnabled;
        fullscreenEnabled = resolved.fullscreenEnabled;
        particleEffectsEnabled = resolved.particleEffectsEnabled;
        ambientEffectsEnabled = resolved.ambientEffectsEnabled;
        fpsCap = sanitizeFpsCap(resolved.fpsCap);
    }

    private boolean isReservedBindingKey(KeyCode code) {
        return code == null || code == KeyCode.UNDEFINED || code == KeyCode.ESCAPE || code == KeyCode.F11 || code == KeyCode.F3;
    }

    private void assignControlBinding(int playerIdx, ControlAction action, KeyCode code) {
        if (playerIdx < 0 || playerIdx >= playerKeyBindings.length || action == null || isReservedBindingKey(code)) return;
        KeyCode previous = keyForPlayer(playerIdx, action);
        for (int i = 0; i < playerKeyBindings.length; i++) {
            for (ControlAction other : ControlAction.values()) {
                if (i == playerIdx && other == action) continue;
                if (keyForPlayer(i, other) == code) {
                    playerKeyBindings[i][other.ordinal()] = previous;
                }
            }
        }
        playerKeyBindings[playerIdx][action.ordinal()] = code;
    }

    private KeyCode keyForPlayer(int playerIdx, ControlAction action) {
        if (action == null) return KeyCode.UNDEFINED;
        if (playerIdx < 0 || playerIdx >= playerKeyBindings.length) {
            return action.defaultKey(0);
        }
        KeyCode code = playerKeyBindings[playerIdx][action.ordinal()];
        return code != null ? code : action.defaultKey(playerIdx);
    }

    private String displayKeyName(KeyCode code) {
        if (code == null) return "UNBOUND";
        return code.getName().toUpperCase(Locale.ROOT);
    }

    private String controlBindingButtonId(int playerIdx, ControlAction action) {
        return playerIdx + ":" + action.name();
    }

    private void refreshControlBindingButton(Button button, int playerIdx, ControlAction action, boolean awaiting) {
        if (button == null || action == null) return;
        String text = awaiting ? "PRESS A KEY..." : displayKeyName(keyForPlayer(playerIdx, action));
        String color = awaiting ? "#F9A825" : "#455A64";
        button.setText(text);
        button.setStyle(MenuTheme.buttonStyle(color, 18));
        updateControlHighlight(button);
    }

    private void setSettingsTabActive(Button tab, boolean active) {
        String color = active ? "#FBC02D" : "#455A64";
        String textColor = active ? "#111111" : "white";
        tab.setStyle(MenuTheme.buttonStyle(color, 18, textColor));
        updateControlHighlight(tab);
    }

    private void confirmExitGame(Stage stage) {
        Alert alert = new Alert(Alert.AlertType.CONFIRMATION,
                "Exit Bird Fight 3?",
                ButtonType.YES,
                ButtonType.NO);
        alert.setTitle("Exit Game");
        alert.setHeaderText("Are you sure you want to quit?");
        alert.initOwner(stage);
        alert.showAndWait().ifPresent(choice -> {
            if (choice == ButtonType.YES) {
                shutdownAndExit();
            }
        });
    }

    private void setScenePreservingFullscreen(Stage stage, Scene scene) {
        currentStage = stage;
        releaseWiimoteMenuPointerPress();
        stage.setScene(scene);
        applyDisplaySettings(stage);
        ensureSceneAutoScaled(scene);
        installWiimoteMenuPointerTracking(scene);
        if (usesWiimoteUiPointer(scene)) {
            setFightSetupClawCursor(scene, false);
            syncWiimoteMenuPointer(scene);
        } else if (isWiimoteSelectorScene(scene)) {
            setFightSetupClawCursor(scene, false);
        } else if (scene != null) {
            scene.setCursor(Cursor.DEFAULT);
        }
        if (achievementToastShowing && achievementToastPopup != null) {
            positionAchievementToast(achievementToastPopup);
        }
        tryShowQueuedAchievementToast();
    }

    private Rectangle2D getStageScreenBounds(Stage stage, Scene scene) {
        try {
            double x = stage.getX();
            double y = stage.getY();
            double w = stage.getWidth() > 0 ? stage.getWidth() : (scene.getWidth() > 0 ? scene.getWidth() : WIDTH);
            double h = stage.getHeight() > 0 ? stage.getHeight() : (scene.getHeight() > 0 ? scene.getHeight() : HEIGHT);
            List<Screen> screens = Screen.getScreensForRectangle(x, y, w, h);
            Screen screen = screens.isEmpty() ? Screen.getPrimary() : screens.getFirst();
            return screen.getVisualBounds();
        } catch (Exception e) {
            return Screen.getPrimary().getVisualBounds();
        }
    }

    private void playButtonClick() {
        if (!sfxEnabled) return;
        if (buttonClickClip != null) {
            buttonClickClip.stop();
            playManagedSfx(buttonClickClip, BUTTON_CLICK_BASE_VOLUME);
        }
    }

    private void playErrorSound() {
        if (!sfxEnabled) return;
        if (butterClip != null) {
            playManagedSfx(butterClip, ERROR_SOUND_BASE_VOLUME);
        } else if (bonkClip != null) {
            playManagedSfx(bonkClip, ERROR_SOUND_BASE_VOLUME);
        }
    }

    // === WIIMOTE HIGHLIGHT ===
    private void applyConsoleHighlight(Scene scene) {
        if (scene == null) return;
        if (!Boolean.TRUE.equals(scene.getProperties().get("consoleHighlightInstalled"))) {
            scene.getProperties().put("consoleHighlightInstalled", true);
            scene.focusOwnerProperty().addListener((obs, oldFocus, newFocus) -> {
                if (oldFocus instanceof Control oldCtrl) updateControlHighlight(oldCtrl);
                if (newFocus instanceof Control newCtrl) updateControlHighlight(newCtrl);
            });
            scene.addEventFilter(KeyEvent.KEY_PRESSED, e -> setConsoleHighlightActive(true, scene));
            scene.addEventFilter(MouseEvent.MOUSE_MOVED, e -> setConsoleHighlightActive(false, scene));
            scene.addEventFilter(MouseEvent.MOUSE_DRAGGED, e -> setConsoleHighlightActive(false, scene));
            scene.addEventFilter(MouseEvent.MOUSE_PRESSED, e -> setConsoleHighlightActive(false, scene));
        }
        refreshSceneHighlights(scene);
    }

    private void setConsoleHighlightActive(boolean active, Scene scene) {
        if (consoleHighlightActive == active) return;
        consoleHighlightActive = active;
        refreshSceneHighlights(scene);
    }

    private void refreshSceneHighlights(Scene scene) {
        if (scene == null) return;
        installHighlightHandlers(scene.getRoot());
    }

    private void installHighlightHandlers(Node node) {
        if (node == null) return;
        if (node instanceof Control ctrl) {
            if (!Boolean.TRUE.equals(ctrl.getProperties().get("uiHighlightInstalled"))) {
                ctrl.getProperties().put("uiHighlightInstalled", true);
                ctrl.hoverProperty().addListener((obs, oldVal, newVal) -> updateControlHighlight(ctrl));
                ctrl.focusedProperty().addListener((obs, oldVal, newVal) -> updateControlHighlight(ctrl));
                ctrl.disabledProperty().addListener((obs, oldVal, newVal) -> updateControlHighlight(ctrl));
            }
            updateControlHighlight(ctrl);
        }
        if (node instanceof ScrollPane scroll && scroll.getContent() != null) {
            installHighlightHandlers(scroll.getContent());
        }
        if (node instanceof Parent p) {
            for (Node child : p.getChildrenUnmodifiable()) {
                installHighlightHandlers(child);
            }
        }
    }

    private void updateControlHighlight(Control ctrl) {
        if (ctrl == null) return;
        if (!isHighlightEligible(ctrl)) {
            restoreControl(ctrl);
            return;
        }
        boolean shouldHighlight = ctrl.isHover() || (consoleHighlightActive && ctrl.isFocused());
        if (shouldHighlight) {
            highlightControlSimple(ctrl);
        } else {
            restoreControl(ctrl);
        }
    }

    private boolean isHighlightEligible(Control ctrl) {
        return ctrl.isFocusTraversable()
                && !ctrl.isDisabled()
                && !Boolean.TRUE.equals(ctrl.getProperties().get("skipConsoleHighlight"));
    }

    private void highlightControlSimple(Control ctrl) {
        if (!Boolean.TRUE.equals(ctrl.getProperties().get("highlightEffectInstalled"))) {
            ctrl.getProperties().put("highlightEffectInstalled", true);
            ctrl.getProperties().put("highlightRestoreEffect", ctrl.getEffect());
        }
        Effect baseEffect = (Effect) ctrl.getProperties().get("highlightRestoreEffect");
        DropShadow glow = new DropShadow(18, Color.rgb(255, 255, 255, 0.9));
        glow.setSpread(0.22);
        glow.setInput(baseEffect);
        ctrl.setEffect(glow);
    }

    private void restoreControl(Control ctrl) {
        if (!Boolean.TRUE.equals(ctrl.getProperties().get("highlightEffectInstalled"))) return;
        Effect original = (Effect) ctrl.getProperties().get("highlightRestoreEffect");
        ctrl.setEffect(original);
    }

