    private void enhanceNullRockForm(Bird bird) {
        if (bird == null) return;
        applyNullRockBossTemplate(bird);
    }

    private void applyNullRockBossTemplate(Bird bird) {
        if (bird == null) return;
        bird.setBaseMultipliers(
                nullRockTrueFormSizeMultiplier(),
                Math.max(bird.basePowerMultiplier, nullRockTrueFormPowerMultiplier()),
                Math.max(bird.baseSpeedMultiplier, nullRockTrueFormSpeedMultiplier())
        );
        bird.health = Math.max(bird.health, nullRockTrueFormHealth());
        bird.specialMaxCooldown = Math.max(bird.specialMaxCooldown, 1080);
    }

    private String namedVariantSkinKey(BirdType type, String name) {
        if (type == null || name == null) return null;
        String normalizedName = name.toLowerCase(Locale.ROOT);
        if (type == BirdType.PIGEON && normalizedName.contains("echo")) return BEACON_PIGEON_SKIN;
        if (type == BirdType.PIGEON && normalizedName.contains("beacon")) return BEACON_PIGEON_SKIN;
        if (type == BirdType.PIGEON && normalizedName.contains("noir")) return "NOIR_PIGEON";
        if (type == BirdType.PIGEON && normalizedName.contains("freeman")) return FREEMAN_PIGEON_SKIN;
        if (type == BirdType.PIGEON && normalizedName.contains("city")) return "CITY_PIGEON";
        if (type == BirdType.EAGLE && normalizedName.contains("stock photo")) return STOCK_PHOTO_EAGLE_SKIN;
        if (type == BirdType.EAGLE && normalizedName.contains("sky king")) return "SKY_KING_EAGLE";
        if (type == BirdType.HUMMINGBIRD && normalizedName.contains("neon")) return classicSkinDataKey(type);
        if (type == BirdType.PHOENIX && normalizedName.contains("nova")) return NOVA_PHOENIX_SKIN;
        if (type == BirdType.FALCON && normalizedName.contains("dune")) return DUNE_FALCON_SKIN;
        if (type == BirdType.PENGUIN && normalizedName.contains("mint")) return MINT_PENGUIN_SKIN;
        if (type == BirdType.TITMOUSE && normalizedName.contains("volt")) return CIRCUIT_TITMOUSE_SKIN;
        if (type == BirdType.RAZORBILL && normalizedName.contains("prism")) return PRISM_RAZORBILL_SKIN;
        if (type == BirdType.PELICAN && normalizedName.contains("aurora")) return AURORA_PELICAN_SKIN;
        if (type == BirdType.VULTURE && normalizedName.contains("null rock")) return NULL_ROCK_VULTURE_SKIN;
        if (type == BirdType.VULTURE && normalizedName.contains("null roc")) return TIDE_VULTURE_SKIN;
        return null;
    }

    private String adventureOpponentSkinKey(AdventureBattle battle) {
        if (battle == null) return null;
        return namedVariantSkinKey(battle.opponentType, battle.opponentName);
    }

    private String skinKeyForBird(Bird bird) {
        if (bird == null || bird.type == null) return null;
        BirdType type = bird.type;
        if (type == BirdType.PIGEON) {
            if (bird.isCitySkin) return "CITY_PIGEON";
            if (bird.isNoirSkin) return "NOIR_PIGEON";
            if (bird.isFreemanSkin) return FREEMAN_PIGEON_SKIN;
            if (bird.isBeaconSkin) return BEACON_PIGEON_SKIN;
            return null;
        }
        if (type == BirdType.EAGLE) {
            if (bird.isPhotoEagleSkin) return STOCK_PHOTO_EAGLE_SKIN;
            if (bird.isClassicSkin) return "SKY_KING_EAGLE";
            return null;
        }
        if (type == BirdType.PHOENIX && bird.isNovaSkin) return NOVA_PHOENIX_SKIN;
        if (type == BirdType.FALCON && bird.isDuneSkin) return DUNE_FALCON_SKIN;
        if (type == BirdType.PENGUIN && bird.isMintSkin) return MINT_PENGUIN_SKIN;
        if (type == BirdType.TITMOUSE && bird.isCircuitSkin) return CIRCUIT_TITMOUSE_SKIN;
        if (type == BirdType.RAZORBILL && bird.isPrismSkin) return PRISM_RAZORBILL_SKIN;
        if (type == BirdType.PELICAN && bird.isAuroraSkin) return AURORA_PELICAN_SKIN;
        if (type == BirdType.HUMMINGBIRD && bird.isSunflareSkin) return SUNFLARE_HUMMINGBIRD_SKIN;
        if (type == BirdType.SHOEBILL && bird.isGlacierSkin) return GLACIER_SHOEBILL_SKIN;
        if (type == BirdType.VULTURE && bird.isNullRockSkin) return NULL_ROCK_VULTURE_SKIN;
        if (type == BirdType.VULTURE && bird.isTideSkin) return TIDE_VULTURE_SKIN;
        if (type == BirdType.MOCKINGBIRD && bird.isEclipseSkin) return ECLIPSE_MOCKINGBIRD_SKIN;
        if (type == BirdType.BAT && bird.isUmbraSkin) return UMBRA_BAT_SKIN;
        if (type == BirdType.ROOSTER && bird.isSunforgeSkin) return SUNFORGE_ROOSTER_SKIN;
        if (bird.isClassicSkin) return classicSkinDataKey(type);
        return null;
    }

    private AdventureChapter[] chaptersForAdventureRoute(AdventureRoute route) {
        return route == AdventureRoute.TEMPEST ? tempestAdventureChapters : adventureChapters;
    }

    private void ensureAdventureRouteState(AdventureRoute route) {
        AdventureRoute resolved = route == null ? AdventureRoute.MAIN : route;
        int idx = resolved.ordinal();
        AdventureChapter[] chapters = chaptersForAdventureRoute(resolved);
        int chapterCount = chapters.length;
        if (adventureChapterProgressByRoute[idx] == null || adventureChapterProgressByRoute[idx].length != chapterCount) {
            int[] oldProgress = adventureChapterProgressByRoute[idx];
            boolean[] oldCompleted = adventureChapterCompletedByRoute[idx];
            adventureChapterProgressByRoute[idx] = new int[chapterCount];
            adventureChapterCompletedByRoute[idx] = new boolean[chapterCount];
            if (oldProgress != null) {
                System.arraycopy(oldProgress, 0, adventureChapterProgressByRoute[idx], 0, Math.min(oldProgress.length, chapterCount));
            }
            if (oldCompleted != null) {
                System.arraycopy(oldCompleted, 0, adventureChapterCompletedByRoute[idx], 0, Math.min(oldCompleted.length, chapterCount));
            }
        }
        boolean[] unlocked = adventureUnlockedByRoute[idx];
        if (resolved == AdventureRoute.MAIN) {
            unlocked[BirdType.PIGEON.ordinal()] = true;
            unlocked[BirdType.ROOSTER.ordinal()] = roosterUnlocked;
        } else {
            unlocked[BirdType.PELICAN.ordinal()] = true;
        }
        if (adventureSelectedBirdByRoute[idx] == null) {
            adventureSelectedBirdByRoute[idx] = resolved.defaultBird;
        }
        BirdType selectedBird = adventureSelectedBirdByRoute[idx];
        if (selectedBird == null || !unlocked[selectedBird.ordinal()]) {
            adventureSelectedBirdByRoute[idx] = firstAdventureBirdForRoute(resolved);
        }
        adventureSelectedSkinKeyByRoute[idx] = normalizeAdventureSkinChoice(adventureSelectedBirdByRoute[idx], adventureSelectedSkinKeyByRoute[idx]);
        if (chapterCount > 0) {
            adventureChapterIndexByRoute[idx] = Math.clamp(adventureChapterIndexByRoute[idx], 0, chapterCount - 1);
        } else {
            adventureChapterIndexByRoute[idx] = 0;
        }
    }

    private BirdType firstAdventureBirdForRoute(AdventureRoute route) {
        boolean[] unlocked = adventureUnlockedByRoute[route.ordinal()];
        for (BirdType type : BirdType.values()) {
            if (unlocked[type.ordinal()]) {
                return type;
            }
        }
        return route.defaultBird;
    }

    private void storeActiveAdventureRouteState() {
        ensureAdventureRouteState(selectedAdventureRoute);
        int idx = selectedAdventureRoute.ordinal();
        if (adventureChapterProgressByIndex != null) {
            adventureChapterProgressByRoute[idx] = adventureChapterProgressByIndex;
        }
        if (adventureChapterCompletedByIndex != null) {
            adventureChapterCompletedByRoute[idx] = adventureChapterCompletedByIndex;
        }
        int chapterCount = adventureChapterProgressByRoute[idx].length;
        adventureChapterIndexByRoute[idx] = chapterCount > 0 ? Math.clamp(adventureChapterIndex, 0, chapterCount - 1) : 0;
        adventureSelectedBirdByRoute[idx] = adventureSelectedBird;
        adventureSelectedSkinKeyByRoute[idx] = adventureSelectedSkinKey;
        System.arraycopy(adventureUnlocked, 0, adventureUnlockedByRoute[idx], 0, adventureUnlocked.length);
    }

    private void setAdventureRoute(AdventureRoute route) {
        AdventureRoute resolved = route == null ? AdventureRoute.MAIN : route;
        if (adventureChapterProgressByIndex != null || adventureChapterCompletedByIndex != null) {
            storeActiveAdventureRouteState();
        }
        selectedAdventureRoute = resolved;
        ensureAdventureRouteState(resolved);
        int idx = resolved.ordinal();
        adventureChapterProgressByIndex = adventureChapterProgressByRoute[idx];
        adventureChapterCompletedByIndex = adventureChapterCompletedByRoute[idx];
        System.arraycopy(adventureUnlockedByRoute[idx], 0, adventureUnlocked, 0, adventureUnlocked.length);
        int chapterCount = adventureChapterProgressByIndex.length;
        adventureChapterIndex = chapterCount > 0 ? Math.clamp(adventureChapterIndexByRoute[idx], 0, chapterCount - 1) : 0;
        adventureChapterProgress = chapterCount > 0 ? adventureChapterProgressByIndex[adventureChapterIndex] : 0;
        adventureChapterCompleted = chapterCount > 0 && adventureChapterCompletedByIndex[adventureChapterIndex];
        adventureSelectedBird = adventureSelectedBirdByRoute[idx];
        if (adventureSelectedBird == null || isAdventureBirdUnlocked(adventureSelectedBird)) {
            adventureSelectedBird = firstAdventureBirdForRoute(resolved);
        }
        adventureSelectedSkinKey = normalizeAdventureSkinChoice(adventureSelectedBird, adventureSelectedSkinKeyByRoute[idx]);
        adventureSelectedBirdByRoute[idx] = adventureSelectedBird;
        adventureSelectedSkinKeyByRoute[idx] = adventureSelectedSkinKey;
        currentAdventureBattle = null;
    }

    private void setAdventureBirdUnlocked(AdventureRoute route, BirdType type, boolean unlocked) {
        if (type == null) return;
        ensureAdventureRouteState(route);
        adventureUnlockedByRoute[route.ordinal()][type.ordinal()] = unlocked;
        if (route == selectedAdventureRoute) {
            adventureUnlocked[type.ordinal()] = unlocked;
        }
    }

    boolean isAdventureBirdAvailableForCurrentRoute(BirdType type) {
        if (type == null) {
            return true;
        }
        ensureAdventureRouteState(selectedAdventureRoute);
        return adventureUnlocked[type.ordinal()];
    }

    void unlockAdventureBirdForCurrentRoute(BirdType type) {
        if (type == null) {
            return;
        }
        setAdventureBirdUnlocked(selectedAdventureRoute, type, true);
    }

    private boolean[] mainAdventureChapterCompletedState() {
        ensureAdventureRouteState(AdventureRoute.MAIN);
        return adventureChapterCompletedByRoute[AdventureRoute.MAIN.ordinal()];
    }

    private String adventureRosterText() {
        return adventureRosterText(selectedAdventureRoute);
    }

    private String adventureRosterText(AdventureRoute route) {
        ensureAdventureRouteState(route);
        boolean[] unlocked = route == selectedAdventureRoute
                ? adventureUnlocked
                : adventureUnlockedByRoute[route.ordinal()];
        List<String> names = new ArrayList<>();
        for (BirdType bt : BirdType.values()) {
            if (unlocked[bt.ordinal()]) names.add(bt.name);
        }
        return names.isEmpty() ? route.defaultBird.name : String.join(", ", names);
    }

    private String adventureRewardText(AdventureBattle battle) {
        if (battle == null || battle.unlockReward == null) {
            return "Reward: Story progress";
        }
        if (selectedAdventureRoute == AdventureRoute.TEMPEST) {
            return "Crew reward: " + battle.unlockReward.name + " joins Tempest Run";
        }
        return "Unlock reward: " + battle.unlockReward.name;
    }

    private AdventureChapter activeAdventureChapter() {
        AdventureChapter[] chapters = chaptersForAdventureRoute(selectedAdventureRoute);
        if (chapters.length == 0) return null;
        adventureChapterIndex = Math.clamp(adventureChapterIndex, 0, chapters.length - 1);
        return chapters[adventureChapterIndex];
    }

    private void ensureAdventureChapterState() {
        ensureAdventureRouteState(selectedAdventureRoute);
        int idx = selectedAdventureRoute.ordinal();
        adventureChapterProgressByIndex = adventureChapterProgressByRoute[idx];
        adventureChapterCompletedByIndex = adventureChapterCompletedByRoute[idx];
    }

    private AdventureBattle activeAdventureBattle() {
        AdventureChapter chapter = activeAdventureChapter();
        if (chapter == null || chapter.battles.length == 0) return null;
        adventureBattleIndex = Math.clamp(adventureBattleIndex, 0, chapter.battles.length - 1);
        return chapter.battles[adventureBattleIndex];
    }

    private int unitedFinaleChapterIndex() {
        for (int i = 0; i < adventureChapters.length; i++) {
            String title = adventureChapters[i].title;
            if (title != null && title.contains("Sky of All Wings")) return i;
        }
        return -1;
    }

    private boolean isUnitedFinaleClimaxBattle(AdventureBattle battle) {
        return battle != null
                && selectedAdventureRoute == AdventureRoute.MAIN
                && adventureChapterIndex == unitedFinaleChapterIndex()
                && UNITED_FINALE_CLIMAX_TITLE.equals(battle.title);
    }

    private boolean isUnitedFinaleBeaconBattle(AdventureBattle battle) {
        return battle != null
                && selectedAdventureRoute == AdventureRoute.MAIN
                && adventureChapterIndex == unitedFinaleChapterIndex()
                && (UNITED_FINALE_PENULTIMATE_TITLE.equals(battle.title) || UNITED_FINALE_CLIMAX_TITLE.equals(battle.title));
    }

    private boolean isUnitedFinaleClimaxContext() {
        AdventureBattle battle = currentAdventureBattle != null ? currentAdventureBattle : activeAdventureBattle();
        return (adventureModeActive || currentAdventureBattle != null) && isUnitedFinaleClimaxBattle(battle);
    }

    private Bird unitedFinaleBoss() {
        if (!isUnitedFinaleClimaxContext()) return null;
        Bird best = null;
        for (Bird b : players) {
            if (b == null) continue;
            if (getEffectiveTeam(b.playerIndex) != 2) continue;
            if (b.health > 0) return b;
            if (best == null) best = b;
        }
        return best;
    }

    private Bird firstLivingAdventureAlly() {
        Bird player = players[0];
        if (player != null && player.health > 0) return player;
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;
            if (getEffectiveTeam(b.playerIndex) == 1) return b;
        }
        return null;
    }

    private boolean isUnitedFinaleMassBattleContext() {
        return unitedFinaleMassBattleActive && isUnitedFinaleClimaxContext();
    }

    private List<UnitedFinaleSupportEntry> buildUnitedFinaleSupportEntries(BirdType playerType) {
        List<UnitedFinaleSupportEntry> entries = new ArrayList<>();
        queueUnitedFinaleSupport(entries, playerType, BirdType.EAGLE, "Ally: Sky King", "SKY_KING_EAGLE");
        queueUnitedFinaleSupport(entries, playerType, BirdType.PHOENIX, "Ally: Nova Phoenix", NOVA_PHOENIX_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.HUMMINGBIRD, "Ally: Neon Hummingbird", classicSkinDataKey(BirdType.HUMMINGBIRD));
        queueUnitedFinaleSupport(entries, playerType, BirdType.FALCON, "Ally: Dune Falcon", DUNE_FALCON_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.TITMOUSE, "Ally: Volt Titmouse", CIRCUIT_TITMOUSE_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.BAT, "Ally: Umbra Bat", UMBRA_BAT_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.RAVEN, "Ally: Night Raven", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.PIGEON, "Ally: Beacon Pigeon", BEACON_PIGEON_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.PENGUIN, "Ally: Mint Penguin", MINT_PENGUIN_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.PELICAN, "Ally: Aurora Pelican", AURORA_PELICAN_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.TURKEY, "Ally: Ground Turkey", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.ROADRUNNER, "Ally: Dust Devil Roadrunner", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.SHOEBILL, "Ally: Glacier Shoebill", GLACIER_SHOEBILL_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.GRINCHHAWK, "Ally: Grinch-Hawk", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.RAZORBILL, "Ally: Prism Razorbill", PRISM_RAZORBILL_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.ROOSTER, "Ally: Sunforge Rooster", SUNFORGE_ROOSTER_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.MOCKINGBIRD, "Ally: Charles", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.VULTURE, "Ally: Tide Vulture", TIDE_VULTURE_SKIN);
        queueUnitedFinaleSupport(entries, playerType, BirdType.OPIUMBIRD, "Ally: Opium Bird", null);
        queueUnitedFinaleSupport(entries, playerType, BirdType.HEISENBIRD, "Ally: Heisenbird", null);
        return entries;
    }

    private void queueUnitedFinaleSupport(List<UnitedFinaleSupportEntry> entries,
                                          BirdType playerType,
                                          BirdType type,
                                          String displayName,
                                          String skinKey) {
        if (type == null || type == playerType) return;
        double health = 94.0 + type.power * 2.6;
        double powerMult = 1.04 + Math.min(0.22, type.power * 0.0105);
        double speedMult = 1.02 + Math.min(0.18, type.speed * 0.03);
        entries.add(new UnitedFinaleSupportEntry(type, displayName, skinKey, health, powerMult, speedMult));
    }

    private void createUnitedFinaleSupportBird(UnitedFinaleSupportEntry entry,
                                               int slot,
                                               double spawnX,
                                               double verticalOffset) {
        Bird support = createStoryBird(
                spawnX,
                entry.type(),
                slot,
                entry.displayName(),
                entry.health(),
                entry.powerMult(),
                entry.speedMult(),
                true
        );
        applyPreviewSkinChoiceToBird(support, entry.type(), entry.skinKey());
        support.y = Math.max(CEILING_Y + 140, support.y - verticalOffset);
        support.specialCooldown = 0;
        support.rageTimer = Math.max(support.rageTimer, 160);
        support.overchargeAttackTimer = Math.max(support.overchargeAttackTimer, 120);
        support.speedTimer = Math.max(support.speedTimer, 220);
        support.speedMultiplier = Math.max(support.speedMultiplier, support.baseSpeedMultiplier * (1.1));
        support.powerMultiplier = Math.max(support.powerMultiplier, support.basePowerMultiplier * (1.08));
        support.facingRight = true;
        support.vx = 2.4;
        if (slot < adventureTeams.length) {
            adventureTeams[slot] = 1;
        }
    }

    private void populateUnitedFinaleMassRoster(BirdType playerType) {
        List<UnitedFinaleSupportEntry> entries = buildUnitedFinaleSupportEntries(playerType);
        int slot = 1;
        double baseX = 1300.0;
        double columnSpacing = 340.0;
        double rowSpacing = 150.0;
        int rows = 3;
        for (int i = 0; i < entries.size() && slot < players.length - 1; i++) {
            int row = i % rows;
            int col = i / rows;
            double spawnX = baseX + col * columnSpacing + (row == 1 ? 90.0 : row == 2 ? 45.0 : 0.0);
            double verticalOffset = row * rowSpacing;
            createUnitedFinaleSupportBird(entries.get(i), slot, spawnX, verticalOffset);
            slot++;
        }
    }

    void onTrueNullRockAscension(Bird boss) {
        if (boss == null) return;
        addToKillFeed("TRUE NULL ROCK: the divine core opens.");
        shakeIntensity = Math.max(shakeIntensity, 44);
        hitstopFrames = Math.max(hitstopFrames, 18);
        triggerFlash(0.94, false);
        if (isUnitedFinaleClimaxContext()) {
            empowerUnitedFinaleAllies(108, 240, 200);
        }
    }

    private void applyAdventureBattleRuntimeEffects() {
        AdventureBattle battle = currentAdventureBattle != null ? currentAdventureBattle : activeAdventureBattle();
        if (battle == null) return;
        if (selectedAdventureRoute == AdventureRoute.TEMPEST) {
            applyTempestAdventureRuntimeEffects(battle);
            return;
        }
        if (!isUnitedFinaleClimaxBattle(battle)) return;

        Bird boss = unitedFinaleBoss();
        if (boss == null || boss.health <= 0 || matchEnded) return;
        double bossMaxHealth = unitedFinaleBossMaxHealth();
        double bossRatio = bossMaxHealth <= 0 ? 1.0 : Math.clamp(boss.health / bossMaxHealth, 0.0, 1.0);

        if (!unitedFinaleEventTriggered[0]) {
            unitedFinaleEventTriggered[0] = true;
            addToKillFeed("BEACON CROWN: every bird answers the call.");
            shakeIntensity = Math.max(shakeIntensity, 28);
            hitstopFrames = Math.max(hitstopFrames, 14);
            empowerUnitedFinaleAllies(0, 120, 90);
            unitedFinaleDarkForceCooldown = 220;
        }
        if (!unitedFinaleEventTriggered[1]) {
            unitedFinaleEventTriggered[1] = true;
            runUnitedFinaleEvent(1, boss);
        }
        if (!unitedFinaleEventTriggered[2] && boss.health <= bossMaxHealth * 0.78) {
            unitedFinaleEventTriggered[2] = true;
            runUnitedFinaleEvent(2, boss);
        }
        if (!unitedFinaleBossEnraged && boss.health <= bossMaxHealth * 0.62) {
            unitedFinaleBossEnraged = true;
            addToKillFeed("THE NULL ROCK: THE CROWN GOES FERAL.");
            boss.rageTimer = Math.max(boss.rageTimer, 420);
            boss.powerMultiplier = Math.max(boss.powerMultiplier, boss.basePowerMultiplier * 1.28);
            boss.speedMultiplier = Math.max(boss.speedMultiplier, boss.baseSpeedMultiplier * 1.12);
            boss.specialCooldown = 0;
            shakeIntensity = Math.max(shakeIntensity, 36);
            triggerFlash(0.85, false);
            summonUnitedFinaleDarkForceWave(boss, bossRatio);
            unitedFinaleDarkForceCooldown = 170;
        }
        if (!unitedFinaleEventTriggered[3] && boss.health <= bossMaxHealth * 0.56) {
            unitedFinaleEventTriggered[3] = true;
            runUnitedFinaleEvent(3, boss);
        }
        if (!unitedFinaleEventTriggered[4] && boss.health <= bossMaxHealth * 0.36) {
            unitedFinaleEventTriggered[4] = true;
            runUnitedFinaleEvent(4, boss);
        }
        if (!unitedFinaleEventTriggered[5] && boss.health <= bossMaxHealth * 0.16) {
            unitedFinaleEventTriggered[5] = true;
            runUnitedFinaleEvent(5, boss);
        }

        if (unitedFinaleDarkForceCooldown > 0) {
            unitedFinaleDarkForceCooldown--;
        }
        if (unitedFinaleDarkForceCooldown <= 0) {
            summonUnitedFinaleDarkForceWave(boss, bossRatio);
            unitedFinaleDarkForceCooldown = bossRatio <= 0.18 ? 120
                    : bossRatio <= 0.36 ? 160
                    : bossRatio <= 0.60 ? 210
                    : 280;
        }
    }

    private Bird tempestAdventureBoss() {
        Bird best = null;
        for (Bird bird : players) {
            if (bird == null) continue;
            if (adventureTeamMode && getEffectiveTeam(bird.playerIndex) == 1) continue;
            if (!adventureTeamMode && bird.playerIndex == 0) continue;
            if (bird.health > 0) return bird;
            if (best == null) best = bird;
        }
        return best;
    }

    private void applyTempestAdventureRuntimeEffects(AdventureBattle battle) {
        if (battle == null || matchEnded) return;
        if (adventureChapterIndex != 3 || adventureBattleIndex != 2) return;

        Bird boss = tempestAdventureBoss();
        if (boss == null || boss.health <= 0) return;
        double bossMaxHealth = adjustedBossHealth(battle.opponentName, battle.opponentHealth);
        double bossRatio = bossMaxHealth <= 0 ? 1.0 : Math.clamp(boss.health / bossMaxHealth, 0.0, 1.0);

        if (!tempestRunEventTriggered[0]) {
            tempestRunEventTriggered[0] = true;
            addToKillFeed("TEMPEST RUN: the weather forge wakes up around the Crown.");
            hitstopFrames = Math.max(hitstopFrames, 10);
            shakeIntensity = Math.max(shakeIntensity, 18);
            empowerUnitedFinaleAllies(0, 120, 90);
        }
        if (!tempestRunEventTriggered[1] && bossRatio <= 0.74) {
            tempestRunEventTriggered[1] = true;
            addToKillFeed("TEMPEST RUN: Falcon cuts the eye open for one clean lane.");
            windVents.add(new WindVent(1700, battlefieldIslandY - 120, 240));
            windVents.add(new WindVent(4300, battlefieldIslandY - 120, 240));
            powerUps.add(new PowerUp(3000, battlefieldIslandY - 760, PowerUpType.SPEED));
            Bird owner = firstLivingAdventureAlly();
            if (owner != null) {
                spawnUnitedFinaleAlliedCrows(owner, 2);
            }
            triggerFlash(0.55, false);
        }
        if (!tempestRunBossEnraged && bossRatio <= 0.46) {
            tempestRunBossEnraged = true;
            addToKillFeed("STORMGLASS KING: the forge overloads into a live supercell.");
            boss.rageTimer = Math.max(boss.rageTimer, 300);
            boss.overchargeAttackTimer = Math.max(boss.overchargeAttackTimer, 260);
            boss.specialCooldown = 0;
            boss.powerMultiplier = Math.max(boss.powerMultiplier, boss.basePowerMultiplier * 1.12);
            boss.speedMultiplier = Math.max(boss.speedMultiplier, boss.baseSpeedMultiplier * 1.06);
            powerUps.add(new PowerUp(2200, battlefieldIslandY - 820, PowerUpType.HEALTH));
            powerUps.add(new PowerUp(3800, battlefieldIslandY - 820, PowerUpType.OVERCHARGE));
            shakeIntensity = Math.max(shakeIntensity, 28);
        }
        if (!tempestRunEventTriggered[2] && bossRatio <= 0.24) {
            tempestRunEventTriggered[2] = true;
            addToKillFeed("TEMPEST RUN: the convoy commits everything to the last pass.");
            Bird owner = firstLivingAdventureAlly();
            empowerUnitedFinaleAllies(90, 180, 140);
            if (owner != null) {
                spawnUnitedFinaleAlliedCrows(owner, 4);
                spawnUnitedFinaleChicks(owner);
            }
            for (int i = 0; i < 4; i++) {
                crowMinions.add(new CrowMinion(900 + random.nextDouble() * 4200, 220 + random.nextDouble() * 280, null));
            }
        }
        if (!tempestRunEventTriggered[3] && bossRatio <= 0.10) {
            tempestRunEventTriggered[3] = true;
            addToKillFeed("TEMPEST RUN: one more clean hit ends the route.");
            powerUps.add(new PowerUp(3000, battlefieldIslandY - 940, PowerUpType.TITAN));
            hitstopFrames = Math.max(hitstopFrames, 8);
            triggerFlash(0.78, false);
        }
    }

    private void summonUnitedFinaleDarkForceWave(Bird boss, double bossRatio) {
        if (boss == null || boss.health <= 0) return;
        int wave = unitedFinaleDarkForceWave++;
        int phase = wave % 4;
        double highLane = battlefieldIslandY - 520;
        double midLane = battlefieldIslandY - 320;
        double lowLane = battlefieldIslandY - 120;

        switch (phase) {
            case 0 -> {
                addToKillFeed("THE NULL ROCK: giant crows blot out the Beacon beam.");
                summonDarkForceWing(boss, CrowMinion.VARIANT_GIANT_CROW, bossRatio < 0.45 ? 3 : 2, highLane, true);
                summonDarkForceWing(boss, CrowMinion.VARIANT_GIANT_CROW, bossRatio < 0.45 ? 3 : 2, midLane, false);
            }
            case 1 -> {
                addToKillFeed("THE NULL ROCK: ravens rake across the whole platform.");
                summonDarkForceWing(boss, CrowMinion.VARIANT_RAVEN, bossRatio < 0.35 ? 5 : 4, midLane, true);
                summonDarkForceWing(boss, CrowMinion.VARIANT_RAVEN, bossRatio < 0.35 ? 4 : 3, lowLane, false);
            }
            case 2 -> {
                addToKillFeed("THE NULL ROCK: void ravens split from the eclipse.");
                summonDarkForceWing(boss, CrowMinion.VARIANT_VOID_RAVEN, bossRatio < 0.30 ? 4 : 3, highLane - 40, true);
                summonDarkForceWing(boss, CrowMinion.VARIANT_VOID_RAVEN, bossRatio < 0.30 ? 3 : 2, highLane + 70, false);
            }
            default -> {
                addToKillFeed("THE NULL ROCK: the dark flock descends all at once.");
                summonDarkForceWing(boss, CrowMinion.VARIANT_GIANT_CROW, 2, highLane, wave % 2 == 0);
                summonDarkForceWing(boss, CrowMinion.VARIANT_RAVEN, bossRatio < 0.28 ? 5 : 3, midLane, true);
                summonDarkForceWing(boss, CrowMinion.VARIANT_VOID_RAVEN, bossRatio < 0.42 ? 3 : 2, lowLane, false);
            }
        }

        if (bossRatio < 0.26) {
            Bird owner = firstLivingAdventureAlly();
            if (owner != null) {
                spawnUnitedFinaleAlliedCrows(owner, 4);
            }
        }
        shakeIntensity = Math.max(shakeIntensity, bossRatio < 0.28 ? 24 : 16);
    }

    private void summonDarkForceWing(Bird owner, int variant, int count, double laneY, boolean fromLeft) {
        if (owner == null || count <= 0) return;
        double edge = fromLeft ? battlefieldLeftBound() - 160 : battlefieldRightBound() + 160;
        double dir = fromLeft ? 1.0 : -1.0;
        for (int i = 0; i < count; i++) {
            double x = edge - dir * i * 96;
            double y = laneY + random.nextDouble() * 180 - 90 + i * 18;
            CrowMinion crow = new CrowMinion(x, y, null).withVariant(variant);
            crow.owner = owner;
            crow.vx = dir * (2.4 + random.nextDouble() * 1.2);
            crow.vy = -0.8 + random.nextDouble() * 1.6;
            crowMinions.add(crow);
        }
    }

    void summonNullRockSpecialFlock(Bird owner, boolean ultimate) {
        if (owner == null || owner.health <= 0) return;
        addToKillFeed(shortName(owner.name) + (ultimate ? " ULT OPENS THE VOID FLOCK!" : " summons the dark flock!"));
        double centerY = owner.y + 40 * owner.sizeMultiplier;
        double highLane = Math.clamp(centerY - 280, 160.0, GROUND_Y - 240.0);
        double midLane = Math.clamp(centerY - 80, 180.0, GROUND_Y - 180.0);
        double lowLane = Math.clamp(centerY + 120, 220.0, GROUND_Y - 140.0);
        boolean fromLeft = !owner.facingRight;
        summonDarkForceWing(owner, CrowMinion.VARIANT_GIANT_CROW, ultimate ? 3 : 2, highLane, fromLeft);
        summonDarkForceWing(owner, CrowMinion.VARIANT_RAVEN, ultimate ? 5 : 3, midLane, !fromLeft);
        summonDarkForceWing(owner, CrowMinion.VARIANT_VOID_RAVEN, ultimate ? 3 : 2, lowLane, fromLeft);
        if (ultimate) {
            summonDarkForceWing(owner, CrowMinion.VARIANT_MURDER_CROW, 4, Math.clamp(centerY + 10, 200.0, GROUND_Y - 160.0), !fromLeft);
        }
    }

    void onNullRockPhaseShift(Bird owner, int phaseIndex) {
        if (owner == null) return;
        String line = switch (phaseIndex) {
            case 0 -> "THE NULL ROCK hardens into a void shell.";
            case 1 -> "THE NULL ROCK sheds another layer and calls heavier wings.";
            case 2 -> "THE NULL ROCK tears the air open for raven shadows.";
            default -> "THE NULL ROCK enters its last shell and refuses to fall.";
        };
        addToKillFeed(line);
        shakeIntensity = Math.max(shakeIntensity, 24 + phaseIndex * 4);
        hitstopFrames = Math.max(hitstopFrames, 10 + phaseIndex * 2);
        triggerFlash(0.72, false);

        double centerX = owner.x + 40 * owner.sizeMultiplier;
        double centerY = owner.y + 40 * owner.sizeMultiplier;
        for (int i = 0; i < 42; i++) {
            double angle = Math.PI * 2 * i / 42.0;
            double speed = 4 + random.nextDouble() * 9;
            Color c = i % 2 == 0 ? Color.web("#FFCDD2") : Color.web("#80DEEA");
            particles.add(new Particle(
                    centerX,
                    centerY,
                    Math.cos(angle) * speed,
                    Math.sin(angle) * speed - 3.5,
                    c.deriveColor(0, 1, 1, 0.82)
            ));
        }

        double highLane = Math.clamp(centerY - 260, 160.0, GROUND_Y - 240.0);
        double midLane = Math.clamp(centerY - 60, 180.0, GROUND_Y - 180.0);
        double lowLane = Math.clamp(centerY + 130, 220.0, GROUND_Y - 130.0);
        boolean fromLeft = phaseIndex % 2 == 0;
        switch (phaseIndex) {
            case 0 -> summonDarkForceWing(owner, CrowMinion.VARIANT_GIANT_CROW, 2, highLane, true);
            case 1 -> summonDarkForceWing(owner, CrowMinion.VARIANT_RAVEN, 4, midLane, false);
            case 2 -> {
                summonDarkForceWing(owner, CrowMinion.VARIANT_RAVEN, 3, midLane, true);
                summonDarkForceWing(owner, CrowMinion.VARIANT_VOID_RAVEN, 2, lowLane, false);
            }
            default -> {
                summonDarkForceWing(owner, CrowMinion.VARIANT_GIANT_CROW, 2, highLane, fromLeft);
                summonDarkForceWing(owner, CrowMinion.VARIANT_VOID_RAVEN, 3, lowLane, !fromLeft);
            }
        }
    }

    private void runUnitedFinaleEvent(int eventIndex, Bird boss) {
        if (boss == null) return;
        switch (eventIndex) {
            case 1 -> {
                addToKillFeed("SKY WING: Eagle, Falcon, Hummingbird, Titmouse, Bat, and Raven dive together!");
                empowerUnitedFinaleAllies(0, 150, 120);
                windVents.add(new WindVent(1200, GROUND_Y - 520, 460));
                windVents.add(new WindVent(3000, GROUND_Y - 620, 520));
                windVents.add(new WindVent(4580, GROUND_Y - 520, 460));
                powerUps.add(new PowerUp(1700, GROUND_Y - 900, PowerUpType.SPEED));
                powerUps.add(new PowerUp(3000, GROUND_Y - 1080, PowerUpType.THERMAL));
                powerUps.add(new PowerUp(4300, GROUND_Y - 900, PowerUpType.NEON));
                boss.vy -= 12;
                boss.applyStun(18);
                damageBossFromUnitedFlock(boss, 18, Color.web("#FFE082"), Color.CYAN);
            }
            case 2 -> {
                addToKillFeed("EMBER CHOIR: Pigeon, Phoenix, Pelican, and Penguin lock the line and burn the void back!");
                empowerUnitedFinaleAllies(65, 180, 120);
                powerUps.add(new PowerUp(2000, GROUND_Y - 760, PowerUpType.HEALTH));
                powerUps.add(new PowerUp(3000, GROUND_Y - 980, PowerUpType.RAGE));
                powerUps.add(new PowerUp(4000, GROUND_Y - 760, PowerUpType.OVERCHARGE));
                boss.vx *= 0.4;
                boss.vy -= 10;
                boss.applyStun(22);
                damageBossFromUnitedFlock(boss, 20, Color.web("#FFCA28"), Color.ORANGERED);
            }
            case 3 -> {
                addToKillFeed("GROUND RING: Turkey, Roadrunner, Shoebill, Grinch-Hawk, and Razorbill hammer the titan's core!");
                empowerUnitedFinaleAllies(0, 200, 140);
                powerUps.add(new PowerUp(1800, GROUND_Y - 820, PowerUpType.TITAN));
                powerUps.add(new PowerUp(3000, GROUND_Y - 1120, PowerUpType.HEALTH));
                powerUps.add(new PowerUp(4200, GROUND_Y - 820, PowerUpType.OVERCHARGE));
                boss.vx *= 0.2;
                boss.vy -= 18;
                boss.applyStun(28);
                shakeIntensity = Math.max(shakeIntensity, 42);
                damageBossFromUnitedFlock(boss, 28, Color.web("#FF7043"), Color.WHITE);
            }
            case 4 -> {
                addToKillFeed("SHADOW FLOCK: Rooster, Charles, Vulture, Opium Bird, and Heisenbird flood the crown!");
                empowerUnitedFinaleAllies(58, 220, 180);
                Bird owner = firstLivingAdventureAlly();
                if (owner != null) {
                    spawnUnitedFinaleAlliedCrows(owner, 6);
                    spawnUnitedFinaleChicks(owner);
                }
                boss.vx *= 0.3;
                boss.applyStun(24);
                damageBossFromUnitedFlock(boss, 16, Color.web("#AB47BC"), Color.web("#29B6F6"));
            }
            case 5 -> {
                addToKillFeed("ALL WINGS: the full Bird Fight 3 roster hits at once. Finish it!");
                empowerUnitedFinaleAllies(74, 300, 240);
                Bird owner = firstLivingAdventureAlly();
                if (owner != null) {
                    spawnUnitedFinaleAlliedCrows(owner, 10);
                    spawnUnitedFinaleChicks(owner);
                }
                powerUps.add(new PowerUp(1600, GROUND_Y - 880, PowerUpType.HEALTH));
                powerUps.add(new PowerUp(2400, GROUND_Y - 980, PowerUpType.SPEED));
                powerUps.add(new PowerUp(3000, GROUND_Y - 1180, PowerUpType.RAGE));
                powerUps.add(new PowerUp(3600, GROUND_Y - 980, PowerUpType.OVERCHARGE));
                powerUps.add(new PowerUp(4400, GROUND_Y - 880, PowerUpType.TITAN));
                boss.vx = 0;
                boss.vy -= 24;
                boss.applyStun(36);
                shakeIntensity = Math.max(shakeIntensity, 55);
                hitstopFrames = Math.max(hitstopFrames, 16);
                damageBossFromUnitedFlock(boss, 36, Color.web("#FFF176"), Color.web("#80DEEA"));
            }
            default -> {
            }
        }
    }

    private void empowerUnitedFinaleAllies(double healthFloor, int rageFrames, int overchargeFrames) {
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;
            if (getEffectiveTeam(b.playerIndex) != 1) continue;
            if (healthFloor > 0 && b.health < healthFloor) {
                b.health = healthFloor;
            }
            b.specialCooldown = 0;
            b.rageTimer = Math.max(b.rageTimer, rageFrames);
            b.overchargeAttackTimer = Math.max(b.overchargeAttackTimer, overchargeFrames);
            b.speedTimer = Math.max(b.speedTimer, 180);
            b.speedMultiplier = Math.max(b.speedMultiplier, b.baseSpeedMultiplier * 1.14);
            b.powerMultiplier = Math.max(b.powerMultiplier, b.basePowerMultiplier * 1.16);
        }
    }

    private void damageBossFromUnitedFlock(Bird boss, double damage, Color primary, Color secondary) {
        if (boss == null || boss.health <= 0 || damage <= 0) return;
        double dealt = boss.receiveExternalDamage(damage);
        if (dealt <= 0) return;
        damageDealt[0] += (int) Math.round(dealt);
        triggerFlash(Math.min(1.0, 0.35 + dealt / 55.0), boss.health <= 0);
        playHitSound(dealt);

        double centerX = boss.x + 40 * boss.sizeMultiplier;
        double centerY = boss.y + 40 * boss.sizeMultiplier;
        for (int i = 0; i < 72; i++) {
            double angle = Math.PI * 2 * i / 72.0;
            double speed = 5 + random.nextDouble() * 14;
            Color color = (i % 2 == 0 ? primary : secondary).deriveColor(0, 1, 1, 0.82);
            particles.add(new Particle(
                    centerX,
                    centerY,
                    Math.cos(angle) * speed,
                    Math.sin(angle) * speed - 5,
                    color
            ));
        }
    }

    private void spawnUnitedFinaleAlliedCrows(Bird owner, int count) {
        if (owner == null) return;
        double centerX = owner.x + 40 * owner.sizeMultiplier;
        double centerY = owner.y + 20 * owner.sizeMultiplier;
        for (int i = 0; i < count; i++) {
            double angle = Math.PI * 2 * i / count;
            double dist = 90 + i * 12.0;
            CrowMinion crow = new CrowMinion(
                    centerX + Math.cos(angle) * dist,
                    centerY + Math.sin(angle) * dist,
                    null
            );
            crow.owner = owner;
            crow.hasCrown = i % 3 == 0;
            crow.vx = Math.cos(angle) * 4.2;
            crow.vy = Math.sin(angle) * 2.4 - 1.5;
            crowMinions.add(crow);
        }
    }

    private void spawnUnitedFinaleChicks(Bird owner) {
        if (owner == null) return;
        double centerX = owner.x + 40 * owner.sizeMultiplier;
        double spawnY = owner.y + 48 * owner.sizeMultiplier;
        for (int i = 0; i < 3; i++) {
            double offset = (i - 1) * 44 * owner.sizeMultiplier;
            ChickMinion chick = new ChickMinion(centerX + offset, spawnY, i, true, owner);
            chick.x -= chick.width * 0.5;
            chick.onGround = true;
            chickMinions.add(chick);
        }
    }

    private String classicCharacterReward(BirdType type) {
        if (type == BirdType.HUMMINGBIRD) {
            return "Titmouse Character";
        }
        return "";
    }

    private BirdType firstUnlockedBird() {
        for (BirdType bt : BirdType.values()) {
            if (isBirdUnlocked(bt)) return bt;
        }
        return BirdType.PIGEON;
    }

