    private void gameTick() {
        if (lastUpdate == 0) {
            lastUpdate = System.nanoTime();
            return;
        }

        final long FRAME_TIME = 16_666_666L;   // exactly 60 FPS
        long frameNow = System.nanoTime();
        long elapsed = frameNow - lastUpdate;
        lastUpdate = frameNow;

        if (trainingModeActive && trainingFrameAdvancePause && trainingFrameAdvanceRequests <= 0) {
            accumulator = 0;
            return;
        }

        if (hitstopFrames > 0) {
            hitstopFrames--;
            if (trainingModeActive && trainingFrameAdvancePause) {
                trainingFrameAdvanceRequests--;
            }
            return;
        }

        pollWiimoteGameplayInputs();

        boolean lanClientViewOnly = lanModeActive && lanIsClient;
        if (lanModeActive && lanIsHost && lanMatchActive) {
            applyLanInputMasks();
        }

        if (trainingModeActive && trainingFrameAdvancePause) {
            accumulator = FRAME_TIME;
        } else {
            double elapsedScale = trainingModeActive && trainingSlowMotionEnabled ? TRAINING_SLOW_MOTION_SCALE : 1.0;
            accumulator += (long) (elapsed * elapsedScale);
        }

        final long MAX_UPDATES = 6;
        int updates = 0;

        while (accumulator >= FRAME_TIME && updates < MAX_UPDATES) {
            pollWiimoteGameplayInputs();
            if (lanModeActive && lanIsHost && lanMatchActive) {
                applyLanInputMasks();
            }
            updateMatchIntroCountdown();
            boolean introLocked = isMatchIntroLocked();
            if (!lanClientViewOnly) {
                if (!introLocked) {
                    for (int i = 0; i < activePlayers; i++) {
                        if (players[i] != null) {
                            players[i].update(1.0);
                        }
                    }
                    long now = System.nanoTime();
                    applyMatchModeRuntimeEffects(now);
                    spawnPowerUp(now);
                    if (!matchEnded && !trainingModeActive && matchTimer > 0) matchTimer--;
                    updateWorldFixed();
                    trimTransientEffectOverflow();
                } else {
                    updateDynamicCamera();
                }
            }

            if (!introLocked) {
                updateParticlesFixed();
                trimTransientEffectOverflow();
            }

            accumulator -= FRAME_TIME;
            updates++;
            if (trainingModeActive && trainingFrameAdvancePause && trainingFrameAdvanceRequests > 0) {
                trainingFrameAdvanceRequests--;
                accumulator = 0;
                break;
            }
        }
        if (!particleEffectsEnabled && !particles.isEmpty()) {
            particles.clear();
        }
    }

    int scaledParticleBurstCount(int requested) {
        if (!particleEffectsEnabled || requested <= 0) {
            return 0;
        }
        double loadPenalty = 0.0;
        if (isLargeFightLoad()) {
            loadPenalty += 0.22;
        }
        loadPenalty += Math.min(0.28, Math.max(0, activePlayers - 4) * 0.02);
        loadPenalty += Math.min(0.24,
                crowMinions.size() * 0.004
                        + chickMinions.size() * 0.01
                        + piranhaHazards.size() * 0.012);
        double fillRatio = Math.clamp((double) particles.size() / Math.max(1, activeParticleSoftCap()), 0.0, 1.4);
        loadPenalty += Math.min(0.38, fillRatio * 0.36);
        double scale = Math.clamp(1.0 - loadPenalty, 0.24, 1.0);
        int minimum = requested >= 180 ? 24
                : requested >= 100 ? 18
                : requested >= 60 ? 12
                : 6;
        return Math.max(minimum, (int) Math.round(requested * scale));
    }

    private boolean isLargeFightLoad() {
        return activePlayers >= 8 || crowMinions.size() + chickMinions.size() + piranhaHazards.size() >= 14;
    }

    private int activeParticleSoftCap() {
        int cap = isLargeFightLoad() ? LARGE_FIGHT_PARTICLE_CAP : PARTICLE_SOFT_CAP;
        cap -= Math.max(0, activePlayers - 4) * 30;
        cap -= Math.min(480, crowMinions.size() * 8 + chickMinions.size() * 14 + piranhaHazards.size() * 18);
        return Math.max(PARTICLE_FLOOR_CAP, cap);
    }

    private int activeCrowMinionCap() {
        int cap = isLargeFightLoad() ? LARGE_FIGHT_CROW_CAP : CROW_MINION_CAP;
        cap -= Math.max(0, activePlayers - 4);
        return Math.max(18, cap);
    }

    private int activeChickMinionCap() {
        int cap = isLargeFightLoad() ? LARGE_FIGHT_CHICK_CAP : CHICK_MINION_CAP;
        cap -= Math.max(0, activePlayers - 4) / 2;
        return Math.max(8, cap);
    }

    private int activePiranhaHazardCap() {
        int cap = isLargeFightLoad() ? LARGE_FIGHT_PIRANHA_CAP : PIRANHA_HAZARD_CAP;
        cap -= Math.max(0, activePlayers - 4) / 3;
        return Math.max(4, cap);
    }

    private void trimTransientEffectOverflow() {
        int particleCap = activeParticleSoftCap();
        if (particles.size() > particleCap) {
            particles.subList(0, particles.size() - particleCap).clear();
        }
        int crowCap = activeCrowMinionCap();
        long protectedCrows = crowMinions.stream().filter(CrowMinion::isOverflowProtected).count();
        int effectiveCrowCap = crowCap + (int) protectedCrows;
        if (crowMinions.size() > effectiveCrowCap) {
            int overflow = crowMinions.size() - effectiveCrowCap;
            for (Iterator<CrowMinion> it = crowMinions.iterator(); it.hasNext() && overflow > 0; ) {
                CrowMinion crow = it.next();
                if (crow.isOverflowProtected()) {
                    continue;
                }
                it.remove();
                overflow--;
            }
        }
        int chickCap = activeChickMinionCap();
        if (chickMinions.size() > chickCap) {
            chickMinions.subList(0, chickMinions.size() - chickCap).clear();
        }
        int piranhaCap = activePiranhaHazardCap();
        if (piranhaHazards.size() > piranhaCap) {
            piranhaHazards.subList(0, piranhaHazards.size() - piranhaCap).clear();
        }
    }

    private boolean isWorldRectNearCamera(double x, double y, double width, double height, double margin) {
        double viewWidth = WIDTH / Math.max(0.01, zoom);
        double viewHeight = HEIGHT / Math.max(0.01, zoom);
        double minX = camX - margin;
        double minY = camY - margin;
        double maxX = camX + viewWidth + margin;
        double maxY = camY + viewHeight + margin;
        return !(x + width >= minX) || !(x <= maxX) || !(y + height >= minY) || !(y <= maxY);
    }

    private void resetTrackedCameraBounds() {
        trackedCamMinX = Double.NaN;
        trackedCamMaxX = Double.NaN;
        trackedCamMinY = Double.NaN;
        trackedCamMaxY = Double.NaN;
        Arrays.fill(cameraLeadX, 0.0);
        Arrays.fill(cameraLeadY, 0.0);
        cameraTagInEaseFrames = 0;
    }

    private void syncTrackedCameraToCurrentView() {
        double viewWidth = WIDTH / Math.max(0.01, zoom);
        double viewHeight = HEIGHT / Math.max(0.01, zoom);
        trackedCamMinX = camX;
        trackedCamMaxX = camX + viewWidth;
        trackedCamMinY = camY;
        trackedCamMaxY = camY + viewHeight;
    }

    private double easeCameraBound(double current, double target, boolean outward, boolean tagInSmoothing) {
        double speed = outward
                ? (tagInSmoothing ? CAMERA_TAG_IN_BOUND_EXPAND_SPEED : CAMERA_BOUND_EXPAND_SPEED)
                : CAMERA_BOUND_CONTRACT_SPEED;
        double delta = Math.abs(target - current);
        if (outward) {
            speed = Math.min(CAMERA_FAST_BOUND_SPEED, speed + delta / 1800.0);
        } else {
            speed = Math.min(0.28, speed + delta / 3200.0);
        }
        return current + (target - current) * Math.clamp(speed, 0.0, 1.0);
    }

    private double easeCameraLead(double current, double target) {
        double speed;
        if (Math.signum(current) != 0.0 && Math.signum(target) != 0.0 && Math.signum(current) != Math.signum(target)) {
            speed = 0.22;
        } else if (Math.abs(target) > Math.abs(current)) {
            speed = 0.34;
        } else {
            speed = 0.10;
        }
        return current + (target - current) * speed;
    }

    private void updateDynamicCamera() {
        double minX = Double.MAX_VALUE;
        double maxX = -Double.MAX_VALUE;
        double minY = Double.MAX_VALUE;
        double maxY = -Double.MAX_VALUE;
        int aliveCount = 0;
        double fastestSpeed = 0.0;
        double accumulatedLeadX = 0.0;
        double accumulatedLeadY = 0.0;
        for (int i = 0; i < players.length; i++) {
            Bird b = players[i];
            if (b != null && b.health > 0) {
                aliveCount++;
                double desiredLeadX = Math.clamp(b.vx * CAMERA_LOOKAHEAD_FRAMES, -520.0, 520.0);
                double desiredLeadY = Math.clamp(b.vy * (CAMERA_LOOKAHEAD_FRAMES * 0.7), -280.0, 280.0);
                cameraLeadX[i] = easeCameraLead(cameraLeadX[i], desiredLeadX);
                cameraLeadY[i] = easeCameraLead(cameraLeadY[i], desiredLeadY);
                double birdMinX = Math.clamp(b.x, 0.0, WORLD_WIDTH - 80.0);
                double birdMaxX = Math.clamp(b.x + 80.0, 80.0, WORLD_WIDTH);
                double birdMinY = Math.clamp(b.y, 0.0, WORLD_HEIGHT - 80.0);
                double birdMaxY = Math.clamp(b.y + 80.0, 80.0, WORLD_HEIGHT);
                minX = Math.min(minX, birdMinX);
                maxX = Math.max(maxX, birdMaxX);
                minY = Math.min(minY, birdMinY);
                maxY = Math.max(maxY, birdMaxY);
                accumulatedLeadX += cameraLeadX[i];
                accumulatedLeadY += cameraLeadY[i];
                fastestSpeed = Math.max(fastestSpeed, Math.hypot(b.vx, b.vy));
            } else {
                cameraLeadX[i] = easeCameraLead(cameraLeadX[i], 0.0);
                cameraLeadY[i] = easeCameraLead(cameraLeadY[i], 0.0);
            }
        }
        if (aliveCount <= 0) return;

        boolean tagInSmoothing = cameraTagInEaseFrames > 0;
        if (Double.isNaN(trackedCamMinX) || Double.isNaN(trackedCamMaxX)
                || Double.isNaN(trackedCamMinY) || Double.isNaN(trackedCamMaxY)) {
            trackedCamMinX = minX;
            trackedCamMaxX = maxX;
            trackedCamMinY = minY;
            trackedCamMaxY = maxY;
        } else {
            trackedCamMinX = easeCameraBound(trackedCamMinX, minX, minX < trackedCamMinX, tagInSmoothing);
            trackedCamMaxX = easeCameraBound(trackedCamMaxX, maxX, maxX > trackedCamMaxX, tagInSmoothing);
            trackedCamMinY = easeCameraBound(trackedCamMinY, minY, minY < trackedCamMinY, tagInSmoothing);
            trackedCamMaxY = easeCameraBound(trackedCamMaxY, maxY, maxY > trackedCamMaxY, tagInSmoothing);
        }

        double targetZoom = getTargetZoom(aliveCount, fastestSpeed);

        double zoomDelta = Math.abs(targetZoom - zoom);
        double zoomSpeed = targetZoom < zoom
                ? Math.clamp((tagInSmoothing ? CAMERA_TAG_IN_ZOOM_OUT_SPEED : ZOOM_SPEED) + zoomDelta * 0.18, 0.02, 0.12)
                : Math.clamp(CAMERA_ZOOM_IN_SPEED + zoomDelta * 0.12, CAMERA_ZOOM_IN_SPEED, 0.08);
        zoom += (targetZoom - zoom) * zoomSpeed;

        double leadWeight = aliveCount == 1 ? 0.55 : aliveCount == 2 ? 0.26 : 0.18;
        double centerX = (trackedCamMinX + trackedCamMaxX) / 2.0 + (accumulatedLeadX / aliveCount) * leadWeight;
        double centerY = (trackedCamMinY + trackedCamMaxY) / 2.0 + (accumulatedLeadY / aliveCount) * leadWeight;
        double targetCamX = centerX - WIDTH / (2 * zoom);
        double targetCamY = centerY - HEIGHT / (2 * zoom);
        targetCamX = Math.clamp(targetCamX, 0, cameraMaxXForZoom(zoom));
        targetCamY = Math.clamp(targetCamY, 0, cameraMaxYForZoom(zoom));

        double panDistance = Math.max(Math.abs(targetCamX - camX), Math.abs(targetCamY - camY));
        double panSpeed = tagInSmoothing
                ? 0.18
                : Math.clamp(CAMERA_PAN_SPEED + panDistance / 2400.0 + fastestSpeed / 260.0,
                CAMERA_PAN_SPEED, CAMERA_FAST_PAN_SPEED);
        camX += (targetCamX - camX) * panSpeed;
        camY += (targetCamY - camY) * panSpeed;
        camX = Math.clamp(camX, 0, cameraMaxXForZoom(zoom));
        camY = Math.clamp(camY, 0, cameraMaxYForZoom(zoom));

        if (cameraTagInEaseFrames > 0) {
            cameraTagInEaseFrames--;
        }
    }

    private double getTargetZoom(int aliveCount, double fastestSpeed) {
        double targetZoom;
        if (aliveCount >= 2) {
            double birdsWidth = trackedCamMaxX - trackedCamMinX;
            double birdsHeight = trackedCamMaxY - trackedCamMinY;
            double spreadRatioX = Math.clamp(birdsWidth / WORLD_WIDTH, 0.0, 1.0);
            double spreadRatioY = Math.clamp(birdsHeight / WORLD_HEIGHT, 0.0, 1.0);
            double paddingX = 80.0 + (1.0 - spreadRatioX) * 520.0;
            double paddingY = 120.0 + (1.0 - spreadRatioY) * 420.0;
            double targetZoomW = WIDTH / (birdsWidth + paddingX);
            double targetZoomH = HEIGHT / (birdsHeight + paddingY);
            targetZoom = Math.min(targetZoomW, targetZoomH);
            targetZoom = Math.clamp(targetZoom, minimumCameraZoom(), MAX_ZOOM);
        } else {
            targetZoom = Math.clamp(0.9 - fastestSpeed * 0.004, 0.78, 0.9);
        }
        return targetZoom;
    }

    private double minimumCameraZoom() {
        return Math.min(MIN_ZOOM, WIDTH / WORLD_WIDTH);
    }

    private double cameraMaxXForZoom(double zoomLevel) {
        double safeZoom = Math.max(0.01, zoomLevel);
        return Math.max(0.0, WORLD_WIDTH - WIDTH / safeZoom);
    }

    private double cameraMaxYForZoom(double zoomLevel) {
        double safeZoom = Math.max(0.01, zoomLevel);
        return Math.max(0.0, WORLD_HEIGHT - HEIGHT / safeZoom);
    }

    private void updateWorldFixed() {
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;
            for (NectarNode node : nectarNodes) {
                if (!node.active) continue;
                double dx = node.x - (b.x + 40);
                double dy = node.y - (b.y + 40);
                if (dx * dx + dy * dy < 6400) {
                    node.active = false;
                    if (node.isSpeed) {
                        b.speedBoostTimer = 300;
                        b.speedMultiplier = 1.2;
                        addToKillFeed(shortName(b.name) + " sipped SPEED NECTAR! +20% speed");
                    } else {
                        b.hoverRegenTimer = 300;
                        b.hoverRegenMultiplier = 1.5;
                        addToKillFeed(shortName(b.name) + " sipped HOVER NECTAR! Better hover regen");
                    }
                    int particleCount = scaledParticleBurstCount(30);
                    for (int i = 0; i < particleCount; i++) {
                        double angle = Math.random() * Math.PI * 2;
                        particles.add(new Particle(node.x, node.y, Math.cos(angle) * 8, Math.sin(angle) * 8 - 4,
                                node.isSpeed ? Color.YELLOW : Color.AQUA));
                    }
                }
            }
        }
        updateSwingingVines();

        for (Iterator<CrowMinion> it = crowMinions.iterator(); it.hasNext(); ) {
            CrowMinion c = it.next();
            c.age++;
            if (c.overflowProtectionFrames > 0) {
                c.overflowProtectionFrames--;
            }
            if (c.hitFlashTimer > 0) {
                c.hitFlashTimer--;
            }
            if (c.retargetCooldown > 0) {
                c.retargetCooldown--;
            }
            Bird closest = c.target;
            if (closest != null && (closest.health <= 0 || (c.owner != null && !canDamage(c.owner, closest)))) {
                closest = null;
            }
            if (closest == null || c.retargetCooldown <= 0) {
                double bestSq = Double.MAX_VALUE;
                for (Bird b : players) {
                    if (b == null || b.health <= 0) continue;
                    if (c.owner != null && !canDamage(c.owner, b)) continue;
                    double dx = b.x + 40 - c.x;
                    double dy = b.y + 40 - c.y;
                    double distSq = dx * dx + dy * dy;
                    if (distSq < bestSq) {
                        bestSq = distSq;
                        closest = b;
                    }
                }
                c.target = closest;
                c.retargetCooldown = isLargeFightLoad() ? 10 : 5;
            }
            if (closest != null) {
                double targetX = closest.x + 40;
                double targetY = closest.y + 40;
                if (isDockWaterActive() && isDockWaterAt(targetX, targetY)) {
                    targetY = dockWaterSurfaceY() - 26;
                }
                double dx = targetX - c.x;
                double dy = targetY - c.y;
                double dist = Math.sqrt(dx * dx + dy * dy);
                if (dist > 0) {
                    double spd = c.maxSpeed();
                    c.vx += dx / dist * c.homingAccel();
                    c.vy += dy / dist * c.homingAccel();
                    double speedSq = c.vx * c.vx + c.vy * c.vy;
                    if (speedSq > spd * spd) {
                        double speedNow = Math.sqrt(speedSq);
                        c.vx = c.vx / speedNow * spd;
                        c.vy = c.vy / speedNow * spd;
                    }
                }
                if (dist < 48) {
                    int damage = c.contactDamage();
                    double dealtDamage = closest.receiveExternalDamage(damage);
                    if (dealtDamage <= 0) {
                        it.remove();
                        continue;
                    }
                    int shownDamage = (int) Math.round(dealtDamage);
                    String source = c.displayName();
                    addToKillFeed(source + " devours " + shortName(closest.name) + "! -" + shownDamage + " HP");
                    closest.vx += c.vx * 1.5;
                    closest.vy -= 12;
                    boolean hostile = c.effectiveVariant() != CrowMinion.VARIANT_ALLIED_CROW;
                    int particleCount = scaledParticleBurstCount(hostile ? 35 : 18);
                    Color particleColor = hostile
                            ? Color.web("#260108").deriveColor(0, 1, 1, 0.95)
                            : Color.DARKRED.deriveColor(0, 1, 1, 0.9);
                    for (int i = 0; i < particleCount; i++) {
                        double angle = Math.random() * Math.PI * 2;
                        double spd = 6 + Math.random() * 20;
                        particles.add(new Particle(c.x, c.y, Math.cos(angle) * spd, Math.sin(angle) * spd - 8, particleColor));
                    }
                    if (hostile) {
                        triggerFlash(0.6, false);
                        shakeIntensity = Math.max(shakeIntensity, 20);
                    }
                    it.remove();
                    continue;
                }
            }
            c.x += c.vx;
            c.y += c.vy;
            if (isDockWaterActive() && isDockWaterAt(c.x, c.y + 10)) {
                c.y = dockWaterSurfaceY() - 14;
                c.vy = -Math.max(1.4, Math.abs(c.vy) * 0.55 + 0.8);
                c.vx *= 0.96;
            }
            if (c.age > 1800 || c.x < -1500 || c.x > WORLD_WIDTH + 1500 || c.y < -1500 || c.y > WORLD_HEIGHT + 1500) {
                it.remove();
            }
        }

        for (Iterator<PiranhaHazard> it = piranhaHazards.iterator(); it.hasNext(); ) {
            PiranhaHazard p = it.next();
            p.age++;
            if (p.biteCooldown > 0) p.biteCooldown--;
            if (p.breachCooldown > 0) p.breachCooldown--;
            if (p.retargetCooldown > 0) p.retargetCooldown--;

            if (!isDockWaterActive()) {
                it.remove();
                continue;
            }

            double surfaceY = dockWaterSurfaceY();
            double minY = surfaceY + 26;
            double maxY = dockDrownDepthY() - 54;
            Bird target = p.target;
            if (target == null || target.health <= 0 || p.retargetCooldown <= 0) {
                Bird best = null;
                double bestSq = Double.MAX_VALUE;
                for (Bird b : players) {
                    if (b == null || b.health <= 0) continue;
                    double tx = b.x + 40;
                    double ty = b.y + 40;
                    boolean inWater = isDockWaterAt(tx, ty);
                    boolean nearSurface = tx >= dockWaterX
                            && tx <= dockWaterX + dockWaterW
                            && ty >= surfaceY - 120
                            && ty <= surfaceY + 150;
                    if (!inWater && !nearSurface) continue;
                    double dx = tx - p.x;
                    double dy = ty - p.y;
                    double distSq = dx * dx + dy * dy;
                    if (distSq < bestSq) {
                        bestSq = distSq;
                        best = b;
                    }
                }
                p.target = best;
                target = best;
                p.retargetCooldown = 10;
            }

            double targetX = target != null ? target.x + 40 : p.x + Math.signum(p.vx == 0 ? 1.0 : p.vx) * 120;
            double targetY = target != null ? target.y + 48 : dockWaterMidY();
            boolean targetNearSurface = target != null && targetY <= surfaceY + 94;
            boolean breaching = p.y < minY - 2 || p.vy < -3.2;

            if (!breaching && p.breachCooldown <= 0 && targetNearSurface && p.y <= minY + 84
                    && Math.abs(targetX - p.x) < 160) {
                p.vy = -9.8 - Math.max(0.0, 80.0 - Math.abs(targetX - p.x)) * 0.018;
                p.vx += Math.signum(targetX - p.x) * 2.0;
                p.breachCooldown = 72;
                breaching = true;
                for (int i = 0; i < scaledParticleBurstCount(8); i++) {
                    double sprayX = p.x + (Math.random() - 0.5) * 30;
                    particles.add(new Particle(
                            sprayX,
                            surfaceY + Math.random() * 10,
                            (Math.random() - 0.5) * 5,
                            -3.2 - Math.random() * 3.5,
                            Color.web("#B3E5FC", 0.85)
                    ));
                }
            } else if (!breaching && p.breachCooldown <= 0 && target == null && p.age % 210 == 0) {
                p.vy = -7.8;
                p.breachCooldown = 150;
                breaching = true;
            }

            if (breaching) {
                double dx = targetX - p.x;
                p.vx += Math.signum(dx == 0 ? (p.vx == 0 ? 1.0 : p.vx) : dx) * 0.16;
                p.vx = Math.clamp(p.vx, -8.4, 8.4);
                p.x += p.vx;
                p.y += p.vy;
                p.vy += 0.58;
                if (p.y < surfaceY - 78) {
                    p.y = surfaceY - 78;
                    p.vy = Math.max(p.vy, -1.8);
                }
                if (p.y >= minY) {
                    p.y = minY;
                    p.vy = Math.abs(p.vy) * 0.22;
                    for (int i = 0; i < scaledParticleBurstCount(8); i++) {
                        particles.add(new Particle(
                                p.x + (Math.random() - 0.5) * 24,
                                surfaceY + Math.random() * 8,
                                (Math.random() - 0.5) * 4.5,
                                -2.0 - Math.random() * 2.0,
                                Color.web("#80DEEA", 0.8)
                        ));
                    }
                }
            } else {
                double desiredY = target != null
                        ? Math.clamp(maxY, surfaceY + 36, targetY)
                        : dockWaterMidY();

                double dx = targetX - p.x;
                double dy = desiredY - p.y;
                double dist = Math.hypot(dx, dy);
                if (dist > 0.001) {
                    p.vx += dx / dist * 0.22;
                    p.vy += dy / dist * 0.18;
                }
                p.vx = Math.clamp(p.vx, -7.2, 7.2);
                p.vy = Math.clamp(p.vy, -5.4, 5.4);

                p.x += p.vx;
                p.y += p.vy;

                if (p.y < minY) {
                    p.y = minY;
                    p.vy = Math.abs(p.vy) * 0.35;
                }
                if (p.y > maxY) {
                    p.y = maxY;
                    p.vy = -Math.abs(p.vy) * 0.45;
                }
            }

            if (p.x < dockWaterX + 20) {
                p.x = dockWaterX + 20;
                p.vx = Math.abs(p.vx) * 0.7;
            }
            if (p.x > dockWaterX + dockWaterW - 20) {
                p.x = dockWaterX + dockWaterW - 20;
                p.vx = -Math.abs(p.vx) * 0.7;
            }

            if (target != null && p.biteCooldown <= 0) {
                if (Math.hypot(targetX - p.x, targetY - p.y) < (breaching ? 78 : 62)) {
                    double dealtDamage = target.receiveExternalDamage(breaching ? 10 : 7);
                    if (dealtDamage > 0) {
                        addToKillFeed("PIRANHA ripped " + shortName(target.name) + "! -" + (int) Math.round(dealtDamage) + " HP");
                        target.vx += Math.signum(p.vx == 0 ? (targetX >= p.x ? 1 : -1) : p.vx) * (breaching ? 11.5 : 8.5);
                        target.vy -= breaching ? 10.0 : 7.5;
                        for (int i = 0; i < scaledParticleBurstCount(16); i++) {
                            double angle = Math.random() * Math.PI * 2;
                            double spd = 4 + Math.random() * 7;
                            particles.add(new Particle(
                                    p.x,
                                    p.y,
                                    Math.cos(angle) * spd,
                                    Math.sin(angle) * spd - 2,
                                    Color.web("#EF5350")
                            ));
                        }
                        p.biteCooldown = breaching ? 60 : 50;
                    }
                }
            }

            if (p.age > 1600) {
                it.remove();
            }
        }

        for (Iterator<ChickMinion> it = chickMinions.iterator(); it.hasNext(); ) {
            ChickMinion chick = it.next();
            chick.age++;
            if (chick.attackCooldown > 0) chick.attackCooldown--;
            if (chick.jumpCooldown > 0) chick.jumpCooldown--;
            if (chick.retargetCooldown > 0) chick.retargetCooldown--;

            Bird target = chick.target;
            if (target == null || target.health <= 0 || (chick.owner != null && !canDamage(chick.owner, target))
                    || chick.retargetCooldown <= 0) {
                Bird closest = null;
                double bestSq = Double.MAX_VALUE;
                double ccx = chick.x + chick.width * 0.5;
                double ccy = chick.y + chick.height * 0.5;
                for (Bird b : players) {
                    if (b == null || b.health <= 0) continue;
                    if (chick.owner != null && !canDamage(chick.owner, b)) continue;
                    double dx = (b.x + 40) - ccx;
                    double dy = (b.y + 40) - ccy;
                    double distSq = dx * dx + dy * dy;
                    if (distSq < bestSq) {
                        bestSq = distSq;
                        closest = b;
                    }
                }
                chick.target = closest;
                target = closest;
                chick.retargetCooldown = isLargeFightLoad() ? 12 : 6;
            }

            boolean wasOnGround = chick.onGround;
            if (target != null) {
                double ccx = chick.x + chick.width * 0.5;
                double ccy = chick.y + chick.height * 0.5;
                double dx = (target.x + 40) - ccx;
                double dy = (target.y + 40) - ccy;
                double dir = dx == 0 ? 0 : Math.signum(dx);
                double desiredVx = dir * chick.speed;
                chick.vx += (desiredVx - chick.vx) * chick.accel;
                if (Math.abs(chick.vx) > chick.speed) chick.vx = dir * chick.speed;
                boolean targetAbove = dy < -30;
                    boolean closePounce = Math.abs(dx) < 140;
                    if (wasOnGround && chick.jumpCooldown <= 0 && (targetAbove || closePounce)) {
                        chick.vy = -chick.jumpStrength;
                        double jumpBoost = chick.variant == 1 ? 1.05 : (chick.variant == 0 ? 0.78 : 0.6);
                        chick.vx += dir * chick.speed * jumpBoost;
                        if (chick.variant == 1) {
                            chick.jumpCooldown = chick.ultimate ? 14 : 20;
                        } else if (chick.variant == 0) {
                            chick.jumpCooldown = chick.ultimate ? 22 : 28;
                        } else {
                            chick.jumpCooldown = chick.ultimate ? 26 : 34;
                        }
                        chick.onGround = false;
                    }
            } else {
                chick.vx *= 0.92;
            }

            chick.vy += GRAVITY * 0.8;

            double prevY = chick.y;
            chick.x += chick.vx;
            chick.y += chick.vy;

            boolean landed = false;
            double bottom = chick.y + chick.height;
            if (bottom >= GROUND_Y) {
                chick.y = GROUND_Y - chick.height;
                chick.vy = 0;
                landed = true;
            }
            if (!landed && chick.vy >= 0) {
                double prevBottom = prevY + chick.height;
                for (Platform p : platforms) {
                    double left = chick.x + chick.width * 0.1;
                    double right = chick.x + chick.width * 0.9;
                    if (right < p.x || left > p.x + p.w) continue;
                    if (prevBottom <= p.y && bottom >= p.y) {
                        chick.y = p.y - chick.height;
                        chick.vy = 0;
                        landed = true;
                        break;
                    }
                }
            }
            chick.onGround = landed;
            if (landed) {
                chick.vx *= 0.85;
            }

            if (target != null && chick.attackCooldown <= 0) {
                if (chick.owner != null && !canDamage(chick.owner, target)) {
                    chick.target = null;
                } else {
                    double ccx = chick.x + chick.width * 0.5;
                    double ccy = chick.y + chick.height * 0.5;
                    double dx = (target.x + 40) - ccx;
                    double dy = (target.y + 40) - ccy;
                    if (dx * dx + dy * dy < 2500) {
                        double dealtDamage = target.receiveExternalDamage(chick.damage);
                        if (dealtDamage <= 0) {
                            chick.attackCooldown = 18;
                            continue;
                        }
                        if (dealtDamage > 0 && chick.owner != null) {
                            chick.owner.gainUltimateFromMinionDamage(dealtDamage);
                        }
                        String ownerTag = chick.owner != null ? shortName(chick.owner.name) + "'s " : "";
                        addToKillFeed(ownerTag + "CHICK pecked " + shortName(target.name) + "! -" + (int) Math.round(dealtDamage) + " HP");
                        target.vx += Math.signum(dx) * (chick.ultimate ? 9 : 7);
                        target.vy -= chick.ultimate ? 8 : 6;
                        int particleCount = scaledParticleBurstCount(chick.ultimate ? 16 : 12);
                        Color puff = chick.ultimate ? Color.GOLD : Color.web("#FFD54F");
                        for (int i = 0; i < particleCount; i++) {
                            double angle = Math.random() * Math.PI * 2;
                            double spd = 4 + Math.random() * 6;
                            particles.add(new Particle(ccx, ccy, Math.cos(angle) * spd, Math.sin(angle) * spd - 3, puff));
                        }
                        chick.attackCooldown = chick.ultimate ? 32 : 44;
                    }
                }
            }

            if (chick.age > chick.maxAge || chick.x < -600 || chick.x > WORLD_WIDTH + 600 || chick.y > WORLD_HEIGHT + 600) {
                it.remove();
            }
        }

        updateDockStageHazards();
        updateMatchTimerState();

        if (!(competitionModeEnabled && !storyModeActive && !adventureModeActive && !classicModeActive)
                && selectedMap == MapType.CITY
                && System.nanoTime() - lastWindBurstTime > WIND_BURST_INTERVAL) {
            lastWindBurstTime = System.nanoTime();
            Collections.shuffle(windVents);
            int bursts = 2 + random.nextInt(2);
            for (int i = 0; i < Math.min(bursts, windVents.size()); i++) {
                WindVent vent = windVents.get(i);
                vent.cooldown = 120;
                for (Bird b : players) {
                    if (b != null && b.health > 0) {
                        double dx = b.x + 40 - (vent.x + vent.w / 2);
                        if (Math.abs(dx) < vent.w / 2 + 100 && b.y > vent.y - 300) {
                            if (b.isDownHeld()) {
                                b.vy *= 0.85;
                            } else {
                                b.vy = Math.min(b.vy, WIND_FORCE);
                            }
                            addToKillFeed("WIND GUST lifts " + shortName(b.name) + "!");
                            int particleCount = scaledParticleBurstCount(40);
                            for (int j = 0; j < particleCount; j++) {
                                double angle = -Math.PI / 2 + (Math.random() - 0.5) * 0.8;
                                double spd = 8 + Math.random() * 12;
                                particles.add(new Particle(vent.x + vent.w / 2 + (Math.random() - 0.5) * vent.w, vent.y - 20, Math.cos(angle) * spd, Math.sin(angle) * spd, Color.CYAN.deriveColor(0, 1, 1, 0.7)));
                            }
                        }
                    }
                }
            }
        }
        for (WindVent v : windVents) if (v.cooldown > 0) v.cooldown--;

        updateDynamicCamera();

        if (trainingModeActive) {
            updateTrainingLabState();
        }

        checkForMatchCompletion();
    }

    private void updateDockStageHazards() {
        if (selectedMap != MapType.DOCK) {
            dockLeverCooldown = 0;
            dockShipBomb = null;
            Arrays.fill(dockLeverHeld, false);
            return;
        }

        if (dockLeverCooldown > 0) {
            dockLeverCooldown--;
        }

        int playerCount = Math.min(activePlayers, players.length);
        for (int i = 0; i < playerCount; i++) {
            Bird bird = players[i];
            boolean pressed = isAttackPressed(i) || isSpecialPressed(i);
            if (bird == null || bird.health <= 0) {
                dockLeverHeld[i] = pressed;
                continue;
            }

            boolean nearLever = isBirdNearDockLever(bird);
            if (nearLever && pressed && !dockLeverHeld[i]) {
                if (dockLeverCooldown <= 0 && dockShipBomb == null) {
                    Bird target = findDockBombTarget(bird);
                    if (target != null) {
                        launchDockShipBomb(bird, target);
                    } else {
                        bird.cooldownFlash = 18;
                    }
                } else {
                    bird.cooldownFlash = 18;
                }
            }
            dockLeverHeld[i] = pressed;
        }

        updateDockShipBomb();
    }

    private boolean isBirdNearDockLever(Bird bird) {
        if (bird == null || dockLeverX == 0) return false;
        if (!bird.isOnGround()) return false;
        double centerX = bird.x + 40 * bird.sizeMultiplier;
        double centerY = bird.y + 40 * bird.sizeMultiplier;
        return Math.abs(centerX - dockLeverX) <= 92
                && Math.abs(centerY - dockLeverY) <= 112;
    }

    private Bird findDockBombTarget(Bird puller) {
        Bird best = null;
        double bestDist = Double.MAX_VALUE;
        for (Bird other : players) {
            if (other == null || other == puller || other.health <= 0) continue;
            if (!canDamage(puller, other)) continue;
            double dx = (other.x + 40 * other.sizeMultiplier) - (puller.x + 40 * puller.sizeMultiplier);
            double dy = (other.y + 40 * other.sizeMultiplier) - (puller.y + 40 * puller.sizeMultiplier);
            double distSq = dx * dx + dy * dy;
            if (distSq < bestDist) {
                bestDist = distSq;
                best = other;
            }
        }
        return best;
    }

    private void launchDockShipBomb(Bird puller, Bird target) {
        dockShipBomb = new DockShipBomb(
                dockShipCannonMuzzleX(),
                dockShipCannonMuzzleY(),
                0,
                0,
                dockBombTargetX(target),
                dockBombTargetY(target),
                puller.playerIndex,
                target.playerIndex,
                DOCK_BOMB_FUSE_FRAMES
        );
        dockShipBomb.launchDelayFrames = DOCK_BOMB_LOCKON_FRAMES;
        dockShipBomb.fired = false;
        dockShipBomb.cannonFlashFrames = 0;
        dockLeverCooldown = DOCK_LEVER_COOLDOWN_FRAMES;
        puller.cooldownFlash = 20;
        addToKillFeed(shortName(puller.name) + " sighted " + shortName(target.name) + " for bombardment!");

        for (int i = 0; i < scaledParticleBurstCount(18); i++) {
            particles.add(new Particle(
                    dockLeverX + (Math.random() - 0.5) * 18,
                    dockLeverY - 10 + (Math.random() - 0.5) * 12,
                    (Math.random() - 0.5) * 2.8,
                    -2.2 - Math.random() * 2.8,
                    Color.web("#FFCA28", 0.9)
            ));
        }
    }

    private void fireDockShipBomb() {
        if (dockShipBomb == null || dockShipBomb.fired) {
            return;
        }
        double startX = dockShipCannonMuzzleX();
        double startY = dockShipCannonMuzzleY();
        dockShipBomb.x = startX;
        dockShipBomb.y = startY;
        double travelFrames = Math.clamp(48.0 + Math.abs(dockShipBomb.targetX - startX) / 34.0, 48.0, 78.0);
        dockShipBomb.vx = (dockShipBomb.targetX - startX) / travelFrames;
        dockShipBomb.vy = (dockShipBomb.targetY - startY - 0.5 * DOCK_BOMB_GRAVITY * travelFrames * travelFrames) / travelFrames;
        dockShipBomb.fuse = Math.max(18, (int) Math.ceil(travelFrames) + 10);
        dockShipBomb.fired = true;
        dockShipBomb.cannonFlashFrames = DOCK_BOMB_CANNON_FLASH_FRAMES;
        shakeIntensity = Math.max(shakeIntensity, 9);
        playCherrybombSfx();
        addToKillFeed("The pirate ship opens fire!");
        for (int i = 0; i < scaledParticleBurstCount(22); i++) {
            particles.add(new Particle(
                    startX + (Math.random() - 0.5) * 20,
                    startY + (Math.random() - 0.5) * 16,
                    -3.0 - Math.random() * 7.2,
                    -3.2 + (Math.random() - 0.5) * 4.0,
                    Color.web(i % 3 == 0 ? "#FFF59D" : "#FFB74D", 0.92)
            ));
        }
        for (int i = 0; i < scaledParticleBurstCount(14); i++) {
            particles.add(new Particle(
                    startX + (Math.random() - 0.5) * 12,
                    startY + 10 + (Math.random() - 0.5) * 10,
                    -1.6 - Math.random() * 3.0,
                    0.8 + Math.random() * 1.8,
                    Color.web("#6D4C41", 0.74)
            ));
        }
    }

    private void updateDockShipBomb() {
        if (dockShipBomb == null) {
            return;
        }

        if (dockShipBomb.cannonFlashFrames > 0) {
            dockShipBomb.cannonFlashFrames--;
        }

        if (dockShipBomb.exploded) {
            dockShipBomb.explosionFrames--;
            if (dockShipBomb.explosionFrames <= 0) {
                dockShipBomb = null;
            }
            return;
        }

        Bird target = dockShipBomb.targetPlayerIndex >= 0 && dockShipBomb.targetPlayerIndex < players.length
                ? players[dockShipBomb.targetPlayerIndex]
                : null;
        if (!dockShipBomb.fired && target != null && target.health > 0) {
            dockShipBomb.targetX = dockBombTargetX(target);
            dockShipBomb.targetY = dockBombTargetY(target);
        }

        if (!dockShipBomb.fired) {
            if (dockShipBomb.launchDelayFrames > 0) {
                dockShipBomb.launchDelayFrames--;
            }
            if (dockShipBomb.launchDelayFrames <= 0) {
                fireDockShipBomb();
            }
            return;
        }

        dockShipBomb.fuse--;
        dockShipBomb.x += dockShipBomb.vx;
        dockShipBomb.y += dockShipBomb.vy;
        dockShipBomb.vy += DOCK_BOMB_GRAVITY;

        if (particleEffectsEnabled && random.nextDouble() < 0.9) {
            particles.add(new Particle(
                    dockShipBomb.x + (Math.random() - 0.5) * 14,
                    dockShipBomb.y + 8,
                    (Math.random() - 0.5) * 1.8,
                    1.0 + Math.random() * 2.6,
                    Color.web("#5D4037", 0.78)
            ));
            particles.add(new Particle(
                    dockShipBomb.x + (Math.random() - 0.5) * 10,
                    dockShipBomb.y - 12,
                    (Math.random() - 0.5) * 1.2,
                    -1.6 - Math.random() * 1.6,
                    Color.web("#FFB74D", 0.84)
            ));
        }

        boolean explode = dockShipBomb.fuse <= 0
                || Math.hypot(dockShipBomb.targetX - dockShipBomb.x, dockShipBomb.targetY - dockShipBomb.y) < 52
                || dockBombHitsPlatform(dockShipBomb)
                || (isDockWaterAt(dockShipBomb.x, dockShipBomb.y) && dockShipBomb.y >= dockWaterSurfaceY() + 6)
                || dockShipBomb.y >= GROUND_Y + 8;
        if (explode) {
            explodeDockShipBomb();
        }
    }

    private boolean dockBombHitsPlatform(DockShipBomb bomb) {
        for (Platform p : platforms) {
            if (bomb.x >= p.x - 6 && bomb.x <= p.x + p.w + 6
                    && bomb.y >= p.y - 8 && bomb.y <= p.y + p.h + 8
                    && bomb.vy >= -1.0) {
                bomb.y = p.y;
                return true;
            }
        }
        return false;
    }

    private void explodeDockShipBomb() {
        if (dockShipBomb == null) return;

        DockShipBomb bomb = dockShipBomb;
        bomb.exploded = true;
        bomb.explosionFrames = 16;
        bomb.vx = 0;
        bomb.vy = 0;

        Bird owner = bomb.ownerPlayerIndex >= 0 && bomb.ownerPlayerIndex < players.length
                ? players[bomb.ownerPlayerIndex]
                : null;
        double radius = 220.0;
        double heaviestHit = 0.0;
        for (Bird other : players) {
            if (other == null || other.health <= 0) continue;
            if (owner != null && !canDamage(owner, other)) continue;
            double centerX = other.x + 40 * other.sizeMultiplier;
            double centerY = other.y + 40 * other.sizeMultiplier;
            double dx = centerX - bomb.x;
            double dy = centerY - bomb.y;
            double dist = Math.hypot(dx, dy);
            if (dist > radius + 32) continue;

            double falloff = 1.0 - Math.min(1.0, dist / radius);
            double oldHealth = other.health;
            double dealtDamage = other.receiveExternalDamage(18 + falloff * 30);
            if (dealtDamage <= 0) continue;

            heaviestHit = Math.max(heaviestHit, dealtDamage);
            if (owner != null) {
                damageDealt[owner.playerIndex] += (int) Math.round(dealtDamage);
                owner.gainUltimateFromMinionDamage(dealtDamage);
                if (oldHealth > 0 && other.health <= 0) {
                    eliminations[owner.playerIndex]++;
                }
            }
            double dir = dx == 0 ? (other.x >= bomb.x ? 1.0 : -1.0) : Math.signum(dx);
            other.vx += dir * (12 + falloff * 18);
            other.vy -= 9 + falloff * 14;
            other.applyStun(18 + falloff * 12);
            addToKillFeed("PIRATE BOMB blasted " + shortName(other.name) + "! -" + (int) Math.round(dealtDamage) + " HP");
        }

        int particleCount = scaledParticleBurstCount(72);
        for (int i = 0; i < particleCount; i++) {
            double angle = Math.random() * Math.PI * 2;
            double speed = 5 + Math.random() * 16;
            Color color = i % 3 == 0 ? Color.web("#FFCA28") : (i % 3 == 1 ? Color.web("#6D4C41") : Color.web("#FF7043"));
            particles.add(new Particle(
                    bomb.x,
                    bomb.y,
                    Math.cos(angle) * speed,
                    Math.sin(angle) * speed - 3,
                    color
            ));
        }
        shakeIntensity = Math.max(shakeIntensity, 30);
        hitstopFrames = Math.max(hitstopFrames, 10);
        triggerFlash(Math.min(0.95, 0.38 + heaviestHit / 42.0), false);
    }

    private void updateSwingingVines() {
        if (swingingVines.isEmpty()) {
            for (Bird b : players) {
                if (b != null && b.onVine) {
                    b.dropFromVine();
                }
            }
            return;
        }

        for (Iterator<SwingingVine> it = swingingVines.iterator(); it.hasNext(); ) {
            SwingingVine vine = it.next();
            if (vine.detaching) {
                vine.updateDetaching();
                if (vine.isFullyDetachedOffscreen()) {
                    it.remove();
                }
                continue;
            }
            vine.angularVelocity += (Math.random() - 0.5) * (vine.temporary ? 0.0012 : 0.0016);
            if (!vine.temporary && Math.random() < 0.006) {
                vine.angularVelocity += (Math.random() - 0.5) * 0.032;
            }
            double gravity = vine.temporary ? 0.0105 : 0.0088;
            vine.angularVelocity += -gravity * Math.sin(vine.angle);
            vine.angularVelocity *= vine.temporary ? 0.992 : 0.994;
            vine.angle += vine.angularVelocity;
            vine.angle = Math.clamp(vine.angle, -Math.PI / 2.2, Math.PI / 2.2);
            vine.updatePlatformPosition();

            boolean occupied = false;
            for (Bird b : players) {
                if (b == null) {
                    continue;
                }
                if (b.health <= 0) {
                    if (b.onVine && b.attachedVine == vine) {
                        b.dropFromVine();
                    }
                    continue;
                }
                double birdLeft = b.x + 18;
                double birdRight = b.x + 62 * b.sizeMultiplier;
                double birdBottom = b.y + 80 * b.sizeMultiplier;
                double birdTop = b.y;
                double platLeft = vine.platformX - 10;
                double platRight = vine.platformX + vine.platformW + 10;
                double platTop = vine.platformY;
                boolean horizontallyOver = birdLeft < platRight && birdRight > platLeft;
                boolean verticallyOnTop = birdBottom >= platTop - 8 && birdBottom <= platTop + 28;

                if (!b.onVine && horizontallyOver && verticallyOnTop && b.vy >= 0 && birdTop < platTop + 14) {
                    b.attachToVine(vine);
                    addToKillFeed(shortName(b.name) + " grabbed a vine!");
                }

                if (b.onVine && b.attachedVine == vine) {
                    occupied = true;
                    b.syncToAttachedVine();
                    b.vineRideFrames++;

                    if (!isAI[b.playerIndex]) {
                        if (isLeftPressed(b.playerIndex)) {
                            vine.angularVelocity -= vine.temporary ? 0.0054 : 0.0046;
                        }
                        if (isRightPressed(b.playerIndex)) {
                            vine.angularVelocity += vine.temporary ? 0.0054 : 0.0046;
                        }
                    } else {
                        Bird target = getBird(b);
                        if (target != null) {
                            if (target.x < b.x) {
                                vine.angularVelocity -= 0.006;
                            }
                            if (target.x > b.x) {
                                vine.angularVelocity += 0.006;
                            }
                        }
                    }

                    boolean manualLaunch = isJumpPressed(b.playerIndex);
                    boolean autoLaunch = shouldAutoLaunchFromVine(vine);
                    if (manualLaunch || autoLaunch) {
                        b.launchFromVine(autoLaunch);
                        if (!autoLaunch) {
                            addToKillFeed(shortName(b.name) + " swung off the vine!");
                        }
                        occupied = false;
                    }
                }
            }

            if (vine.temporary && !occupied) {
                vine.startDetaching();
            }
        }

        for (Bird b : players) {
            if (b == null || !b.onVine) {
                continue;
            }
            if (b.attachedVine == null || !swingingVines.contains(b.attachedVine)) {
                b.dropFromVine();
                continue;
            }
            double platY = b.attachedVine.platformY;
            if (b.y + 80 * b.sizeMultiplier > platY + 58) {
                b.dropFromVine();
            }
        }
    }

    private boolean shouldAutoLaunchFromVine(SwingingVine vine) {
        if (vine == null || vine.detaching) {
            return false;
        }
        if (vine.tipSpeed() < VINE_AUTO_LAUNCH_SPEED) {
            return false;
        }
        if (Math.abs(vine.angle) < VINE_AUTO_LAUNCH_ANGLE) {
            return false;
        }
        return Math.signum(vine.angle) == Math.signum(vine.angularVelocity);
    }

    private Bird getBird(Bird b) {
        Bird target = null;
        double best = Double.MAX_VALUE;
        for (Bird other : players) {
            if (other != null && other.health > 0 && other != b) {
                double d = Math.abs(other.x - b.x);
                if (d < best) {
                    best = d;
                    target = other;
                }
            }
        }
        return target;
    }

    private void updateParticlesFixed() {
        if (!particleEffectsEnabled) return;
        for (Iterator<Particle> it = particles.iterator(); it.hasNext(); ) {
            Particle p = it.next();
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.4;
            p.life--;
            if (p.life <= 0
                    || p.y > WORLD_HEIGHT + 200
                    || p.y < -400
                    || p.x < -400
                    || p.x > WORLD_WIDTH + 400) {
                it.remove();
            }
        }
    }

    private void drawGame(GraphicsContext g) {
        g.clearRect(0, 0, WIDTH, HEIGHT);
        g.save();
        g.scale(zoom, zoom);
        g.translate(-camX, -camY);
        currentRenderShakeX = 0.0;
        currentRenderShakeY = 0.0;

        if (screenShakeEnabled && shakeIntensity > 0) {
            double shakeX = (Math.random() - 0.5) * shakeIntensity * 2;
            double shakeY = (Math.random() - 0.5) * shakeIntensity * 2;
            currentRenderShakeX = shakeX;
            currentRenderShakeY = shakeY;
            g.translate(shakeX, shakeY);
            shakeIntensity *= 0.9;
            if (shakeIntensity < 0.5) shakeIntensity = 0;
        } else if (!screenShakeEnabled && shakeIntensity > 0) {
            shakeIntensity = 0;
        }

        boolean ambientFx = ambientEffectsEnabled;

        // === BACKGROUND (different per map) ===
        switch (selectedMap) {
            case FOREST -> drawForestArena(g, ambientFx);
            case SKYCLIFFS -> {
                for (int i = 0; i < 600; i++) {
                    double ratio = i / 600.0;
                    Color c = Color.ORANGERED.interpolate(Color.DEEPSKYBLUE.darker(), ratio);
                    g.setFill(c.deriveColor(0, 1, 1, 0.75));
                    g.fillRect(0, i * (WORLD_HEIGHT / 600.0), WORLD_WIDTH, WORLD_HEIGHT / 600.0 + 3);
                }
                g.setFill(Color.PURPLE.darker().darker().darker());
                for (int m = 0; m < MOUNTAIN_X.length - 1; m++) {
                    double baseY = GROUND_Y + 300;
                    double peakY = mountainPeaks[m];
                    double midX = MOUNTAIN_X[m] + 400 + (m % 2 == 0 ? 100 : -100);
                    g.fillPolygon(new double[]{MOUNTAIN_X[m], midX, MOUNTAIN_X[m+1]}, new double[]{baseY, peakY, baseY}, 3);
                }
                if (ambientFx) {
                    double cloudTime = System.currentTimeMillis() / 40.0;
                    g.setFill(Color.WHITE.deriveColor(0, 1, 1, 0.3));
                    renderRandom.setSeed(42L);
                    Random cloudRandom = renderRandom;
                    for (int layer = 0; layer < 4; layer++) {
                        double speed = 0.15 + layer * 0.15;
                        double offset = cloudTime * speed;
                        for (int i = 0; i < 25; i++) {
                            cloudRandom.setSeed(i + layer * 100);
                            double baseX = i * 320;
                            double cx = (baseX + offset * (layer + 1)) % (WORLD_WIDTH + 1000) - 500;
                            double cy = 50 + layer * 350 + cloudRandom.nextDouble() * 300;
                            double size = 150 + layer * 100;
                            g.fillOval(cx - size/2, cy - size/4, size, size/2);
                            g.fillOval(cx - size/3, cy - size/5, size * 0.85, size/2 * 0.85);
                            g.fillOval(cx + size/4, cy - size/6, size * 0.75, size/2 * 0.75);
                        }
                    }
                }
                g.setFill(Color.LIGHTBLUE.deriveColor(0, 1, 1, 0.25));
                g.fillRect(0, GROUND_Y - 300, WORLD_WIDTH, 500);
                g.setFill(Color.SIENNA.darker().darker());
                g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y);
                g.setFill(Color.SIENNA.darker().darker().darker());
                g.setStroke(Color.SADDLEBROWN.darker().darker());
                g.setLineWidth(10);
                for (Platform p : platforms) {
                    g.fillRoundRect(p.x + 10, p.y + 10, p.w - 20, p.h - 10, 50, 50);
                    g.strokeRoundRect(p.x + 10, p.y + 10, p.w - 20, p.h - 10, 50, 50);
                    g.setFill(Color.DARKGREEN.brighter().brighter());
                    g.fillRoundRect(p.x + 40, p.y + 5, p.w - 80, 40, 40, 40);
                    renderRandom.setSeed((long) (p.x * 1000));
                    Random crackRand = renderRandom;
                    g.setStroke(Color.BLACK);
                    g.setLineWidth(4);
                    for (int c = 0; c < 10; c++) {
                        double crackStartX = p.x + crackRand.nextDouble() * p.w;
                        double crackEndX = crackStartX + (crackRand.nextDouble() - 0.5) * 120;
                        g.strokeLine(crackStartX, p.y + 20, crackEndX, p.y + p.h - 20);
                    }
                    g.setFill(Color.DARKGREEN.darker());
                    for (int v = 0; v < 8; v++) {
                        double vineX = p.x + crackRand.nextDouble() * p.w;
                        g.fillRect(vineX, p.y + p.h, 12, 60 + crackRand.nextDouble() * 40);
                    }
                }
                g.setStroke(Color.GOLD.brighter().brighter().brighter());
                g.setLineWidth(16);
                for (Platform p : platforms) {
                    if (p.y < GROUND_Y - 1200) g.strokeRoundRect(p.x - 10, p.y - 10, p.w + 20, p.h + 20, 60, 60);
                }
                for (WindVent v : windVents) {
                    if (ambientFx) {
                        double pulse = 0.5 + 0.5 * Math.sin(System.currentTimeMillis() / 300.0 + v.x);
                        g.setFill(Color.CYAN.deriveColor(0, 1, 1 + pulse, 0.5));
                        g.fillOval(v.x + v.w/2 - 100, v.y - 150, 200, 300);
                    } else {
                        g.setFill(Color.CYAN.deriveColor(0, 1, 1, 0.22));
                        g.fillOval(v.x + v.w/2 - 100, v.y - 150, 200, 300);
                    }
                }
            }
            case VIBRANT_JUNGLE -> {
                for (int i = 0; i < 600; i++) {
                    double ratio = i / 600.0;
                    Color c = Color.TEAL.interpolate(Color.LIMEGREEN.darker(), ratio);
                    g.setFill(c.deriveColor(0, 1, 1, 0.85));
                    g.fillRect(0, i * (WORLD_HEIGHT / 600.0), WORLD_WIDTH, WORLD_HEIGHT / 600.0 + 3);
                }
                g.setFill(Color.SADDLEBROWN.darker().darker());
                g.setStroke(Color.SIENNA.darker());
                g.setLineWidth(20);
                for (double tx : JUNGLE_TREE_X) {
                    g.fillRect(tx - 100, GROUND_Y - 2100, 200, 2200);
                    g.strokeRect(tx - 100, GROUND_Y - 2100, 200, 2200);
                    g.setFill(Color.SADDLEBROWN.darker());
                    g.fillOval(tx - 180, GROUND_Y - 100, 360, 200);
                    g.setStroke(Color.SIENNA.darker().darker());
                    g.setLineWidth(6);
                    for (int i = 0; i < 15; i++) {
                        double offset = (i % 2 == 0 ? 30 : -30);
                        g.strokeLine(tx - 80 + offset, GROUND_Y - 2000, tx - 80 + offset, GROUND_Y - 100);
                    }
                    g.setFill(Color.DARKGREEN.darker().darker());
                    g.fillOval(tx - 300, GROUND_Y - 2150, 600, 300);
                }
                g.setFill(Color.DARKGREEN.darker().darker());
                for (int m = 0; m < MOUNTAIN_X.length - 1; m++) {
                    double baseY = GROUND_Y + 500;
                    double peakY = mountainPeaks[m];
                    double midX = MOUNTAIN_X[m] + 400;
                    g.fillPolygon(new double[]{MOUNTAIN_X[m], midX, MOUNTAIN_X[m+1]}, new double[]{baseY, peakY, baseY}, 3);
                }
                g.setFill(Color.WHITE.deriveColor(0, 1, 1, 0.25));
                g.fillRect(800, GROUND_Y - 1300, 1000, 1500);
                g.fillRect(3200, GROUND_Y - 1400, 900, 1600);
                g.fillRect(5000, GROUND_Y - 1200, 1100, 1400);
                g.setFill(Color.DARKOLIVEGREEN.darker());
                g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y);
                g.setFill(Color.SEAGREEN.darker());
                for (Platform p : platforms) {
                    g.fillRoundRect(p.x, p.y, p.w, p.h, 40, 40);
                    g.setFill(Color.web("#8BC34A", 0.6));
                    g.fillOval(p.x + p.w / 2 - 36, p.y - 34, 72, 40);
                    g.setFill(Color.SEAGREEN.darker());
                }
                for (NectarNode node : nectarNodes) {
                    if (node.active) {
                        Color orb = node.isSpeed ? Color.GOLD.brighter() : Color.AQUA.brighter();
                        g.setFill(orb);
                        g.fillOval(node.x - 20, node.y - 20, 40, 40);
                        g.setFill(Color.WHITE.deriveColor(0, 1, 1, 0.6));
                        g.fillOval(node.x - 10, node.y - 10, 20, 20);
                    }
                }
                for (WindVent v : windVents) {
                    double ventWidth = Math.max(170, v.w * 0.55);
                    double ventHeight = 230 + v.w * 0.36;
                    g.setFill(Color.CYAN.deriveColor(0, 1, 1, 0.18));
                    g.fillOval(v.x + v.w / 2 - ventWidth / 2, v.y - ventHeight * 0.72, ventWidth, ventHeight);
                }
            }
            case DESERT -> drawDesertArena(g, ambientFx);
            case DOCK -> drawDockArena(g, ambientFx);
            case BATTLEFIELD -> {
                if (isBeaconCrownBattlefieldContext()) {
                    drawBeaconCrownBattlefield(g, ambientFx);
                } else {
                    for (int i = 0; i < 520; i++) {
                        double ratio = i / 520.0;
                        Color c = Color.web("#7EC8FF").interpolate(Color.web("#DFF6F0"), ratio);
                        g.setFill(c);
                        g.fillRect(0, i * (WORLD_HEIGHT / 520.0), WORLD_WIDTH, WORLD_HEIGHT / 520.0 + 3);
                    }

                    g.setStroke(Color.web("#3E2723"));
                    g.setLineWidth(4);
                    for (Platform p : platforms) {
                        g.setFill(Color.web("#5D4037"));
                        g.fillRoundRect(p.x, p.y, p.w, p.h, 34, 34);
                        g.setFill(Color.web("#2E7D32"));
                        g.fillRoundRect(p.x + 8, p.y - 12, p.w - 16, p.h + 16, 34, 34);
                        g.strokeRoundRect(p.x, p.y, p.w, p.h, 34, 34);
                    }
                }
            }
            case BEACON_CROWN -> drawBeaconCrownBattlefield(g, ambientFx);
            case CAVE -> {
                // Deep cave gradient
                for (int i = 0; i < 700; i++) {
                    double ratio = i / 700.0;
                    Color c = Color.rgb(10, 12, 24).interpolate(Color.rgb(32, 22, 50), ratio);
                    g.setFill(c);
                    g.fillRect(0, i * (WORLD_HEIGHT / 700.0), WORLD_WIDTH, WORLD_HEIGHT / 700.0 + 3);
                }

                // Cave silhouette layers
                g.setFill(Color.rgb(18, 14, 30));
                for (int i = 0; i < 20; i++) {
                    double bx = i * 320;
                    g.fillPolygon(
                            new double[]{bx, bx + 160, bx + 320},
                            new double[]{0, 160 + (i % 3) * 40, 0},
                            3
                    );
                    g.fillPolygon(
                            new double[]{bx, bx + 160, bx + 320},
                            new double[]{GROUND_Y + 250, GROUND_Y + 60 + (i % 4) * 50, GROUND_Y + 250},
                            3
                    );
                }

                // Back-layer stalactites/stalagmites
                g.setFill(Color.rgb(24, 18, 38));
                for (int i = 0; i < 28; i++) {
                    double bx = i * 230 + (i % 2) * 70;
                    double topLen = 120 + (i % 5) * 35;
                    g.fillPolygon(new double[]{bx, bx + 44, bx + 88}, new double[]{0, topLen, 0}, 3);
                    double bottomLen = 90 + (i % 4) * 42;
                    g.fillPolygon(new double[]{bx + 30, bx + 74, bx + 118},
                            new double[]{GROUND_Y + 240, GROUND_Y + 240 - bottomLen, GROUND_Y + 240}, 3);
                }

                if (ambientFx) {
                    // Distant bat silhouettes for atmosphere (animated, non-linear scatter)
                    renderRandom.setSeed(9042L);
                    Random batRand = renderRandom;
                    double batTime = System.currentTimeMillis() / 700.0;
                    for (int i = 0; i < 32; i++) {
                        double bx = 120 + batRand.nextDouble() * (WORLD_WIDTH - 240);
                        double byBase = 120 + batRand.nextDouble() * (GROUND_Y - 520);
                        double speed = 0.5 + batRand.nextDouble() * 1.4;
                        double phase = batRand.nextDouble() * Math.PI * 2;
                        double ampX = 35 + batRand.nextDouble() * 90;
                        double ampY = 10 + batRand.nextDouble() * 35;
                        double bxAnim = bx + Math.sin(batTime * speed + phase) * ampX;
                        double by = byBase + Math.cos(batTime * speed * 1.3 + phase) * ampY;
                        double flap = 0.7 + 0.3 * Math.sin(batTime * 5.0 * speed + phase);
                        g.setFill(Color.rgb(8, 8, 16, 0.42 + 0.16 * flap));
                        g.fillOval(bxAnim - 15, by, 30, 15);
                        g.fillOval(bxAnim - (44 * flap), by - 5, 32 * flap + 6, 18);
                        g.fillOval(bxAnim + 12, by - 5, 32 * flap + 6, 18);
                    }

                    // Glowing crystals/mushrooms for unique cave identity (scattered, non-linear)
                    renderRandom.setSeed(6117L);
                    Random crystalRand = renderRandom;
                    for (int i = 0; i < 46; i++) {
                        double cx = 60 + crystalRand.nextDouble() * (WORLD_WIDTH - 120);
                        double cy = GROUND_Y - 70 - crystalRand.nextDouble() * 260;
                        Color glow = crystalRand.nextBoolean() ? Color.CYAN : Color.MEDIUMPURPLE;
                        g.setFill(glow.deriveColor(0, 1, 1, 0.25));
                        g.fillOval(cx - 50, cy - 50, 100, 100);
                        g.setFill(glow.brighter());
                        g.fillPolygon(
                                new double[]{cx - 14, cx, cx + 14},
                                new double[]{cy + 20, cy - 22, cy + 20},
                                3
                        );
                        if (i % 3 == 0) {
                            g.setFill(Color.web("#66ffe0", 0.55));
                            g.fillOval(cx - 9, cy - 34, 18, 12);
                        }
                    }
                }

                // Solid rock floor
                g.setFill(Color.rgb(35, 30, 46));
                g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y);

                // Platforms as rocky shelves
                g.setFill(Color.rgb(82, 76, 96));
                g.setStroke(Color.rgb(130, 118, 156));
                g.setLineWidth(4);
                for (Platform p : platforms) {
                    g.fillRoundRect(p.x, p.y, p.w, p.h, 20, 20);
                    g.strokeRoundRect(p.x, p.y, p.w, p.h, 20, 20);
                    if (p.y < GROUND_Y - 120) {
                        g.setFill(Color.CYAN.deriveColor(0, 1, 1, 0.2));
                        g.fillOval(p.x + p.w * 0.5 - 18, p.y - 18, 36, 24);
                        // Hanging crystals from undersides
                        g.setFill(Color.MEDIUMPURPLE.deriveColor(0, 1, 1, 0.4));
                        double c1 = p.x + p.w * 0.28;
                        double c2 = p.x + p.w * 0.72;
                        g.fillPolygon(new double[]{c1 - 7, c1, c1 + 7}, new double[]{p.y + p.h, p.y + p.h + 24, p.y + p.h}, 3);
                        g.fillPolygon(new double[]{c2 - 7, c2, c2 + 7}, new double[]{p.y + p.h, p.y + p.h + 24, p.y + p.h}, 3);
                        g.setFill(Color.rgb(82, 76, 96));
                    }
                }

                // Echo draft vents
                for (WindVent v : windVents) {
                    if (ambientFx) {
                        double pulse = 0.5 + 0.5 * Math.sin(System.currentTimeMillis() / 260.0 + v.x * 0.02);
                        g.setFill(Color.CYAN.deriveColor(0, 1, 1, 0.22 + 0.18 * pulse));
                        g.fillOval(v.x + v.w / 2 - 120, v.y - 210, 240, 420);
                    } else {
                        g.setFill(Color.CYAN.deriveColor(0, 1, 1, 0.18));
                        g.fillOval(v.x + v.w / 2 - 120, v.y - 210, 240, 420);
                    }
                }

                // Low cave fog
                if (ambientFx) {
                    g.setFill(Color.rgb(120, 100, 180, 0.12));
                    g.fillRect(0, GROUND_Y - 140, WORLD_WIDTH, 220);
                }
            }
            case CITY -> {
                g.setFill(Color.MIDNIGHTBLUE.darker());
                g.fillRect(0, 0, WORLD_WIDTH, WORLD_HEIGHT);
                if (ambientFx) {
                    g.setFill(Color.WHITE);
                    for (double[] star : cityStars) {
                        g.fillOval(star[0] - 1, star[1] - 1, 2, 2);
                    }
                }
                g.setFill(Color.rgb(15, 15, 30));
                double[] farX = {100, 900, 1700, 2700, 3700, 4700, 5500};
                for (double fx : farX) {
                    g.fillRect(fx - 200, GROUND_Y - 1400, 400, 1400);
                    g.fillRect(fx - 150, GROUND_Y - 1600, 300, 200);
                }
                double pulse = ambientFx ? (0.5 + 0.5 * Math.sin(System.currentTimeMillis() / 300.0)) : 0.0;
                double windowAlpha = ambientFx ? (0.3 + 0.4 * pulse) : 0.25;
                g.setFill(Color.rgb(255, 100, 200, windowAlpha));
                for (double fx : farX) {
                    for (int row = 0; row < 6; row++) {
                        for (int col = 0; col < 2; col++) {
                            double wx = fx - 150 + col * 200;
                            double wy = GROUND_Y - 1200 + row * 180;
                            g.fillRect(wx, wy, 60, 80);
                        }
                    }
                }
                g.setFill(Color.rgb(30, 30, 50));
                g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y);
                g.setFill(Color.rgb(65, 65, 85));
                g.setStroke(Color.CYAN.brighter());
                g.setLineWidth(4);
                for (Platform p : platforms) {
                    g.fillRect(p.x, p.y, p.w, p.h);
                    g.strokeRect(p.x, p.y, p.w, p.h);
                }
                g.setStroke(Color.MAGENTA.brighter());
                g.setLineWidth(2);
                for (Platform p : platforms) {
                    if (p.y < GROUND_Y - 400) g.strokeRect(p.x - 8, p.y - 8, p.w + 16, p.h + 16);
                }
                g.setFont(Font.font("Arial Black", FontWeight.BOLD, 32));
                if (ambientFx) {
                    g.setEffect(new Glow(1.0));
                    double time = System.currentTimeMillis();
                    for (Platform p : platforms) {
                        if (p.signText != null) {
                            double neonPulse = 0.7 + 0.3 * Math.sin(time / 200.0 + p.x * 0.01);
                            Color signColor = (p.x % 800 < 400) ? Color.MAGENTA.brighter() : Color.CYAN.brighter();
                            g.setFill(signColor.deriveColor(0, 1, 1, neonPulse));
                            double textWidth = p.signText.length() * 18;
                            g.fillText(p.signText, p.x + p.w / 2 - textWidth / 2, p.y - 20);
                        }
                    }
                    g.setEffect(null);
                } else {
                    g.setEffect(null);
                    g.setFill(Color.rgb(180, 180, 200, 0.5));
                    for (Platform p : platforms) {
                        if (p.signText != null) {
                            double textWidth = p.signText.length() * 18;
                            g.fillText(p.signText, p.x + p.w / 2 - textWidth / 2, p.y - 20);
                        }
                    }
                }
                g.setFill(Color.rgb(90, 90, 110));
                for (Platform p : platforms) {
                    if (p.w > 300 && p.y < GROUND_Y - 200) {
                        g.fillRect(p.x + p.w * 0.25, p.y - 45, 100, 45);
                        g.fillRect(p.x + p.w * 0.65, p.y - 45, 100, 45);
                        g.setFill(Color.rgb(50, 50, 70));
                        g.fillOval(p.x + p.w * 0.25 + 30, p.y - 35, 40, 25);
                        g.fillOval(p.x + p.w * 0.65 + 30, p.y - 35, 40, 25);
                    }
                }
            }
        }

        if (!swingingVines.isEmpty()) {
            drawSwingingVines(g, ambientFx);
        }

        if (particleEffectsEnabled) {
            for (Particle p : particles) {
                if (p.life <= 0 || isWorldRectNearCamera(p.x - 4, p.y - 4, 8, 8, 96)) {
                    continue;
                }
                g.setFill(p.color.deriveColor(0, 1, 1, p.life / 60.0));
                g.fillOval(p.x - 4, p.y - 4, 8, 8);
            }
        }

        for (PowerUp p : powerUps) {
            p.floatOffset += 0.1;
            double offset = Math.sin(p.floatOffset) * 10;
            if (isWorldRectNearCamera(p.x - 44, p.y - 44, 88, 88, 160)) {
                continue;
            }
            drawPowerUpSprite(g, p, offset);
        }

        if (dockShipBomb != null) {
            drawDockShipBomb(g, dockShipBomb);
        }

        for (PiranhaHazard piranha : piranhaHazards) {
            if (isWorldRectNearCamera(piranha.x - 42, piranha.y - 28, 84, 56, 180)) {
                continue;
            }
            drawPiranhaHazard(g, piranha);
        }

        for (CrowMinion c : crowMinions) {
            double size = 70 * c.drawScale();
            if (isWorldRectNearCamera(c.x - size * 0.6, c.y - size * 0.5, size * 1.2, size, 220)) {
                continue;
            }
            drawCrowMinion(g, c);
        }

        for (ChickMinion chick : chickMinions) {
            if (isWorldRectNearCamera(chick.x, chick.y, chick.width, chick.height, 180)) {
                continue;
            }
            drawChickMinion(g, chick);
        }

        for (Bird b : players) {
            if (b != null && b.health > 0) {
                double size = 80 * b.sizeMultiplier;
                if (isWorldRectNearCamera(b.x, b.y, size, size, 220)) {
                    continue;
                }
                // Always draw birds at full opacity; HUD elements will fade when they overlap birds.
                b.draw(g);
                drawPlayerTag(g, b);
            }
        }

        if (trainingModeActive && trainingCombatOverlayEnabled) {
            drawTrainingCombatOverlay(g);
        }

        g.restore();
    }

    private void drawSwingingVines(GraphicsContext g, boolean ambientFx) {
        boolean junglePalette = selectedMap == MapType.VIBRANT_JUNGLE;
        for (SwingingVine vine : swingingVines) {
            drawSwingingVine(g, vine, ambientFx, junglePalette);
        }
    }

    private void drawSwingingVine(GraphicsContext g, SwingingVine vine, boolean ambientFx, boolean junglePalette) {
        double tipX = vine.gripX();
        double tipY = vine.gripY();
        double controlX = (vine.baseX + tipX) * 0.5 - Math.cos(vine.angle) * (junglePalette ? 34 : 22);
        double controlY = vine.baseY + vine.length * 0.42 + Math.abs(Math.sin(vine.angle)) * 28;
        int segments = 16;

        Color vineCore = junglePalette ? Color.web("#2E7D32") : Color.web("#33691E");
        Color vineHighlight = junglePalette ? Color.web("#66BB6A") : Color.web("#7CB342");
        Color leaf = junglePalette ? Color.web("#8BC34A") : Color.web("#9CCC65");
        if (vine.temporary) {
            vineCore = Color.web("#43A047");
            vineHighlight = Color.web("#A5D6A7");
            leaf = Color.web("#C5E1A5");
        }
        if (vine.detaching) {
            vineCore = vineCore.deriveColor(0, 1, 1, 0.88);
            vineHighlight = vineHighlight.deriveColor(0, 1, 1, 0.7);
            leaf = leaf.deriveColor(0, 1, 1, 0.86);
        }

        double prevX = vine.baseX;
        double prevY = vine.baseY;
        for (int i = 1; i <= segments; i++) {
            double t = i / (double) segments;
            double pointX = quadraticPoint(vine.baseX, controlX, tipX, t);
            double pointY = quadraticPoint(vine.baseY, controlY, tipY, t);
            g.setStroke(vineCore);
            g.setLineWidth(10 - t * 4);
            g.strokeLine(prevX, prevY, pointX, pointY);
            g.setStroke(vineHighlight.deriveColor(0, 1, 1, 0.62));
            g.setLineWidth(4 - t * 1.4);
            g.strokeLine(prevX + 1.5, prevY, pointX + 1.5, pointY);

            if (junglePalette && (i == 4 || i == 8 || i == 12)) {
                drawSwingingVineLeafCluster(g, pointX, pointY, leaf, ambientFx);
            }
            prevX = pointX;
            prevY = pointY;
        }

        if (!vine.detaching) {
            g.setFill(Color.web("#4E342E"));
            g.fillOval(vine.baseX - 14, vine.baseY - 12, 28, 24);
        } else {
            g.setStroke(Color.web("#6D4C41", 0.8));
            g.setLineWidth(3.0);
            g.strokeLine(vine.baseX - 6, vine.baseY - 5, vine.baseX + 3, vine.baseY + 8);
            g.strokeLine(vine.baseX + 1, vine.baseY - 6, vine.baseX + 8, vine.baseY + 6);
        }

        g.setFill(leaf);
        g.fillOval(tipX - 22, tipY - 14, 44, 28);
        g.fillOval(tipX - 12, tipY - 22, 30, 22);
        g.fillOval(tipX - 24, tipY - 8, 26, 18);

        if (ambientFx && junglePalette) {
            g.setEffect(new Glow(vine.temporary ? 0.35 : 0.18));
            g.setFill(Color.web("#F06292", vine.temporary ? 0.44 : 0.28));
            g.fillOval(tipX - 10, tipY - 10, 20, 20);
            g.setEffect(null);
        }
    }

    private void drawSwingingVineLeafCluster(GraphicsContext g, double x, double y, Color leaf, boolean ambientFx) {
        g.setFill(leaf);
        g.fillOval(x - 12, y - 10, 24, 16);
        g.fillOval(x - 4, y - 16, 20, 14);
        g.fillOval(x - 16, y - 4, 18, 14);
        if (ambientFx) {
            g.setFill(Color.web("#F8BBD0", 0.55));
            g.fillOval(x - 5, y - 5, 10, 10);
        }
    }

    private double quadraticPoint(double start, double control, double end, double t) {
        double inv = 1.0 - t;
        return inv * inv * start + 2 * inv * t * control + t * t * end;
    }

    private void drawForestArena(GraphicsContext g, boolean ambientFx) {
        drawForestHillLayer(g, Color.web("#B7D4B0", 0.72), GROUND_Y + 220, 250, 110, 0.12, 8_101L);
        drawForestHillLayer(g, Color.web("#7FA27B", 0.76), GROUND_Y + 310, 360, 150, 0.20, 8_102L);
        drawForestHillLayer(g, Color.web("#4E7253", 0.88), GROUND_Y + 420, 440, 180, 0.30, 8_103L);

        drawForestTreeLayer(g, 0.18, GROUND_Y + 60, 420, 250, 360,
                Color.web("#4A2E20", 0.26), Color.web("#315A38", 0.34), 8_120L);
        drawForestTreeLayer(g, 0.30, GROUND_Y + 70, 560, 320, 300,
                Color.web("#402318", 0.44), Color.web("#224C2D", 0.56), 8_121L);

        if (ambientFx) {
            drawForestSunbeams(g);
            drawForestAmbientMotes(g);
        }

        g.setFill(Color.web("#4E342E"));
        g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y);
        g.setFill(Color.web("#245A2B"));
        g.fillRect(0, GROUND_Y, WORLD_WIDTH, 120);
        g.setFill(Color.web("#4CAF50", 0.28));
        renderRandom.setSeed(8_130L);
        Random grassRandom = renderRandom;
        for (int i = 0; i < 180; i++) {
            double patchX = -40 + i * 34 + grassRandom.nextDouble() * 26;
            double patchW = 70 + grassRandom.nextDouble() * 60;
            double patchH = 20 + grassRandom.nextDouble() * 26;
            g.fillOval(patchX, GROUND_Y - 8 - patchH * 0.25, patchW, patchH);
        }

        g.setFill(Color.web("#5FAE5B", 0.2));
        for (Platform p : platforms) {
            if (p.y < GROUND_Y - 50) {
                g.fillRoundRect(p.x - 34, p.y - 42, p.w + 68, 92, 70, 70);
            }
        }

        g.setStroke(Color.web("#4E342E", 0.42));
        g.setLineWidth(2.5);
        for (Platform p : platforms) {
            if (p.y >= GROUND_Y - 40) {
                continue;
            }
            renderRandom.setSeed(Double.doubleToLongBits(p.x * 31.0 + p.y * 17.0 + p.w * 13.0));
            Random rootRandom = renderRandom;
            int rootCount = Math.clamp((int) Math.round(p.w / 170.0), 1, 4);
            for (int i = 0; i < rootCount; i++) {
                double startX = p.x + 30 + rootRandom.nextDouble() * Math.max(30, p.w - 60);
                double length = 28 + rootRandom.nextDouble() * 34;
                double drift = (rootRandom.nextDouble() - 0.5) * 18;
                g.strokeLine(startX, p.y + p.h, startX + drift, p.y + p.h + length);
            }
        }

        g.setFill(Color.web("#5D4037"));
        g.setStroke(Color.web("#8D6E63"));
        g.setLineWidth(3);
        for (Platform p : platforms) {
            g.fillRoundRect(p.x, p.y, p.w, p.h, 18, 18);
            g.strokeRoundRect(p.x, p.y, p.w, p.h, 18, 18);

            g.setFill(Color.web("#2E7D32"));
            g.fillRoundRect(p.x - 6, p.y - 16, p.w + 12, 24, 24, 24);
            g.setFill(Color.web("#81C784", 0.88));
            g.fillOval(p.x + 12, p.y - 14, 46, 18);
            g.fillOval(p.x + p.w * 0.33, p.y - 16, 54, 20);
            g.fillOval(p.x + p.w * 0.62, p.y - 14, 52, 18);
            g.fillOval(p.x + p.w - 56, p.y - 12, 44, 16);
            g.setFill(Color.web("#5D4037"));
        }
    }

    private void drawForestHillLayer(GraphicsContext g, Color color, double baseY, double amplitude, double variance,
                                     double movementFactor, long seed) {
        final int points = 22;
        double[] xPoints = new double[points + 2];
        double[] yPoints = new double[points + 2];
        renderRandom.setSeed(seed);
        for (int i = 0; i < points; i++) {
            double worldX = -420 + i * ((WORLD_WIDTH + 840) / (double) (points - 1));
            double wave = Math.sin((worldX + seed * 0.11) / 360.0) * amplitude * 0.18;
            double ridge = Math.cos((worldX + seed * 0.07) / 640.0) * amplitude * 0.1;
            double lift = amplitude * 0.34 + renderRandom.nextDouble() * variance;
            xPoints[i] = parallaxAdjustedWorldX(worldX, movementFactor);
            yPoints[i] = baseY - lift - wave - ridge;
        }
        xPoints[points] = parallaxAdjustedWorldX(WORLD_WIDTH + 480, movementFactor);
        yPoints[points] = WORLD_HEIGHT + 120;
        xPoints[points + 1] = parallaxAdjustedWorldX(-480, movementFactor);
        yPoints[points + 1] = WORLD_HEIGHT + 120;
        g.setFill(color);
        g.fillPolygon(xPoints, yPoints, xPoints.length);
    }

    private void drawForestTreeLayer(GraphicsContext g, double movementFactor, double baseY, double minHeight,
                                     double heightVariance, double spacing, Color trunkColor, Color canopyColor, long seed) {
        renderRandom.setSeed(seed);
        Random treeRandom = renderRandom;
        for (int i = 0; i < 24; i++) {
            double worldX = -240 + i * spacing + treeRandom.nextDouble() * 70;
            double drawX = parallaxAdjustedWorldX(worldX, movementFactor);
            double trunkHeight = minHeight + treeRandom.nextDouble() * heightVariance;
            double trunkWidth = 26 + treeRandom.nextDouble() * 28;
            double canopyWidth = 170 + treeRandom.nextDouble() * 120;
            double canopyHeight = 110 + treeRandom.nextDouble() * 90;
            double trunkTopY = baseY - trunkHeight;

            g.setFill(trunkColor);
            g.fillRoundRect(drawX - trunkWidth * 0.5, trunkTopY, trunkWidth, trunkHeight + 70,
                    trunkWidth, Math.min(trunkWidth, trunkHeight + 70));

            g.setFill(canopyColor);
            g.fillOval(drawX - canopyWidth * 0.52, trunkTopY - canopyHeight * 0.26, canopyWidth, canopyHeight);
            g.fillOval(drawX - canopyWidth * 0.82, trunkTopY + canopyHeight * 0.05, canopyWidth * 0.72, canopyHeight * 0.72);
            g.fillOval(drawX - canopyWidth * 0.06, trunkTopY + canopyHeight * 0.02, canopyWidth * 0.72, canopyHeight * 0.76);
            if (treeRandom.nextDouble() < 0.55) {
                g.fillOval(drawX - canopyWidth * 0.28, trunkTopY - canopyHeight * 0.42,
                        canopyWidth * 0.62, canopyHeight * 0.62);
            }
        }
    }

    private void drawForestSunbeams(GraphicsContext g) {
        double time = System.currentTimeMillis() / 1800.0;
        g.setFill(Color.web("#FFF9C4", 0.08));
        for (int i = 0; i < 6; i++) {
            double beamCenterX = parallaxAdjustedWorldX(180 + i * 980 + Math.sin(time + i * 0.8) * 80, 0.10);
            double beamWidth = 170 + (i % 3) * 34;
            g.fillPolygon(
                    new double[]{beamCenterX - beamWidth, beamCenterX + beamWidth, beamCenterX + beamWidth * 0.42, beamCenterX - beamWidth * 0.42},
                    new double[]{0, 0, GROUND_Y + 140, GROUND_Y + 140},
                    4
            );
        }
    }

    private void drawForestAmbientMotes(GraphicsContext g) {
        double time = System.currentTimeMillis() / 950.0;
        renderRandom.setSeed(8_140L);
        Random moteRandom = renderRandom;
        for (int i = 0; i < 48; i++) {
            double baseX = moteRandom.nextDouble() * WORLD_WIDTH;
            double baseY = 160 + moteRandom.nextDouble() * (GROUND_Y - 260);
            double driftX = Math.sin(time * 0.8 + i * 1.37) * (14 + moteRandom.nextDouble() * 20);
            double driftY = Math.cos(time * 0.65 + i * 0.93) * (8 + moteRandom.nextDouble() * 14);
            double x = baseX + driftX;
            double y = baseY + driftY;
            boolean glowing = i % 6 == 0;
            g.setFill(glowing ? Color.web("#FFF59D", 0.54) : Color.web("#C5E1A5", 0.3));
            double size = glowing ? 6.2 : 3.8;
            g.fillOval(x - size * 0.5, y - size * 0.5, size, size * 0.78);
        }
    }

    private double parallaxAdjustedWorldX(double worldX, double movementFactor) {
        return worldX + camX * (1.0 - movementFactor);
    }

    private void drawTrainingCombatOverlay(GraphicsContext g) {
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;

            g.setLineWidth(3.0 / Math.max(0.25, zoom));
            g.setStroke((isTrainingDummy(b) ? Color.web("#FFB74D") : Color.web("#80DEEA")).deriveColor(0, 1, 1, 0.88));
            g.strokeRect(
                    b.debugCombatLeft(),
                    b.debugCombatTop(),
                    b.debugCombatWidth(),
                    b.debugCombatHeight()
            );

            if (!b.debugAttackBoxActive()) continue;
            g.setStroke(Color.web("#FF5252").deriveColor(0, 1, 1, 0.94));
            g.strokeRect(
                    b.debugAttackBoxLeft(),
                    b.debugAttackBoxTop(),
                    b.debugAttackBoxWidth(),
                    b.debugAttackBoxHeight()
            );
        }
    }

    private void drawBeaconCrownBattlefield(GraphicsContext g, boolean ambientFx) {
        Bird boss;
        double bossRatio = 1.0;
        if (isUnitedFinaleClimaxContext()) {
            boss = unitedFinaleBoss();
            bossRatio = boss == null ? 1.0 : Math.clamp(boss.health / unitedFinaleBossMaxHealth(), 0.0, 1.0);
        } else if (bossRushModeActive && classicModeActive) {
            bossRushLeadBoss();
            bossRatio = bossRushEnemyHealthRatio();
        } else {
            for (Bird b : players) {
                if (b != null && b.health > 0 && b.isNullRockForm()) {
                    bossRatio = Math.clamp(b.health / Math.max(1.0, b.getMaxHealth()), 0.0, 1.0);
                    break;
                }
            }
        }
        for (int i = 0; i < 640; i++) {
            double ratio = i / 640.0;
            Color top = Color.web("#04060C");
            Color bottom = Color.web("#1A2036");
            Color c = top.interpolate(bottom, ratio);
            g.setFill(c);
            g.fillRect(0, i * (WORLD_HEIGHT / 640.0), WORLD_WIDTH, WORLD_HEIGHT / 640.0 + 3);
        }

        double time = System.currentTimeMillis() / 280.0;
        double pulse = ambientFx ? 0.5 + 0.5 * Math.sin(time) : 0.45;
        double centerX = WORLD_WIDTH / 2.0;
        double eclipseY = 420;

        g.setFill(Color.rgb(10, 10, 18, 0.94));
        g.fillOval(centerX - 210, eclipseY - 210, 420, 420);
        g.setStroke(Color.web("#FFE082", 0.38 + (1.0 - bossRatio) * 0.24 + pulse * 0.1));
        g.setLineWidth(22);
        g.strokeOval(centerX - 250, eclipseY - 250, 500, 500);
        g.setStroke(Color.web("#80DEEA", 0.14 + pulse * 0.08));
        g.setLineWidth(8);
        g.strokeOval(centerX - 280, eclipseY - 280, 560, 560);

        double beamBaseY = battlefieldIslandY + 30;
        g.setFill(Color.web("#FFE082", 0.16 + (1.0 - bossRatio) * 0.12 + pulse * 0.06));
        g.fillPolygon(
                new double[]{centerX - 150, centerX - 58, centerX + 58, centerX + 150},
                new double[]{beamBaseY, 620, 620, beamBaseY},
                4
        );
        g.setFill(Color.web("#80DEEA", 0.16 + pulse * 0.08));
        g.fillPolygon(
                new double[]{centerX - 60, centerX - 22, centerX + 22, centerX + 60},
                new double[]{beamBaseY, 590, 590, beamBaseY},
                4
        );

        for (int i = 0; i < 7; i++) {
            double shardX = 650 + i * 760 + Math.sin(time * 0.4 + i) * 28;
            double shardY = 260 + (i % 3) * 120 + Math.cos(time * 0.55 + i) * 20;
            double shardH = 90 + (i % 2) * 35;
            g.setFill(Color.web(i % 2 == 0 ? "#FFE082" : "#80DEEA", 0.24));
            g.fillPolygon(
                    new double[]{shardX - 28, shardX, shardX + 28},
                    new double[]{shardY + shardH * 0.45, shardY - shardH * 0.55, shardY + shardH * 0.45},
                    3
            );
        }

        g.setFill(Color.rgb(18, 12, 26, 0.55));
        g.fillRect(0, GROUND_Y - 240, WORLD_WIDTH, 320);

        for (Platform p : platforms) {
            boolean high = p.y < battlefieldIslandY - 320;
            g.setFill(high ? Color.web("#4E342E") : Color.web("#3B2F3B"));
            g.fillRoundRect(p.x, p.y, p.w, p.h, 34, 34);
            g.setFill(high ? Color.web("#FFE082", 0.26) : Color.web("#80DEEA", 0.22));
            g.fillRoundRect(p.x + 10, p.y - 12, p.w - 20, p.h + 18, 34, 34);
            g.setStroke(high ? Color.web("#FFF59D") : Color.web("#B2EBF2"));
            g.setLineWidth(high ? 4.2 : 3.0);
            g.strokeRoundRect(p.x, p.y, p.w, p.h, 34, 34);
        }
    }

    private void drawDesertArena(GraphicsContext g, boolean ambientFx) {
        for (int i = 0; i < 620; i++) {
            double ratio = i / 620.0;
            Color c = Color.web("#F7B267").interpolate(Color.web("#FDE7B2"), ratio);
            g.setFill(c);
            g.fillRect(0, i * (WORLD_HEIGHT / 620.0), WORLD_WIDTH, WORLD_HEIGHT / 620.0 + 3);
        }

        double time = System.currentTimeMillis() / 760.0;
        double horizonY = GROUND_Y - 250;
        double waterline = dockWaterSurfaceY();

        g.setFill(Color.web("#FFD180", 0.52));
        g.fillOval(420, 110, 500, 500);
        g.setFill(Color.web("#FFF8E1", 0.22));
        g.fillOval(560, 245, 220, 220);

        g.setFill(Color.web("#D8A45B", 0.46));
        for (int i = 0; i < 6; i++) {
            double duneX = i * 880 - 240;
            double duneW = 980 + (i % 2) * 120;
            double duneH = 92 + (i % 3) * 18;
            g.fillOval(duneX, horizonY + 26 + (i % 2) * 10, duneW, duneH);
        }

        g.setFill(Color.web("#B9733A", 0.52));
        g.fillPolygon(
                new double[]{DESERT_CLIFF_BASE_X - 120, DESERT_CLIFF_MID_X - 90, DESERT_CLIFF_TOP_X + 70,
                        DESERT_CLIFF_HIGH_X + 80, WORLD_WIDTH - 140, WORLD_WIDTH - 380, DESERT_CLIFF_BASE_X - 240},
                new double[]{horizonY + 120, horizonY - 70, horizonY - 190, horizonY - 156, horizonY - 20, horizonY + 126, horizonY + 188},
                7
        );
        g.setFill(Color.web("#D8A45B", 0.38));
        g.fillPolygon(
                new double[]{DESERT_CLIFF_BASE_X + 24, DESERT_CLIFF_MID_X - 24, DESERT_CLIFF_TOP_X + 92,
                        DESERT_CLIFF_HIGH_X + 70, WORLD_WIDTH - 210, WORLD_WIDTH - 420, DESERT_CLIFF_BASE_X - 96},
                new double[]{horizonY + 82, horizonY - 38, horizonY - 116, horizonY - 100, horizonY + 18, horizonY + 114, horizonY + 144},
                7
        );

        if (ambientFx) {
            g.setStroke(Color.web("#FFF8E1", 0.16));
            g.setLineWidth(2.2);
            for (int i = 0; i < 12; i++) {
                double lineY = 240 + i * 80;
                double x1 = 180 + Math.sin(time * 0.5 + i * 0.8) * 60;
                double x2 = WORLD_WIDTH - 220 + Math.cos(time * 0.45 + i * 0.65) * 70;
                g.strokeLine(x1, lineY, x2, lineY - 46);
            }
        }

        double tumbleSpan = WORLD_WIDTH + 900;
        for (int i = 0; i < 5; i++) {
            double tumbleX = (time * (42 + i * 7) + i * 1180) % tumbleSpan - 260;
            if (tumbleX < -120 || tumbleX > WORLD_WIDTH + 120) {
                continue;
            }
            double tumbleY = horizonY + 180 + Math.sin(time * (0.7 + i * 0.05) + i) * 12;
            double radius = 20 + i * 4;
            double alpha = ambientFx ? 0.28 : 0.18;
            drawDesertTumbleweed(g, tumbleX, tumbleY, radius, time * (70 + i * 11) + i * 21, alpha);
            if (ambientFx) {
                g.setFill(Color.web("#E3B26B", 0.16));
                g.fillOval(tumbleX - radius * 1.6, tumbleY + radius * 0.6, radius * 2.0, radius * 0.58);
                g.fillOval(tumbleX - radius * 0.2, tumbleY + radius * 0.8, radius * 1.4, radius * 0.42);
            }
        }

        g.setFill(Color.web("#C7904F"));
        g.fillRect(0, GROUND_Y, WORLD_WIDTH, WORLD_HEIGHT - GROUND_Y + 120);
        g.setFill(Color.web("#E6B96F"));
        for (int i = 0; i < 7; i++) {
            double duneX = -180 + i * 920;
            g.fillOval(duneX, GROUND_Y - 18 + (i % 2) * 8, 560, 54);
        }
        if (isDockWaterActive()) {
            double pondBowlX = dockWaterX - 28;
            double pondBowlW = dockWaterW + 56;
            double pondDepth = 320;
            double pondBowlY = waterline - pondDepth;
            double pondRimX = pondBowlX - 44;
            double pondRimW = pondBowlW + 88;
            double pondRimDepth = pondDepth + 54;
            double pondRimY = waterline - pondRimDepth;

            g.setFill(Color.web("#C68E4F", 0.92));
            g.fillArc(pondRimX, pondRimY, pondRimW, pondRimDepth * 2.0, 180, 180, ArcType.CHORD);
            g.setFill(Color.web("#E8C37A", 0.88));
            g.fillArc(pondRimX - 34, waterline - 108, pondRimW + 68, 204, 180, 180, ArcType.CHORD);

            g.setFill(Color.web("#2A8C9E", 0.92));
            g.fillArc(pondBowlX, pondBowlY, pondBowlW, pondDepth * 2.0, 180, 180, ArcType.CHORD);
            g.setFill(Color.web("#52C7C3", 0.30));
            g.fillArc(dockWaterX + 54, waterline - 6, dockWaterW - 108, 116, 180, 180, ArcType.CHORD);
            g.setFill(Color.web("#0F6270", 0.20));
            g.fillArc(dockWaterX + 112, waterline + 36, dockWaterW - 224, 168, 180, 180, ArcType.CHORD);
            g.setStroke(Color.web("#B2EBF2", 0.68));
            g.setLineWidth(4.0);
            g.strokeArc(pondBowlX, pondBowlY, pondBowlW, pondDepth * 2.0, 180, 180, ArcType.OPEN);
            g.strokeLine(dockWaterX + 22, waterline, dockWaterX + dockWaterW - 22, waterline);
            g.setStroke(Color.web("#E0F7FA", 0.24));
            g.setLineWidth(2.0);
            for (int i = 0; i < 7; i++) {
                double waveInset = 54 + i * 12;
                double waveY = waterline + 18 + i * 24;
                double shift = Math.sin(time * 1.5 + i * 0.75) * 7;
                g.strokeLine(dockWaterX + waveInset, waveY + shift, dockWaterX + dockWaterW - waveInset, waveY - shift * 0.45);
            }
            g.setFill(Color.web("#8BC34A", 0.58));
            g.fillOval(dockWaterX - 120, waterline - 44, 220, 86);
            g.fillOval(dockWaterX + dockWaterW - 120, waterline - 36, 210, 76);

            g.setFill(Color.web("#E6BC73"));
            g.fillPolygon(
                    new double[]{dockWaterX - 248, dockWaterX - 154, dockWaterX - 92, dockWaterX - 18, dockWaterX + 72, dockWaterX + 136, dockWaterX - 248},
                    new double[]{GROUND_Y + 12, GROUND_Y - 4, GROUND_Y - 22, waterline - 28, waterline - 4, GROUND_Y + 18, GROUND_Y + 18},
                    7
            );
            g.fillPolygon(
                    new double[]{dockWaterX + dockWaterW + 248, dockWaterX + dockWaterW + 154, dockWaterX + dockWaterW + 92,
                            dockWaterX + dockWaterW + 18, dockWaterX + dockWaterW - 72, dockWaterX + dockWaterW - 136,
                            dockWaterX + dockWaterW + 248},
                    new double[]{GROUND_Y + 12, GROUND_Y - 4, GROUND_Y - 22, waterline - 28, waterline - 4, GROUND_Y + 18, GROUND_Y + 18},
                    7
            );
        }

        g.setFill(Color.web("#E7C173"));
        g.fillRoundRect(0, GROUND_Y - 14, DESERT_OASIS_X - 18, 20, 18, 18);
        double desertMidGroundX = DESERT_OASIS_X + DESERT_OASIS_W + 18;
        g.fillRoundRect(desertMidGroundX, GROUND_Y - 14, DESERT_CLIFF_BASE_X - desertMidGroundX + 30, 20, 18, 18);
        g.setStroke(Color.web("#B07A43", 0.72));
        g.setLineWidth(2.6);
        g.strokeLine(0, GROUND_Y + 2, DESERT_OASIS_X - 26, GROUND_Y + 2);
        g.strokeLine(desertMidGroundX, GROUND_Y + 2, DESERT_CLIFF_BASE_X - 28, GROUND_Y + 2);

        double[][] cactusData = {
                {360, GROUND_Y - 200, 44, 190},
                {1780, GROUND_Y - 180, 38, 168},
                {2640, GROUND_Y - 190, 42, 178},
                {3920, GROUND_Y - 185, 40, 176}
        };
        g.setFill(Color.web("#3E7D4C"));
        g.setStroke(Color.web("#1B5E20"));
        g.setLineWidth(3.2);
        for (double[] cactus : cactusData) {
            double cx = cactus[0];
            double cy = cactus[1];
            double cw = cactus[2];
            double ch = cactus[3];
            g.fillRoundRect(cx, cy, cw, ch, 20, 20);
            g.fillRoundRect(cx - 22, cy + 54, 18, 64, 14, 14);
            g.fillRoundRect(cx + cw + 4, cy + 38, 18, 72, 14, 14);
            g.strokeRoundRect(cx, cy, cw, ch, 20, 20);
        }

        double palmBaseX = dockWaterX - 110;
        g.setStroke(Color.web("#7B5A38"));
        g.setLineWidth(16);
        g.strokeLine(palmBaseX, GROUND_Y - 8, palmBaseX - 40, GROUND_Y - 210);
        g.strokeLine(palmBaseX + 80, GROUND_Y - 8, palmBaseX + 120, GROUND_Y - 196);
        g.setStroke(Color.web("#2E7D32"));
        g.setLineWidth(9);
        for (int i = 0; i < 5; i++) {
            double leafY = GROUND_Y - 220 + i * 6;
            g.strokeLine(palmBaseX - 40, GROUND_Y - 210, palmBaseX - 140 + i * 8, leafY - 24 - i * 4);
            g.strokeLine(palmBaseX - 40, GROUND_Y - 210, palmBaseX + 40 + i * 16, leafY - 42 + i * 2);
            g.strokeLine(palmBaseX + 120, GROUND_Y - 196, palmBaseX + 20 - i * 12, leafY - 18 + i * 5);
            g.strokeLine(palmBaseX + 120, GROUND_Y - 196, palmBaseX + 210 - i * 4, leafY - 34 - i * 3);
        }

        double[][] cliffLayers = {
                {DESERT_CLIFF_BASE_X, DESERT_CLIFF_LOW_X, DESERT_CLIFF_LOW_Y},
                {DESERT_CLIFF_LOW_X - 72, DESERT_CLIFF_MID_X, DESERT_CLIFF_MID_Y},
                {DESERT_CLIFF_MID_X - 74, DESERT_CLIFF_TOP_X, DESERT_CLIFF_TOP_Y},
                {DESERT_CLIFF_TOP_X - 72, DESERT_CLIFF_HIGH_X, DESERT_CLIFF_HIGH_Y},
                {DESERT_CLIFF_HIGH_X - 56, DESERT_CLIFF_SUMMIT_X, DESERT_CLIFF_SUMMIT_Y}
        };
        Color[] cliffFill = {
                Color.web("#B17943"),
                Color.web("#A96E3C"),
                Color.web("#9B6334"),
                Color.web("#8D572D"),
                Color.web("#7E4D29")
        };
        Color[] cliffHighlight = {
                Color.web("#D29A57", 0.26),
                Color.web("#CB8E4E", 0.24),
                Color.web("#C07D43", 0.22),
                Color.web("#AF6E39", 0.18),
                Color.web("#9C6031", 0.16)
        };
        for (int i = 0; i < cliffLayers.length; i++) {
            double baseX = cliffLayers[i][0];
            double topX = cliffLayers[i][1];
            double topY = cliffLayers[i][2];
            g.setFill(cliffFill[i]);
            g.fillPolygon(
                    new double[]{baseX, topX, WORLD_WIDTH, WORLD_WIDTH, baseX},
                    new double[]{GROUND_Y, topY, topY, GROUND_Y, GROUND_Y},
                    5
            );
            g.setFill(cliffHighlight[i]);
            g.fillPolygon(
                    new double[]{baseX + 48, topX + 56, WORLD_WIDTH - 26, WORLD_WIDTH - 84, baseX + 110},
                    new double[]{GROUND_Y - 10, topY + 34, topY + 28, GROUND_Y - 126, GROUND_Y - 60},
                    5
            );
            g.setStroke(Color.web("#6C4427", 0.78));
            g.setLineWidth(3.0);
            g.strokeLine(baseX, GROUND_Y, topX, topY);
            g.strokeLine(topX, topY, WORLD_WIDTH, topY);
        }

        for (Platform p : platforms) {
            if (p.y >= GROUND_Y - 6 || p.x < -50 || p.x > WORLD_WIDTH - 50) {
                continue;
            }
            boolean plateau = p.y < GROUND_Y - 80;
            boolean cliffPlatform = isDesertCliffPlatform(p);
            Color rock = cliffPlatform ? Color.web("#8A542C") : plateau ? Color.web("#936033") : Color.web("#A16B35");
            Color cap = cliffPlatform ? Color.web("#D4A05A") : plateau ? Color.web("#C99556") : Color.web("#D7A35E");
            g.setFill(rock);
            g.fillRoundRect(p.x, p.y, p.w, p.h, 24, 24);
            g.setFill(cap);
            g.fillRoundRect(p.x + 10, p.y - 12, Math.max(24, p.w - 20), Math.max(20, p.h * 0.36), 24, 24);
            g.setStroke(Color.web("#5D4037"));
            g.setLineWidth(3.2);
            g.strokeRoundRect(p.x, p.y, p.w, p.h, 24, 24);
            if (plateau && !cliffPlatform) {
                g.setStroke(Color.web("#6D4C41", 0.72));
                g.setLineWidth(7);
                for (double supportX = p.x + 44; supportX < p.x + p.w - 18; supportX += 120) {
                    g.strokeLine(supportX, p.y + p.h, supportX, GROUND_Y + 8);
                }
            }
        }
    }

    private boolean isDesertCliffPlatform(Platform p) {
        return p != null && p.x >= DESERT_CLIFF_LOW_X - 60 && p.y < GROUND_Y - 40;
    }

    private void drawDesertTumbleweed(GraphicsContext g, double x, double y, double radius, double rotationDeg, double alpha) {
        g.save();
        g.translate(x, y);
        g.rotate(rotationDeg);
        g.setStroke(Color.web("#8A6138", alpha));
        g.setLineWidth(Math.max(1.6, radius * 0.08));
        for (int i = 0; i < 3; i++) {
            double ring = radius * (1.0 - i * 0.18);
            g.strokeOval(-ring, -ring * 0.82, ring * 2.0, ring * 1.64);
        }
        for (int i = 0; i < 8; i++) {
            double angle = i * Math.PI / 4.0;
            double inner = radius * 0.24;
            double outer = radius * 0.98;
            g.strokeLine(Math.cos(angle) * inner, Math.sin(angle) * inner,
                    Math.cos(angle) * outer, Math.sin(angle) * outer);
        }
        g.restore();
    }

    private void drawDockArena(GraphicsContext g, boolean ambientFx) {
        for (int i = 0; i < 620; i++) {
            double ratio = i / 620.0;
            Color c = Color.web("#0B2030").interpolate(Color.web("#2C6E87"), ratio);
            g.setFill(c);
            g.fillRect(0, i * (WORLD_HEIGHT / 620.0), WORLD_WIDTH, WORLD_HEIGHT / 620.0 + 3);
        }

        double time = System.currentTimeMillis() / 820.0;
        double horizonY = GROUND_Y - 250;
        g.setFill(Color.web("#FFD180", 0.26));
        g.fillOval(420, 140, 520, 520);
        g.setFill(Color.web("#FFFFFF", 0.08));
        g.fillOval(520, 220, 320, 320);

        g.setFill(Color.web("#10293A", 0.85));
        for (int i = 0; i < 9; i++) {
            double baseX = i * 720 - 120;
            double height = 220 + (i % 3) * 60;
            g.fillRect(baseX, horizonY - height, 280, height);
            g.fillRect(baseX + 220, horizonY - height * 0.72, 180, height * 0.72);
            g.fillPolygon(
                    new double[]{baseX + 420, baseX + 540, baseX + 660},
                    new double[]{horizonY, horizonY - 120 - (i % 2) * 40, horizonY},
                    3
            );
        }

        g.setFill(Color.web("#0C1D28", 0.65));
        g.fillRect(0, horizonY, WORLD_WIDTH, WORLD_HEIGHT - horizonY);
        g.setStroke(Color.web("#7FDBFF", 0.14));
        g.setLineWidth(3);
        for (int i = 0; i < 18; i++) {
            double waveY = horizonY + 55 + i * 28;
            double y1 = waveY + Math.sin(time + i * 0.8) * 5;
            g.strokeLine(0, y1, WORLD_WIDTH, y1);
        }

        g.setFill(Color.web("#0E2430", 0.82));
        g.fillPolygon(
                new double[]{820, 980, 1180, 1360, 1240, 900},
                new double[]{horizonY + 70, horizonY - 20, horizonY + 10, horizonY + 100, horizonY + 130, horizonY + 120},
                6
        );
        g.fillPolygon(
                new double[]{4180, 4370, 4600, 4780, 4660, 4300},
                new double[]{horizonY + 40, horizonY - 40, horizonY - 10, horizonY + 96, horizonY + 126, horizonY + 116},
                6
        );
        g.setFill(Color.web("#D7CCC8", 0.16));
        g.fillPolygon(new double[]{1000, 1170, 1000}, new double[]{horizonY - 10, horizonY + 86, horizonY + 146}, 3);
        g.fillPolygon(new double[]{4390, 4580, 4390}, new double[]{horizonY - 30, horizonY + 78, horizonY + 146}, 3);

        if (ambientFx) {
            g.setFill(Color.web("#FFF8E1", 0.12));
            for (int i = 0; i < 8; i++) {
                double gullX = 500 + i * 650 + Math.sin(time * 0.55 + i * 0.7) * 70;
                double gullY = 180 + (i % 3) * 80 + Math.cos(time * 0.75 + i) * 18;
                g.fillArc(gullX - 20, gullY, 26, 14, 15, 145, ArcType.OPEN);
                g.fillArc(gullX - 2, gullY, 26, 14, 20, 145, ArcType.OPEN);
            }
        }

        double waterline = dockWaterSurfaceY();
        g.setFill(Color.web("#8D6E63"));
        g.fillRect(0, GROUND_Y - 6, dockWaterX - 24, WORLD_HEIGHT - GROUND_Y + 180);
        g.setFill(Color.web("#C8A268"));
        g.fillRect(0, GROUND_Y - 20, dockWaterX - 46, WORLD_HEIGHT - GROUND_Y + 180);
        g.setFill(Color.web("#E6C68A", 0.72));
        g.fillPolygon(
                new double[]{dockWaterX - 300, dockWaterX - 120, dockWaterX + 34, dockWaterX + 10, dockWaterX - 260},
                new double[]{GROUND_Y + 22, GROUND_Y - 58, GROUND_Y - 26, GROUND_Y + 42, GROUND_Y + 76},
                5
        );
        g.setFill(Color.web("#F4D79E", 0.34));
        for (int i = 0; i < 6; i++) {
            double duneX = 220 + i * 320;
            g.fillOval(duneX, GROUND_Y - 34 + (i % 2) * 8, 240, 54);
        }

        g.setFill(Color.web("#0A2533", 0.84));
        g.fillRect(dockWaterX, waterline, dockWaterW, WORLD_HEIGHT - waterline + 220);
        g.setFill(Color.web("#173C4D", 0.48));
        g.fillRect(dockWaterX + 30, waterline + 16, dockWaterW - 60, 34);
        g.setStroke(Color.web("#80DEEA", 0.24));
        g.setLineWidth(3.2);
        for (int i = 0; i < 14; i++) {
            double waveY = waterline + 18 + i * 26;
            double waveShift = Math.sin(time * 1.2 + i * 0.9) * 8;
            g.strokeLine(dockWaterX, waveY + waveShift, dockWaterX + dockWaterW, waveY - waveShift * 0.35);
        }
        g.setStroke(Color.web("#B3E5FC", 0.55));
        g.setLineWidth(4);
        g.strokeLine(dockWaterX, waterline, dockWaterX + dockWaterW, waterline);

        double shipX = dockShipVisualX();
        double shipY = dockShipVisualY();
        double shipScale = DOCK_SHIP_SCALE;
        boolean shipActive = dockShipBomb != null && !dockShipBomb.exploded;
        double cannonGlow = shipActive
                ? (dockShipBomb.fired
                ? 0.22 + Math.max(0.0, dockShipBomb.cannonFlashFrames / (double) DOCK_BOMB_CANNON_FLASH_FRAMES) * 0.55
                : 0.16 + (1.0 - Math.max(0, dockShipBomb.launchDelayFrames) / (double) DOCK_BOMB_LOCKON_FRAMES) * 0.28)
                : 0.08;
        g.save();
        g.translate(shipX, shipY);
        g.scale(shipScale, shipScale);
        g.setFill(Color.web("#132734", 0.92));
        g.fillPolygon(
                new double[]{30, 220, 670, 860, 930, 180},
                new double[]{154, 106, 114, 148, 198, 214},
                6
        );
        g.setFill(Color.web("#1E3948", 0.76));
        g.fillPolygon(
                new double[]{88, 232, 646, 780, 196},
                new double[]{150, 118, 126, 152, 186},
                5
        );
        g.setStroke(Color.web("#4E342E", 0.74));
        g.setLineWidth(10);
        g.strokeLine(308, -242, 308, 116);
        g.strokeLine(520, -188, 520, 132);
        g.strokeLine(714, -120, 714, 144);
        g.setStroke(Color.web("#BCAAA4", 0.24));
        g.setLineWidth(2.4);
        g.strokeLine(308, -210, 122, 20);
        g.strokeLine(308, -110, 620, 70);
        g.strokeLine(520, -150, 312, 20);
        g.strokeLine(520, -38, 756, 88);
        g.strokeLine(714, -92, 566, 48);
        g.setFill(Color.web("#263238", 0.84));
        g.fillPolygon(
                new double[]{308, 118, 308},
                new double[]{-214, -24, 28},
                3
        );
        g.fillPolygon(
                new double[]{520, 332, 520},
                new double[]{-150, 14, 54},
                3
        );
        g.fillPolygon(
                new double[]{714, 572, 714},
                new double[]{-82, 34, 72},
                3
        );
        g.setFill(Color.web("#FFECB3", 0.14));
        for (int i = 0; i < 5; i++) {
            g.fillOval(210 + i * 112, 136 + (i % 2) * 6, 38, 16);
        }
        g.setStroke(Color.web("#3E2723", 0.9));
        g.setLineWidth(16);
        g.strokeLine(78, 146, -18, 134);
        g.setStroke(Color.web("#4A2E1F", 0.92));
        g.setLineWidth(10);
        g.strokeLine(82, 148, -36, 132);
        g.setFill(Color.web("#FFCC80", cannonGlow));
        g.fillOval(4, 106, 132, 58);
        g.setFill(Color.web("#FFE082", cannonGlow * 0.92));
        g.fillOval(-12, 114, 92, 42);
        g.restore();

        g.setFill(Color.web("#4E342E", 0.95));
        g.fillRoundRect(720, GROUND_Y - 250, 420, 140, 18, 18);
        g.fillRoundRect(980, GROUND_Y - 420, 300, 170, 18, 18);
        g.setFill(Color.web("#6D4C41", 0.94));
        g.fillPolygon(
                new double[]{920, 1090, 1280, 1200, 980},
                new double[]{GROUND_Y - 420, GROUND_Y - 580, GROUND_Y - 420, GROUND_Y - 350, GROUND_Y - 350},
                5
        );
        g.setStroke(Color.web("#D7CCC8", 0.22));
        g.setLineWidth(3);
        for (int i = 0; i < 3; i++) {
            g.strokeRect(800 + i * 90, GROUND_Y - 200, 54, 40);
            g.strokeRect(1020 + i * 68, GROUND_Y - 360, 42, 34);
        }

        g.setStroke(Color.web("#5D4037", 0.85));
        g.setLineWidth(14);
        g.strokeLine(3180, GROUND_Y - 192, 4880, GROUND_Y - 192);
        g.setLineWidth(10);
        for (double supportX = 3240; supportX <= 4820; supportX += 220) {
            g.strokeLine(supportX, GROUND_Y - 164, supportX, waterline + 110);
        }
        g.setStroke(Color.web("#BCAAA4", 0.28));
        g.setLineWidth(2.2);
        g.strokeLine(3300, GROUND_Y - 540, 3460, GROUND_Y - 220);
        g.strokeLine(4300, GROUND_Y - 780, 4520, GROUND_Y - 220);

        for (Platform p : platforms) {
            boolean skiff = isDockSkiffPlatform(p);
            boolean bridge = p.x >= 3000;
            boolean highRigging = p.y < GROUND_Y - 520;
            Color wood = highRigging ? Color.web("#5D4037") : Color.web("#6D4C41");
            Color trim = highRigging ? Color.web("#A1887F") : Color.web("#8D6E63");
            g.setFill(wood);
            g.fillRoundRect(p.x, p.y, p.w, p.h, 24, 24);
            g.setStroke(Color.web("#3E2723"));
            g.setLineWidth(3.4);
            g.strokeRoundRect(p.x, p.y, p.w, p.h, 24, 24);
            g.setStroke(trim);
            g.setLineWidth(2.0);
            for (int i = 1; i < Math.max(2, (int) (p.w / 110)); i++) {
                double plankX = p.x + i * (p.w / Math.max(2, (int) (p.w / 110) + 1));
                g.strokeLine(plankX, p.y + 6, plankX, p.y + p.h - 6);
            }
            g.setFill(Color.web("#D7CCC8", 0.16));
            g.fillRoundRect(p.x + 10, p.y + 6, Math.max(20, p.w - 20), Math.max(10, p.h * 0.24), 18, 18);

            if (skiff) {
                g.setStroke(Color.web("#4E342E", 0.85));
                g.setLineWidth(5);
                g.strokeArc(p.x - 18, p.y + 4, p.w + 36, p.h + 30, 0, 180, ArcType.OPEN);
            } else if (bridge && p.y >= GROUND_Y - 260) {
                g.setStroke(Color.web("#4E342E", 0.72));
                g.setLineWidth(7);
                for (double postX = p.x + 40; postX < p.x + p.w - 10; postX += 120) {
                    g.strokeLine(postX, p.y + p.h, postX, waterline + 95);
                }
            } else if (p.y >= battlefieldIslandY - 180) {
                g.setStroke(Color.web("#4E342E", 0.72));
                g.setLineWidth(8);
                double supportBottom = p.x + p.w < dockWaterX - 20 ? GROUND_Y + 10 : waterline + 30;
                for (double postX = p.x + 50; postX < p.x + p.w - 20; postX += 140) {
                    g.strokeLine(postX, p.y + p.h, postX, supportBottom);
                }
            } else {
                double mastBaseX = p.x + p.w / 2;
                g.setStroke(Color.web("#5D4037", 0.72));
                g.setLineWidth(5);
                g.strokeLine(mastBaseX, battlefieldIslandY + 8, mastBaseX, p.y + p.h);
                g.setStroke(Color.web("#D7CCC8", 0.22));
                g.setLineWidth(2);
                g.strokeLine(mastBaseX, p.y + p.h, mastBaseX - 160, battlefieldIslandY + 20);
                g.strokeLine(mastBaseX, p.y + p.h, mastBaseX + 160, battlefieldIslandY + 20);
            }
        }

        double leverBaseY = dockLeverY + 26;
        boolean leverReady = dockLeverCooldown <= 0;
        g.setFill(leverReady ? Color.web("#7B5A3B") : Color.web("#546E7A"));
        g.fillRoundRect(dockLeverX - 34, leverBaseY - 10, 68, 18, 10, 10);
        g.setStroke(Color.web("#2E1F16"));
        g.setLineWidth(3);
        g.strokeRoundRect(dockLeverX - 34, leverBaseY - 10, 68, 18, 10, 10);
        double handleTipX = dockLeverX + (leverReady ? 18 : -18);
        double handleTipY = dockLeverY + (leverReady ? -20 : -34);
        g.setStroke(leverReady ? Color.web("#FFCA28") : Color.web("#90A4AE"));
        g.setLineWidth(5);
        g.strokeLine(dockLeverX, leverBaseY - 4, handleTipX, handleTipY);
        g.setFill(leverReady ? Color.web("#FFE082") : Color.web("#CFD8DC"));
        g.fillOval(handleTipX - 8, handleTipY - 8, 16, 16);
        g.setFill(Color.web("#FFF8E1", leverReady ? 0.72 : 0.46));
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 20));
        String leverText = leverReady ? "LEVER READY" : "RELOAD " + (int) Math.ceil(dockLeverCooldown / 60.0) + "s";
        g.fillText(leverText, dockLeverX - 60, dockLeverY - 24);

        for (WindVent v : windVents) {
            g.setFill(Color.web("#B3E5FC", ambientFx ? 0.22 : 0.14));
            g.fillOval(v.x + v.w / 2 - 120, v.y - 180, 240, 300);
            g.setStroke(Color.web("#E1F5FE", 0.18));
            g.setLineWidth(2);
            g.strokeOval(v.x + v.w / 2 - 94, v.y - 140, 188, 224);
        }
    }

    private void drawCrowMinion(GraphicsContext g, CrowMinion crow) {
        int variant = crow.effectiveVariant();
        double pulseVal = 1.0 + 0.3 * Math.sin(crow.age * 0.4);
        double scale = pulseVal * crow.drawScale();
        double hitFlash = Math.clamp(crow.hitFlashTimer / 10.0, 0.0, 1.0);
        double drawX = crow.x + (hitFlash > 0 ? (crow.hitFlashTimer % 2 == 0 ? 2.4 : -2.4) * scale : 0.0);
        double drawY = crow.y - hitFlash * 2.0 * scale;

        Color body = switch (variant) {
            case CrowMinion.VARIANT_GIANT_CROW -> Color.web("#140407");
            case CrowMinion.VARIANT_RAVEN -> Color.web("#111822");
            case CrowMinion.VARIANT_VOID_RAVEN -> Color.web("#08070D");
            case CrowMinion.VARIANT_MURDER_CROW -> Color.rgb(20, 0, 0);
            default -> Color.BLACK;
        };
        Color wings = switch (variant) {
            case CrowMinion.VARIANT_GIANT_CROW -> Color.web("#2B070C");
            case CrowMinion.VARIANT_RAVEN -> Color.web("#283445");
            case CrowMinion.VARIANT_VOID_RAVEN -> Color.web("#25102B");
            case CrowMinion.VARIANT_MURDER_CROW -> Color.rgb(40, 0, 0);
            default -> Color.rgb(30, 30, 40);
        };
        Color eyes = switch (variant) {
            case CrowMinion.VARIANT_RAVEN -> Color.web("#90CAF9");
            case CrowMinion.VARIANT_VOID_RAVEN -> Color.web("#FF80AB");
            default -> Color.RED.brighter();
        };
        if (hitFlash > 0) {
            body = body.interpolate(Color.web("#FFEBEE"), 0.18 + hitFlash * 0.28);
            wings = wings.interpolate(Color.web("#FFF59D"), 0.10 + hitFlash * 0.22);
        }

        g.setFill(body);
        g.fillOval(drawX - 12 * scale, drawY - 10 * scale, 24 * scale, 20 * scale);
        double wingHeight = variant == CrowMinion.VARIANT_GIANT_CROW ? 34 * scale : 25 * scale;
        double wingWidth = variant == CrowMinion.VARIANT_VOID_RAVEN ? 24 * scale : 20 * scale;
        g.setFill(wings);
        g.fillOval(drawX - 25 * scale, drawY - 8 * scale, wingWidth, wingHeight);
        g.fillOval(drawX + 5 * scale, drawY - 8 * scale, wingWidth, wingHeight);
        g.setFill(eyes);
        g.fillOval(drawX - 4 * scale, drawY - 5 * scale, 8 * scale, 8 * scale);
        g.fillOval(drawX + 10 * scale, drawY - 5 * scale, 8 * scale, 8 * scale);
        if (variant == CrowMinion.VARIANT_VOID_RAVEN) {
            g.setStroke(Color.web("#FF80AB").deriveColor(0, 1, 1, 0.75));
            g.setLineWidth(2.0);
            g.strokeOval(drawX - 18 * scale, drawY - 18 * scale, 36 * scale, 28 * scale);
        }
        if (crow.hasCrown) {
            double crownW = 18 * scale;
            double crownH = 10 * scale;
            double cy = drawY - 18 * scale;
            double[] xs = new double[]{
                    drawX - crownW / 2, drawX - crownW / 4, drawX, drawX + crownW / 4, drawX + crownW / 2, drawX + crownW / 2, drawX - crownW / 2
            };
            double[] ys = new double[]{
                    cy + crownH, cy, cy + crownH * 0.3, cy, cy + crownH, cy + crownH * 1.3, cy + crownH * 1.3
            };
            g.setFill(variant == CrowMinion.VARIANT_VOID_RAVEN ? Color.web("#B71C5C") : Color.GOLD);
            g.fillPolygon(xs, ys, xs.length);
            g.setStroke(variant == CrowMinion.VARIANT_VOID_RAVEN ? Color.web("#FFCDD2") : Color.web("#FFF59D"));
            g.setLineWidth(1.2);
            g.strokePolygon(xs, ys, xs.length);
        }
    }

    private void drawPiranhaHazard(GraphicsContext g, PiranhaHazard piranha) {
        double dir = piranha.vx >= 0 ? 1.0 : -1.0;
        double bodyW = 46;
        double bodyH = 24;
        double x = piranha.x;
        double y = piranha.y;
        double bitePulse = piranha.biteCooldown > 0 ? 1.0 : 0.0;

        g.setFill(Color.web("#0A1A20", 0.28));
        g.fillOval(x - bodyW * 0.5, y + 10, bodyW, 10);

        g.setFill(Color.web("#C62828"));
        g.fillOval(x - bodyW * 0.5, y - bodyH * 0.5, bodyW, bodyH);
        g.setFill(Color.web("#EF5350"));
        g.fillOval(x - bodyW * 0.12, y - bodyH * 0.42, bodyW * 0.44, bodyH * 0.48);
        g.setFill(Color.web("#8E0000"));
        g.fillPolygon(
                new double[]{x - dir * bodyW * 0.46, x - dir * bodyW * 0.74, x - dir * bodyW * 0.46},
                new double[]{y, y - bodyH * 0.46, y + bodyH * 0.46},
                3
        );
        g.setFill(Color.web("#FFCDD2"));
        g.fillPolygon(
                new double[]{x + dir * bodyW * 0.28, x + dir * bodyW * 0.58, x + dir * bodyW * 0.28},
                new double[]{y - bodyH * 0.16, y - bodyH * 0.02, y + bodyH * 0.1},
                3
        );
        g.fillPolygon(
                new double[]{x + dir * bodyW * 0.28, x + dir * bodyW * 0.58, x + dir * bodyW * 0.28},
                new double[]{y + bodyH * 0.16, y + bodyH * 0.02, y - bodyH * 0.1},
                3
        );
        g.setFill(Color.WHITE);
        g.fillOval(x + dir * 10, y - 8, 6, 6);
        g.setFill(Color.BLACK);
        g.fillOval(x + dir * 11, y - 7, 3, 3);
        if (bitePulse > 0) {
            g.setStroke(Color.web("#FFEB3B", 0.6));
            g.setLineWidth(2.2);
            g.strokeOval(x - bodyW * 0.56, y - bodyH * 0.72, bodyW * 1.1, bodyH * 1.45);
        }
    }

    private void drawDockShipBomb(GraphicsContext g, DockShipBomb bomb) {
        if (bomb == null) return;
        double pulse = 0.5 + 0.5 * Math.sin(System.currentTimeMillis() / 95.0);
        if (!bomb.exploded) {
            double warningRadius = DOCK_BOMB_WARNING_RADIUS + pulse * 10.0;
            double telegraphAlpha = bomb.fired ? 0.2 : 0.28 + (1.0 - Math.max(0, bomb.launchDelayFrames) / (double) DOCK_BOMB_LOCKON_FRAMES) * 0.22;
            g.setFill(Color.web("#D50000", telegraphAlpha * 0.38));
            g.fillOval(bomb.targetX - warningRadius, bomb.targetY - warningRadius, warningRadius * 2, warningRadius * 2);
            g.setStroke(Color.web("#FF5252", Math.min(0.92, telegraphAlpha + 0.24)));
            g.setLineWidth(4.5);
            g.strokeOval(bomb.targetX - warningRadius, bomb.targetY - warningRadius, warningRadius * 2, warningRadius * 2);
            g.setStroke(Color.web("#FF8A80", Math.min(0.96, telegraphAlpha + 0.3)));
            g.setLineWidth(2.6);
            g.strokeLine(bomb.targetX - warningRadius * 0.72, bomb.targetY, bomb.targetX + warningRadius * 0.72, bomb.targetY);
            g.strokeLine(bomb.targetX, bomb.targetY - warningRadius * 0.72, bomb.targetX, bomb.targetY + warningRadius * 0.72);
        }

        double muzzleX = dockShipCannonMuzzleX();
        double muzzleY = dockShipCannonMuzzleY();
        if (!bomb.fired) {
            g.setStroke(Color.web("#FF8A80", 0.26 + pulse * 0.12));
            g.setLineWidth(3.2);
            g.setLineDashes(18, 12);
            g.strokeLine(muzzleX, muzzleY, bomb.targetX, bomb.targetY);
            g.setLineDashes();
            double charge = 1.0 - Math.max(0, bomb.launchDelayFrames) / (double) DOCK_BOMB_LOCKON_FRAMES;
            double chargeRadius = 28 + charge * 40;
            g.setFill(Color.web("#FFB74D", 0.22 + charge * 0.24));
            g.fillOval(muzzleX - chargeRadius, muzzleY - chargeRadius * 0.72, chargeRadius * 2, chargeRadius * 1.44);
            g.setStroke(Color.web("#FFF59D", 0.34 + charge * 0.36));
            g.setLineWidth(3.0);
            g.strokeOval(muzzleX - chargeRadius * 0.78, muzzleY - chargeRadius * 0.52, chargeRadius * 1.56, chargeRadius * 1.04);
            return;
        }

        if (bomb.cannonFlashFrames > 0) {
            double flash = bomb.cannonFlashFrames / (double) DOCK_BOMB_CANNON_FLASH_FRAMES;
            g.setFill(Color.web("#FFD54F", 0.22 + flash * 0.48));
            g.fillOval(muzzleX - 62, muzzleY - 34, 124, 68);
            g.setFill(Color.web("#FFF8E1", 0.24 + flash * 0.54));
            g.fillPolygon(
                    new double[]{muzzleX - 8, muzzleX - 88, muzzleX - 30, muzzleX - 108, muzzleX - 24},
                    new double[]{muzzleY - 14, muzzleY - 32, muzzleY, muzzleY + 20, muzzleY + 14},
                    5
            );
        }

        if (bomb.exploded) {
            double radius = 90 + bomb.explosionFrames * 8;
            g.setFill(Color.web("#FFCA28", 0.28));
            g.fillOval(bomb.x - radius, bomb.y - radius, radius * 2, radius * 2);
            g.setStroke(Color.web("#FFF59D", 0.75));
            g.setLineWidth(4);
            g.strokeOval(bomb.x - radius * 0.78, bomb.y - radius * 0.78, radius * 1.56, radius * 1.56);
            return;
        }

        for (int i = 5; i >= 1; i--) {
            double trailX = bomb.x - bomb.vx * i * 2.1;
            double trailY = bomb.y - bomb.vy * i * 2.1 + DOCK_BOMB_GRAVITY * i * i * 0.45;
            double size = 16 + i * 5;
            g.setFill(Color.web("#6D4C41", 0.08 + i * 0.06));
            g.fillOval(trailX - size * 0.5, trailY - size * 0.42, size, size * 0.84);
        }
        g.setStroke(Color.web("#6D4C41", 0.56));
        g.setLineWidth(2.6);
        g.strokeLine(bomb.x + 8, bomb.y - 10, bomb.x + 18, bomb.y - 24);
        g.setFill(Color.web("#2B2B2B"));
        g.fillOval(bomb.x - 22, bomb.y - 22, 44, 44);
        g.setStroke(Color.web("#B0BEC5"));
        g.setLineWidth(2.8);
        g.strokeOval(bomb.x - 22, bomb.y - 22, 44, 44);
        g.setFill(Color.web("#FF7043", 0.92));
        g.fillOval(bomb.x + 14, bomb.y - 28, 12, 12);
        g.setFill(Color.web("#FFD180", 0.32));
        g.fillOval(bomb.x - 34, bomb.y - 16, 24, 14);
    }

    private void drawChickMinion(GraphicsContext g, ChickMinion chick) {
        double pulse = 1.0 + 0.05 * Math.sin(chick.age * 0.35);
        double w = chick.width * pulse;
        double h = chick.height * pulse;
        double x = chick.x + (chick.width - w) * 0.5;
        double y = chick.y + (chick.height - h) * 0.5;
        boolean facingRight = chick.vx >= 0;
        boolean sunforgeBrood = chick.owner != null
                && chick.owner.type == BirdType.ROOSTER
                && chick.owner.isSunforgeSkin;

        Color body;
        Color accent;
        Color trim = null;
        if (sunforgeBrood) {
            switch (chick.variant) {
                case 1 -> {
                    body = Color.web("#455A64");
                    accent = Color.web("#4DD0E1");
                    trim = Color.web("#FFD54F");
                }
                case 2 -> {
                    body = Color.web("#8D6E63");
                    accent = Color.web("#FF7043");
                    trim = Color.web("#FFD54F");
                }
                default -> {
                    body = Color.web("#6D4C41");
                    accent = Color.web("#FFB300");
                    trim = Color.web("#FFF176");
                }
            }
        } else {
            switch (chick.variant) {
                case 1 -> {
                    body = Color.web("#FFF8E1");
                    accent = Color.web("#4FC3F7");
                    trim = Color.web("#90CAF9");
                }
                case 2 -> {
                    body = Color.web("#FFB74D");
                    accent = Color.web("#6D4C41");
                }
                default -> {
                    body = Color.web("#FFD54F");
                    accent = Color.web("#F57C00");
                    trim = Color.web("#FF7043");
                }
            }
        }

        if (chick.ultimate) {
            Color aura = sunforgeBrood ? Color.web("#FFB300") : Color.GOLD;
            g.setFill(aura.deriveColor(0, 1, 1, 0.25));
            g.fillOval(x - w * 0.6, y - h * 0.7, w * 2.2, h * 2.0);
            body = body.brighter();
        }

        g.setFill(body);
        g.fillOval(x, y + h * 0.2, w * 1.1, h * 0.8);

        if (sunforgeBrood) {
            g.setStroke(Color.web("#FFD54F").deriveColor(0, 1, 1, chick.ultimate ? 0.95 : 0.7));
            g.setLineWidth(Math.max(1.6, w * 0.06));
            g.strokeOval(x - w * 0.02, y + h * 0.18, w * 1.14, h * 0.84);
        }

        g.setFill(body.darker());
        g.fillOval(x + w * 0.25, y + h * 0.35, w * 0.45, h * 0.4);

        double headW = w * 0.45;
        double headH = h * 0.45;
        double headX = facingRight ? x + w * 0.7 : x - headW * 0.1;
        double headY = y + h * 0.05;
        g.setFill(body.brighter());
        g.fillOval(headX, headY, headW, headH);

        if (chick.variant == 1) {
            g.setFill(accent);
            double crestX = headX + headW * 0.1;
            double crestY = headY - headH * 0.25;
            g.fillPolygon(
                    new double[]{crestX, crestX + headW * 0.35, crestX + headW * 0.7},
                    new double[]{crestY + headH * 0.8, crestY, crestY + headH * 0.8},
                    3
            );
        } else if (chick.variant == 0 && trim != null) {
            g.setStroke(trim);
            g.setLineWidth(2.0);
            g.strokeLine(x + w * 0.35, y + h * 0.5, x + w * 0.7, y + h * 0.58);
        } else if (chick.variant == 2) {
            g.setFill(accent);
            g.fillOval(x + w * 0.18, y + h * 0.52, w * 0.18, h * 0.18);
            g.fillOval(x + w * 0.38, y + h * 0.55, w * 0.18, h * 0.18);
        }

        if (sunforgeBrood) {
            g.setStroke(trim != null ? trim : Color.web("#FFE082"));
            g.setLineWidth(Math.max(1.2, w * 0.045));
            g.strokeLine(x + w * 0.24, y + h * 0.34, x + w * 0.82, y + h * 0.46);
        }

        g.setFill(accent);
        if (facingRight) {
            g.fillPolygon(
                    new double[]{headX + headW * 0.9, headX + headW * 1.15, headX + headW * 0.9},
                    new double[]{headY + headH * 0.45, headY + headH * 0.55, headY + headH * 0.65},
                    3
            );
        } else {
            g.fillPolygon(
                    new double[]{headX + headW * 0.1, headX - headW * 0.15, headX + headW * 0.1},
                    new double[]{headY + headH * 0.45, headY + headH * 0.55, headY + headH * 0.65},
                    3
            );
        }

        g.setFill(sunforgeBrood ? Color.web("#FFF8E1") : Color.BLACK);
        double eyeX = facingRight ? headX + headW * 0.6 : headX + headW * 0.25;
        double eyeY = headY + headH * 0.35;
        g.fillOval(eyeX, eyeY, headW * 0.15, headW * 0.15);

        if (chick.ultimate) {
            double crownW = headW * 0.9;
            double crownH = headH * 0.55;
            double cx = headX + headW * 0.5;
            double cy = headY - crownH * 0.4;
            double[] xs = new double[]{
                    cx - crownW / 2, cx - crownW * 0.2, cx, cx + crownW * 0.2, cx + crownW / 2,
                    cx + crownW / 2, cx - crownW / 2
            };
            double[] ys = new double[]{
                    cy + crownH, cy, cy + crownH * 0.35, cy, cy + crownH,
                    cy + crownH * 1.25, cy + crownH * 1.25
            };
            g.setFill(Color.GOLD);
            g.fillPolygon(xs, ys, xs.length);
            g.setStroke(Color.web("#FFF59D"));
            g.setLineWidth(1.0);
            g.strokePolygon(xs, ys, xs.length);
        }
    }

    private void drawBirdCompanionPreview(Canvas canvas, BirdCompanionEntry entry) {
        GraphicsContext g = canvas.getGraphicsContext2D();
        double w = canvas.getWidth();
        double h = canvas.getHeight();
        g.clearRect(0, 0, w, h);

        g.setFill(entry.accent.deriveColor(0, 1, 1, 0.18));
        g.fillRoundRect(4, 4, w - 8, h - 8, 16, 16);
        g.setStroke(entry.accent.deriveColor(0, 1, 1, 0.85));
        g.setLineWidth(2);
        g.strokeRoundRect(4, 4, w - 8, h - 8, 16, 16);

        if (entry.kind == BirdCompanionKind.CHICK) {
            g.setFill(Color.rgb(0, 0, 0, 0.2));
            g.fillOval(w * 0.22, h * 0.72, w * 0.48, h * 0.16);
            double scale = Math.min(w / 84.0, h / 62.0);
            g.save();
            g.translate(w * 0.14, h * 0.08);
            g.scale(scale, scale);
            ChickMinion chick = new ChickMinion(18, 18, entry.variant, entry.empowered, null);
            chick.x = 16;
            chick.y = 12;
            chick.vx = 2.0;
            chick.age = 18;
            drawChickMinion(g, chick);
            g.restore();
            return;
        }

        g.setFill(Color.rgb(0, 0, 0, 0.25));
        g.fillOval(w * 0.16, h * 0.7, w * 0.56, h * 0.16);
        CrowMinion crow = new CrowMinion(28, 22, null);
        crow.age = 18;
        int variant = entry.variant >= 0 ? entry.variant
                : (entry.empowered ? CrowMinion.VARIANT_MURDER_CROW : CrowMinion.VARIANT_ALLIED_CROW);
        crow.withVariant(variant);
        double scale = Math.min(w / 78.0, h / 58.0) / Math.max(1.0, crow.drawScale() * 2.0);
        g.save();
        g.translate(w * 0.5 - crow.x * scale, h * 0.5 - crow.y * scale);
        g.scale(scale, scale);
        drawCrowMinion(g, crow);
        g.restore();
    }






    private void drawPlayerTag(GraphicsContext g, Bird b) {
        String tag = "P" + (b.playerIndex + 1);
        Font font = Font.font("Arial Black", 20);
        Text text = new Text(tag);
        text.setFont(font);
        double textW = text.getLayoutBounds().getWidth();
        double textH = text.getLayoutBounds().getHeight();

        double drawSize = 80 * b.sizeMultiplier;
        double centerX = b.x + drawSize / 2.0;
        double boxW = textW + 14;
        double boxH = textH + 6;
        double boxX = centerX - boxW / 2.0;
        double boxY = b.y - boxH - 12;

        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.6));
        g.fillRoundRect(boxX, boxY, boxW, boxH, 10, 10);
        g.setStroke(Color.WHITE.deriveColor(0, 1, 1, 0.85));
        g.setLineWidth(1.4);
        g.strokeRoundRect(boxX, boxY, boxW, boxH, 10, 10);
        g.setFill(Color.WHITE);
        g.setFont(font);
        g.fillText(tag, centerX - textW / 2.0, boxY + boxH - 4);
    }

    private void drawPowerUpSprite(GraphicsContext g, PowerUp p, double offset) {
        double cx = p.x;
        double cy = p.y + offset;

        g.setFill(p.type.color.deriveColor(0, 1, 1, 0.22));
        g.fillOval(cx - 44, cy - 44, 88, 88);
        g.setStroke(Color.WHITE.deriveColor(0, 1, 1, 0.8));
        g.setLineWidth(2.2);
        g.strokeOval(cx - 31, cy - 31, 62, 62);

        switch (p.type) {
            case HEALTH -> {
                g.setFill(Color.rgb(210, 20, 20));
                g.fillOval(cx - 22, cy - 22, 44, 44);
                g.setFill(Color.WHITE);
                g.fillRoundRect(cx - 6, cy - 16, 12, 32, 6, 6);
                g.fillRoundRect(cx - 16, cy - 6, 32, 12, 6, 6);
            }
            case SPEED -> {
                g.setFill(Color.CYAN.brighter());
                g.fillPolygon(new double[]{cx - 20, cx - 2, cx - 20}, new double[]{cy - 14, cy, cy + 14}, 3);
                g.fillPolygon(new double[]{cx - 2, cx + 16, cx - 2}, new double[]{cy - 14, cy, cy + 14}, 3);
                g.setStroke(Color.WHITE);
                g.setLineWidth(2);
                g.strokeLine(cx - 26, cy - 18, cx - 10, cy - 18);
                g.strokeLine(cx - 26, cy + 18, cx - 10, cy + 18);
            }
            case RAGE -> {
                g.setFill(Color.ORANGERED);
                g.fillPolygon(
                        new double[]{cx - 18, cx - 6, cx - 2, cx + 4, cx + 16, cx + 6, cx - 2},
                        new double[]{cy + 18, cy + 2, cy + 12, cy - 14, cy + 4, cy, cy + 18},
                        7
                );
                g.setStroke(Color.YELLOW);
                g.setLineWidth(2);
                g.strokeLine(cx - 14, cy + 18, cx + 12, cy - 8);
            }
            case SHRINK -> {
                g.setStroke(Color.MEDIUMPURPLE.brighter());
                g.setLineWidth(3);
                g.strokeOval(cx - 18, cy - 18, 36, 36);
                g.setFill(Color.MEDIUMPURPLE.brighter());
                g.fillPolygon(new double[]{cx - 24, cx - 12, cx - 12}, new double[]{cy, cy - 6, cy + 6}, 3);
                g.fillPolygon(new double[]{cx + 24, cx + 12, cx + 12}, new double[]{cy, cy - 6, cy + 6}, 3);
                g.fillPolygon(new double[]{cx, cx - 6, cx + 6}, new double[]{cy - 24, cy - 12, cy - 12}, 3);
                g.fillPolygon(new double[]{cx, cx - 6, cx + 6}, new double[]{cy + 24, cy + 12, cy + 12}, 3);
            }
            case NEON -> {
                g.setStroke(Color.MAGENTA.brighter());
                g.setLineWidth(3);
                for (int i = 0; i < 6; i++) {
                    double a = i * Math.PI / 3;
                    g.strokeLine(cx, cy, cx + Math.cos(a) * 22, cy + Math.sin(a) * 22);
                }
                g.setFill(Color.CYAN.brighter());
                g.fillOval(cx - 8, cy - 8, 16, 16);
            }
            case THERMAL -> {
                g.setFill(Color.GOLD);
                g.fillPolygon(new double[]{cx - 14, cx, cx + 14}, new double[]{cy + 6, cy - 16, cy + 6}, 3);
                g.fillPolygon(new double[]{cx - 10, cx, cx + 10}, new double[]{cy + 18, cy, cy + 18}, 3);
                g.setStroke(Color.WHITE);
                g.setLineWidth(2);
                g.strokeLine(cx, cy + 20, cx, cy - 22);
            }
            case VINE_GRAPPLE -> {
                g.setStroke(Color.LIMEGREEN.brighter());
                g.setLineWidth(4);
                g.strokeOval(cx - 15, cy - 15, 30, 30);
                g.strokeLine(cx + 10, cy + 10, cx + 22, cy + 22);
                g.setFill(Color.FORESTGREEN);
                g.fillOval(cx + 18, cy + 20, 10, 10);
            }
            case OVERCHARGE -> {
                g.setFill(Color.DEEPSKYBLUE.brighter());
                g.fillPolygon(
                        new double[]{cx - 10, cx + 2, cx - 2, cx + 12, cx, cx + 4},
                        new double[]{cy - 18, cy - 3, cy - 3, cy + 18, cy + 4, cy + 4},
                        6
                );
                g.setStroke(Color.WHITE);
                g.setLineWidth(2);
                g.strokeLine(cx - 20, cy - 14, cx - 10, cy - 14);
                g.strokeLine(cx + 12, cy + 14, cx + 22, cy + 14);
            }
            case TITAN -> {
                g.setFill(Color.DARKGOLDENROD);
                g.fillRoundRect(cx - 16, cy - 20, 32, 40, 10, 10);
                g.setStroke(Color.GOLD.brighter());
                g.setLineWidth(2.6);
                g.strokeRoundRect(cx - 16, cy - 20, 32, 40, 10, 10);
                g.setFill(Color.WHITE);
                g.fillPolygon(new double[]{cx - 3, cx + 3, cx + 3, cx + 8, cx, cx - 8, cx - 3},
                        new double[]{cy - 14, cy - 14, cy - 2, cy - 2, cy + 12, cy -2, cy -2}, 7);
            }
            case BROADSIDE -> {
                g.setFill(Color.web("#5D4037"));
                g.fillRoundRect(cx - 18, cy - 10, 26, 20, 8, 8);
                g.setStroke(Color.web("#D7CCC8"));
                g.setLineWidth(2.4);
                g.strokeRoundRect(cx - 18, cy - 10, 26, 20, 8, 8);
                g.setStroke(Color.web("#FFCC80"));
                g.setLineWidth(3);
                g.strokeLine(cx + 8, cy, cx + 22, cy);
                g.strokeLine(cx + 12, cy - 10, cx + 22, cy - 16);
                g.strokeLine(cx + 12, cy + 10, cx + 22, cy + 16);
                g.setFill(Color.web("#8D6E63"));
                g.fillOval(cx - 22, cy - 5, 12, 10);
            }
        }
    }

    private void appendStartLog(String msg) {
        try {
            java.io.File out = new java.io.File(System.getProperty("user.home"), "Desktop\\birdgame3-start-log.txt");
            try (java.io.PrintStream ps = new java.io.PrintStream(new java.io.FileOutputStream(out, true))) {
                ps.println(java.time.LocalDateTime.now() + " - " + msg);
            }
        } catch (Exception ignore) {
        }
    }

    @Override
    public void start(Stage stage) {
        try {
            appendStartLog("enter start");
            currentStage = stage;
            appendStartLog("set currentStage");
            // Ensure the JVM exits immediately when the window is closed from OS window controls
            stage.setOnCloseRequest(evt -> {
                appendStartLog("stage close requested");
                shutdownAndExit();
            });
            appendStartLog("set onCloseRequest");
            stage.setTitle("Bird Fight 3 - Power-Up Chaos!");
            appendStartLog("set title");
            stage.setResizable(true);
            stage.centerOnScreen();
            stage.setFullScreenExitKeyCombination(KeyCombination.NO_MATCH);
            stage.setFullScreenExitHint("");
            appendStartLog("before scheduling input init");
            // Initialize native input managers on a background thread to avoid blocking/crashing the JavaFX thread.
            Thread inputInitThread = getThread();
            inputInitThread.start();
            appendStartLog("scheduled input init");
            loadAchievements();
            appendStartLog("loadAchievements done");
            fullscreenEnabled = true;
            syncWiimoteModesToManager();
            appendStartLog("synced wiimote modes");
            loadSounds();
            appendStartLog("loadSounds done");
            startWiimoteMenuTimer();
            appendStartLog("before showMenu");
            showMenu(stage);
            appendStartLog("after showMenu");
            appendStartLog("before stage.show");
            stage.show();
            appendStartLog("after stage.show");
            javafx.application.Platform.runLater(() -> applyDisplaySettings(stage));
            appendStartLog("scheduled applyDisplaySettings");
            tryShowQueuedAchievementToast();
            appendStartLog("end start");
        } catch (Throwable t) {
            ThrowableLogSupport.log(LOGGER, Level.SEVERE, "Application startup failed", t);
            ThrowableLogSupport.writeReport(
                    java.nio.file.Path.of(System.getProperty("user.home"), "birdgame3-start-error.txt"),
                    false,
                    "Application startup failure",
                    t
            );
            // Re-throw so JavaFX still reports the error as before.
            throw t;
        }
    }

    private Thread getThread() {
        Thread inputInitThread = new Thread(() -> {
            appendStartLog("input init thread start");
            try {
                WiimoteInputManager w = null;
                try {
                    w = new WiimoteInputManager();
                    appendStartLog("wiimote init OK");
                } catch (Throwable t) {
                    appendStartLog("wiimote init failed: " + t);
                    ThrowableLogSupport.log(LOGGER, Level.WARNING, "WiimoteInputManager failed", t);
                    ThrowableLogSupport.writeReport(
                            java.nio.file.Path.of(System.getProperty("user.home"), "Desktop", "birdgame3-uncaught.txt"),
                            true,
                            "WiimoteInputManager init failure",
                            t
                    );
                }
                wiimoteInputManager = w;

                XboxInputManager x = null;
                try {
                    x = new XboxInputManager();
                    appendStartLog("xbox init OK");
                } catch (Throwable t) {
                    appendStartLog("xbox init failed: " + t);
                    ThrowableLogSupport.log(LOGGER, Level.WARNING, "XboxInputManager failed", t);
                    ThrowableLogSupport.writeReport(
                            java.nio.file.Path.of(System.getProperty("user.home"), "Desktop", "birdgame3-uncaught.txt"),
                            true,
                            "XboxInputManager init failure",
                            t
                    );
                }
                xboxInputManager = x;
            } catch (Throwable t) {
                appendStartLog("input init thread top-level failure: " + t);
                ThrowableLogSupport.log(LOGGER, Level.SEVERE, "Input init thread failed", t);
            } finally {
                appendStartLog("input init thread end");
            }
        }, "InputInit");
        inputInitThread.setDaemon(true);
        return inputInitThread;
    }

