        if (CLASSIC_CONTINUE_KEY.equals(key)) return "Classic Continue";
        if (CHAR_BAT_KEY.equals(key)) return "Bat";
        if (CHAR_FALCON_KEY.equals(key)) return "Falcon";
        if (CHAR_HEISENBIRD_KEY.equals(key)) return "Heisenbird";
