    private void setupUnitedFinaleAdventureRoster(AdventureBattle battle, BirdType playerType, String skinKey) {
        if (UNITED_FINALE_CLIMAX_TITLE.equals(battle.title)) {
            unitedFinaleMassBattleActive = true;
            activePlayers = Math.min(players.length, BirdType.values().length + 1);
            Bird player = createStoryBird(900, playerType, 0, "You: " + playerType.name, 100, 1.0, 1.0, false);
            applySkinChoiceToBird(player, playerType, skinKey);

            int bossSlot = activePlayers - 1;
            Bird boss = createStoryBird(5200, battle.opponentType, bossSlot, battle.opponentName,
                    battle.opponentHealth, battle.opponentPowerMult, battle.opponentSpeedMult, true);
            applyNullRockBossTemplate(boss);
            applyPreviewSkinChoiceToBird(boss, battle.opponentType, NULL_ROCK_VULTURE_SKIN);
            boss.powerMultiplier = Math.max(boss.powerMultiplier, boss.basePowerMultiplier * 1.08);
            boss.speedMultiplier = Math.max(boss.speedMultiplier, boss.baseSpeedMultiplier * 1.04);

            adventureTeamMode = true;
            Arrays.fill(adventureTeams, 2);
            adventureTeams[0] = 1;
            adventureTeams[bossSlot] = 2;
            populateUnitedFinaleMassRoster(playerType);
            return;
        }

        unitedFinaleMassBattleActive = false;
        if (UNITED_FINALE_PENULTIMATE_TITLE.equals(battle.title)) {
            activePlayers = 4;
            Bird player = createStoryBird(900, playerType, 0, "You: " + playerType.name, 100, 1.0, 1.0, false);
            applySkinChoiceToBird(player, playerType, skinKey);

            Bird eagle = createStoryBird(1580, BirdType.EAGLE, 1, "Ally: Sky King", 124, 1.2, 1.14, true);
            applyPreviewSkinChoiceToBird(eagle, BirdType.EAGLE, "SKY_KING_EAGLE");

            Bird phoenix = createStoryBird(2300, BirdType.PHOENIX, 2, "Ally: Nova Phoenix", 122, 1.2, 1.1, true);
            applyPreviewSkinChoiceToBird(phoenix, BirdType.PHOENIX, NOVA_PHOENIX_SKIN);

            Bird boss = createStoryBird(5000, battle.opponentType, 3, battle.opponentName,
                    battle.opponentHealth, battle.opponentPowerMult, battle.opponentSpeedMult, true);
            boss.setBaseMultipliers(
                    2.25,
                    adjustedBossPowerMultiplier(battle.opponentName, battle.opponentPowerMult),
                    adjustedBossSpeedMultiplier(battle.opponentName, battle.opponentSpeedMult)
            );
            boss.health = adjustedBossHealth(battle.opponentName, battle.opponentHealth);
            applyPreviewSkinChoiceToBird(boss, battle.opponentType, TIDE_VULTURE_SKIN);

            adventureTeamMode = true;
            Arrays.fill(adventureTeams, 2);
            adventureTeams[0] = 1;
            adventureTeams[1] = 1;
            adventureTeams[2] = 1;
            adventureTeams[3] = 2;
            return;
        }

        activePlayers = 4;
        Bird player = createStoryBird(900, playerType, 0, "You: " + playerType.name, 100, 1.0, 1.0, false);
        applySkinChoiceToBird(player, playerType, skinKey);

        Bird eagle = createStoryBird(1650, BirdType.EAGLE, 1, "Ally: Sky King", 122, 1.18, 1.12, true);
        applyPreviewSkinChoiceToBird(eagle, BirdType.EAGLE, "SKY_KING_EAGLE");

        Bird herald = createStoryBird(4050, BirdType.RAVEN, 2, "Enemy: Crown Herald", 162, 1.12, 1.14, true);
        applyPreviewSkinChoiceToBird(herald, BirdType.RAVEN, null);

        Bird warden = createStoryBird(5000, BirdType.VULTURE, 3, "Enemy: Storm Warden", 180, 1.17, 0.98, true);
        applyPreviewSkinChoiceToBird(warden, BirdType.VULTURE, TIDE_VULTURE_SKIN);

        adventureTeamMode = true;
        Arrays.fill(adventureTeams, 2);
        adventureTeams[0] = 1;
        adventureTeams[1] = 1;
        adventureTeams[2] = 2;
        adventureTeams[3] = 2;
    }

    private void applyAdventureBattleArenaModifiers(AdventureBattle battle) {
        if (battle == null) return;
        if (selectedAdventureRoute == AdventureRoute.TEMPEST) {
            applyTempestAdventureArenaModifiers(battle);
            return;
        }
        if (adventureChapterIndex == 0) {
            switch (adventureBattleIndex) {
                case 0 -> {
                    addToKillFeed("ROOFTOP SPRINT: Neon signals boost speed.");
                    powerUps.add(new PowerUp(1200, GROUND_Y - 760, PowerUpType.NEON));
                    powerUps.add(new PowerUp(3200, GROUND_Y - 820, PowerUpType.SPEED));
                }
                case 1 -> {
                    addToKillFeed("OLD FRIEND RUN: Thermal vents surge on the cliffs.");
                    windVents.add(new WindVent(900, GROUND_Y - 340, 500));
                    windVents.add(new WindVent(2800, GROUND_Y - 360, 520));
                    powerUps.add(new PowerUp(2600, GROUND_Y - 980, PowerUpType.THERMAL));
                }
                case 2 -> {
                    addToKillFeed("CARRION SCOUT: Crow eyes watch the fight.");
                    for (int i = 0; i < 4; i++) {
                        double cx = 900 + random.nextDouble() * 4200;
                        double cy = 260 + random.nextDouble() * 420;
                        crowMinions.add(new CrowMinion(cx, cy, players[0]));
                    }
                    powerUps.add(new PowerUp(3000, GROUND_Y - 900, PowerUpType.RAGE));
                    powerUps.add(new PowerUp(3600, GROUND_Y - 760, PowerUpType.HEALTH));
                }
            }
            return;
        }
        if (adventureChapterIndex == unitedFinaleChapterIndex()) {
            switch (adventureBattleIndex) {
                case 0 -> {
                    addToKillFeed("LAST APPROACH: Hummingbird and Titmouse cut an air lane through the storm.");
                    windVents.add(new WindVent(900, GROUND_Y - 340, 520));
                    windVents.add(new WindVent(2400, GROUND_Y - 420, 620));
                    windVents.add(new WindVent(4300, GROUND_Y - 360, 520));
                    powerUps.add(new PowerUp(1700, GROUND_Y - 940, PowerUpType.SPEED));
                    powerUps.add(new PowerUp(3000, GROUND_Y - 1180, PowerUpType.THERMAL));
                    powerUps.add(new PowerUp(4350, GROUND_Y - 880, PowerUpType.NEON));
                    if (players[0] != null) {
                        spawnUnitedFinaleAlliedCrows(players[0], 3);
                    }
                    adventureMatchTimerOverride = 95 * 60;
                }
                case 1 -> {
                    addToKillFeed("CRACK THE CROWN: Break the shell before the giant inside can spread.");
                    windVents.add(new WindVent(1500, GROUND_Y - 520, 420));
                    windVents.add(new WindVent(4500, GROUND_Y - 520, 420));
                    windVents.add(new WindVent(3000, GROUND_Y - 720, 520));
                    powerUps.add(new PowerUp(2200, GROUND_Y - 900, PowerUpType.HEALTH));
                    powerUps.add(new PowerUp(3000, GROUND_Y - 1080, PowerUpType.OVERCHARGE));
                    powerUps.add(new PowerUp(3800, GROUND_Y - 900, PowerUpType.SPEED));
                    powerUps.add(new PowerUp(3000, GROUND_Y - 780, PowerUpType.TITAN));
                    shakeIntensity = Math.max(shakeIntensity, 20);
                    adventureMatchTimerOverride = 130 * 60;
                }
                case 2 -> {
                    addToKillFeed("THE NULL ROCK: the Beacon Crown splits wide for the last battle.");
                    windVents.add(new WindVent(1100, GROUND_Y - 540, 520));
                    windVents.add(new WindVent(3000, GROUND_Y - 760, 640));
                    windVents.add(new WindVent(4900, GROUND_Y - 540, 520));
                    powerUps.add(new PowerUp(1400, GROUND_Y - 880, PowerUpType.HEALTH));
                    powerUps.add(new PowerUp(2250, GROUND_Y - 1080, PowerUpType.SPEED));
                    powerUps.add(new PowerUp(3000, GROUND_Y - 1260, PowerUpType.OVERCHARGE));
                    powerUps.add(new PowerUp(3750, GROUND_Y - 1080, PowerUpType.RAGE));
                    powerUps.add(new PowerUp(4600, GROUND_Y - 880, PowerUpType.TITAN));
                    if (players[0] != null) {
                        spawnUnitedFinaleAlliedCrows(players[0], 4);
                    }
                    shakeIntensity = Math.max(shakeIntensity, 28);
                    adventureMatchTimerOverride = 150 * 60;
                }
            }
            return;
        }
        if (adventureChapterIndex != 6) return;
        switch (adventureBattleIndex) {
            case 0 -> {
                addToKillFeed("MIRROR SPRINT: Twin signals bend the rooftops.");
                powerUps.add(new PowerUp(1200, GROUND_Y - 760, PowerUpType.NEON));
                powerUps.add(new PowerUp(2200, GROUND_Y - 640, PowerUpType.TITAN));
                powerUps.add(new PowerUp(3200, GROUND_Y - 860, PowerUpType.SPEED));
                powerUps.add(new PowerUp(4700, GROUND_Y - 760, PowerUpType.SHRINK));
                windVents.add(new WindVent(1600, GROUND_Y - 340, 500));
                windVents.add(new WindVent(4200, GROUND_Y - 360, 520));
                adventureMatchTimerOverride = 80 * 60;
            }
            case 1 -> {
                addToKillFeed("SHARD REVERSAL: Crystal echoes distort the cave air.");
                powerUps.add(new PowerUp(1400, GROUND_Y - 980, PowerUpType.OVERCHARGE));
                powerUps.add(new PowerUp(3000, GROUND_Y - 1040, PowerUpType.SHRINK));
                powerUps.add(new PowerUp(4500, GROUND_Y - 860, PowerUpType.HEALTH));
                for (int i = 0; i < 3; i++) {
                    double cx = 1000 + random.nextDouble() * 4000;
                    double cy = 260 + random.nextDouble() * 520;
                    crowMinions.add(new CrowMinion(cx, cy, null));
                }
                adventureMatchTimerOverride = 85 * 60;
            }
            case 2 -> {
                addToKillFeed("BEACON PARADOX: The light fights back.");
                powerUps.add(new PowerUp(1200, GROUND_Y - 760, PowerUpType.RAGE));
                powerUps.add(new PowerUp(3000, GROUND_Y - 960, PowerUpType.OVERCHARGE));
                powerUps.add(new PowerUp(4600, GROUND_Y - 760, PowerUpType.HEALTH));
                powerUps.add(new PowerUp(3000, GROUND_Y - 600, PowerUpType.TITAN));
                windVents.add(new WindVent(2200, GROUND_Y - 320, 520));
                windVents.add(new WindVent(3600, GROUND_Y - 340, 500));
                for (int i = 0; i < 4; i++) {
                    double cx = 900 + random.nextDouble() * 4200;
                    double cy = 240 + random.nextDouble() * 520;
                    crowMinions.add(new CrowMinion(cx, cy, null));
                }
                adventureMatchTimerOverride = 90 * 60;
            }
        }
    }

