    private String formatElapsedMillis(long elapsedMillis) {
        long safe = Math.max(0L, elapsedMillis);
        long totalSeconds = safe / 1000L;
        long minutes = totalSeconds / 60L;
        long seconds = totalSeconds % 60L;
        long centiseconds = (safe % 1000L) / 10L;
        return String.format(Locale.US, "%d:%02d.%02d", minutes, seconds, centiseconds);
    }

    private int bossRushRankScore(String rank) {
        if ("S".equals(rank)) return 4;
        if ("A".equals(rank)) return 3;
        if ("B".equals(rank)) return 2;
        if ("C".equals(rank)) return 1;
        return 0;
    }

    private String bossRushRankFor(long elapsedMillis, int deaths, boolean exCleared) {
        if (deaths == 0 && elapsedMillis <= 8L * 60_000L + 30_000L && exCleared) return "S";
        if (deaths <= 1 && elapsedMillis <= 10L * 60_000L + 30_000L) return "A";
        if (deaths <= 2 && elapsedMillis <= 13L * 60_000L) return "B";
        return "C";
    }

    private boolean hasBossRushRecordedClear(long elapsedMillis) {
        return elapsedMillis > 0L && elapsedMillis < Long.MAX_VALUE;
    }

    private boolean isBetterBossRushRecord(String newRank, long newElapsedMillis, String bestRank, long bestElapsedMillis) {
        if (!hasBossRushRecordedClear(bestElapsedMillis)) return true;
        int newScore = bossRushRankScore(newRank);
        int bestScore = bossRushRankScore(bestRank);
        if (newScore != bestScore) return newScore > bestScore;
        return newElapsedMillis < bestElapsedMillis;
    }

    private long bossRushBestClearMillisFor(BirdType type) {
        if (type == null) return Long.MAX_VALUE;
        return bossRushBestClearMillisByBird[type.ordinal()];
    }

    private String bossRushBestRankFor(BirdType type) {
        if (type == null) return "";
        String rank = bossRushBestRankByBird[type.ordinal()];
        return rank == null ? "" : rank;
    }

    boolean shouldShowBossRushSelectCompletionBadge(BirdType type) {
        return type != null && hasBossRushRecordedClear(bossRushBestClearMillisFor(type));
    }

    boolean shouldShowBossRushSelectPerfectBadge(BirdType type) {
        return type != null && bossRushPerfectBadgeByBird[type.ordinal()];
    }

    String bossRushBadgeDisplayLabel(BirdType type) {
        if (type == null) {
            return "-";
        }
        if (shouldShowBossRushSelectPerfectBadge(type)) {
            return "PERFECT";
        }
        if (shouldShowBossRushSelectCompletionBadge(type)) {
            return "CLEAR";
        }
        return "NOT EARNED";
    }

    String bossRushBestStatusForBird(BirdType type) {
        long bestElapsedMillis = bossRushBestClearMillisFor(type);
        if (!hasBossRushRecordedClear(bestElapsedMillis)) {
            return "No clear recorded";
        }
        String rank = bossRushBestRankFor(type);
        if (rank.isBlank()) {
            rank = "-";
        }
        return rank + "  |  " + formatElapsedMillis(bestElapsedMillis);
    }

    private void refreshBossRushOverallBestRecord() {
        bossRushBestClearMillis = Long.MAX_VALUE;
        bossRushBestBird = null;
        bossRushBestRank = "";
        for (BirdType type : BirdType.values()) {
            long bestElapsedMillis = bossRushBestClearMillisFor(type);
            if (!hasBossRushRecordedClear(bestElapsedMillis)) {
                continue;
            }
            String rank = bossRushBestRankFor(type);
            if (isBetterBossRushRecord(rank, bestElapsedMillis, bossRushBestRank, bossRushBestClearMillis)) {
                bossRushBestClearMillis = bestElapsedMillis;
                bossRushBestBird = type;
                bossRushBestRank = rank;
            }
        }
    }

    private void recordBossRushCompletion(BirdType type, String rank, long elapsedMillis, boolean perfectRouteCompleted) {
        if (type == null || !hasBossRushRecordedClear(elapsedMillis)) {
            return;
        }
        int idx = type.ordinal();
        if (isBetterBossRushRecord(rank, elapsedMillis, bossRushBestRankByBird[idx], bossRushBestClearMillisByBird[idx])) {
            bossRushBestClearMillisByBird[idx] = elapsedMillis;
            bossRushBestRankByBird[idx] = rank == null ? "" : rank;
        }
        if (perfectRouteCompleted) {
            bossRushPerfectBadgeByBird[idx] = true;
        }
        refreshBossRushOverallBestRecord();
    }

    int incrementBossRushClearCount() {
        return ++bossRushClearCount;
    }

    void recordBossRushProfileCompletion(BirdType type, String rank, long elapsedMillis, boolean perfectRouteCompleted) {
        recordBossRushCompletion(type, rank, elapsedMillis, perfectRouteCompleted);
    }

    void incrementTournamentChampionshipsWon() {
        ++tournamentChampionshipsWon;
    }

    String bossRushOverallBestStatus() {
        if (bossRushBestClearMillis == Long.MAX_VALUE || bossRushBestClearMillis <= 0L) {
            return "No clear recorded";
        }
        String bird = bossRushBestBird == null ? "Unknown" : bossRushBestBird.name;
        String rank = (bossRushBestRank == null || bossRushBestRank.isBlank()) ? "-" : bossRushBestRank;
        return rank + "  |  " + formatElapsedMillis(bossRushBestClearMillis) + "  |  " + bird;
    }

    private boolean isBossRushExEncounter(ClassicEncounter encounter) {
        return encounter != null && BOSS_RUSH_EX_NAME.equals(encounter.name);
    }

    private boolean isBossRushBeaconCrownEncounter(ClassicEncounter encounter) {
        return encounter != null && ("Null Roc Ascending".equals(encounter.name) || isBossRushExEncounter(encounter));
    }

    private boolean isBeaconCrownBattlefieldContext() {
        AdventureBattle battle = currentAdventureBattle != null ? currentAdventureBattle
                : (adventureModeActive ? activeAdventureBattle() : null);
        if (isUnitedFinaleBeaconBattle(battle)) {
            return true;
        }
        if (bossRushModeActive && classicModeActive && isBossRushBeaconCrownEncounter(classicEncounter)) {
            return true;
        }
        return selectedMap == MapType.BEACON_CROWN
                && !storyModeActive
                && !adventureModeActive
                && !classicModeActive;
    }

    private Bird bossRushLeadBoss() {
        if (!bossRushModeActive || !classicModeActive || classicEncounter == null) return null;
        Bird fallback = null;
        for (Bird b : players) {
            if (b == null) continue;
            if (getEffectiveTeam(b.playerIndex) != 2) continue;
            if (b.health > 0) return b;
            if (fallback == null) fallback = b;
        }
        return fallback;
    }

    private List<Bird> livingBossRushEnemies() {
        List<Bird> enemies = new ArrayList<>();
        if (!bossRushModeActive || !classicModeActive || classicEncounter == null) return enemies;
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;
            if (getEffectiveTeam(b.playerIndex) == 2) {
                enemies.add(b);
            }
        }
        return enemies;
    }

    private double bossRushEnemyHealthRatio() {
        if (!bossRushModeActive || classicEncounter == null || classicEncounter.enemies == null || classicEncounter.enemies.length == 0) {
            return 1.0;
        }
        double totalHealth = 0;
        for (ClassicFighter fighter : classicEncounter.enemies) {
            if (fighter != null) totalHealth += Math.max(1.0, adjustedBossHealth(fighter.title, fighter.health));
        }
        if (totalHealth <= 0) return 1.0;
        double currentHealth = 0;
        for (Bird enemy : livingBossRushEnemies()) {
            currentHealth += Math.max(0, enemy.health);
        }
        return Math.clamp(currentHealth / totalHealth, 0.0, 1.0);
    }

    private void damageBossRushEnemies(double totalDamage, Color primary, Color secondary) {
        List<Bird> enemies = livingBossRushEnemies();
        if (enemies.isEmpty() || totalDamage <= 0) return;
        double share = totalDamage / enemies.size();
        for (Bird enemy : enemies) {
            damageBossFromUnitedFlock(enemy, share, primary, secondary);
        }
    }

    private boolean shouldUpdateBossRushRecord(String rank, long elapsedMillis) {
        return isBetterBossRushRecord(rank, elapsedMillis, bossRushBestRank, bossRushBestClearMillis);
    }

    private void completeBossRushRun(Stage stage, boolean exCleared) {
        long elapsedMillis = bossRushRunStartMillis > 0L ? Math.max(0L, System.currentTimeMillis() - bossRushRunStartMillis) : 0L;
        String rank = bossRushRankFor(elapsedMillis, classicDeaths, exCleared);
        int payout = BOSS_RUSH_CLEAR_BONUS + (exCleared ? BOSS_RUSH_EX_CLEAR_BONUS : 0);
        grantBirdCoins(payout);
        boolean newRecord = shouldUpdateBossRushRecord(rank, elapsedMillis);
        boolean perfectRouteCompleted = exCleared && bossRushPerfectRun;
        bossRushClearCount = profileProgressController.onBossRushCompleted(
                classicSelectedBird,
                rank,
                elapsedMillis,
                perfectRouteCompleted,
                clearCount -> achievementEvaluator.onBossRushCompleted(clearCount, exCleared)
        );
        classicDeaths = 0;

        String exText = exCleared
                ? "EX route collapsed the Void Crown."
                : (bossRushPerfectRun
                ? "Perfect route reached the crown, but the EX gate was left unopened."
                : "Perfect route was broken, so the EX gate stayed closed.");
        String recordText = newRecord
                ? "New record: " + rank + "  |  " + formatElapsedMillis(elapsedMillis) + "."
                : "Best record: " + bossRushOverallBestStatus() + ".";
        showStoryDialogue(
                stage,
                "Boss Rush Cleared",
                exCleared ? "Voidcaster Prime" : "Beaconcaster Prime",
                "Route cleared with " + classicSelectedBird.name + ".\n"
                        + "Rank: " + rank + "  |  Time: " + formatElapsedMillis(elapsedMillis) + "\n"
                        + "Bird Coins awarded: +" + payout + "  |  Clears logged: " + bossRushClearCount + "\n"
                        + exText + "\n"
                        + recordText,
                () -> showClassicBirdSelect(stage)
        );
    }

    private String buildClassicRunCodename(Random rng) {
        String[] a = {"Tempest", "Neon", "Iron", "Night", "Solar", "Ghost", "Abyss", "Prism"};
        String[] b = {"Circuit", "Dynasty", "Gauntlet", "Arc", "Protocol", "Crown", "Storm", "Orbit"};
        return a[rng.nextInt(a.length)] + " " + b[rng.nextInt(b.length)];
    }

    private List<ClassicEncounter> buildClassicRun(BirdType playerType) {
        return buildClassicRun(playerType, random);
    }

    private List<ClassicEncounter> buildClassicRun(BirdType playerType, Random rng) {
        List<ClassicEncounter> run = new ArrayList<>();
        Set<MapType> usedMaps = new HashSet<>();
        Set<BirdType> usedBirds = new HashSet<>();
        classicLastMap = null;
        classicLastTwist = null;
        classicLastMutator = null;
        classicUsedTwists.clear();
        classicUsedMutators.clear();

        int roundOneVariant = rng.nextInt(3);
        if (roundOneVariant == 0) {
            BirdType r1 = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Qualifier: First Impact",
                    "Skycaster",
                    "One rival enters. Win clean and establish tempo.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.NONE, MatchMutator.RAGE_FRENZY),
                    pickClassicTwist(rng, ClassicTwist.STORM_LIFTS, ClassicTwist.NECTAR_BLOOM, ClassicTwist.WIND_RALLY, ClassicTwist.VINE_SURGE),
                    85 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r1, "Rival: " + r1.name, 120, 1.08, 1.03)
                    },
                    false
            ));
        } else if (roundOneVariant == 1) {
            BirdType r1a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r1b = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Skirmish: Twin Talons",
                    "Skycaster",
                    "Two lighter foes push early pace. Win clean and stay composed.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.NONE, MatchMutator.OVERCHARGE_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.NECTAR_BLOOM, ClassicTwist.SHADOW_CACHE, ClassicTwist.MEDIC_CACHE),
                    80 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r1a, "Dart Wing: " + r1a.name, 84, 0.9, 1.06),
                            classicFighter(r1b, "Dart Wing: " + r1b.name, 86, 0.92, 1.05)
                    },
                    false
            ));
        } else {
            BirdType r1 = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Hazard Pulse",
                    "Arena Warden",
                    "A tuned rival with hazards online early. Survive the opening storm.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TITAN_RUMBLE, MatchMutator.CROW_SURGE),
                    pickClassicTwist(rng, ClassicTwist.SHOCK_DROPS, ClassicTwist.TITAN_CACHE, ClassicTwist.OVERCHARGE_FURY),
                    88 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r1, "Charger: " + r1.name, 132, 1.12, 1.02)
                    },
                    false
            ));
        }

        int roundTwoVariant = rng.nextInt(3);
        if (roundTwoVariant == 0) {
            BirdType r2a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r2b = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Ambush: Split-Lane Pressure",
                    "Arena Warden",
                    "Two enemies coordinate from opposite angles. One misstep snowballs.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.RAGE_FRENZY, MatchMutator.OVERCHARGE_BRAWL, MatchMutator.NONE),
                    pickClassicTwist(rng, ClassicTwist.TITAN_CACHE, ClassicTwist.SHOCK_DROPS, ClassicTwist.OVERCHARGE_FURY),
                    95 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r2a, "Pressure Wing: " + r2a.name, 96, 0.93, 0.98),
                            classicFighter(r2b, "Pressure Wing: " + r2b.name, 94, 0.92, 1.0)
                    },
                    false
            ));
        } else if (roundTwoVariant == 1) {
            BirdType ally = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType enemy = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Wingmate: Lockstep Clash",
                    "Command Relay",
                    "You gain an ally to break a stronger rival. Stay together and trade aggro.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TURBO_BRAWL, MatchMutator.OVERCHARGE_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.RAGE_RITUAL, ClassicTwist.NECTAR_BLOOM, ClassicTwist.MEDIC_CACHE),
                    92 * 60,
                    new ClassicFighter[]{
                            classicFighter(ally, "Ally: " + ally.name, 104, 1.0, 1.06)
                    },
                    new ClassicFighter[]{
                            classicFighter(enemy, "Vanguard: " + enemy.name, 160, 1.18, 1.06)
                    },
                    false
            ));
        } else {
            BirdType ally = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType e1 = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType e2 = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Gridlock: Two-on-Two",
                    "Command Relay",
                    "Pair up and control space. Both sides bring balanced threats.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TITAN_RUMBLE, MatchMutator.TURBO_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.WIND_RALLY, ClassicTwist.SHADOW_CACHE, ClassicTwist.VINE_SURGE),
                    98 * 60,
                    new ClassicFighter[]{
                            classicFighter(ally, "Ally: " + ally.name, 110, 1.02, 1.05)
                    },
                    new ClassicFighter[]{
                            classicFighter(e1, "Twin: " + e1.name, 118, 1.05, 1.03),
                            classicFighter(e2, "Twin: " + e2.name, 118, 1.05, 1.03)
                    },
                    false
            ));
        }

        int roundThreeVariant = rng.nextInt(3);
        if (roundThreeVariant == 0) {
            BirdType ally = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3b = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Relay: Duo Protocol",
                    "Command Relay",
                    "You gain one ally. Keep formation and rotate aggro before they isolate either of you.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TURBO_BRAWL, MatchMutator.OVERCHARGE_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.NECTAR_BLOOM, ClassicTwist.STORM_LIFTS, ClassicTwist.VINE_SURGE),
                    95 * 60,
                    new ClassicFighter[]{
                            classicFighter(ally, "Ally: " + ally.name, 108, 1.0, 1.08)
                    },
                    new ClassicFighter[]{
                            classicFighter(r3a, "Pair Captain: " + r3a.name, 130, 1.12, 1.04),
                            classicFighter(r3b, "Pair Captain: " + r3b.name, 124, 1.1, 1.06)
                    },
                    false
            ));
        } else if (roundThreeVariant == 1) {
            BirdType r3a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3b = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3c = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Rush: Lone Pack",
                    "Ruin Oracle",
                    "Three lighter enemies hunt together. Control space before they surround you.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.CROW_SURGE, MatchMutator.RAGE_FRENZY),
                    pickClassicTwist(rng, ClassicTwist.CROW_CARNIVAL, ClassicTwist.SHADOW_CACHE, ClassicTwist.MEDIC_CACHE),
                    96 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r3a, "Pack Wing: " + r3a.name, 78, 0.84, 1.0),
                            classicFighter(r3b, "Pack Wing: " + r3b.name, 76, 0.84, 1.0),
                            classicFighter(r3c, "Pack Wing: " + r3c.name, 74, 0.84, 1.02)
                    },
                    false
            ));
        } else {
            BirdType ally = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r3b = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Lockdown: Control Lanes",
                    "Arena Warden",
                    "Two elite enemies hold territory. Work with your ally to dislodge them.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TITAN_RUMBLE, MatchMutator.TURBO_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.RAGE_RITUAL, ClassicTwist.TITAN_CACHE, ClassicTwist.OVERCHARGE_FURY),
                    96 * 60,
                    new ClassicFighter[]{
                            classicFighter(ally, "Ally: " + ally.name, 112, 1.04, 1.06)
                    },
                    new ClassicFighter[]{
                            classicFighter(r3a, "Warden: " + r3a.name, 142, 1.16, 1.05),
                            classicFighter(r3b, "Warden: " + r3b.name, 138, 1.14, 1.05)
                    },
                    false
            ));
        }

        int roundFourVariant = rng.nextInt(3);
        if (roundFourVariant == 0) {
            BirdType r4a = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r4b = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType r4c = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Gauntlet: Three-Flock Crush",
                    "Ruin Oracle",
                    "Three coordinated hunters attack in waves. They are individually weaker, but relentless together.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.CROW_SURGE, MatchMutator.TURBO_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.CROW_CARNIVAL, ClassicTwist.SHOCK_DROPS, ClassicTwist.OVERCHARGE_FURY),
                    98 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicFighter(r4a, "Gauntlet Wing: " + r4a.name, 84, 0.82, 0.94),
                            classicFighter(r4b, "Gauntlet Wing: " + r4b.name, 82, 0.8, 0.96),
                            classicFighter(r4c, "Gauntlet Wing: " + r4c.name, 80, 0.8, 0.98)
                    },
                    false
            ));
        } else if (roundFourVariant == 1) {
            BirdType ally = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType e1 = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType e2 = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Crossfire: Double Clash",
                    "Command Relay",
                    "Both sides field duos. Focus targets together to avoid staggered defeats.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TITAN_RUMBLE, MatchMutator.CROW_SURGE),
                    pickClassicTwist(rng, ClassicTwist.WIND_RALLY, ClassicTwist.STORM_LIFTS, ClassicTwist.VINE_SURGE),
                    95 * 60,
                    new ClassicFighter[]{
                            classicFighter(ally, "Ally: " + ally.name, 114, 1.04, 1.08)
                    },
                    new ClassicFighter[]{
                            classicFighter(e1, "Duelist: " + e1.name, 136, 1.12, 1.06),
                            classicFighter(e2, "Duelist: " + e2.name, 132, 1.1, 1.06)
                    },
                    false
            ));
        } else {
            BirdType miniBoss = pickClassicEnemy(rng, playerType, usedBirds);
            BirdType support = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Breaker: Boss Escort",
                    "Skycaster Prime",
                    "A mini-boss enters with support. Control space and split them apart.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TURBO_BRAWL, MatchMutator.OVERCHARGE_BRAWL),
                    pickClassicTwist(rng, ClassicTwist.TITAN_CACHE, ClassicTwist.RAGE_RITUAL, ClassicTwist.MEDIC_CACHE),
                    105 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicBossFighter(miniBoss, "Boss: " + miniBoss.name, 165, 1.14, 1.06),
                            classicFighter(support, "Escort: " + support.name, 105, 0.98, 1.03)
                    },
                    true
            ));
        }

        BirdType boss = pickClassicEnemy(rng, playerType, usedBirds);
        BirdType lieutenant = pickClassicEnemy(rng, playerType, usedBirds);
        boolean allyFinale = rng.nextBoolean();
        if (allyFinale) {
            BirdType r5ally = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Finale: Crown Circuit",
                    "Skycaster Prime",
                    "Final arena. A boss duo controls the map core. Break them to clear Classic for this bird.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TURBO_BRAWL, MatchMutator.CROW_SURGE, MatchMutator.TITAN_RUMBLE),
                    pickClassicTwist(rng, ClassicTwist.TITAN_CACHE, ClassicTwist.STORM_LIFTS, ClassicTwist.CROW_CARNIVAL, ClassicTwist.OVERCHARGE_FURY),
                    110 * 60,
                    new ClassicFighter[]{
                            classicFighter(r5ally, "Ally: " + r5ally.name, 112, 1.04, 1.08)
                    },
                    new ClassicFighter[]{
                            classicBossFighter(boss, "Boss: " + boss.name, 210, 1.32, 1.08),
                            classicBossFighter(lieutenant, "Boss: " + lieutenant.name, 175, 1.24, 1.12)
                    },
                    true
            ));
        } else {
            BirdType elite = pickClassicEnemy(rng, playerType, usedBirds);
            run.add(new ClassicEncounter(
                    "Finale: Storm Crown",
                    "Skycaster Prime",
                    "Final arena. The boss leads an elite wing. Break them to clear Classic for this bird.",
                    pickClassicMap(rng, usedMaps),
                    pickClassicMutator(rng, MatchMutator.TURBO_BRAWL, MatchMutator.CROW_SURGE, MatchMutator.TITAN_RUMBLE),
                    pickClassicTwist(rng, ClassicTwist.TITAN_CACHE, ClassicTwist.WIND_RALLY, ClassicTwist.RAGE_RITUAL, ClassicTwist.MEDIC_CACHE),
                    118 * 60,
                    new ClassicFighter[0],
                    new ClassicFighter[]{
                            classicBossFighter(boss, "Boss: " + boss.name, 200, 1.24, 1.06),
                            classicFighterWithCpu(lieutenant, "Elite: " + lieutenant.name, 80, 1.08),
                            classicFighterWithCpu(elite, "Elite: " + elite.name, 72, 1.06)
                    },
                    true
            ));
        }

        return run;
    }

