    private int legacyTeamPlacementScore(int teamId) {
        int total = 0;
        for (int i = 0; i < activePlayers; i++) {
            Bird bird = players[i];
            if (bird != null && getEffectiveTeam(i) == teamId) {
                total += eliminations[i] * 100 + damageDealt[i] + (int) bird.health;
            }
        }
        return total;
    }

