    void clearGameplayInputs() {
        pressedKeys.clear();
        clearActionStates(localActionPressed);
        clearActionStates(aiActionPressed);
        clearActionStates(lanActionPressed);
        clearActionStates(wiimoteActionPressed);
        Arrays.fill(wiimoteLeftHeld, false);
        Arrays.fill(wiimoteRightHeld, false);
        Arrays.fill(wiimoteGameplayPauseHeld, false);
    }

    private boolean isActionPressed(int playerIdx, ControlAction action) {
        if (isValidPlayerIndex(playerIdx) || action == null) return false;
        int actionIdx = action.ordinal();
        return localActionPressed[playerIdx][actionIdx]
                || aiActionPressed[playerIdx][actionIdx]
                || lanActionPressed[playerIdx][actionIdx]
                || wiimoteActionPressed[playerIdx][actionIdx];
    }

    private void clearActionStates(boolean[][] states) {
        for (boolean[] playerStates : states) {
            Arrays.fill(playerStates, false);
        }
    }

    private void pollWiimoteGameplayInputs() {
        clearActionStates(wiimoteActionPressed);
        if (wiimoteInputManager == null && xboxInputManager == null) {
            Arrays.fill(wiimoteLeftHeld, false);
            Arrays.fill(wiimoteRightHeld, false);
            Arrays.fill(wiimoteGameplayPauseHeld, false);
            return;
        }

        if (lanModeActive && lanIsClient) {
            Arrays.fill(wiimoteGameplayPauseHeld, false);
            syncLanWiimoteInputMask();
            return;
        }

        if (handleAssignedXboxDisconnectDuringGameplay()) {
            Arrays.fill(wiimoteGameplayPauseHeld, false);
            return;
        }

        int maxPlayers = Math.min(activePlayers, wiimoteActionPressed.length);
        for (int i = 0; i < maxPlayers; i++) {
            if (players[i] == null || isAI[i]) {
                resetWiimoteGameplayHoldState(i);
                continue;
            }
            if (lanModeActive && lanIsHost && i != 0) {
                resetWiimoteGameplayHoldState(i);
                continue;
            }
            WiimoteMappedState state = controllerStateForPlayer(i);
            boolean connected = state.connected();
            boolean left = connected && state.left();
            boolean right = connected && state.right();
            boolean jump = connected && state.jump();
            boolean attack = connected && state.attack();
            boolean special = connected && state.special();
            boolean grab = connected && state.grab();
            boolean block = connected && state.block();
            boolean tauntCycle = connected && state.tauntCycle();
            boolean tauntExecute = connected && state.tauntExecute();
            boolean pauseHeld = connected && state.menuPause();
            if (pauseHeld && !wiimoteGameplayPauseHeld[i] && currentStage != null && currentStage.getScene() == gameplayScene) {
                wiimoteGameplayPauseHeld[i] = true;
                wiimoteMenuPauseHeld = true;
                handleGameplayPauseRequest(currentStage);
                return;
            }
            wiimoteGameplayPauseHeld[i] = pauseHeld;
            setActionState(wiimoteActionPressed, i, ControlAction.LEFT, left);
            setActionState(wiimoteActionPressed, i, ControlAction.RIGHT, right);
            setActionState(wiimoteActionPressed, i, ControlAction.JUMP, jump);
            setActionState(wiimoteActionPressed, i, ControlAction.ATTACK, attack);
            setActionState(wiimoteActionPressed, i, ControlAction.SPECIAL, special);
            setActionState(wiimoteActionPressed, i, ControlAction.GRAB, grab);
            setActionState(wiimoteActionPressed, i, ControlAction.BLOCK, block);
            setActionState(wiimoteActionPressed, i, ControlAction.TAUNT_CYCLE, tauntCycle);
            setActionState(wiimoteActionPressed, i, ControlAction.TAUNT_EXECUTE, tauntExecute);

            if (left && !wiimoteLeftHeld[i]) {
                players[i].registerDashTap(-1);
            }
            if (right && !wiimoteRightHeld[i]) {
                players[i].registerDashTap(1);
            }
            wiimoteLeftHeld[i] = left;
            wiimoteRightHeld[i] = right;
        }
    }

    private void syncLanWiimoteInputMask() {
        int wiimotePlayer = Math.clamp(Math.max(lanPlayerIndex, 0), 0, 3);
        WiimoteMappedState state = controllerStateForPlayer(wiimotePlayer);
        boolean connected = state.connected();
        boolean left = connected && state.left();
        boolean right = connected && state.right();
        boolean jump = connected && state.jump();
        boolean attack = connected && state.attack();
        boolean special = connected && state.special();
        boolean grab = connected && state.grab();
        boolean block = connected && state.block();
        boolean tauntCycle = connected && state.tauntCycle();
        boolean tauntExecute = connected && state.tauntExecute();
        int nextMask = 0;
        if (left) nextMask |= LanProtocol.INPUT_LEFT;
        if (right) nextMask |= LanProtocol.INPUT_RIGHT;
        if (jump) nextMask |= LanProtocol.INPUT_JUMP;
        if (attack) nextMask |= LanProtocol.INPUT_ATTACK;
        if (special) nextMask |= LanProtocol.INPUT_SPECIAL;
        if (grab) nextMask |= LanProtocol.INPUT_GRAB;
        if (block) nextMask |= LanProtocol.INPUT_BLOCK;
        if (tauntCycle) nextMask |= LanProtocol.INPUT_TAUNT_CYCLE;
        if (tauntExecute) nextMask |= LanProtocol.INPUT_TAUNT_EXEC;
        if (nextMask != lanLocalInputMask) {
            lanLocalInputMask = nextMask;
            if (lanClient != null) {
                lanClient.sendInputMask(lanLocalInputMask);
            }
        }
    }

    private void resetWiimoteGameplayHoldState(int playerIdx) {
        if (isValidPlayerIndex(playerIdx)) {
            return;
        }
        wiimoteLeftHeld[playerIdx] = false;
        wiimoteRightHeld[playerIdx] = false;
    }

    void setLocalActionsForKey(KeyCode code, boolean down) {
        if (code == null) return;
        int maxPlayers = Math.min(activePlayers, localActionPressed.length);
        for (int i = 0; i < maxPlayers; i++) {
            if (isAI[i]) continue;
            if (keyboardControlsPlayer(i)) continue;
            if (lanModeActive && lanIsHost && i != 0) continue;
            ControlAction action = effectiveKeyboardActionForKey(i, code);
            if (action != null) {
                setActionState(localActionPressed, i, action, down);
            }
        }
    }

    private void setLanActionState(int playerIdx, ControlAction action, boolean down) {
        setActionState(lanActionPressed, playerIdx, action, down);
    }

    private void setActionState(boolean[][] states, int playerIdx, ControlAction action, boolean down) {
        if (isValidPlayerIndex(playerIdx) || action == null) return;
        states[playerIdx][action.ordinal()] = down;
    }

    private ControlAction effectiveKeyboardActionForKey(int playerIdx, KeyCode code) {
        ControlAction action = actionForKey(playerIdx, code);
        if (action != null) {
            return action;
        }
        return mirroredSharedKeyboardActionForKey(playerIdx, code);
    }

    private ControlAction mirroredSharedKeyboardActionForKey(int playerIdx, KeyCode code) {
        if (!sharedKeyboardAliasActive(playerIdx) || code == null) {
            return null;
        }
        int aliasPlayer = playerIdx == 0 ? 2 : 3;
        for (ControlAction action : ControlAction.values()) {
            if (keyForPlayer(aliasPlayer, action) == code) {
                return action;
            }
        }
        return null;
    }

    private boolean sharedKeyboardAliasActive(int playerIdx) {
        if (playerIdx < 0 || playerIdx > 1) {
            return false;
        }
        if (activePlayers != 2 || lanModeActive) {
            return false;
        }
        return !isAI[0]
                && !isAI[1]
                && !keyboardControlsPlayer(0)
                && !keyboardControlsPlayer(1);
    }

    private boolean isValidPlayerIndex(int playerIdx) {
        return playerIdx < 0 || playerIdx >= players.length;
    }

    private ControlAction actionForKey(int playerIdx, KeyCode code) {
        if (isValidPlayerIndex(playerIdx) || code == null) return null;
        for (ControlAction action : ControlAction.values()) {
            if (keyForPlayer(playerIdx, action) == code) {
                return action;
            }
        }
        return null;
    }

    private boolean isGameplayKeyForPlayer(KeyCode code) {
        if (isValidPlayerIndex(0) || code == null) return true;
        for (ControlAction action : ControlAction.values()) {
            if (keyForPlayer(0, action) == code) {
                return false;
            }
        }
        return true;
    }

    private int inputBitForKey(KeyCode code, int playerIdx) {
        ControlAction action = effectiveKeyboardActionForKey(playerIdx, code);
        if (action != null) {
            return action.inputMask;
        }
        return 0;
    }

    private void drawDebugBalanceHud(GraphicsContext g) {
        if (!debugHudEnabled) return;

        double panelX = 20;
        double panelY = 20;
        double panelW = 760;
        double panelH = 170 + activePlayers * 26;

        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.78));
        g.fillRoundRect(panelX, panelY, panelW, panelH, 18, 18);
        g.setStroke(Color.CYAN.brighter());
        g.setLineWidth(2.5);
        g.strokeRoundRect(panelX, panelY, panelW, panelH, 18, 18);

        double elapsedSec = Math.max(1.0, matchStartNano > 0
                ? (System.nanoTime() - matchStartNano) / 1_000_000_000.0
                : 1.0);

        g.setFill(Color.CYAN.brighter());
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 24));
        g.fillText("DEBUG BALANCE HUD (F3)", panelX + 18, panelY + 32);

        g.setFill(Color.LIGHTGRAY);
        g.setFont(Font.font("Consolas", 17));
        g.fillText("Match " + (int) elapsedSec + "s | Map: " + mapDisplayName(selectedMap),
                panelX + 18, panelY + 58);

        g.setFill(Color.WHITE);
        g.setFont(Font.font("Consolas", 16));
        g.fillText("Player                        DPS   Specials  Elims  Falls  WRd", panelX + 18, panelY + 84);

        for (int i = 0; i < activePlayers; i++) {
            Bird b = players[i];
            if (b == null) continue;

            String row = getString(i, elapsedSec, b);
            g.setFill(b.type.color.brighter());
            g.fillText(row, panelX + 18, panelY + 112 + i * 26);
        }

        g.setFill(Color.GRAY.brighter());
        g.setFont(Font.font("Consolas", 14));
        g.fillText("WRd = bird type lifetime win-rate delta from 50%", panelX + 18, panelY + panelH - 10);
    }

    private String getString(int i, double elapsedSec, Bird b) {
        double dps = damageDealt[i] / elapsedSec;
        int picks = typePicks[b.type.ordinal()];
        int wins = typeWins[b.type.ordinal()];
        double wr = picks > 0 ? wins / (double) picks : 0.5;
        int wrDelta = (int) Math.round((wr - 0.5) * 100.0);
        String wrText = (wrDelta >= 0 ? "+" : "") + wrDelta + "%";

        return String.format(
                "%-28s %5.1f %8d %7d %6d %6s",
                b.name.length() > 28 ? b.name.substring(0, 28) : b.name,
                dps,
                specialsUsed[i],
                eliminations[i],
                falls[i],
                wrText
        );
    }

    public void recordSpecialImpact(int playerIdx, int damage, boolean didHit) {
        if (playerIdx < 0 || playerIdx >= specialHits.length) return;
        if (didHit) specialHits[playerIdx]++;
        if (damage > 0) specialDamageDealt[playerIdx] += damage;
    }

    public int getCpuLevel(int playerIdx) {
        int level = 5;
        if (adventureModeActive && currentAdventureBattle != null) {
            level = currentAdventureBattle.cpuLevel;
        } else if (classicModeActive && classicEncounter != null) {
            if (playerIdx >= 0 && playerIdx < classicCpuLevels.length && classicCpuLevels[playerIdx] > 0) {
                level = classicCpuLevels[playerIdx];
            } else {
                level = getClassicCpuLevel();
            }
        } else if (playerIdx >= 0 && playerIdx < cpuLevels.length) {
            level = cpuLevels[playerIdx];
        }
        level = adjustedBossCpuLevel(playerIdx, level);
        if (level < 1) level = 1;
        if (level > 9) level = 9;
        return level;
    }

    private int getClassicCpuLevel() {
        if (classicEncounter != null && classicEncounter.cpuLevel > 0) {
            int lockedLevel = classicEncounter.cpuLevel;
            if (lockedLevel > 9) lockedLevel = 9;
            return lockedLevel;
        }
        int total = classicRun.size();
        if (total <= 1) return 5;
        int maxIndex = Math.max(1, total - 1);
        int level = 1 + (int) Math.round(8.0 * classicRoundIndex / maxIndex);
        if (level < 1) level = 1;
        if (level > 9) level = 9;
        return level;
    }

    public int getEffectiveTeam(int playerIdx) {
        if (playerIdx < 0 || playerIdx >= players.length) return -1;
        if (classicModeActive) {
            if (!classicTeamMode) return playerIdx;
            return classicTeams[playerIdx] <= 0 ? 1 : classicTeams[playerIdx];
        }
        if (storyModeActive) {
            if (storyTeamMode) {
                return storyTeams[playerIdx] <= 0 ? 1 : storyTeams[playerIdx];
            }
            return playerIdx;
        }
        if (adventureModeActive) {
            if (adventureTeamMode) {
                return adventureTeams[playerIdx] <= 0 ? 1 : adventureTeams[playerIdx];
            }
            return playerIdx;
        }
        if (!teamModeEnabled) return playerIdx;
        return playerTeams[playerIdx] == 2 ? 2 : 1;
    }

    public boolean areAllies(int playerA, int playerB) {
        if (playerA < 0 || playerA >= players.length || playerB < 0 || playerB >= players.length) return false;
        return getEffectiveTeam(playerA) == getEffectiveTeam(playerB);
    }

    public boolean canDamage(Bird attacker, Bird target) {
        if (attacker == null || target == null || attacker == target) return false;
        if (target.health <= 0) return false;
        if (target.isCombatInvulnerable()) return false;
        return !areAllies(attacker.playerIndex, target.playerIndex);
    }

    public void addToKillFeed(String message) {
        killFeed.addFirst(message);  // newest on top
        if (killFeed.size() > MAX_FEED_LINES) {
            killFeed.removeLast();
        }
    }

    public void triggerFlash(double whiteIntensity, boolean isKill) {
        flashAlpha = whiteIntensity;
        redFlashAlpha = isKill ? 0.0 : whiteIntensity * 0.55;
        flashTimer = isKill ? 22 : 14;

        if (isKill) {
            hitstopFrames = Math.max(hitstopFrames, 20);
            shakeIntensity = Math.max(shakeIntensity, 30);
        }
// Global cap to prevent freeze
        hitstopFrames = Math.min(hitstopFrames, 25);
    }

