    private void positionBattlefieldSpawns() {
        List<Bird> active = new ArrayList<>();
        for (Bird b : players) {
            if (b != null) active.add(b);
        }
        if (active.isEmpty()) return;

        if (selectedMap == MapType.DESERT) {
            double[] spawnCenters = buildSpawnCenters(active.size(), 360.0, WORLD_WIDTH - 360.0);
            for (int i = 0; i < active.size(); i++) {
                Bird b = active.get(i);
                double center = spawnCenters[Math.min(i, spawnCenters.length - 1)];
                double halfWidth = 40 * b.sizeMultiplier;
                double spawnY = desertSpawnYForCenter(center, b.sizeMultiplier);
                b.x = center - halfWidth;
                b.y = spawnY;
                b.vx = 0;
                b.vy = 0;
            }
            return;
        }

        if (selectedMap == MapType.DOCK) {
            double[] spawnCenters = buildSpawnCenters(active.size(), 1040.0, 4560.0);
            for (int i = 0; i < active.size(); i++) {
                Bird b = active.get(i);
                double center = spawnCenters[Math.min(i, spawnCenters.length - 1)];
                double halfWidth = 40 * b.sizeMultiplier;
                double spawnY = center < 2600 ? GROUND_Y - 220 * b.sizeMultiplier : GROUND_Y - 300 * b.sizeMultiplier;
                b.x = center - halfWidth;
                b.y = spawnY;
                b.vx = 0;
                b.vy = 0;
            }
            return;
        }

        if ((selectedMap != MapType.BATTLEFIELD && selectedMap != MapType.BEACON_CROWN)
                || battlefieldIslandW <= 0) {
            double[] spawnCenters = buildSpawnCenters(active.size(), 420.0, WORLD_WIDTH - 420.0);
            for (int i = 0; i < active.size(); i++) {
                Bird b = active.get(i);
                double center = spawnCenters[Math.min(i, spawnCenters.length - 1)];
                double halfWidth = 40 * b.sizeMultiplier;
                b.x = center - halfWidth;
                b.y = GROUND_Y - 80 * b.sizeMultiplier;
                b.vx = 0;
                b.vy = 0;
            }
            return;
        }

        double margin = Math.clamp(battlefieldIslandW * 0.15, 120.0, 220.0);
        double[] spawnCenters = buildSpawnCenters(active.size(),
                battlefieldIslandX + margin,
                battlefieldIslandX + battlefieldIslandW - margin);

        for (int i = 0; i < active.size(); i++) {
            Bird b = active.get(i);
            double center = spawnCenters[Math.min(i, spawnCenters.length - 1)];
            double halfWidth = 40 * b.sizeMultiplier;
            b.x = center - halfWidth;
            b.y = battlefieldIslandY - 80 * b.sizeMultiplier;
            b.vx = 0;
            b.vy = 0;
        }
    }

    private double[] buildSpawnCenters(int count, double left, double right) {
        if (count <= 0) {
            return new double[0];
        }
        if (count == 1) {
            return new double[]{(left + right) / 2.0};
        }
        double[] centers = new double[count];
        double span = Math.max(0.0, right - left);
        double inset = Math.clamp(span * 0.34, 140.0, span * 0.45);
        double innerLeft = left + inset;
        double innerRight = right - inset;
        double usableSpan = Math.max(0.0, innerRight - innerLeft);
        double spacing = usableSpan / Math.max(1, count - 1);
        for (int i = 0; i < count; i++) {
            centers[i] = innerLeft + spacing * i;
        }
        return centers;
    }

    private double desertSpawnYForCenter(double center, double sizeMultiplier) {
        double bodyHeight = 80 * sizeMultiplier;
        if (center >= DESERT_CLIFF_SUMMIT_X) {
            return DESERT_CLIFF_SUMMIT_Y - bodyHeight;
        }
        if (center >= DESERT_CLIFF_HIGH_X) {
            return DESERT_CLIFF_HIGH_Y - bodyHeight;
        }
        if (center >= DESERT_CLIFF_TOP_X) {
            return DESERT_CLIFF_TOP_Y - bodyHeight;
        }
        if (center >= DESERT_CLIFF_MID_X) {
            return DESERT_CLIFF_MID_Y - bodyHeight;
        }
        if (center >= DESERT_CLIFF_LOW_X) {
            return DESERT_CLIFF_LOW_Y - bodyHeight;
        }
        return GROUND_Y - bodyHeight;
    }

    double battlefieldSpawnCenterX() {
        if (selectedMap == MapType.DOCK) {
            return 1760;
        }
        if (battlefieldIslandW > 0) {
            return battlefieldIslandX + battlefieldIslandW / 2.0;
        }
        return WORLD_WIDTH / 2.0;
    }

    double battlefieldSpawnY(double sizeMultiplier) {
        if (selectedMap == MapType.DOCK) {
            return GROUND_Y - 220 * sizeMultiplier;
        }
        if (battlefieldIslandW > 0) {
            return battlefieldIslandY - 80 * sizeMultiplier;
        }
        return GROUND_Y - 300;
    }

    double battlefieldVoidFloorY() {
        if (battlefieldIslandW > 0) {
            return battlefieldIslandY + 120.0;
        }
        return GROUND_Y;
    }

    private double battlefieldBoundsMargin() {
        return Math.max(500, battlefieldIslandW * 0.7);
    }

    double battlefieldLeftBound() {
        if (battlefieldIslandW > 0) {
            return battlefieldIslandX - battlefieldBoundsMargin();
        }
        return 0;
    }

    double battlefieldRightBound() {
        if (battlefieldIslandW > 0) {
            return battlefieldIslandX + battlefieldIslandW + battlefieldBoundsMargin();
        }
        return WORLD_WIDTH;
    }

    boolean isDockWaterActive() {
        return (selectedMap == MapType.DOCK || selectedMap == MapType.DESERT) && dockWaterW > 0 && dockWaterH > 0;
    }

    boolean isDockWaterAt(double worldX, double worldY) {
        return isDockWaterActive()
                && worldX >= dockWaterX
                && worldX <= dockWaterX + dockWaterW
                && worldY >= dockWaterY
                && worldY <= dockWaterY + dockWaterH;
    }

    double dockWaterSurfaceY() {
        return dockWaterY;
    }

    double dockWaterStartX() {
        return dockWaterX;
    }

    double dockWaterWidth() {
        return dockWaterW;
    }

    double dockDrownDepthY() {
        return dockDrownY > 0 ? dockDrownY : WORLD_HEIGHT + 1;
    }

    double dockWaterMidY() {
        return dockWaterY + Math.min(220.0, dockWaterH * 0.42);
    }

    private boolean isDockSkiffPlatform(Platform p) {
        if (p == null || selectedMap != MapType.DOCK) return false;
        double centerX = p.x + p.w / 2.0;
        return centerX >= dockWaterX - 40
                && centerX <= dockWaterX + 1100
                && p.y >= dockWaterY - 48
                && p.y <= dockWaterY + 18
                && p.w <= 320
                && p.h <= 28;
    }

    private double dockShipVisualX() {
        return WORLD_WIDTH * 0.5 - 448.0 * DOCK_SHIP_SCALE;
    }

    private double dockShipVisualY() {
        return dockWaterSurfaceY() - 360.0;
    }

    private double dockShipCannonMuzzleX() {
        return dockShipVisualX() + 120.0 * DOCK_SHIP_SCALE;
    }

    private double dockShipCannonMuzzleY() {
        return dockShipVisualY() + 146.0 * DOCK_SHIP_SCALE;
    }

    private double dockBombTargetX(Bird target) {
        if (target == null) {
            return Math.clamp(battlefieldSpawnCenterX(), 120.0, WORLD_WIDTH - 120.0);
        }
        return Math.clamp(target.x + 40 * target.sizeMultiplier, 120.0, WORLD_WIDTH - 120.0);
    }

    private double dockBombTargetY(Bird target) {
        if (target == null) {
            return Math.clamp(GROUND_Y - 80.0, 120.0, dockDrownDepthY() - 90.0);
        }
        return Math.clamp(target.y + 40 * target.sizeMultiplier, 120.0, dockDrownDepthY() - 90.0);
    }

