    void startMatch(Stage stage) {
        prepareMatchStart(stage);
        boolean[] menuAI = Arrays.copyOf(isAI, isAI.length);
        Arrays.fill(players, null);
        Arrays.fill(isAI, false);
        StoryChapter storyChapter = null;
        AdventureBattle adventureBattle = null;
        ClassicEncounter classicRound = null;
        if (dailyChallengeModeActive && classicModeActive) {
            if (classicRun.isEmpty()) {
                DailyChallengePlan plan = buildDailyChallengePlan(classicSelectedBird);
                dailyChallengeRunKey = plan.key();
                dailyChallengeSeed = plan.seed();
                classicRunCodename = plan.codename();
                classicSelectedBird = plan.birdType();
                classicRun.addAll(plan.encounters());
                classicRoundIndex = 0;
            }
            long roundSeed = dailyChallengeSeed ^ ((long) (classicRoundIndex + 1) * 0x94D049BB133111EBL);
            random.setSeed(roundSeed);
            renderRandom.setSeed(roundSeed ^ 0x369DEA0F31A53F85L);
        }
        if (trainingModeActive) {
            resetTrainingLabState();
            setupTrainingRoster();
        } else if (classicModeActive) {
            if (classicRun.isEmpty()) {
                classicRun.addAll(buildClassicRun(classicSelectedBird));
                classicRoundIndex = 0;
            }
            if (classicRoundIndex < 0 || classicRoundIndex >= classicRun.size()) {
                classicRoundIndex = 0;
            }
            classicRound = classicRun.get(classicRoundIndex);
            classicEncounter = classicRound;
            setupClassicEncounterRoster(classicRound);
        } else if (storyModeActive) {
            StoryChapter[] chapters = activeStoryChapters();
            if (storyChapterIndex < 0 || storyChapterIndex >= chapters.length) {
                storyChapterIndex = 0;
            }
            storyChapter = chapters[storyChapterIndex];
            setupStoryChapterRoster(storyChapter);
        } else if (adventureModeActive) {
            adventureBattle = currentAdventureBattle != null ? currentAdventureBattle : activeAdventureBattle();
            setupAdventureBattleRoster(adventureBattle);
        } else {
            List<BirdType> pool = unlockedBirdPool();
            int slots = lanModeActive ? LAN_MAX_PLAYERS : activePlayers;
            for (int i = 0; i < slots; i++) {
                if (lanModeActive && !lanSlotConnected[i]) {
                    players[i] = null;
                    isAI[i] = false;
                    continue;
                }
                BirdType type = lanModeActive ? lanSelectedBirds[i] : fightSelectedBirds[i];
                boolean randomPick = lanModeActive ? lanRandomBirds[i] : fightRandomSelected[i];
                if (type == null || (lanModeActive && randomPick) || (!lanModeActive && (randomPick || !isBirdUnlocked(type)))) {
                    type = pool.get(random.nextInt(pool.size()));
                    if (lanModeActive) {
                        lanSelectedBirds[i] = type;
                        lanRandomBirds[i] = false;
                    }
                }
                double startX = 300 + i * (WIDTH - 600) / (double) Math.max(1, slots - 1);
                isAI[i] = !lanModeActive && menuAI[i];
                players[i] = new Bird(startX, type, i, this);
                if (lanModeActive) {
                    String skinKey = randomPick ? randomAdventureSkinChoice(type) : lanSelectedSkinKeys[i];
                    applyPreviewSkinChoiceToBird(players[i], type, skinKey);
                } else {
                    String skinKey = randomPick ? randomAdventureSkinChoice(type) : fightSelectedSkinKeys[i];
                    skinKey = normalizeAdventureSkinChoice(type, skinKey);
                    fightSelectedSkinKeys[i] = skinKey;
                    applySkinChoiceToBird(players[i], type, skinKey);
                }

                applyAdaptiveBalance(players[i]);
            }
        }

        smashCombatRulesActive = !trainingModeActive && !storyModeActive && !adventureModeActive && !classicModeActive;
        if (smashCombatRulesActive) {
            Arrays.fill(scores, 0);
            for (int i = 0; i < activePlayers; i++) {
                if (players[i] != null) {
                    scores[i] = smashStartingStocks();
                }
            }
        }

        if (tournamentModeActive) {
            applyTournamentSlotNames();
        }

        platforms.clear();
        windVents.clear();
        nectarNodes.clear();
        swingingVines.clear();
        crowMinions.clear();
        piranhaHazards.clear();
        chickMinions.clear();
        particles.clear();
        powerUps.clear();
        dockWaterX = 0;
        dockWaterY = 0;
        dockWaterW = 0;
        dockWaterH = 0;
        dockDrownY = 0;
        dockLeverX = 0;
        dockLeverY = 0;
        dockLeverCooldown = 0;
        dockShipBomb = null;
        Arrays.fill(dockLeverHeld, false);

        if (selectedMap != MapType.CITY || lanModeActive) cityStars.clear();

        Random mapRandom = lanModeActive ? new Random(lanMatchSeed) : random;

        if (selectedMap == MapType.CITY && cityStars.isEmpty()) {
            for (int i = 0; i < 250; i++) {
                cityStars.add(new double[]{
                        mapRandom.nextDouble() * WORLD_WIDTH,
                        mapRandom.nextDouble() * (GROUND_Y - 200)
                });
            }
        }

// Common elements for both void-island maps
        if (selectedMap == MapType.BATTLEFIELD) {
            double islandW = 1200;
            double islandH = 70;
            double islandX = (WORLD_WIDTH - islandW) / 2.0;
            double islandY = GROUND_Y - 80;
            platforms.add(new Platform(islandX, islandY, islandW, islandH));
            platforms.add(new Platform(islandX + 120, islandY - 260, 360, 45));
            platforms.add(new Platform(islandX + islandW - 480, islandY - 260, 360, 45));
            platforms.add(new Platform(islandX + (islandW - 420) / 2.0, islandY - 420, 420, 45));
            battlefieldIslandX = islandX;
            battlefieldIslandW = islandW;
            battlefieldIslandY = islandY;
        } else if (selectedMap == MapType.BEACON_CROWN) {
            setupBeaconCrownBattlefield();
        } else if (selectedMap == MapType.DOCK) {
            setupDockArena();
        } else if (selectedMap == MapType.DESERT) {
            setupDesertArena();
        } else {
            platforms.add(new Platform(0, GROUND_Y, WORLD_WIDTH, 600)); // thick floor
            platforms.add(new Platform(-100, 0, 100, WORLD_HEIGHT)); // left wall
            platforms.add(new Platform(WORLD_WIDTH, 0, 100, WORLD_HEIGHT)); // right wall
            battlefieldIslandX = 0;
            battlefieldIslandW = 0;
            battlefieldIslandY = 0;
        }

        if (selectedMap == MapType.FOREST) {
            // === ORIGINAL FOREST PLATFORMS (unchanged) ===
            double[] treeX = {800, 2100, 3400, 4800, 5600};
            for (double tx : treeX) {
                platforms.add(new Platform(tx - 200, GROUND_Y - 800, 400, 30));
                platforms.add(new Platform(tx - 150, GROUND_Y - 500, 300, 30));
                platforms.add(new Platform(tx - 100, GROUND_Y - 200, 200, 30));
            }
            for (int i = 0; i < 25; i++) {
                double px = 300 + mapRandom.nextDouble() * (WORLD_WIDTH - 600);
                double py = 800 + mapRandom.nextDouble() * (GROUND_Y - 1000);
                double pw = 200 + mapRandom.nextDouble() * 400;
                platforms.add(new Platform(px, py, pw, 30));
            }
        } else if (selectedMap == MapType.SKYCLIFFS) {
            // === SKY CLIFFS PLATFORMS - More accessible with stepping stones ===
            double[] cliffX = {600, 1600, 2600, 3600, 4600, 5400};

            // Main large ledges (keep for epic fights)
            for (double cx : cliffX) {
                platforms.add(new Platform(cx - 400, GROUND_Y - 600, 800, 60));  // main wide
                platforms.add(new Platform(cx - 200, GROUND_Y - 1000, 400, 50)); // higher
                platforms.add(new Platform(cx - 100, GROUND_Y - 1400, 200, 40)); // small high
            }

            // NEW: Stepping stone chains from ground to highs (spaced for short jumps)
            // Left side chain
            platforms.add(new Platform(800, GROUND_Y - 200, 400, 50));
            platforms.add(new Platform(700, GROUND_Y - 450, 350, 50));
            platforms.add(new Platform(900, GROUND_Y - 700, 400, 50));
            platforms.add(new Platform(750, GROUND_Y - 950, 300, 50));

            // Central chain
            platforms.add(new Platform(2200, GROUND_Y - 180, 500, 50));
            platforms.add(new Platform(2100, GROUND_Y - 420, 450, 50));
            platforms.add(new Platform(2300, GROUND_Y - 660, 500, 50));
            platforms.add(new Platform(2200, GROUND_Y - 900, 400, 50));
            platforms.add(new Platform(2150, GROUND_Y - 1150, 350, 50));

            // Right side chain
            platforms.add(new Platform(4200, GROUND_Y - 220, 450, 50));
            platforms.add(new Platform(4100, GROUND_Y - 480, 400, 50));
            platforms.add(new Platform(4300, GROUND_Y - 740, 450, 50));
            platforms.add(new Platform(4200, GROUND_Y - 1000, 350, 50));

            // Extra mid-level connectors
            platforms.add(new Platform(1000, GROUND_Y - 800, 500, 50));
            platforms.add(new Platform(3000, GROUND_Y - 900, 600, 50));
            platforms.add(new Platform(5000, GROUND_Y - 700, 500, 50));

            // Wind vents (thermal updrafts) - keep + add a few low ones for early boosts
            for (double cx : cliffX) {
                windVents.add(new WindVent(cx - 300, GROUND_Y - 600, 600));
                windVents.add(new WindVent(cx - 150, GROUND_Y - 1000, 300));
            }
            // Low vents for short jumpers
            windVents.add(new WindVent(700, GROUND_Y - 250, 400));
            windVents.add(new WindVent(2100, GROUND_Y - 230, 500));
            windVents.add(new WindVent(4100, GROUND_Y - 270, 450));

            // Fixed mountain peaks
            mountainPeaks = new double[MOUNTAIN_X.length - 1];
            for (int i = 0; i < mountainPeaks.length; i++) {
                mountainPeaks[i] = GROUND_Y - 400 - mapRandom.nextDouble() * 600;
            }
        } else if (selectedMap == MapType.VIBRANT_JUNGLE) {
            setupVibrantJungleArena(mapRandom);
        } else if (selectedMap == MapType.CAVE) {
            // Hard cave ceiling to support bat hanging and vertical combat lanes.
            platforms.add(new Platform(0, 0, WORLD_WIDTH, 70));

            // Main cavern shelves
            platforms.add(new Platform(500, GROUND_Y - 420, 900, 55));
            platforms.add(new Platform(1850, GROUND_Y - 620, 760, 55));
            platforms.add(new Platform(3000, GROUND_Y - 500, 920, 55));
            platforms.add(new Platform(4350, GROUND_Y - 700, 760, 55));
            platforms.add(new Platform(5200, GROUND_Y - 430, 620, 55));

            // Stalactite hangs (underside-friendly narrow ledges)
            double[] stalactiteX = {650, 1300, 2050, 2800, 3550, 4300, 5050, 5650};
            for (double sx : stalactiteX) {
                platforms.add(new Platform(sx - 140, 240 + mapRandom.nextDouble() * 300, 280, 34));
            }

            // Midair crystal bridges
            for (int i = 0; i < 12; i++) {
                double px = 260 + i * 470 + mapRandom.nextDouble() * 120;
                double py = 500 + mapRandom.nextDouble() * (GROUND_Y - 900);
                platforms.add(new Platform(px, py, 220 + mapRandom.nextDouble() * 180, 30));
            }

            // Vertical shafts with updraft pockets
            double[] ventX = {950, 2400, 3900, 5400};
            for (double vx : ventX) {
                windVents.add(new WindVent(vx - 180, GROUND_Y - 820, 360));
                windVents.add(new WindVent(vx - 130, GROUND_Y - 1450, 260));
            }

            mountainPeaks = new double[MOUNTAIN_X.length - 1];
            for (int i = 0; i < mountainPeaks.length; i++) {
                mountainPeaks[i] = GROUND_Y - 1000 - mapRandom.nextDouble() * 800;
            }
        } else if (selectedMap == MapType.BATTLEFIELD
                || selectedMap == MapType.BEACON_CROWN
                || selectedMap == MapType.DOCK
                || selectedMap == MapType.DESERT) {
            mountainPeaks = null;
        } else { // CITY - Clean, structured nighttime rooftops
            // Main building rooftops (wide, aligned platforms)
            double[] buildingX = {400, 1400, 2400, 3400, 4400, 5400};
            for (double bx : buildingX) {
                platforms.add(new Platform(bx - 350, GROUND_Y - 320, 700, 50));
                platforms.add(new Platform(bx - 200, GROUND_Y - 120, 400, 40));

                Platform high1 = new Platform(bx - 150, GROUND_Y - 720, 300, 40);
                Platform high2 = new Platform(bx + 50, GROUND_Y - 1020, 200, 40);

                String[] possibleSigns = {"CLUB", "BAR", "HOTEL", "EAT", "LIVE", "24/7", "OPEN", "PIZZA", "DIVE", "LOUNGE"};
                high1.signText = possibleSigns[mapRandom.nextInt(possibleSigns.length)];
                high2.signText = possibleSigns[mapRandom.nextInt(possibleSigns.length)];

                platforms.add(high1);
                platforms.add(high2);

                // Wind vents (unchanged)
                windVents.add(new WindVent(bx - 350 + 100, GROUND_Y - 320, 500));
                windVents.add(new WindVent(bx - 350 + 500, GROUND_Y - 320, 100));
            }

            // Smaller connecting platforms between buildings
            platforms.add(new Platform(800, GROUND_Y - 450, 400, 40));
            platforms.add(new Platform(1800, GROUND_Y - 600, 400, 40));
            platforms.add(new Platform(2800, GROUND_Y - 400, 400, 40));
            platforms.add(new Platform(3800, GROUND_Y - 550, 400, 40));
            platforms.add(new Platform(4800, GROUND_Y - 480, 400, 40));

            // A few lower street-level platforms
            platforms.add(new Platform(1000, GROUND_Y - 100, 600, 40));
            platforms.add(new Platform(3000, GROUND_Y - 150, 500, 40));
            platforms.add(new Platform(4500, GROUND_Y - 80, 400, 40));

            // NO random floating pillars/antennas - removed completely

            // Rooftop vents already added in the building loop above.
        }

        if (storyModeActive && storyChapter != null) {
            applyStoryChapterArenaModifiers();
            if (storyMatchTimerOverride > 0) {
                matchTimer = storyMatchTimerOverride;
            }
        }
        if (adventureModeActive && adventureBattle != null) {
            applyAdventureBattleArenaModifiers(adventureBattle);
            if (adventureMatchTimerOverride > 0) {
                matchTimer = adventureMatchTimerOverride;
            }
        }
        if (classicModeActive && classicRound != null) {
            applyClassicEncounterArenaModifiers(classicRound);
            if (classicRound.timerFrames > 0) {
                matchTimer = classicRound.timerFrames;
            }
        }
        configureMatchModes();
        positionBattlefieldSpawns();
        if (trainingModeActive) {
            captureTrainingSpawns();
        }
        resetFightHudStateForMatchStart();

        Canvas canvas = new Canvas(WIDTH, HEIGHT);
        GraphicsContext g = canvas.getGraphicsContext2D();
        StackPane root = new StackPane(canvas);
        gameRoot = root;
        root.setStyle(selectedMap == MapType.DOCK
                ? "-fx-background-color: linear-gradient(to bottom, #0F3047 0%, #1E5D78 55%, #0A171F 100%);"
                : selectedMap == MapType.DESERT
                ? "-fx-background-color: linear-gradient(to bottom, #F3A85A 0%, #F7D28B 48%, #D59A52 100%);"
                : (selectedMap == MapType.FOREST || selectedMap == MapType.BATTLEFIELD)
                ? "-fx-background-color: linear-gradient(to bottom, #87CEEB 0%, #B3E5FC 50%, #E0F2F1 100%);"
                : "-fx-background-color: #000011;");
        Scene scene = new Scene(root, WIDTH, HEIGHT);
        gameplayScene = scene;
        makeSceneResponsive(scene);
        uiCanvas = new Canvas(WIDTH, HEIGHT);
        ui = uiCanvas.getGraphicsContext2D();
        root.getChildren().add(uiCanvas);

        pressedKeys.clear();
        scene.setOnKeyPressed(e -> handleGameplayKeyPress(stage, e));
        scene.setOnKeyReleased(this::handleGameplayKeyRelease);

        if (timer != null) timer.stop();
        lastUpdate = 0;
        accumulator = 0;
        resetRenderTimer();

        timer = new AnimationTimer() {
            @Override
            public void handle(long now) {
                gameTick();
                if (lanModeActive && lanIsHost) {
                    boolean hasClients = lanHost != null && lanHost.hasClients();
                    if (hasClients && now - lastLanSnapshotNs >= LAN_SNAPSHOT_INTERVAL_NS) {
                        if (lanHost != null) {
                            lanHost.broadcastState(buildLanState());
                        }
                        lastLanSnapshotNs = now;
                    }
                }
                if (!shouldRenderFrame(now)) {
                    return;
                }
                FightHudLayout hudLayout = buildFightHudLayout();
                currentFightHudOcclusionRects = hudLayout.occlusionRects();
                drawGame(g);

                ui.clearRect(0, 0, WIDTH, HEIGHT);
                drawFightHud(ui, hudLayout);
                if (trainingModeActive) {
                    drawTrainingLabHud(ui);
                }
                drawDebugBalanceHud(ui);
                drawFightFlashOverlay(ui);
            }
        };

        timer.start();
        setScenePreservingFullscreen(stage, scene);
        startMusic();
        canvas.requestFocus();

        zoom = 0.6;
        camX = 1000;
        camY = 800;
        syncTrackedCameraToCurrentView();
    }

    private void drawUnitedFinaleRaidHud(GraphicsContext g) {
        Bird player = players[0];
        Bird boss = unitedFinaleBoss();
        if (player != null && player.health > 0) {
            drawHealthBar(g, player, 24);
        }
        if (boss != null) {
            drawHealthBar(g, boss, WIDTH - 424);
        }

        int livingAllies = 0;
        int totalAllies = 0;
        for (Bird b : players) {
            if (b == null || b.playerIndex == 0) continue;
            if (getEffectiveTeam(b.playerIndex) != 1) continue;
            totalAllies++;
            if (b.health > 0) livingAllies++;
        }

        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.72));
        g.fillRoundRect(WIDTH / 2.0 - 250, (double) 82 - 4, 500, 62, 18, 18);
        g.setStroke(Color.web("#FFF59D"));
        g.setLineWidth(2);
        g.strokeRoundRect(WIDTH / 2.0 - 250, (double) 82 - 4, 500, 62, 18, 18);
        g.setFill(Color.web("#FFF9C4"));
        g.setFont(HUD_CLASSIC_TITLE_FONT);
        g.fillText("ALL WINGS ENGAGED", WIDTH / 2.0 - 150, (double) 82 + 22);
        g.setFill(Color.web("#B3E5FC"));
        g.setFont(HUD_CLASSIC_RULES_FONT);
        g.fillText("ALLIES AIRBORNE: " + livingAllies + "/" + totalAllies, WIDTH / 2.0 - 145, (double) 82 + 48);
    }

    private void drawTrainingLabHud(GraphicsContext g) {
        double panelX = 28;
        double panelY = 250;
        double panelW = 440;
        double panelH = 250;

        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.74));
        g.fillRoundRect(panelX, panelY, panelW, panelH, 24, 24);
        g.setStroke(Color.web("#80DEEA"));
        g.setLineWidth(2);
        g.strokeRoundRect(panelX, panelY, panelW, panelH, 24, 24);

        g.setFill(Color.web("#B2EBF2"));
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 24));
        g.fillText("TRAINING LAB", panelX + 18, panelY + 32);

        g.setFill(Color.WHITE);
        g.setFont(Font.font("Consolas", 18));
        double rowY = panelY + 66;
        double rowGap = 26;
        String comboText = trainingComboHits > 0
                ? trainingComboHits + " hits  |  " + (int) Math.round(trainingComboDamage) + " dmg"
                : "No active combo";
        g.fillText("Combo: " + comboText, panelX + 18, rowY);
        rowY += rowGap;
        g.fillText(String.format(Locale.ROOT, "DPS: %.1f", trainingComboDps()), panelX + 18, rowY);
        rowY += rowGap;
        g.fillText(String.format(Locale.ROOT, "Last Hit: %.1f", trainingLastHitDamage), panelX + 18, rowY);
        rowY += rowGap;
        g.fillText(String.format(Locale.ROOT, "Session Damage: %.1f", trainingSessionDamage), panelX + 18, rowY);
        rowY += rowGap;
        g.fillText("Dummy: " + trainingDummyBehavior.label, panelX + 18, rowY);
        rowY += rowGap;
        g.fillText("Boxes: " + (trainingCombatOverlayEnabled ? "ON" : "OFF")
                        + "  |  Slomo: " + (trainingSlowMotionEnabled ? "ON" : "OFF"),
                panelX + 18, rowY);
        rowY += rowGap;
        g.fillText("Freeze: " + (trainingFrameAdvancePause ? "ON" : "OFF"), panelX + 18, rowY);

        g.setFill(Color.web("#FFE082"));
        g.setFont(Font.font("Consolas", 16));
        double tipsY = panelY + panelH - 76;
        g.fillText("F4 Dummy  F5 Reset  F6 Refill", panelX + 18, tipsY);
        g.fillText("F7 Boxes  F8 Slomo  F9 Freeze  F10 Step", panelX + 18, tipsY + 24);

        if (trainingAcademyMode != TrainingAcademyMode.NONE) {
            drawTrainingAcademyHud(g);
        }
    }

    private void drawTrainingAcademyHud(GraphicsContext g) {
        double panelW = 500;
        double panelH = 278;
        double panelX = WIDTH - panelW - 28;
        double panelY = 250;

        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.78));
        g.fillRoundRect(panelX, panelY, panelW, panelH, 24, 24);
        g.setStroke(Color.web("#FFF176"));
        g.setLineWidth(2);
        g.strokeRoundRect(panelX, panelY, panelW, panelH, 24, 24);

        Font headerFont = Font.font("Consolas", FontWeight.BOLD, 21);
        Font titleFont = Font.font("Arial Black", 26);
        Font bodyFont = Font.font("Consolas", 18);
        Font hintFont = Font.font("Consolas", 16);
        double textX = panelX + 18;
        double maxWidth = panelW - 36;

        g.setFill(Color.web("#FFF59D"));
        g.setFont(headerFont);
        g.fillText(trainingAcademyHeaderText(), textX, panelY + 30);

        g.setFill(Color.WHITE);
        g.setFont(titleFont);
        g.fillText(trainingAcademyTitleText(), textX, panelY + 64);

        double rowY = panelY + 96;
        g.setFill(Color.web("#B2EBF2"));
        g.setFont(bodyFont);
        for (String line : wrapTextToLines("Objective: " + trainingAcademyObjectiveText(), bodyFont, maxWidth)) {
            g.fillText(line, textX, rowY);
            rowY += 24;
        }

        rowY += 6;
        g.setFill(Color.web("#CFD8DC"));
        g.setFont(hintFont);
        for (String line : wrapTextToLines("Hint: " + trainingAcademyHintText(), hintFont, maxWidth)) {
            g.fillText(line, textX, rowY);
            rowY += 20;
        }

        rowY += 8;
        g.setFill(trainingAcademyCompletionFrames > 0 ? Color.web("#C5E1A5") : Color.web("#FFE082"));
        g.setFont(bodyFont);
        for (String line : wrapTextToLines("Status: " + trainingAcademyStatusText(), bodyFont, maxWidth)) {
            g.fillText(line, textX, rowY);
            rowY += 24;
        }
    }

    private String trainingAcademyHeaderText() {
        if (trainingAcademyMode == TrainingAcademyMode.GUIDED_TUTORIAL) {
            GuidedTutorialLesson lesson = currentGuidedTutorialLesson();
            return "GUIDED TUTORIAL  " + (lesson.ordinal() + 1) + " / " + GuidedTutorialLesson.values().length;
        }
        BirdTrialDefinition trial = currentBirdTrialDefinition();
        return trial == null ? "BIRD TRIAL" : "BIRD TRIAL  " + (isBirdTrialCompleted(trial.playerBird) ? "COMPLETED" : "ACTIVE");
    }

    private String trainingAcademyTitleText() {
        if (trainingAcademyMode == TrainingAcademyMode.GUIDED_TUTORIAL) {
            return currentGuidedTutorialLesson().title;
        }
        BirdTrialDefinition trial = currentBirdTrialDefinition();
        return trial == null ? "Bird Trial" : trial.title;
    }

    private String trainingAcademyObjectiveText() {
        if (trainingAcademyMode == TrainingAcademyMode.GUIDED_TUTORIAL) {
            return currentGuidedTutorialLesson().objective;
        }
        BirdTrialDefinition trial = currentBirdTrialDefinition();
        return trial == null ? "" : trial.objective;
    }

    private String trainingAcademyHintText() {
        if (trainingAcademyMode == TrainingAcademyMode.GUIDED_TUTORIAL) {
            return currentGuidedTutorialLesson().hint;
        }
        BirdTrialDefinition trial = currentBirdTrialDefinition();
        return trial == null ? "" : trial.hint;
    }

    private String trainingAcademyStatusText() {
        if (trainingAcademyCompletionFrames > 0 && !trainingAcademyCompletionMessage.isBlank()) {
            return trainingAcademyCompletionMessage + ". Advancing...";
        }
        if (trainingAcademyMode == TrainingAcademyMode.GUIDED_TUTORIAL) {
            return switch (currentGuidedTutorialLesson()) {
                case MOVEMENT -> "Left: " + yesNoText(trainingAcademyMoveLeftSeen)
                        + "  Right: " + yesNoText(trainingAcademyMoveRightSeen)
                        + "  Jump: " + yesNoText(trainingAcademyJumpSeen);
                case RECOVERY -> "Returns: " + trainingAcademyRecoveriesCompleted + " / 1";
                case BLOCKING -> "Guard frames: "
                        + Math.min(trainingAcademyBlockFrames, TRAINING_ACADEMY_BLOCK_GOAL_FRAMES)
                        + " / " + TRAINING_ACADEMY_BLOCK_GOAL_FRAMES;
                case SPECIALS -> "Use your special once.";
                case EDGE_PLAY -> "Dummy offstage frames: " + Math.min(trainingAcademyDummyOffstageFrames, 12) + " / 12";
                case MAP_HAZARDS -> "Pull the lever with attack or special.";
            };
        }

        BirdTrialDefinition trial = currentBirdTrialDefinition();
        if (trial == null) {
            return "";
        }
        return switch (trial) {
            case PIGEON -> "Combo hits: " + Math.min(trainingComboHits, 3) + " / 3";
            case EAGLE -> trainingAcademyPunishReady
                    ? "Blocked. Use your special now."
                    : "Guard frames: "
                    + Math.min(trainingAcademyBlockFrames, TRAINING_ACADEMY_BLOCK_GOAL_FRAMES)
                    + " / " + TRAINING_ACADEMY_BLOCK_GOAL_FRAMES;
            case PENGUIN -> "Returns: " + trainingAcademyRecoveriesCompleted + " / 2";
        };
    }

    private String yesNoText(boolean value) {
        return value ? "OK" : "WAIT";
    }

    private record FightHudPanelLayout(Bird bird, Rectangle2D panelRect, Rectangle2D portraitRect) {}

    private record FightHudLayout(List<FightHudPanelLayout> panels, Rectangle2D minimapRect, Rectangle2D infoRect,
                                  List<String> infoLines, Rectangle2D timerRect, List<Rectangle2D> occlusionRects) {}

    private void resetFightHudStateForMatchStart() {
        fightHudPortraitCache.clear();
        currentFightHudOcclusionRects = List.of();
        currentRenderShakeX = 0.0;
        currentRenderShakeY = 0.0;
        matchIntroLastAnnouncedPhase = Integer.MIN_VALUE;
        if (trainingModeActive) {
            matchIntroOverlayFrames = 0;
            matchStartNano = System.nanoTime();
        } else {
            matchIntroOverlayFrames = MATCH_INTRO_COUNTDOWN_FRAMES + MATCH_INTRO_GO_FRAMES;
            matchStartNano = 0L;
        }
    }

    private void updateMatchIntroCountdown() {
        if (trainingModeActive) {
            matchIntroOverlayFrames = 0;
            if (matchStartNano == 0L) {
                matchStartNano = System.nanoTime();
            }
            matchIntroLastAnnouncedPhase = -1;
            return;
        }
        if (matchIntroOverlayFrames <= 0) {
            if (matchStartNano == 0L) {
                matchStartNano = System.nanoTime();
            }
            matchIntroLastAnnouncedPhase = -1;
            return;
        }
        matchIntroOverlayFrames--;
        if (matchIntroOverlayFrames == MATCH_INTRO_GO_FRAMES && matchStartNano == 0L) {
            matchStartNano = System.nanoTime();
        }
        maybePlayMatchIntroSfx();
    }

    private boolean isMatchIntroLocked() {
        return !trainingModeActive && matchIntroOverlayFrames > MATCH_INTRO_GO_FRAMES;
    }

    private boolean isMatchIntroVisible() {
        return !trainingModeActive && matchIntroOverlayFrames > 0;
    }

    private String currentMatchIntroLabel() {
        if (!isMatchIntroVisible()) {
            return null;
        }
        if (matchIntroOverlayFrames > MATCH_INTRO_GO_FRAMES) {
            int count = (int) Math.ceil((matchIntroOverlayFrames - MATCH_INTRO_GO_FRAMES) / 60.0);
            return Integer.toString(Math.max(1, count));
        }
        return "GO!";
    }

    private int currentMatchIntroAnnouncementPhase() {
        String label = currentMatchIntroLabel();
        if (label == null || label.isBlank()) {
            return -1;
        }
        return "GO!".equals(label) ? 0 : Integer.parseInt(label);
    }

    private void maybePlayMatchIntroSfx() {
        int phase = currentMatchIntroAnnouncementPhase();
        if (phase == matchIntroLastAnnouncedPhase) {
            return;
        }
        matchIntroLastAnnouncedPhase = phase;
        if (phase >= 1 && phase <= 3) {
            playMatchIntroCountSfx();
        } else if (phase == 0) {
            playMatchIntroGoSfx();
        }
    }

    private Rectangle2D fightHudCountdownRect() {
        String label = currentMatchIntroLabel();
        if (label == null || label.isBlank()) {
            return null;
        }
        boolean go = "GO!".equals(label);
        double plateWidth = go ? 560 : 340;
        double plateHeight = go ? 176 : 196;
        return new Rectangle2D(WIDTH / 2.0 - plateWidth / 2.0, 116, plateWidth, plateHeight);
    }

    private FightHudLayout buildFightHudLayout() {
        List<FightHudPanelLayout> panels = buildFightHudPanels();
        List<String> infoLines = fightHudInfoLines();
        Rectangle2D minimapRect = new Rectangle2D(24, 24, 190, 138);
        Rectangle2D infoRect = buildFightHudInfoRect(infoLines, minimapRect);
        Rectangle2D timerRect = new Rectangle2D(WIDTH - 274, 28, 240, 102);

        List<Rectangle2D> occlusionRects = new ArrayList<>();
        for (FightHudPanelLayout panel : panels) {
            occlusionRects.add(panel.panelRect());
        }
        occlusionRects.add(minimapRect);
        if (infoRect != null) {
            occlusionRects.add(infoRect);
        }
        occlusionRects.add(timerRect);
        Rectangle2D countdownRect = fightHudCountdownRect();
        if (countdownRect != null) {
            occlusionRects.add(countdownRect);
        }
        return new FightHudLayout(panels, minimapRect, infoRect, infoLines, timerRect, List.copyOf(occlusionRects));
    }

    private List<FightHudPanelLayout> buildFightHudPanels() {
        List<Bird> hudBirds = new ArrayList<>();
        for (int i = 0; i < activePlayers; i++) {
            if (players[i] != null) {
                hudBirds.add(players[i]);
            }
        }
        if (hudBirds.isEmpty() || hudBirds.size() > 6 || (isUnitedFinaleMassBattleContext() && activePlayers > 6)) {
            return List.of();
        }

        int count = hudBirds.size();
        double panelHeight = count >= 5 ? 126 : 146;
        double gap = count >= 5 ? 14 : 24;
        double panelWidth;
        List<Double> xPositions = new ArrayList<>();

        if (count == 1) {
            panelWidth = 460;
            xPositions.add((WIDTH - panelWidth) / 2.0);
        } else if (count == 2) {
            panelWidth = 430;
            xPositions.add(42.0);
            xPositions.add(WIDTH - 42.0 - panelWidth);
        } else {
            double minWidth = count >= 5 ? 250 : 285;
            double maxWidth = count >= 5 ? 300 : 360;
            panelWidth = Math.clamp((WIDTH - 120.0 - gap * (count - 1)) / count, minWidth, maxWidth);
            double totalWidth = panelWidth * count + gap * (count - 1);
            double startX = (WIDTH - totalWidth) / 2.0;
            for (int i = 0; i < count; i++) {
                xPositions.add(startX + i * (panelWidth + gap));
            }
        }

        double panelY = HEIGHT - panelHeight - 22;
        double portraitSize = count >= 5 ? 72 : 88;
        List<FightHudPanelLayout> layouts = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            double panelX = xPositions.get(i);
            Rectangle2D panelRect = new Rectangle2D(panelX, panelY, panelWidth, panelHeight);
            Rectangle2D portraitRect = new Rectangle2D(
                    panelX + 18,
                    panelY + Math.max(14, (panelHeight - portraitSize) / 2.0 - 4),
                    portraitSize,
                    portraitSize
            );
            layouts.add(new FightHudPanelLayout(hudBirds.get(i), panelRect, portraitRect));
        }
        return List.copyOf(layouts);
    }

    private Rectangle2D buildFightHudInfoRect(List<String> infoLines, Rectangle2D minimapRect) {
        if (infoLines == null || infoLines.isEmpty()) {
            return null;
        }
        double maxWidth = 0.0;
        for (String line : infoLines) {
            maxWidth = Math.max(maxWidth, measureTextWidth(line, FIGHT_HUD_STATUS_FONT));
        }
        double paddingX = 22;
        double paddingY = 16;
        double lineHeight = measureTextHeight(FIGHT_HUD_STATUS_FONT) * 1.16;
        double width = Math.clamp(maxWidth + paddingX * 2, 320.0, 780.0);
        double height = paddingY * 2 + lineHeight * infoLines.size();
        double y = minimapRect == null ? 28 : minimapRect.getMaxY() + 16;
        return new Rectangle2D(24, y, width, height);
    }

    private List<String> fightHudInfoLines() {
        List<String> lines = new ArrayList<>();
        if (classicModeActive && classicEncounter != null) {
            String classicModeLabel = dailyChallengeModeActive ? "DAILY" : "CLASSIC";
            lines.add(classicModeLabel + " " + (classicRoundIndex + 1) + "/" + classicRun.size()
                    + "  " + classicEncounter.name.toUpperCase(Locale.ROOT));
            lines.add("RULES  " + classicEncounter.mutator.label + " | " + classicEncounter.twist.label);
            int livesLeft = Math.max(0, 3 - classicDeaths);
            lines.add(dailyChallengeModeActive
                    ? "LIVES " + livesLeft + "/3  SEED " + formatDailyChallengeSeed(dailyChallengeSeed)
                    : "LIVES " + livesLeft + "/3  CONTINUES " + classicContinues);
            return lines;
        }

        if (competitionModeEnabled && !storyModeActive && !adventureModeActive && !classicModeActive) {
            lines.add("COMPETITION MODE");
            lines.add(competitionScoreLine());
        }

        if (activeMutator != MatchMutator.NONE && !competitionModeEnabled && !storyModeActive && !adventureModeActive && !classicModeActive) {
            lines.add("MUTATOR  " + activeMutator.label.toUpperCase(Locale.ROOT));
        }

        return lines;
    }

    private void drawFightHud(GraphicsContext g, FightHudLayout layout) {
        drawFightHudMinimap(g, layout.minimapRect());
        if (layout.infoRect() != null) {
            drawFightHudInfoBanner(g, layout.infoRect(), layout.infoLines());
        }
        drawFightHudTimer(g, layout.timerRect());
        if (isUnitedFinaleMassBattleContext() && activePlayers > 6) {
            drawUnitedFinaleRaidHud(g);
        } else {
            for (FightHudPanelLayout panel : layout.panels()) {
                drawFightHudPanel(g, panel);
            }
        }
        drawFightStartCountdown(g);
    }

    private void drawFightHudMinimap(GraphicsContext g, Rectangle2D rect) {
        if (rect == null) {
            return;
        }

        double mapX = rect.getMinX();
        double mapY = rect.getMinY();
        double mapW = rect.getWidth();
        double mapH = rect.getHeight();
        double innerPad = 10.0;
        double innerX = mapX + innerPad;
        double innerY = mapY + innerPad + 6.0;
        double innerW = mapW - innerPad * 2;
        double innerH = mapH - innerPad * 2 - 8.0;
        double scaleX = innerW / WORLD_WIDTH;
        double scaleY = innerH / WORLD_HEIGHT;

        double hudAlpha = hudAlphaForRect(rect);
        g.save();
        g.setGlobalAlpha(hudAlpha);
        g.setFill(Color.web("#050B11", 0.84));
        g.fillRoundRect(mapX, mapY, mapW, mapH, 24, 24);
        g.setFill(Color.web("#80DEEA", 0.16));
        g.fillRoundRect(mapX, mapY, mapW, 14, 24, 24);
        g.setStroke(Color.web("#90CAF9", 0.94));
        g.setLineWidth(2.2);
        g.strokeRoundRect(mapX, mapY, mapW, mapH, 24, 24);

        g.setFill(Color.web("#09141D", 0.92));
        g.fillRoundRect(innerX, innerY, innerW, innerH, 18, 18);
        g.setStroke(Color.web("#263238", 0.9));
        g.setLineWidth(1.2);
        g.strokeRoundRect(innerX, innerY, innerW, innerH, 18, 18);

        for (Bird b : players) {
            if (b != null && b.health > 0) {
                Color dot = fightHudAccentColor(b);
                g.setFill(dot);
                double mx = innerX + b.x * scaleX;
                double my = innerY + b.y * scaleY;
                g.fillOval(mx - 3.2, my - 3.2, 6.4, 6.4);
            }
        }

        double camViewW = (WIDTH / zoom) * scaleX;
        double camViewH = (HEIGHT / zoom) * scaleY;
        g.setStroke(Color.web("#FFF59D"));
        g.setLineWidth(2.0);
        g.strokeRoundRect(innerX + camX * scaleX, innerY + camY * scaleY, camViewW, camViewH, 8, 8);

        g.setFill(Color.web("#D7E3EA"));
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 14));
        g.fillText("MAP", mapX + 16, mapY + 22);
        g.restore();
    }

    private void drawFightHudInfoBanner(GraphicsContext g, Rectangle2D rect, List<String> infoLines) {
        if (rect == null || infoLines == null || infoLines.isEmpty()) {
            return;
        }
        Color accent = fightHudAccentColor(null);
        double hudAlpha = hudAlphaForRect(rect);
        g.save();
        g.setGlobalAlpha(hudAlpha);
        g.setFill(Color.web("#050B11", 0.82));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 24, 24);
        g.setFill(accent.deriveColor(0, 1, 1, 0.18));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), 14, 24, 24);
        g.setStroke(accent.deriveColor(0, 1, 1, 0.9));
        g.setLineWidth(2.2);
        g.strokeRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 24, 24);
        g.restore();

        double lineHeight = measureTextHeight(FIGHT_HUD_STATUS_FONT) * 1.16;
        double textX = rect.getMinX() + 22;
        double textY = rect.getMinY() + 18 + measureTextHeight(FIGHT_HUD_STATUS_FONT) * 0.82;
        g.setFill(Color.WHITE);
        g.setFont(FIGHT_HUD_STATUS_FONT);
        for (int i = 0; i < infoLines.size(); i++) {
            Color lineColor = i == 0 ? accent.brighter() : Color.web("#D7E3EA");
            g.setFill(lineColor);
            g.fillText(infoLines.get(i), textX, textY + i * lineHeight);
        }
    }

    private void drawFightHudTimer(GraphicsContext g, Rectangle2D rect) {
        boolean suddenDeathActive = suddenDeath.isActive();
        Color accent = trainingModeActive
                ? Color.web("#80DEEA")
                : suddenDeathActive
                ? Color.web("#FF7043")
                : matchTimer <= 600
                ? Color.web("#FFD54F")
                : Color.web("#8BC34A");

        double hudAlpha = hudAlphaForRect(rect);
        g.save();
        g.setGlobalAlpha(hudAlpha);
        g.setFill(Color.web("#050B11", 0.86));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 28, 28);
        g.setFill(accent.deriveColor(0, 1, 1, 0.18));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), 16, 28, 28);
        g.setStroke(accent.deriveColor(0, 1, 1, 0.94));
        g.setLineWidth(2.4);
        g.strokeRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 28, 28);

        double centerX = rect.getMinX() + rect.getWidth() / 2.0;
        g.setTextAlign(TextAlignment.CENTER);
        g.setFill(Color.web("#D7E3EA"));
        g.setFont(FIGHT_HUD_TIMER_LABEL_FONT);
        g.fillText(trainingModeActive ? "MODE" : "TIME", centerX, rect.getMinY() + 32);

        if (trainingModeActive) {
            g.setFill(accent);
            g.setFont(Font.font("Arial Black", FontWeight.BOLD, 34));
            g.fillText("TRAINING", centerX, rect.getMinY() + 78);
        } else if (suddenDeathActive) {
            g.setFill(Color.web("#FFE0B2"));
            g.setFont(Font.font("Arial Black", FontWeight.BOLD, 26));
            g.fillText("SUDDEN", centerX, rect.getMinY() + 62);
            g.fillText("DEATH", centerX, rect.getMinY() + 90);
        } else {
            g.setFill(Color.WHITE);
            g.setFont(FIGHT_HUD_TIMER_VALUE_FONT);
            g.fillText(formatFightHudTimer(Math.max(0, matchTimer)), centerX, rect.getMinY() + 84);
        }
        g.setTextAlign(TextAlignment.LEFT);
        g.restore();
    }

    private void drawFightHudPanel(GraphicsContext g, FightHudPanelLayout layout) {
        Bird bird = layout.bird();
        if (bird == null) {
            return;
        }

        Rectangle2D rect = layout.panelRect();
        Rectangle2D portraitRect = layout.portraitRect();
        Color accent = fightHudAccentColor(bird);
        double aliveAlpha = bird.health > 0 ? 1.0 : 0.68;
        double panelHudAlpha = hudAlphaForRect(rect);
        g.save();
        g.setGlobalAlpha(aliveAlpha * panelHudAlpha);

        g.setFill(Color.web("#000000", 0.34));
        g.fillRoundRect(rect.getMinX(), rect.getMinY() + 7, rect.getWidth(), rect.getHeight(), 30, 30);

        g.setFill(Color.web("#050B11", 0.88));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 30, 30);

        g.setFill(accent.deriveColor(0, 1, 1, 0.18));
        g.fillRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), 14, 30, 30);

        g.setFill(accent.deriveColor(0, 1, 1, 0.11));
        g.fillPolygon(
                new double[]{
                        rect.getMaxX() - 150, rect.getMaxX() - 30, rect.getMaxX() - 30, rect.getMaxX() - 220
                },
                new double[]{
                        rect.getMinY() + 24, rect.getMinY() + 24, rect.getMaxY() - 18, rect.getMaxY() - 18
                },
                4
        );

        g.setStroke(accent.deriveColor(0, 1, 1, 0.92));
        g.setLineWidth(2.2);
        g.strokeRoundRect(rect.getMinX(), rect.getMinY(), rect.getWidth(), rect.getHeight(), 30, 30);

        g.setFill(Color.web("#02060A", 0.96));
        g.fillRoundRect(portraitRect.getMinX(), portraitRect.getMinY(), portraitRect.getWidth(), portraitRect.getHeight(), 22, 22);
        g.setStroke(accent.deriveColor(0, 1, 1, 0.9));
        g.setLineWidth(1.9);
        g.strokeRoundRect(portraitRect.getMinX(), portraitRect.getMinY(), portraitRect.getWidth(), portraitRect.getHeight(), 22, 22);

        WritableImage portrait = fightHudPortraitImage(bird);
        if (portrait != null) {
            g.drawImage(
                    portrait,
                    portraitRect.getMinX() + 6,
                    portraitRect.getMinY() + 6,
                    portraitRect.getWidth() - 12,
                    portraitRect.getHeight() - 12
            );
        }

        String slotLabel = bird.playerIndex >= 0 ? "P" + (bird.playerIndex + 1) : "CPU";
        g.setFill(accent);
        g.fillRoundRect(rect.getMinX() + 14, rect.getMinY() + 10, 50, 24, 14, 14);
        g.setFill(Color.web("#041015"));
        g.setFont(Font.font("Arial Black", FontWeight.BOLD, 15));
        g.fillText(slotLabel, rect.getMinX() + 24, rect.getMinY() + 28);

        String name = shortName(bird.name);
        if (name.isBlank()) {
            name = bird.type != null ? bird.type.name.toUpperCase(Locale.ROOT) : "PLAYER";
        }
        Font nameFont = fitFightHudNameFont(name.toUpperCase(Locale.ROOT), rect.getWidth() - portraitRect.getWidth() - 120);
        double healthBarX = portraitRect.getMaxX() + 16;
        g.setFill(Color.WHITE);
        g.setFont(nameFont);
        g.fillText(name.toUpperCase(Locale.ROOT), healthBarX, rect.getMinY() + 40);

        g.setFill(Color.web("#B0BEC5"));
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 15));
        int score = bird.playerIndex >= 0 && bird.playerIndex < scores.length ? scores[bird.playerIndex] : 0;
        if (usesSmashCombatRules()) {
            g.fillText("STOCKS", healthBarX, rect.getMinY() + 64);
            double iconSize = rect.getWidth() < 330 ? 18.0 : 20.0;
            drawFightHudStockIcons(g, bird, accent, healthBarX + 72, rect.getMinY() + 46, iconSize);
        } else {
            g.fillText("SCORE " + score, healthBarX, rect.getMinY() + 64);
        }

        double maxHealth = Math.max(1.0, bird.getMaxHealth());
        double shownDamage = displayedDamageForBird(bird);
        double healthRatio = Math.clamp(bird.health / maxHealth, 0.0, 1.0);
        double barRatio = usesSmashCombatRules()
                ? Math.min(1.0, shownDamage / 180.0)
                : healthRatio;
        int shownHealth = (int) Math.round(shownDamage);
        Color healthColor = usesSmashCombatRules()
                ? fightHudDamageColor(shownDamage)
                : fightHudHealthColor(healthRatio);
        if (!usesSmashCombatRules() && bird.health <= 0) {
            healthColor = Color.web("#EF5350");
        }

        g.setTextAlign(TextAlignment.RIGHT);
        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.42));
        g.setFont(FIGHT_HUD_DAMAGE_FONT);
        g.fillText(Integer.toString(shownHealth), rect.getMaxX() - 31, rect.getMinY() + 81);
        g.setFill(healthColor);
        g.fillText(Integer.toString(shownHealth), rect.getMaxX() - 36, rect.getMinY() + 76);
        g.setFont(Font.font("Arial Black", FontWeight.BOLD, 22));
        g.setFill(Color.web("#ECEFF1"));
        g.fillText("%", rect.getMaxX() - 12, rect.getMinY() + 76);
        g.setTextAlign(TextAlignment.LEFT);

        double healthBarY = rect.getMinY() + 82;
        double healthBarW = rect.getWidth() - (healthBarX - rect.getMinX()) - 26;
        double healthBarH = 14;
        g.setFill(Color.web("#111A21", 0.95));
        g.fillRoundRect(healthBarX, healthBarY, healthBarW, healthBarH, 12, 12);
        g.setFill(usesSmashCombatRules() ? Color.web("#16242E") : Color.web("#5F1313"));
        g.fillRoundRect(healthBarX, healthBarY, healthBarW, healthBarH, 12, 12);
        g.setFill(healthColor);
        g.fillRoundRect(healthBarX, healthBarY, healthBarW * barRatio, healthBarH, 12, 12);
        if (!usesSmashCombatRules() && bird.health > maxHealth) {
            double overMax = Math.max(1.0, Bird.STARTING_HEALTH - maxHealth);
            double overRatio = Math.min(1.0, (bird.health - maxHealth) / overMax);
            g.setFill(Color.SILVER.deriveColor(0, 1, 1, 0.84));
            g.fillRoundRect(healthBarX, healthBarY, healthBarW * overRatio, healthBarH, 12, 12);
        }
        g.setStroke(Color.web("#D7E3EA", 0.74));
        g.setLineWidth(1.3);
        g.strokeRoundRect(healthBarX, healthBarY, healthBarW, healthBarH, 12, 12);

        double ultBarX = rect.getMinX() + 18;
        double ultBarY = rect.getMaxY() - 24;
        double ultBarW = rect.getWidth() - 36;
        double ultBarH = 10;
        double ultRatio = bird.getUltimateRatio();
        Color ultColor = bird.isUltimateReady()
                ? Color.web("#FFD54F")
                : Color.web("#4DD0E1");
        g.setFill(Color.web("#071018", 0.96));
        g.fillRoundRect(ultBarX, ultBarY, ultBarW, ultBarH, 12, 12);
        g.setFill(ultColor);
        g.fillRoundRect(ultBarX, ultBarY, ultBarW * ultRatio, ultBarH, 12, 12);
        g.setStroke(Color.web("#F5F7FA", 0.7));
        g.setLineWidth(1.2);
        g.strokeRoundRect(ultBarX, ultBarY, ultBarW, ultBarH, 12, 12);

        g.setFill(Color.web("#B0BEC5"));
        g.setFont(Font.font("Consolas", FontWeight.BOLD, 14));
        g.fillText("ULT", ultBarX, ultBarY - 4);
        g.setTextAlign(TextAlignment.RIGHT);
        g.setFill(bird.isUltimateReady() ? Color.web("#FFF59D") : Color.web("#B3E5FC"));
        g.fillText(
                bird.isUltimateReady() ? "READY" : (int) Math.round(ultRatio * 100.0) + "%",
                ultBarX + ultBarW,
                ultBarY - 4
        );
        g.setTextAlign(TextAlignment.LEFT);
        g.restore();
    }

    private void drawFightHudStockIcons(GraphicsContext g, Bird bird, Color accent, double startX, double y, double size) {
        if (bird == null) {
            return;
        }
        int stocks = Math.clamp(smashStartingStocks(), 0, matchScoreForPlayer(bird.playerIndex));
        WritableImage portrait = fightHudPortraitImage(bird);
        double gap = size <= 18.0 ? 5.0 : 6.0;
        for (int i = 0; i < smashStartingStocks(); i++) {
            double x = startX + i * (size + gap);
            boolean filled = i < stocks;
            g.setFill(Color.web("#02060A", filled ? 0.98 : 0.82));
            g.fillRoundRect(x, y, size, size, 8, 8);
            g.setStroke(accent.deriveColor(0, 1, 1, filled ? 0.9 : 0.26));
            g.setLineWidth(1.25);
            g.strokeRoundRect(x, y, size, size, 8, 8);
            if (portrait != null) {
                g.save();
                g.setGlobalAlpha(filled ? 1.0 : 0.18);
                g.drawImage(portrait, x + 1.5, y + 1.5, size - 3.0, size - 3.0);
                g.restore();
            } else if (filled) {
                g.setFill(accent);
                g.fillOval(x + 3.0, y + 3.0, size - 6.0, size - 6.0);
            }
        }
    }

    private void drawFightStartCountdown(GraphicsContext g) {
        String label = currentMatchIntroLabel();
        if (label == null || label.isBlank()) {
            return;
        }

        boolean go = "GO!".equals(label);
        double plateWidth = go ? 560 : 340;
        double plateHeight = go ? 176 : 196;
        double plateX = WIDTH / 2.0 - plateWidth / 2.0;
        double plateY = 116;
        Color accent = go ? Color.web("#FF7043") : Color.web("#FFD54F");
        Font font = go ? FIGHT_HUD_GO_FONT : FIGHT_HUD_COUNTDOWN_FONT;
        double baselineY = plateY + plateHeight * (go ? 0.74 : 0.76);

        g.setFill(Color.web("#03070B", 0.58));
        g.fillRoundRect(plateX, plateY, plateWidth, plateHeight, 40, 40);
        g.setFill(accent.deriveColor(0, 1, 1, 0.18));
        g.fillRoundRect(plateX, plateY, plateWidth, 18, 40, 40);
        g.setStroke(accent.deriveColor(0, 1, 1, 0.94));
        g.setLineWidth(3.0);
        g.strokeRoundRect(plateX, plateY, plateWidth, plateHeight, 40, 40);

        g.setTextAlign(TextAlignment.CENTER);
        g.setFont(font);
        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.4));
        g.fillText(label, WIDTH / 2.0 + 8, baselineY + 8);
        g.setStroke(go ? Color.web("#BF360C") : Color.web("#5D4037"));
        g.setLineWidth(go ? 8.0 : 10.0);
        g.strokeText(label, WIDTH / 2.0, baselineY);
        g.setFill(go ? Color.web("#FFF3E0") : Color.web("#FFF8E1"));
        g.fillText(label, WIDTH / 2.0, baselineY);
        g.setTextAlign(TextAlignment.LEFT);
    }

    private double hudAlphaForRect(Rectangle2D rect) {
        if (rect == null) return 1.0;
        for (Bird b : players) {
            if (b == null || b.health <= 0) continue;
            Rectangle2D bRect = fightHudScreenBounds(b);
            if (rect.intersects(bRect)) {
                return 0.26;
            }
        }
        return 1.0;
    }

    private Rectangle2D fightHudScreenBounds(Bird bird) {
        double size = Math.max(0.6, bird.sizeMultiplier);
        double width = (bird.type == BirdType.BAT ? 170 : 122) * size * zoom;
        double height = (bird.type == BirdType.BAT ? 120 : 108) * size * zoom;
        double x = (bird.x - 22 * size - camX + currentRenderShakeX) * zoom;
        double y = (bird.y - 18 * size - camY + currentRenderShakeY) * zoom;
        return new Rectangle2D(x, y, width, height);
    }

    private WritableImage fightHudPortraitImage(Bird bird) {
        if (bird == null || bird.type == null) {
            return null;
        }
        String skinKey = skinKeyForBird(bird);
        String cacheKey = bird.type.name() + "|" + (skinKey == null ? "" : skinKey);
        WritableImage cached = fightHudPortraitCache.get(cacheKey);
        if (cached != null) {
            return cached;
        }

        Canvas portrait = new Canvas(128, 128);
        drawRosterSprite(portrait, bird.type, skinKey, false, true);
        SnapshotParameters params = new SnapshotParameters();
        params.setFill(Color.TRANSPARENT);
        WritableImage image = portrait.snapshot(params, null);
        fightHudPortraitCache.put(cacheKey, image);
        return image;
    }

    private Font fitFightHudNameFont(String text, double maxWidth) {
        for (int size = 22; size >= 16; size--) {
            Font trial = Font.font("Arial Black", size);
            if (measureTextWidth(text, trial) <= maxWidth) {
                return trial;
            }
        }
        return Font.font("Arial Black", 16);
    }

    private Color fightHudAccentColor(Bird bird) {
        if (trainingModeActive) {
            return Color.web("#80DEEA");
        }
        if (classicModeActive) {
            return Color.web("#FFE082");
        }
        if (competitionModeEnabled && !storyModeActive && !adventureModeActive) {
            return Color.web("#FFD54F");
        }
        if (bird != null && bird.type != null) {
            Color base = bird.type.color;
            if (base.getBrightness() < 0.22) {
                base = base.interpolate(Color.web("#90CAF9"), 0.55);
            }
            return base.deriveColor(0, 0.92, 1.16, 1.0);
        }
        if (activeMutator != MatchMutator.NONE && !storyModeActive && !adventureModeActive) {
            return Color.web("#80DEEA");
        }
        return Color.web("#90CAF9");
    }

    private Color fightHudHealthColor(double ratio) {
        double clamped = Math.clamp(ratio, 0.0, 1.0);
        if (clamped >= 0.65) {
            return Color.web("#76FF03");
        }
        if (clamped >= 0.35) {
            return Color.web("#FFD54F");
        }
        return Color.web("#FF6E40");
    }

    private Color fightHudDamageColor(double damagePercent) {
        if (damagePercent < 40) {
            return Color.web("#F5F7FA");
        }
        if (damagePercent < 90) {
            return Color.web("#FFD54F");
        }
        if (damagePercent < 150) {
            return Color.web("#FF8A65");
        }
        return Color.web("#EF5350");
    }

    private String formatFightHudTimer(int frames) {
        int totalSeconds = Math.max(0, frames / 60);
        int minutes = totalSeconds / 60;
        int seconds = totalSeconds % 60;
        return String.format(Locale.US, "%d:%02d", minutes, seconds);
    }

    private void drawFightFlashOverlay(GraphicsContext g) {
        if (flashTimer <= 0) {
            return;
        }
        flashTimer--;
        if (flashAlpha > 0) {
            g.setFill(Color.WHITE.deriveColor(0, 1, 1, flashAlpha));
            g.fillRect(0, 0, WIDTH, HEIGHT);
            flashAlpha *= 0.89;
        }
        if (redFlashAlpha > 0) {
            g.setFill(Color.RED.deriveColor(0, 1, 1, redFlashAlpha));
            g.fillRect(0, 0, WIDTH, HEIGHT);
            redFlashAlpha *= 0.86;
        }
    }

    private void drawHealthBar(GraphicsContext g, Bird b, double x) {
        double shownDamage = displayedDamageForBird(b);
        int shownHealth = (int) Math.round(shownDamage);
        double maxHealth = Math.max(1.0, b.getMaxHealth());
        double barWidth = 400;
        double healthHeight = 30;
        double ultimateHeight = 8;
        double gap = 2;
        double totalHeight = healthHeight + ultimateHeight + gap;

        g.setFill(Color.BLACK);
        g.fillRoundRect(x - 3, (double) 82 - 3, barWidth + 6, totalHeight + 6, 10, 10);
        g.setFill(usesSmashCombatRules() ? Color.web("#16242E") : Color.RED);
        g.fillRoundRect(x, 82, barWidth, healthHeight, 10, 10);
        boolean compStyle = competitionModeEnabled && !storyModeActive && !adventureModeActive && !classicModeActive;
        Color baseColor = usesSmashCombatRules()
                ? fightHudDamageColor(shownDamage)
                : (compStyle ? Color.DODGERBLUE : Color.LIME);
        double baseRatio = usesSmashCombatRules()
                ? Math.min(1.0, shownDamage / 180.0)
                : Math.clamp(b.health / maxHealth, 0.0, 1.0);
        g.setFill(baseColor);
        g.fillRoundRect(x, 82, barWidth * baseRatio, healthHeight, 10, 10);

        if (!usesSmashCombatRules() && b.health > maxHealth) {
            double overMax = Math.max(1.0, Bird.STARTING_HEALTH - maxHealth);
            double overRatio = Math.min(1.0, (b.health - maxHealth) / overMax);
            g.setFill(Color.SILVER);
            g.fillRoundRect(x, 82, barWidth * overRatio, healthHeight, 10, 10);
        }

        double ultimateY = (double) 82 + healthHeight + gap;
        g.setFill(Color.BLACK.deriveColor(0, 1, 1, 0.75));
        g.fillRoundRect(x, ultimateY, barWidth, ultimateHeight, 8, 8);
        double ultimateRatio = b.getUltimateRatio();
        g.setFill(b.isUltimateReady() ? Color.GOLD : Color.CYAN);
        g.fillRoundRect(x, ultimateY, barWidth * ultimateRatio, ultimateHeight, 8, 8);
        g.setStroke(Color.WHITE.deriveColor(0, 1, 1, 0.8));
        g.setLineWidth(1.5);
        g.strokeRoundRect(x, ultimateY, barWidth, ultimateHeight, 8, 8);

        g.setFill(Color.WHITE);
        g.setFont(HUD_HEALTH_FONT);
        g.fillText(healthBarLabel(b) + " " + shownHealth + "%", x + 20, (double) 82 + healthHeight - 6);
    }

    String healthBarLabel(Bird bird) {
        if (bird == null) {
            return "";
        }
        String slot = shortName(bird.name);
        String skinKey = skinKeyForBird(bird);
        String birdLabel = bird.isTrueNullRockForm()
                ? "True Null Rock"
                : (skinKey != null ? skinDisplayName(skinKey, bird.type) : bird.type.name);
        if (birdLabel == null || birdLabel.isBlank()) {
            birdLabel = bird.type != null ? bird.type.name : "Unknown";
        }
        return slot.isBlank() ? birdLabel : slot + ": " + birdLabel;
    }

    static String shortName(String fullName) {
        if (fullName == null) {
            return "";
        }
        int colon = fullName.indexOf(':');
        if (colon < 0) {
            return fullName;
        }
        return fullName.substring(0, colon).trim();
    }

    private boolean isDailyChallengeFinalVictory(Bird winner) {
        return dailyChallengeModeActive
                && classicModeActive
                && !classicRun.isEmpty()
                && classicRoundIndex >= classicRun.size() - 1
                && didPlayerWinClassic(winner);
    }

    private boolean shouldGrantDailyFirstClearBonus(Bird winner) {
        return isDailyChallengeFinalVictory(winner)
                && dailyChallengeRunKey != null
                && !dailyChallengeRunKey.isBlank()
                && !dailyChallengeRunKey.equals(dailyChallengeBonusClaimedKey);
    }

    private void markDailyChallengeBonusClaimed() {
        if (dailyChallengeRunKey == null || dailyChallengeRunKey.isBlank()) return;
        dailyChallengeBonusClaimedKey = dailyChallengeRunKey;
        dailyChallengeBonusBird = classicSelectedBird;
    }

    private int dailyChallengeProgressForResult(Bird winner) {
        if (!dailyChallengeModeActive || !classicModeActive || classicRun.isEmpty()) return 0;
        int progress = classicRoundIndex;
        if (didPlayerWinClassic(winner)) {
            progress++;
        }
        return Math.clamp(progress, 0, classicRun.size());
    }

    private void recordDailyChallengeResult(Bird winner) {
        if (!dailyChallengeModeActive || dailyChallengeRunKey == null || dailyChallengeRunKey.isBlank()) return;
        int progress = dailyChallengeProgressForResult(winner);
        if (!dailyChallengeRunKey.equals(dailyChallengeBestKey)) {
            dailyChallengeBestKey = dailyChallengeRunKey;
            dailyChallengeBestProgress = 0;
            dailyChallengeBestBird = null;
        }
        if (progress > dailyChallengeBestProgress || (progress == dailyChallengeBestProgress && dailyChallengeBestBird == null)) {
            dailyChallengeBestProgress = progress;
            dailyChallengeBestBird = classicSelectedBird;
            saveAchievements();
        }
    }

    private int awardBirdCoinsForMatch(Bird winner) {
        if (trainingModeActive) return 0;
        int playerCount = lanModeActive ? countLanConnected() : activePlayers;
        int requestedCoins = 30 + playerCount * 10;
        if (winner != null) requestedCoins += 10;
        if (classicModeActive) requestedCoins += 60;
        else if (adventureModeActive) requestedCoins += 40;
        else if (storyModeActive) requestedCoins += 30;
        if (competitionModeEnabled) requestedCoins += 20;
        if (shouldGrantDailyFirstClearBonus(winner)) {
            requestedCoins += DAILY_CHALLENGE_FIRST_CLEAR_BONUS;
        }

        int verifiedCoins = calculateVerifiedBirdCoinsForMatch(winner);
        int coins = Math.clamp(requestedCoins, 0, verifiedCoins);
        if (coins != requestedCoins) {
            System.err.println("Bird coin payout clamped from " + requestedCoins + " to " + coins + '.');
        }

        grantBirdCoins(coins);
        if (shouldGrantDailyFirstClearBonus(winner)) {
            markDailyChallengeBonusClaimed();
        }
        saveAchievements();
        return coins;
    }

    private boolean isMatchHistoryTeamMode() {
        return (teamModeEnabled && !storyModeActive && !adventureModeActive && !classicModeActive)
                || (storyModeActive && storyTeamMode)
                || (adventureModeActive && adventureTeamMode)
                || (classicModeActive && classicTeamMode);
    }

    private void recordMatchHistory(Bird winner, int coinsEarned) {
        if (matchHistoryRecorded || trainingModeActive) return;
        MatchHistoryEntry entry = buildMatchHistoryEntry(winner, coinsEarned);
        if (entry == null) return;
        matchHistoryRecorded = true;
        matchHistory.addFirst(entry);
        if (matchHistory.size() > MATCH_HISTORY_LIMIT) {
            matchHistory.subList(MATCH_HISTORY_LIMIT, matchHistory.size()).clear();
        }
        saveAchievements();
    }

    private MatchHistoryEntry buildMatchHistoryEntry(Bird winner, int coinsEarned) {
        int slotCount = lanModeActive ? LAN_MAX_PLAYERS : activePlayers;
        boolean teamMode = isMatchHistoryTeamMode();
        int winningTeam = teamMode && winner != null ? getEffectiveTeam(winner.playerIndex) : -1;

        List<MatchHistoryEntry.Participant> participants = new ArrayList<>();
        for (int i = 0; i < slotCount; i++) {
            Bird bird = players[i];
            boolean include = bird != null;
            if (lanModeActive && !include) {
                include = lanSlotConnected[i] || lanSelectedBirds[i] != null;
            }
            if (!include) continue;

            BirdType type = bird != null ? bird.type : lanSelectedBirds[i];
            String slotLabel = bird != null ? shortName(bird.name) : "P" + (i + 1);
            boolean isWinner = teamMode
                    ? winningTeam > 0 && getEffectiveTeam(i) == winningTeam
                    : winner != null && i == winner.playerIndex;
            int health = bird != null ? (int) Math.round(displayedDamageForBird(bird)) : 0;
            participants.add(new MatchHistoryEntry.Participant(
                    slotLabel,
                    type != null ? type.name : "Unknown",
                    Math.max(0, damageDealt[i]),
                    Math.max(0, eliminations[i]),
                    Math.max(0, falls[i]),
                    scores[i],
                    health,
                    isWinner
            ));
        }

        if (participants.isEmpty()) return null;
        Comparator<MatchHistoryEntry.Participant> participantOrder = Comparator
                .comparing(MatchHistoryEntry.Participant::winner).reversed()
                .thenComparing(MatchHistoryEntry.Participant::score, Comparator.reverseOrder());
        if (usesSmashCombatRules()) {
            participantOrder = participantOrder
                    .thenComparing(MatchHistoryEntry.Participant::health)
                    .thenComparing(MatchHistoryEntry.Participant::damage, Comparator.reverseOrder());
        } else {
            participantOrder = participantOrder
                    .thenComparing(MatchHistoryEntry.Participant::damage, Comparator.reverseOrder());
        }
        participants.sort(participantOrder);

        return new MatchHistoryEntry(
                System.currentTimeMillis(),
                currentMatchHistoryMode(),
                currentMatchHistoryDetail(),
                mapDisplayName(selectedMap),
                currentMatchHistoryWinner(winner),
                Math.max(0, coinsEarned),
                participants
        );
    }

    private String currentMatchHistoryMode() {
        if (lanModeActive) return "LAN";
        if (dailyChallengeModeActive) return "DAILY CHALLENGE";
        if (bossRushModeActive && classicModeActive) return "BOSS RUSH";
        if (classicModeActive) return "CLASSIC";
        if (storyModeActive) return "STORY";
        if (adventureModeActive) return "ADVENTURE";
        if (trainingModeActive) return "TRAINING";
        if (competitionModeEnabled) return "COMPETITION";
        return "FIGHT";
    }

    private String currentMatchHistoryDetail() {
        List<String> details = new ArrayList<>();
        int playerCount = lanModeActive ? Math.max(1, countLanConnected()) : activePlayers;
        details.add(playerCount + "P");
        details.add(isMatchHistoryTeamMode() ? "Team Battle" : "Free-for-All");

        if (classicModeActive && classicEncounter != null) {
            if (dailyChallengeModeActive && dailyChallengeRunKey != null && !dailyChallengeRunKey.isBlank()) {
                details.add("Daily " + dailyChallengeRunKey);
            }
            details.add((bossRushModeActive ? "Boss " : "Round ") + (classicRoundIndex + 1) + ": " + classicEncounter.name);
        } else if (storyModeActive) {
            StoryChapter[] chapters = activeStoryChapters();
            if (chapters != null && storyChapterIndex >= 0 && storyChapterIndex < chapters.length) {
                details.add(chapters[storyChapterIndex].title);
            }
        } else if (adventureModeActive) {
            AdventureBattle battle = currentAdventureBattle != null ? currentAdventureBattle : activeAdventureBattle();
            if (battle != null) {
                details.add(battle.title);
            }
        } else if (competitionModeEnabled) {
            details.add("Round " + competitionRoundNumber);
        }

        return String.join("  |  ", details);
    }

    private String currentMatchHistoryWinner(Bird winner) {
        if (winner == null) return "TIME'S UP";
        if (isMatchHistoryTeamMode()) {
            int teamId = getEffectiveTeam(winner.playerIndex);
            return teamId > 0 ? teamLabel(teamId) : "TIME'S UP";
        }
        return shortName(winner.name) + " - " + winner.type.name;
    }

    void showMatchSummary(Stage stage, Bird winner) {
        disposeGameplayMusicPlayer();
        menuMusicPlayer = stopMediaPlayer(menuMusicPlayer, false);
        if (victoryMusicPlayer != null) {
            victoryMusicPlayer.stop();
            if (musicEnabled) victoryMusicPlayer.play();
        }
        VBox root = MenuLayout.buildMenuRoot("-fx-background-color: linear-gradient(to bottom, #0f0c29, #302b63, #24243e);",
                MENU_PADDING, 40);

        Label title = new Label(winner != null ? winner.name.toUpperCase() + " WINS!" : "TIME'S UP!");
        title.setFont(Font.font("Arial Black", 110));
        title.setTextFill(winner != null ? Color.GOLD : Color.SILVER);
        title.setEffect(new DropShadow(50, Color.BLACK));
        title.setWrapText(false);
        applyNoEllipsis(title);

        int coinsEarned = awardBirdCoinsForMatch(winner);
        recordMatchHistory(winner, coinsEarned);
        recordDailyChallengeResult(winner);
        Label coinsLabel = new Label("BIRD COINS +" + coinsEarned + "   TOTAL: " + birdCoinBalanceText());
        coinsLabel.setFont(Font.font("Consolas", 28));
        coinsLabel.setTextFill(Color.web("#FFD54F"));

        // Collect all active birds
        List<Bird> activeBirds = new ArrayList<>();
        for (int i = 0; i < activePlayers; i++) {
            if (players[i] != null) activeBirds.add(players[i]);
        }

        HBox buttons = buildSummaryButtons(stage, winner);
        applyWinnerMapProgress(winner);

        boolean teamSummaryMode = isMatchHistoryTeamMode();
        if (teamSummaryMode) {
            int winningTeam = winner != null ? getEffectiveTeam(winner.playerIndex) : -1;
            title.setText(winningTeam > 0 ? teamLabel(winningTeam) + " WINS!" : "TIME'S UP!");
            title.setTextFill(winningTeam > 0 ? teamColor(winningTeam).brighter() : Color.SILVER);

            Map<Integer, List<Bird>> teams = new HashMap<>();
            for (Bird bird : activeBirds) {
                int teamId = getEffectiveTeam(bird.playerIndex);
                teams.computeIfAbsent(teamId, t -> new ArrayList<>()).add(bird);
            }

            List<Integer> ranking = getIntegers(teams);

            HBox podium = new HBox(70);
            podium.setAlignment(Pos.CENTER);

            for (int idx = 0; idx < ranking.size(); idx++) {
                int teamId = ranking.get(idx);
                List<Bird> members = teams.get(teamId);

                int kills = 0;
                int damage = 0;
                int fallsCount = 0;
                for (Bird bird : members) {
                    kills += eliminations[bird.playerIndex];
                    damage += damageDealt[bird.playerIndex];
                    fallsCount += falls[bird.playerIndex];
                }

                String membersText = members.stream()
                        .map(b -> shortName(b.name))
                        .reduce((a, b) -> a + " + " + b)
                        .orElse("-");

                VBox slot = new VBox(12);
                slot.setAlignment(Pos.CENTER);
                slot.setPadding(new Insets(25));
                slot.setStyle("-fx-background-color: rgba(0,0,0,0.5); -fx-background-radius: 25;");

                Label placeLabel = getLabel(summaryPlaceText(idx + 1));
                placeLabel.setFont(Font.font("Arial Black", 64));
                placeLabel.setTextFill(idx == 0 ? Color.GOLD : idx == 1 ? Color.SILVER : Color.web("#CD7F32"));

                Label teamName = new Label(teamLabel(teamId));
                teamName.setFont(Font.font("Arial Black", 50));
                teamName.setTextFill(teamColor(teamId));

                Label memberLabel = new Label(membersText);
                memberLabel.setFont(Font.font("Arial Black", 28));
                memberLabel.setTextFill(Color.WHITE);

                Label statsLabel = new Label("DMG " + damage + "   KILLS " + kills + "   FALLS " + fallsCount);
                statsLabel.setFont(Font.font("Consolas", 24));
                statsLabel.setTextFill(Color.LIGHTGRAY);

                slot.getChildren().addAll(placeLabel, teamName, memberLabel, statsLabel);
                podium.getChildren().add(slot);
            }

            VBox classicPanel = buildClassicSummaryPanel(winner);
            root.getChildren().addAll(title, coinsLabel);
            if (classicPanel != null) {
                root.getChildren().add(classicPanel);
            }
            root.getChildren().addAll(podium, buttons);
            String bgStyle = root.getStyle();
            root.setStyle("-fx-background-color: transparent;");
            StackPane container = new StackPane(root);
            container.setAlignment(Pos.CENTER);
            container.setStyle(bgStyle);
            container.getProperties().put("noAutoScale", true);
            Scene scene = new Scene(container, WIDTH, HEIGHT);
            bindScaleToFit(scene, root);
            scene.widthProperty().addListener((obs, oldVal, newVal) -> {
                double maxWidth = Math.max(300, newVal.doubleValue() - 120);
                fitLabelSingleLine(title, 110, 56, maxWidth);
            });
            javafx.application.Platform.runLater(() -> {
                double maxWidth = Math.max(300, scene.getWidth() - 120);
                fitLabelSingleLine(title, 110, 56, maxWidth);
            });
            setScenePreservingFullscreen(stage, scene);
            return;
        }

        // Sort by performance (same as before)
        activeBirds.sort((a, b) -> {
            if (a == winner) return -1;
            if (b == winner) return 1;
            return compareBirdPlacements(a, b);
        });

        VBox showcase = buildVictoryShowcase(activeBirds);

        VBox classicPanel = buildClassicSummaryPanel(winner);
        root.getChildren().addAll(title, coinsLabel, showcase);
        if (classicPanel != null) {
            root.getChildren().add(classicPanel);
        }
        root.getChildren().add(buttons);
        String bgStyle = root.getStyle();
        root.setStyle("-fx-background-color: transparent;");
        StackPane container = new StackPane(root);
        container.setAlignment(Pos.CENTER);
        container.setStyle(bgStyle);
        container.getProperties().put("noAutoScale", true);
        Scene scene = new Scene(container, WIDTH, HEIGHT);
        bindScaleToFit(scene, root);
        scene.widthProperty().addListener((obs, oldVal, newVal) -> {
            double maxWidth = Math.max(300, newVal.doubleValue() - 120);
            fitLabelSingleLine(title, 110, 56, maxWidth);
        });
        javafx.application.Platform.runLater(() -> {
            double maxWidth = Math.max(300, scene.getWidth() - 120);
            fitLabelSingleLine(title, 110, 56, maxWidth);
        });
        setScenePreservingFullscreen(stage, scene);
    }

    private VBox buildVictoryShowcase(List<Bird> rankedBirds) {
        VBox showcase = new VBox(26);
        showcase.setAlignment(Pos.CENTER);
        showcase.setMaxWidth(1500);

        if (rankedBirds == null || rankedBirds.isEmpty()) {
            return showcase;
        }

        Bird champion = rankedBirds.getFirst();
        showcase.getChildren().add(buildChampionSummaryCard(champion));

        if (rankedBirds.size() > 1) {
            HBox runners = new HBox(22);
            runners.setAlignment(Pos.TOP_CENTER);
            for (int i = 1; i < rankedBirds.size(); i++) {
                VBox runnerCard = buildRunnerSummaryCard(rankedBirds.get(i), i + 1);
                runnerCard.setTranslateY((i - 1) * 18.0);
                runners.getChildren().add(runnerCard);
            }
            showcase.getChildren().add(runners);
        }

        return showcase;
    }

